canvas_presets.script:
/**
 * Title: The Architect (Transparency Optimized)
 * Description: Matrix-style digital rain.
 */
const CONFIG = { fontSize: 16, fontFamily: 'monospace', textColor: '#0f0', fadeAmount: 0.08, dropSpeed: 1, chars: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%^&*()_+' };
let canvas, ctx, width, height, columns, drops = [];

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        startAnimation();
    } else if (e.data.type === 'resize') resize(e.data.width, e.data.height);
};

function resize(w, h) {
    width = w; height = h; canvas.width = w; canvas.height = h;
    columns = Math.floor(width / CONFIG.fontSize);
    drops = Array(columns).fill(-100);
}

function startAnimation() {
    function render() {
        if (!ctx) return;
        ctx.globalCompositeOperation = 'destination-out';
        ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.fadeAmount})`;
        ctx.fillRect(0, 0, width, height);
        ctx.globalCompositeOperation = 'source-over';
        ctx.font = `${CONFIG.fontSize}px ${CONFIG.fontFamily}`;
        for (let i = 0; i < drops.length; i++) {
            ctx.fillStyle = CONFIG.textColor;
            ctx.fillText(CONFIG.chars.charAt(Math.floor(Math.random() * CONFIG.chars.length)), i * CONFIG.fontSize, drops[i] * CONFIG.fontSize);
            if (drops[i] * CONFIG.fontSize > height && Math.random() > 0.975) drops[i] = 0;
            drops[i] += CONFIG.dropSpeed;
        }
        requestAnimationFrame(render);
    }
    render();
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Aetheric Flow
 * Description: 2,000+ energy filaments in a dynamic noise field.
 */
const CONFIG = { particleCount: 2200, noiseScale: 0.003, fieldStrength: 0.12, baseSpeed: 1.2, fadeAmount: 0.06, hueRange: [180, 260], mouseInfluence: 150 };
let canvas, ctx, width, height, particles = [], mouse = { x: -1000, y: -1000 }, zOff = 0;

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        width = canvas.width = e.data.width; height = canvas.height = e.data.height;
        for (let i = 0; i < CONFIG.particleCount; i++) particles.push({ x: Math.random() * width, y: Math.random() * height, prevX: 0, prevY: 0, speed: Math.random() * CONFIG.baseSpeed + 0.5, hue: Math.random() * (CONFIG.hueRange[1] - CONFIG.hueRange[0]) + CONFIG.hueRange[0] });
        render();
    } else if (e.data.type === 'mousemove') { mouse.x = e.data.x; mouse.y = e.data.y; }
};

function render() {
    ctx.globalCompositeOperation = 'destination-out';
    ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.fadeAmount})`;
    ctx.fillRect(0, 0, width, height);
    ctx.globalCompositeOperation = 'source-over';
    zOff += 0.005;
    particles.forEach(p => {
        p.prevX = p.x; p.prevY = p.y;
        let angle = (Math.sin(p.x * CONFIG.noiseScale) + Math.cos(p.y * CONFIG.noiseScale + zOff)) * Math.PI * 2;
        let dx = mouse.x - p.x, dy = mouse.y - p.y, dist = Math.hypot(dx, dy);
        if (dist < CONFIG.mouseInfluence) angle -= (1 - dist / CONFIG.mouseInfluence) * 2;
        p.x += Math.cos(angle) * p.speed; p.y += Math.sin(angle) * p.speed;
        if (p.x < 0 || p.x > width || p.y < 0 || p.y > height) { p.x = p.prevX = Math.random() * width; p.y = p.prevY = Math.random() * height; }
        ctx.beginPath(); ctx.strokeStyle = `hsla(${p.hue}, 80%, 60%, 0.5)`; ctx.moveTo(p.prevX, p.prevY); ctx.lineTo(p.x, p.y); ctx.stroke();
    });
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Geometric Singularity
 * Description: Recursive 3D wireframe lattice warping toward the mouse.
 */
const CONFIG = { gridDensity: 25, warpStrength: 1.8, rotationSpeed: 0.002, lineColor: '0, 255, 150', perspective: 800 };
let canvas, ctx, width, height, time = 0, mouse = { x: 0, y: 0 };

self.onmessage = (e) => {
    if (e.data.type === 'init') { canvas = e.data.canvas; ctx = canvas.getContext('2d'); width = canvas.width = e.data.width; height = canvas.height = e.data.height; mouse = { x: width/2, y: height/2 }; animate(); }
    else if (e.data.type === 'mousemove') { mouse.x = e.data.x; mouse.y = e.data.y; }
};

function project(x, y, z) {
    let scale = CONFIG.perspective / (CONFIG.perspective + z);
    return { x: x * scale + width / 2, y: y * scale + height / 2 };
}

function animate() {
    ctx.clearRect(0, 0, width, height);
    time += CONFIG.rotationSpeed;
    ctx.lineWidth = 0.6; ctx.strokeStyle = `rgba(${CONFIG.lineColor}, 0.3)`;
    const step = width / CONFIG.gridDensity, size = width * 1.5;
    for (let i = -size; i < size; i += step) {
        ctx.beginPath();
        for (let j = -size; j < size; j += step / 2) {
            let dM = Math.hypot(i - (mouse.x - width/2), j - (mouse.y - height/2));
            let z = Math.sin(i*0.002+time)*100 + Math.cos(j*0.002-time)*100 + (CONFIG.warpStrength*20000/(dM+100));
            let p = project(i, j, z);
            if (j === -size) ctx.moveTo(p.x, p.y); else ctx.lineTo(p.x, p.y);
        }
        ctx.stroke();
    }
    requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Aurora Borealis
 * Description: Flowing, undulating aurora-like ribbons of light with green, teal, and purple hues.
 *              Ribbons sway gently using sine waves and respond subtly to mouse position
 *              by shifting their flow direction.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let ribbons = [];

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

const RIBBON_COUNT = 5;

// Aurora color palette: greens, teals, purples
const PALETTE = [
	{ r: 50, g: 220, b: 130 }, // green
	{ r: 30, g: 200, b: 180 }, // teal
	{ r: 80, g: 180, b: 220 }, // cyan-teal
	{ r: 130, g: 80, b: 220 }, // purple
	{ r: 60, g: 240, b: 160 } // bright green
];

class Ribbon {
	constructor(index) {
		this.index = index;
		this.color = PALETTE[index % PALETTE.length];
		this.yBase = 0;
		this.amplitude = 0;
		this.frequency = 0;
		this.speed = 0;
		this.thickness = 0;
		this.phase = Math.random() * Math.PI * 2;
		this.opacity = 0;
		this.recalculate();
	}

	recalculate() {
		// Position ribbon in upper-to-middle area
		this.yBase = height * (0.15 + this.index * 0.12);
		this.amplitude = height * (0.04 + Math.random() * 0.06);
		this.frequency = 0.002 + Math.random() * 0.002;
		this.speed = 0.008 + Math.random() * 0.006;
		this.thickness = height * (0.06 + Math.random() * 0.08);
		this.opacity = 0.04 + Math.random() * 0.04;
	}

	draw(t) {
		const { r, g, b } = this.color;
		const segments = 80;
		const segWidth = (width + 40) / segments;

		// Mouse influence: shift the ribbon horizontally and vertically
		const mouseFractionX = mouse.x > -1000 ? mouse.x / width - 0.5 : 0;
		const mouseFractionY = mouse.y > -1000 ? mouse.y / height - 0.5 : 0;
		const mouseShiftX = mouseFractionX * 30;
		const mouseShiftY = mouseFractionY * 15;

		// Draw multiple layers for glow
		for (let layer = 0; layer < 3; layer++) {
			const layerOpacity = this.opacity * (1 - layer * 0.3);
			const layerThickness = this.thickness * (1 + layer * 0.8);

			ctx.beginPath();

			for (let i = 0; i <= segments; i++) {
				const x = -20 + i * segWidth;
				const xNorm = x / width;

				// Composite sine wave for organic motion
				const wave1 = Math.sin(x * this.frequency + t * this.speed + this.phase);
				const wave2 =
					Math.sin(x * this.frequency * 1.7 + t * this.speed * 0.6 + this.phase * 2.3) * 0.5;
				const wave3 = Math.sin(x * this.frequency * 0.5 + t * this.speed * 1.3) * 0.3;

				const y =
					this.yBase +
					(wave1 + wave2 + wave3) * this.amplitude +
					mouseShiftY * (1 - Math.abs(xNorm - 0.5) * 1.5) +
					Math.sin(xNorm * Math.PI) * mouseShiftX;

				if (i === 0) {
					ctx.moveTo(x, y);
				} else {
					ctx.lineTo(x, y);
				}
			}

			// Create a gradient stroke that fades at edges
			const grad = ctx.createLinearGradient(0, 0, width, 0);
			grad.addColorStop(0, `rgba(${r}, ${g}, ${b}, 0)`);
			grad.addColorStop(0.15, `rgba(${r}, ${g}, ${b}, ${layerOpacity})`);
			grad.addColorStop(0.5, `rgba(${r}, ${g}, ${b}, ${layerOpacity * 1.2})`);
			grad.addColorStop(0.85, `rgba(${r}, ${g}, ${b}, ${layerOpacity})`);
			grad.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);

			ctx.strokeStyle = grad;
			ctx.lineWidth = layerThickness;
			ctx.lineCap = 'round';
			ctx.lineJoin = 'round';
			ctx.stroke();
		}
	}
}

function initRibbons() {
	ribbons = [];
	for (let i = 0; i < RIBBON_COUNT; i++) {
		ribbons.push(new Ribbon(i));
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Draw ribbons back to front
		for (const ribbon of ribbons) {
			ribbon.draw(time);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initRibbons();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			for (const ribbon of ribbons) {
				ribbon.recalculate();
			}
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Bioluminescence
 * Description: Deep sea bioluminescent flashes and drifting organisms. Soft glowing
 *   creatures pulse and drift through dark water, trailing tentacles. Mouse presence
 *   attracts nearby organisms with a gentle pull.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
	// -- Organisms --
	organismCount: 35,                        // Number of floating organisms (10-80)
	organismSizeMin: 3,                       // Minimum organism body radius in px (1-10)
	organismSizeMax: 12,                      // Maximum organism body radius in px (5-25)
	driftSpeed: 18,                           // Base drift speed in px/s (5-60)
	jitter: 0.4,                              // Organic motion jitter strength (0-2)

	// -- Flashing --
	flashFrequency: 0.08,                     // Probability per frame of an organism flashing (0-0.3)
	flashDuration: 60,                        // Flash duration in frames (20-120)
	flashMaxRadius: 60,                       // Maximum glow radius during a flash in px (20-150)
	flashColorPalette: [                      // Colors organisms can flash — array of rgba strings
		'rgba(0, 255, 200, 1)',                 //   cyan-green
		'rgba(80, 180, 255, 1)',                //   sky blue
		'rgba(150, 80, 255, 1)',                //   purple
		'rgba(0, 255, 120, 1)',                 //   green
		'rgba(255, 120, 200, 1)',               //   pink
	],

	// -- Ambient Glow --
	ambientGlowOpacity: 0.12,                // Resting glow opacity around each organism (0-0.4)
	pulseRate: 0.02,                          // Speed of the ambient breathing pulse (0.005-0.1)

	// -- Tentacles --
	tentacleEnabled: true,                    // Draw trailing tentacles behind organisms
	tentacleLength: 8,                        // Number of tentacle segments (3-20)
	tentacleOpacity: 0.25,                    // Base opacity of tentacle strands (0-1)
	tentacleWidth: 1.5,                       // Width of tentacle lines in px (0.5-4)

	// -- Mouse Interaction --
	mouseAttractionRadius: 250,               // Distance at which mouse attracts organisms in px (50-500)
	mouseAttractionForce: 40,                 // Strength of mouse pull in px/s (5-100)

	// -- Environment --
	backgroundTint: 'rgba(0, 5, 20, 0.08)',  // Subtle background overlay color per frame
	particleCount: 60,                        // Tiny ambient deep-sea particles (0-200)
	particleAlpha: 0.15,                      // Alpha of ambient particles (0-0.5)
	particleSize: 1.5,                        // Size of ambient particles in px (0.5-3)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let organisms = [];
let particles = [];
let frameCount = 0;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── ORGANISM CLASS ─────────────────────────────────────────────────────────
function createOrganism(x, y) {
	const size = CONFIG.organismSizeMin +
		Math.random() * (CONFIG.organismSizeMax - CONFIG.organismSizeMin);
	const colorIndex = Math.floor(Math.random() * CONFIG.flashColorPalette.length);
	return {
		x: x !== undefined ? x : Math.random() * width,
		y: y !== undefined ? y : Math.random() * height,
		vx: (Math.random() - 0.5) * CONFIG.driftSpeed,
		vy: (Math.random() - 0.5) * CONFIG.driftSpeed * 0.5 - CONFIG.driftSpeed * 0.3,
		size,
		baseSize: size,
		colorIndex,
		flashTimer: 0,
		flashColor: null,
		phaseOffset: Math.random() * Math.PI * 2,
		trail: [],        // tentacle history positions
		angle: Math.random() * Math.PI * 2,
		angularVel: (Math.random() - 0.5) * 0.02,
	};
}

function createParticle() {
	return {
		x: Math.random() * width,
		y: Math.random() * height,
		vx: (Math.random() - 0.5) * 4,
		vy: -Math.random() * 3 - 1,
		alpha: Math.random() * CONFIG.particleAlpha,
		size: Math.random() * CONFIG.particleSize + 0.5,
	};
}

// ─── INIT ────────────────────────────────────────────────────────────────────
function initAll() {
	organisms = [];
	particles = [];
	for (let i = 0; i < CONFIG.organismCount; i++) {
		organisms.push(createOrganism());
	}
	for (let i = 0; i < CONFIG.particleCount; i++) {
		particles.push(createParticle());
	}
}

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function parseRgba(str) {
	const m = str.match(/[\d.]+/g);
	if (!m || m.length < 3) return [255, 255, 255, 1];
	return [+m[0], +m[1], +m[2], m[3] !== undefined ? +m[3] : 1];
}

// ─── UPDATE ──────────────────────────────────────────────────────────────────
function updateOrganisms() {
	for (const org of organisms) {
		// Organic jitter
		org.vx += (Math.random() - 0.5) * CONFIG.jitter;
		org.vy += (Math.random() - 0.5) * CONFIG.jitter;

		// Gentle upward drift bias
		org.vy -= 0.05;

		// Mouse attraction
		const dx = mouse.x - org.x;
		const dy = mouse.y - org.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < CONFIG.mouseAttractionRadius && dist > 1) {
			const force = (1 - dist / CONFIG.mouseAttractionRadius) * CONFIG.mouseAttractionForce;
			org.vx += (dx / dist) * force * 0.016;
			org.vy += (dy / dist) * force * 0.016;
		}

		// Damping
		org.vx *= 0.98;
		org.vy *= 0.98;

		// Speed limit
		const speed = Math.sqrt(org.vx * org.vx + org.vy * org.vy);
		const maxSpeed = CONFIG.driftSpeed * 2;
		if (speed > maxSpeed) {
			org.vx = (org.vx / speed) * maxSpeed;
			org.vy = (org.vy / speed) * maxSpeed;
		}

		org.x += org.vx * 0.016;
		org.y += org.vy * 0.016;

		// Wrap around
		if (org.x < -50) org.x = width + 50;
		if (org.x > width + 50) org.x = -50;
		if (org.y < -50) org.y = height + 50;
		if (org.y > height + 50) org.y = -50;

		// Tentacle trail
		if (CONFIG.tentacleEnabled) {
			org.trail.unshift({ x: org.x, y: org.y });
			while (org.trail.length > CONFIG.tentacleLength + 1) {
				org.trail.pop();
			}
		}

		// Flash trigger
		if (org.flashTimer <= 0 && Math.random() < CONFIG.flashFrequency * 0.016) {
			org.flashTimer = CONFIG.flashDuration;
			org.flashColor = CONFIG.flashColorPalette[
				Math.floor(Math.random() * CONFIG.flashColorPalette.length)
			];
		}
		if (org.flashTimer > 0) org.flashTimer--;

		// Rotation
		org.angle += org.angularVel;
	}
}

function updateParticles() {
	for (const p of particles) {
		p.x += p.vx * 0.016;
		p.y += p.vy * 0.016;
		if (p.y < -10) { p.y = height + 10; p.x = Math.random() * width; }
		if (p.x < -10) p.x = width + 10;
		if (p.x > width + 10) p.x = -10;
	}
}

// ─── DRAW ────────────────────────────────────────────────────────────────────
function drawParticles() {
	for (const p of particles) {
		ctx.beginPath();
		ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(100, 180, 255, ${p.alpha})`;
		ctx.fill();
	}
}

function drawOrganisms() {
	for (const org of organisms) {
		const pulse = Math.sin(frameCount * CONFIG.pulseRate + org.phaseOffset) * 0.3 + 0.7;
		const isFlashing = org.flashTimer > 0;
		const flashProgress = isFlashing ? org.flashTimer / CONFIG.flashDuration : 0;
		const flashIntensity = Math.sin(flashProgress * Math.PI); // peaks mid-flash

		// Pick base color
		const colorStr = isFlashing ? org.flashColor :
			CONFIG.flashColorPalette[org.colorIndex];
		const rgba = parseRgba(colorStr);

		// Draw tentacles
		if (CONFIG.tentacleEnabled && org.trail.length > 1) {
			for (let i = 1; i < org.trail.length; i++) {
				const t = 1 - i / org.trail.length;
				const alpha = t * CONFIG.tentacleOpacity * pulse;
				ctx.beginPath();
				ctx.moveTo(org.trail[i - 1].x, org.trail[i - 1].y);
				ctx.lineTo(org.trail[i].x, org.trail[i].y);
				ctx.strokeStyle = `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${alpha.toFixed(3)})`;
				ctx.lineWidth = CONFIG.tentacleWidth * t;
				ctx.stroke();
			}
		}

		// Outer glow (ambient or flash)
		const glowRadius = isFlashing
			? org.size * 2 + flashIntensity * CONFIG.flashMaxRadius
			: org.size * 3 * pulse;
		const glowAlpha = isFlashing
			? flashIntensity * 0.5
			: CONFIG.ambientGlowOpacity * pulse;

		const grad = ctx.createRadialGradient(org.x, org.y, 0, org.x, org.y, glowRadius);
		grad.addColorStop(0, `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${glowAlpha.toFixed(3)})`);
		grad.addColorStop(0.4, `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${(glowAlpha * 0.3).toFixed(3)})`);
		grad.addColorStop(1, 'rgba(0, 0, 0, 0)');
		ctx.fillStyle = grad;
		ctx.beginPath();
		ctx.arc(org.x, org.y, glowRadius, 0, Math.PI * 2);
		ctx.fill();

		// Body
		const bodyAlpha = 0.6 + pulse * 0.4;
		const bodySize = org.size * (0.9 + pulse * 0.1);

		// Soft body shape (slightly elliptical)
		ctx.save();
		ctx.translate(org.x, org.y);
		ctx.rotate(org.angle);
		ctx.scale(1, 0.75);
		ctx.beginPath();
		ctx.arc(0, 0, bodySize, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${(bodyAlpha * 0.4).toFixed(3)})`;
		ctx.fill();

		// Inner nucleus
		ctx.beginPath();
		ctx.arc(0, 0, bodySize * 0.4, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${Math.min(255, rgba[0] + 80)}, ${Math.min(255, rgba[1] + 80)}, ${Math.min(255, rgba[2] + 80)}, ${(bodyAlpha * 0.8).toFixed(3)})`;
		ctx.fill();
		ctx.restore();

		// Flash burst ring
		if (isFlashing && flashIntensity > 0.1) {
			ctx.beginPath();
			ctx.arc(org.x, org.y, org.size + flashIntensity * CONFIG.flashMaxRadius * 0.3, 0, Math.PI * 2);
			ctx.strokeStyle = `rgba(${rgba[0]}, ${rgba[1]}, ${rgba[2]}, ${(flashIntensity * 0.3).toFixed(3)})`;
			ctx.lineWidth = 1;
			ctx.stroke();
		}
	}
}

// ─── ANIMATION LOOP ─────────────────────────────────────────────────────────
function startAnimation() {
	function render() {
		if (!ctx) return;
		frameCount++;

		// Dark water background overlay (creates trail effect)
		ctx.fillStyle = CONFIG.backgroundTint;
		ctx.fillRect(0, 0, width, height);

		updateOrganisms();
		updateParticles();

		drawParticles();

		// Additive glow pass
		ctx.globalCompositeOperation = 'lighter';
		drawOrganisms();
		ctx.globalCompositeOperation = 'source-over';

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── MESSAGE HANDLER ─────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Bioluminescent Plankton
 * Description: 30,000 glowing plankton particles that scatter away from your cursor
 *   in panicked swarms, leaving phosphorescent trails. Move your mouse to watch
 *   them flee and reform — like disturbing a bioluminescent bay at night.
 *   Highly interactive: chase them around the screen!
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const PLANKTON_COUNT   = 30000;          // number of particles
const MOUSE_RADIUS     = 100;            // pixel radius of mouse influence
const FORCE_FACTOR     = 2000;           // flee-from-mouse strength
const FRICTION         = 0.92;           // velocity damping per frame (0–1)
const JITTER           = 0.1;            // random drift each frame
const TRAIL_FADE       = 0.08;           // lower = longer trails (0–1)
const BASE_HUE         = 140;            // hue of the plankton (140 = cyan-green)
const HUE_RANGE        = 40;             // color variation range
const BRIGHTNESS_BOOST = 1.4;            // glow multiplier near mouse
/* --------------------------------------------- */

let canvas, ctx, w, h;
let N = PLANKTON_COUNT;
let px = new Float32Array(N);
let py = new Float32Array(N);
let vx = new Float32Array(N);
let vy = new Float32Array(N);
let mx = -9999, my = -9999;
let mouseInfluenceR2 = MOUSE_RADIUS * MOUSE_RADIUS;
let time = 0;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

function initParticles() {
	for (let i = 0; i < N; i++) {
		px[i] = Math.random() * w;
		py[i] = Math.random() * h;
		vx[i] = 0;
		vy[i] = 0;
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initParticles();
			startAnimation();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initParticles();
			break;
		case 'mousemove':
			mx = e.data.x;
			my = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		time++;

		// Fade previous frame for trail effect
		ctx.fillStyle = `rgba(0, 0, 0, ${TRAIL_FADE})`;
		ctx.fillRect(0, 0, w, h);

		for (let i = 0; i < N; i++) {
			const dx = mx - px[i];
			const dy = my - py[i];
			const d2 = dx * dx + dy * dy;

			// Flee from mouse
			if (d2 < mouseInfluenceR2 && d2 > 0) {
				const f = FORCE_FACTOR / d2;
				vx[i] -= dx * f;
				vy[i] -= dy * f;
			}

			// Apply friction and jitter
			vx[i] *= FRICTION;
			vy[i] *= FRICTION;
			vx[i] += (Math.random() - 0.5) * JITTER;
			vy[i] += (Math.random() - 0.5) * JITTER;

			// Move
			px[i] += vx[i];
			py[i] += vy[i];

			// Wrap edges
			if (px[i] < 0) px[i] = w;
			if (px[i] > w) px[i] = 0;
			if (py[i] < 0) py[i] = h;
			if (py[i] > h) py[i] = 0;

			// Color: hue varies by particle index, brightness by velocity
			const speed = Math.sqrt(vx[i] * vx[i] + vy[i] * vy[i]);
			const hue = (BASE_HUE + (i % HUE_RANGE) - HUE_RANGE / 2 + 360) % 360;
			const brightness = Math.min(100, 40 + speed * BRIGHTNESS_BOOST * 30);
			const alpha = Math.min(1, 0.3 + speed * 0.5);

			// Draw as 1–2px glowing dot
			ctx.fillStyle = `hsla(${hue}, 100%, ${brightness}%, ${alpha})`;
			ctx.fillRect(Math.floor(px[i]), Math.floor(py[i]), speed > 1.5 ? 2 : 1, speed > 1.5 ? 2 : 1);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Bit-Stream Corruption
 * Description: A chaotic storm of digital artifacts and ASCII bits that scramble near the cursor.
 */

const CONFIG = {
    bitCount: 150,
    color: 'rgba(255, 255, 0, 0.4)',
    glitchColor: 'rgba(255, 255, 255, 0.8)',
    chars: ['0', '1', 'X', '_', '|', '§', 'Δ'],
    fontSize: 12,
    noiseForce: 0.5
};

let canvas, ctx, w, h;
let bits = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    bits = [];
    for (let i = 0; i < CONFIG.bitCount; i++) {
        bits.push({
            x: Math.random() * w, y: Math.random() * h,
            char: CONFIG.chars[Math.floor(Math.random() * CONFIG.chars.length)],
            vx: (Math.random() - 0.5) * 4,
            vy: (Math.random() - 0.5) * 4,
            life: Math.random() * 100
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    ctx.font = `${CONFIG.fontSize}px 'JetBrains Mono', monospace`;

    for (let b of bits) {
        let dx = mouse.x - b.x; let dy = mouse.y - b.y;
        let dist = Math.hypot(dx, dy);

        // Glitch Logic: Scramble positions near mouse
        if (dist < 200) {
            b.x += (Math.random() - 0.5) * 15;
            b.y += (Math.random() - 0.5) * 15;
            ctx.fillStyle = CONFIG.glitchColor;
        } else {
            b.x += b.vx; b.y += b.vy;
            ctx.fillStyle = CONFIG.color;
        }

        // Digital drift
        if (Math.random() > 0.98) b.char = CONFIG.chars[Math.floor(Math.random() * CONFIG.chars.length)];

        // Screen Wrap
        if (b.x < 0) b.x = w; if (b.x > w) b.x = 0;
        if (b.y < 0) b.y = h; if (b.y > h) b.y = 0;

        ctx.fillText(b.char, b.x, b.y);
    }
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Blueprint Grid
 * Description: Animated technical blueprint with dimension lines, measurement
 *   annotations, scan line effect, and interactive crosshair targeting.
 *   Mouse creates a crosshair target point with live measurements.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Grid --
  gridSize: 20,                    // Minor grid cell size in px (10-50)
  majorGridInterval: 5,            // Major line every N minor cells (2-10)
  gridColor: 'rgba(30,100,200,0.12)',  // Minor grid line color
  majorGridColor: 'rgba(30,100,200,0.25)', // Major grid line color
  gridOpacity: 1.0,                // Overall grid opacity multiplier (0-1)

  // -- Dimension Lines --
  dimensionLineEnabled: true,      // Show animated dimension lines
  dimensionColor: 'rgba(100,180,255,0.5)', // Dimension line/arrow color
  measurementDensity: 6,           // Number of dimension annotations visible (2-15)

  // -- Annotations --
  annotationEnabled: true,         // Show text annotations
  annotationColor: 'rgba(100,200,255,0.7)', // Annotation text color
  annotationFontSize: 10,          // Font size in px (8-16)

  // -- Scan Line --
  scanLineEnabled: true,           // Enable horizontal scan line sweep
  scanLineSpeed: 1.5,              // Scan line speed (0.5-5.0)
  scanLineColor: 'rgba(0,180,255,0.15)', // Scan line glow color

  // -- Crosshair --
  crosshairEnabled: true,          // Show center crosshair
  crosshairColor: 'rgba(0,200,255,0.4)', // Crosshair line color

  // -- Mouse Interaction --
  // Mouse creates a crosshair target point with coordinate readout
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let dimensions = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initDimensions() {
  dimensions = [];
  for (let i = 0; i < CONFIG.measurementDensity; i++) {
    dimensions.push(createDimension(i));
  }
}

function createDimension(index) {
  const isHoriz = Math.random() > 0.5;
  const gs = CONFIG.gridSize * CONFIG.majorGridInterval;
  const snap = (v) => Math.round(v / gs) * gs;
  if (isHoriz) {
    const y = snap(80 + Math.random() * (height - 160));
    const x1 = snap(40 + Math.random() * (width * 0.3));
    const x2 = snap(x1 + 100 + Math.random() * (width * 0.4));
    return { type: 'h', x1, x2, y, age: Math.random() * 200, lifespan: 300 + Math.random() * 400 };
  } else {
    const x = snap(80 + Math.random() * (width - 160));
    const y1 = snap(40 + Math.random() * (height * 0.3));
    const y2 = snap(y1 + 100 + Math.random() * (height * 0.4));
    return { type: 'v', x, y1, y2, age: Math.random() * 200, lifespan: 300 + Math.random() * 400 };
  }
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initDimensions();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initDimensions();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function startAnimation() {
  let scanY = 0;

  function render() {
    if (!ctx) return;
    time += 1;
    ctx.clearRect(0, 0, width, height);

    const gs = CONFIG.gridSize;
    const major = CONFIG.majorGridInterval;
    const opacity = CONFIG.gridOpacity;

    // ── Minor grid ──
    ctx.lineWidth = 0.5;
    ctx.strokeStyle = CONFIG.gridColor;
    ctx.globalAlpha = opacity;
    ctx.beginPath();
    for (let x = 0; x <= width; x += gs) {
      if ((x / gs) % major === 0) continue;
      ctx.moveTo(x, 0);
      ctx.lineTo(x, height);
    }
    for (let y = 0; y <= height; y += gs) {
      if ((y / gs) % major === 0) continue;
      ctx.moveTo(0, y);
      ctx.lineTo(width, y);
    }
    ctx.stroke();

    // ── Major grid ──
    ctx.lineWidth = 1;
    ctx.strokeStyle = CONFIG.majorGridColor;
    ctx.beginPath();
    for (let x = 0; x <= width; x += gs * major) {
      ctx.moveTo(x, 0);
      ctx.lineTo(x, height);
    }
    for (let y = 0; y <= height; y += gs * major) {
      ctx.moveTo(0, y);
      ctx.lineTo(width, y);
    }
    ctx.stroke();
    ctx.globalAlpha = 1.0;

    // ── Dimension lines ──
    if (CONFIG.dimensionLineEnabled) {
      ctx.lineWidth = 1;
      ctx.setLineDash([4, 3]);

      for (let i = 0; i < dimensions.length; i++) {
        const d = dimensions[i];
        d.age += 1;

        // Fade in/out
        let alpha = 1;
        if (d.age < 30) alpha = d.age / 30;
        else if (d.age > d.lifespan - 30) alpha = (d.lifespan - d.age) / 30;
        if (d.age > d.lifespan) {
          dimensions[i] = createDimension(i);
          continue;
        }
        alpha = Math.max(0, Math.min(1, alpha));

        ctx.strokeStyle = CONFIG.dimensionColor;
        ctx.globalAlpha = alpha;

        if (d.type === 'h') {
          const offset = 8;
          // Horizontal dimension line
          ctx.beginPath();
          ctx.moveTo(d.x1, d.y);
          ctx.lineTo(d.x2, d.y);
          ctx.stroke();
          // Tick marks
          ctx.beginPath();
          ctx.moveTo(d.x1, d.y - offset);
          ctx.lineTo(d.x1, d.y + offset);
          ctx.moveTo(d.x2, d.y - offset);
          ctx.lineTo(d.x2, d.y + offset);
          ctx.stroke();
          // Label
          if (CONFIG.annotationEnabled) {
            const dist = Math.abs(d.x2 - d.x1);
            const label = `${(dist / gs).toFixed(1)} u`;
            ctx.fillStyle = CONFIG.annotationColor;
            ctx.font = `${CONFIG.annotationFontSize}px monospace`;
            ctx.textAlign = 'center';
            ctx.fillText(label, (d.x1 + d.x2) / 2, d.y - 10);
          }
        } else {
          const offset = 8;
          ctx.beginPath();
          ctx.moveTo(d.x, d.y1);
          ctx.lineTo(d.x, d.y2);
          ctx.stroke();
          ctx.beginPath();
          ctx.moveTo(d.x - offset, d.y1);
          ctx.lineTo(d.x + offset, d.y1);
          ctx.moveTo(d.x - offset, d.y2);
          ctx.lineTo(d.x + offset, d.y2);
          ctx.stroke();
          if (CONFIG.annotationEnabled) {
            const dist = Math.abs(d.y2 - d.y1);
            const label = `${(dist / gs).toFixed(1)} u`;
            ctx.save();
            ctx.fillStyle = CONFIG.annotationColor;
            ctx.font = `${CONFIG.annotationFontSize}px monospace`;
            ctx.textAlign = 'center';
            ctx.translate(d.x - 12, (d.y1 + d.y2) / 2);
            ctx.rotate(-Math.PI / 2);
            ctx.fillText(label, 0, 0);
            ctx.restore();
          }
        }
        ctx.globalAlpha = 1.0;
      }
      ctx.setLineDash([]);
    }

    // ── Coordinate labels along edges ──
    if (CONFIG.annotationEnabled) {
      ctx.fillStyle = CONFIG.annotationColor;
      ctx.font = `${CONFIG.annotationFontSize - 1}px monospace`;
      ctx.globalAlpha = 0.4;
      ctx.textAlign = 'center';
      for (let x = gs * major; x < width; x += gs * major) {
        ctx.fillText(`${(x / gs).toFixed(0)}`, x, 12);
      }
      ctx.textAlign = 'left';
      for (let y = gs * major; y < height; y += gs * major) {
        ctx.fillText(`${(y / gs).toFixed(0)}`, 4, y - 3);
      }
      ctx.globalAlpha = 1.0;
    }

    // ── Scan line ──
    if (CONFIG.scanLineEnabled) {
      scanY = (scanY + CONFIG.scanLineSpeed) % height;
      const grad = ctx.createLinearGradient(0, scanY - 40, 0, scanY + 40);
      grad.addColorStop(0, 'rgba(0,0,0,0)');
      grad.addColorStop(0.5, CONFIG.scanLineColor);
      grad.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = grad;
      ctx.fillRect(0, scanY - 40, width, 80);
    }

    // ── Center crosshair ──
    if (CONFIG.crosshairEnabled) {
      const cx = width / 2, cy = height / 2;
      ctx.strokeStyle = CONFIG.crosshairColor;
      ctx.lineWidth = 0.5;
      ctx.setLineDash([8, 6]);
      ctx.beginPath();
      ctx.moveTo(cx, 0); ctx.lineTo(cx, height);
      ctx.moveTo(0, cy); ctx.lineTo(width, cy);
      ctx.stroke();
      ctx.setLineDash([]);

      // Small reticle
      const rSize = 12;
      ctx.strokeStyle = CONFIG.crosshairColor;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(cx, cy, rSize, 0, Math.PI * 2);
      ctx.stroke();
    }

    // ── Mouse target crosshair ──
    if (mouse.x > 0 && mouse.y > 0) {
      const mx = mouse.x, my = mouse.y;

      // Crosshair lines
      ctx.strokeStyle = 'rgba(255,100,100,0.5)';
      ctx.lineWidth = 0.5;
      ctx.setLineDash([4, 4]);
      ctx.beginPath();
      ctx.moveTo(mx, 0); ctx.lineTo(mx, height);
      ctx.moveTo(0, my); ctx.lineTo(width, my);
      ctx.stroke();
      ctx.setLineDash([]);

      // Target reticle
      ctx.strokeStyle = 'rgba(255,100,100,0.7)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(mx, my, 8, 0, Math.PI * 2);
      ctx.stroke();

      // Coordinate readout
      ctx.fillStyle = 'rgba(255,150,150,0.8)';
      ctx.font = `${CONFIG.annotationFontSize}px monospace`;
      ctx.textAlign = 'left';
      const coordLabel = `(${(mx / gs).toFixed(1)}, ${(my / gs).toFixed(1)})`;
      ctx.fillText(coordLabel, mx + 14, my - 10);

      // Distance from center
      const dx = mx - width / 2, dy = my - height / 2;
      const dist = Math.sqrt(dx * dx + dy * dy);
      ctx.fillStyle = 'rgba(255,150,150,0.5)';
      ctx.fillText(`Δ ${(dist / gs).toFixed(1)}u`, mx + 14, my + 4);
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Bubble Pop
 * Description: Iridescent bubbles rise from the bottom of the screen.
 *   Click or tap them to pop them with a satisfying particle burst!
 *   Bubbles wobble, shimmer, and have realistic reflections. Popping
 *   creates chain reactions when bubbles are near each other. Score
 *   fades in as you pop more. Touch-friendly with generous hit zones.
 *
 *   Showcases: click, touchstart (multi-pop), mousemove (bubble flee)
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const MAX_BUBBLES         = 20;       // max simultaneous bubbles
const SPAWN_RATE          = 80;       // frames between spawns
const BUBBLE_MIN_R        = 12;       // min radius
const BUBBLE_MAX_R        = 35;       // max radius
const RISE_SPEED          = 0.5;      // base rise speed
const POP_PARTICLES       = 16;       // particles per pop
const CHAIN_RADIUS        = 60;       // chain reaction radius
const FLEE_STRENGTH       = 0.4;      // how much bubbles flee from cursor
/* --------------------------------------------- */

let canvas, ctx, w, h;
let mouse = { x: -9999, y: -9999 };
let bubbles = [];
let popFx = [];
let score = 0;
let scoreAlpha = 0;
let frameCount = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function createBubble() {
	if (bubbles.length >= MAX_BUBBLES) return;
	const r = BUBBLE_MIN_R + Math.random() * (BUBBLE_MAX_R - BUBBLE_MIN_R);
	bubbles.push({
		x: r + Math.random() * (w - r * 2),
		y: h + r + Math.random() * 50,
		r,
		vx: (Math.random() - 0.5) * 0.5,
		vy: -(RISE_SPEED + Math.random() * 0.5) * (40 / (r + 10)),
		hue: Math.random() * 360,
		wobblePhase: Math.random() * Math.PI * 2,
		wobbleSpeed: 0.02 + Math.random() * 0.02,
		shimmerPhase: Math.random() * Math.PI * 2,
		alpha: 0, // fade in
		alive: true
	});
}

function popBubble(bubble, fromChain) {
	if (!bubble.alive) return;
	bubble.alive = false;
	score++;
	scoreAlpha = 1;

	// Pop particles
	const hue = bubble.hue;
	for (let i = 0; i < POP_PARTICLES; i++) {
		const angle = (i / POP_PARTICLES) * Math.PI * 2;
		const speed = 1.5 + Math.random() * 3;
		popFx.push({
			x: bubble.x,
			y: bubble.y,
			vx: Math.cos(angle) * speed + (Math.random() - 0.5),
			vy: Math.sin(angle) * speed + (Math.random() - 0.5),
			size: 2 + Math.random() * 3,
			hue: hue + (Math.random() - 0.5) * 60,
			alpha: 0.9,
			decay: 0.015 + Math.random() * 0.02,
			iridescent: Math.random() > 0.5
		});
	}

	// Shiny ring
	popFx.push({
		x: bubble.x,
		y: bubble.y,
		vx: 0, vy: 0,
		size: bubble.r,
		hue,
		alpha: 0.5,
		decay: 0.03,
		isRing: true,
		ringRadius: bubble.r
	});

	// Chain reaction
	if (!fromChain) {
		for (const other of bubbles) {
			if (!other.alive || other === bubble) continue;
			const dx = other.x - bubble.x;
			const dy = other.y - bubble.y;
			const dist = Math.sqrt(dx * dx + dy * dy);
			if (dist < CHAIN_RADIUS + other.r) {
				setTimeout(() => popBubble(other, true), 80 + Math.random() * 120);
			}
		}
	}
}

function tryPop(x, y) {
	// Check from top (smallest z-order) to bottom
	for (let i = bubbles.length - 1; i >= 0; i--) {
		const b = bubbles[i];
		if (!b.alive) continue;
		const dx = b.x - x;
		const dy = b.y - y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const hitZone = b.r * 1.3; // generous hit zone
		if (dist < hitZone) {
			popBubble(b, false);
			return true;
		}
	}
	return false;
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			animate();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
		case 'click':
			tryPop(e.data.x, e.data.y);
			break;
		case 'touchstart':
			// Multi-touch: try to pop at each finger
			if (e.data.touches) {
				for (const t of e.data.touches) {
					tryPop(t.x, t.y);
				}
			}
			break;
	}
};

function drawBubble(b) {
	if (b.alpha <= 0) return;
	const t = frameCount;

	ctx.save();
	ctx.globalAlpha = b.alpha * 0.85;

	// Iridescent gradient
	const shimmer = Math.sin(t * 0.03 + b.shimmerPhase) * 30;
	const baseHue = (b.hue + shimmer + t * 0.2) % 360;

	const gradient = ctx.createRadialGradient(
		b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1,
		b.x, b.y, b.r
	);
	gradient.addColorStop(0, `hsla(${baseHue}, 80%, 85%, 0.3)`);
	gradient.addColorStop(0.4, `hsla(${baseHue + 40}, 60%, 70%, 0.15)`);
	gradient.addColorStop(0.8, `hsla(${baseHue + 80}, 50%, 60%, 0.08)`);
	gradient.addColorStop(1, `hsla(${baseHue + 120}, 40%, 50%, 0.02)`);

	ctx.beginPath();
	ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
	ctx.fillStyle = gradient;
	ctx.fill();

	// Outline
	ctx.strokeStyle = `hsla(${baseHue}, 60%, 75%, ${0.25 * b.alpha})`;
	ctx.lineWidth = 1;
	ctx.stroke();

	// Highlight reflection
	ctx.beginPath();
	ctx.ellipse(
		b.x - b.r * 0.25,
		b.y - b.r * 0.3,
		b.r * 0.3,
		b.r * 0.15,
		-0.5,
		0, Math.PI * 2
	);
	ctx.fillStyle = `hsla(0, 0%, 100%, ${0.3 * b.alpha})`;
	ctx.fill();

	// Secondary reflection
	ctx.beginPath();
	ctx.arc(b.x + b.r * 0.15, b.y + b.r * 0.2, b.r * 0.08, 0, Math.PI * 2);
	ctx.fillStyle = `hsla(0, 0%, 100%, ${0.15 * b.alpha})`;
	ctx.fill();

	ctx.restore();
}

function drawPopFx() {
	for (let i = popFx.length - 1; i >= 0; i--) {
		const p = popFx[i];
		p.x += p.vx;
		p.y += p.vy;
		if (!p.isRing) p.vy += 0.03;
		p.alpha -= p.decay;

		if (p.alpha <= 0) {
			popFx.splice(i, 1);
			continue;
		}

		if (p.isRing) {
			p.ringRadius += 2;
			ctx.beginPath();
			ctx.arc(p.x, p.y, p.ringRadius, 0, Math.PI * 2);
			ctx.strokeStyle = `hsla(${p.hue}, 70%, 75%, ${p.alpha})`;
			ctx.lineWidth = 1.5;
			ctx.stroke();
		} else {
			const h = p.iridescent ? (p.hue + frameCount * 3) % 360 : p.hue;
			ctx.fillStyle = `hsla(${h}, 80%, 70%, ${p.alpha})`;
			ctx.beginPath();
			ctx.arc(p.x, p.y, p.size * p.alpha, 0, Math.PI * 2);
			ctx.fill();
		}
	}
}

function animate() {
	if (!ctx) return;
	frameCount++;

	// Background
	ctx.fillStyle = 'rgba(8, 10, 20, 0.12)';
	ctx.fillRect(0, 0, w, h);

	// Spawn bubbles
	if (frameCount % SPAWN_RATE === 0) {
		createBubble();
	}

	// Update bubbles
	for (let i = bubbles.length - 1; i >= 0; i--) {
		const b = bubbles[i];

		if (!b.alive) {
			bubbles.splice(i, 1);
			continue;
		}

		// Fade in
		if (b.alpha < 1) b.alpha = Math.min(1, b.alpha + 0.02);

		// Wobble
		b.x += Math.sin(frameCount * b.wobbleSpeed + b.wobblePhase) * 0.5;
		b.x += b.vx;
		b.y += b.vy;

		// Flee from mouse
		const dx = b.x - mouse.x;
		const dy = b.y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < b.r * 3 && dist > 0) {
			const force = FLEE_STRENGTH * (1 - dist / (b.r * 3));
			b.x += (dx / dist) * force;
			b.y += (dy / dist) * force;
		}

		// Remove if off screen
		if (b.y + b.r < -20 || b.x < -b.r * 2 || b.x > w + b.r * 2) {
			bubbles.splice(i, 1);
			continue;
		}

		drawBubble(b);
	}

	// Pop effects
	drawPopFx();

	// Score display
	if (score > 0) {
		if (scoreAlpha > 0.3) scoreAlpha -= 0.005;
		ctx.save();
		ctx.globalAlpha = scoreAlpha;
		ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
		ctx.font = 'bold 20px sans-serif';
		ctx.textAlign = 'center';
		ctx.fillText('\uD83D\uDCAB ' + score, w / 2, 40);
		ctx.textAlign = 'left';
		ctx.restore();
	}

	// Hint text
	if (bubbles.length === 0 && popFx.length === 0 && score === 0) {
		ctx.fillStyle = 'rgba(255, 255, 255, 0.06)';
		ctx.font = '14px sans-serif';
		ctx.textAlign = 'center';
		ctx.fillText('Wait for bubbles, then pop them! \uD83E\uDEE7', w / 2, h / 2);
		ctx.textAlign = 'left';
	}

	requestAnimationFrame(animate);
}

/**
 * Title: Butterfly Garden
 * Description: A magical garden with colorful butterflies that flutter around.
 *   Move your mouse near butterflies to attract them into a gentle, playful swarm.
 *   Features realistic wing-flapping, sparkle trails, floating pollen, and tiny flowers.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let butterflies = [];
let sparkles = [];
let flowers = [];
let pollen = [];

const CONFIG = {
	butterflyCount: 25,
	sparkleCount: 40,
	flowerCount: 18,
	pollenCount: 30,
	attractRadius: 200,
	attractForce: 0.08,
	wanderSpeed: 0.8,
	wingFlapSpeed: 6,
	sparkleTrailLife: 40,
	sparkleTrailInterval: 4,
	wingColors: [
		{ h1: 320, h2: 280, name: 'pink-purple' },
		{ h1: 270, h2: 240, name: 'purple-blue' },
		{ h1: 200, h2: 260, name: 'blue-violet' },
		{ h1: 30, h2: 50, name: 'orange-yellow' },
		{ h1: 340, h2: 20, name: 'rose-coral' },
		{ h1: 50, h2: 80, name: 'gold-lime' },
		{ h1: 180, h2: 220, name: 'teal-blue' },
		{ h1: 290, h2: 330, name: 'violet-pink' },
	],
	flowerColors: [
		'#ff6b9d', '#c084fc', '#60a5fa', '#fbbf24',
		'#fb923c', '#f472b6', '#a78bfa', '#34d399',
	],
};

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function lerp(a, b, t) { return a + (b - a) * t; }
function dist(x1, y1, x2, y2) {
	const dx = x2 - x1, dy = y2 - y1;
	return Math.sqrt(dx * dx + dy * dy);
}

// ─── Sparkle Trail Particle ────────────────────────────────────────
class SparkleTrail {
	constructor(x, y, hue) {
		this.x = x + rand(-3, 3);
		this.y = y + rand(-3, 3);
		this.vx = rand(-0.3, 0.3);
		this.vy = rand(-0.6, -0.1);
		this.life = CONFIG.sparkleTrailLife;
		this.maxLife = this.life;
		this.size = rand(1, 2.5);
		this.hue = hue + rand(-20, 20);
	}

	update() {
		this.x += this.vx;
		this.y += this.vy;
		this.vy -= 0.005;
		this.life--;
	}

	draw(ctx) {
		const alpha = (this.life / this.maxLife) * 0.6;
		if (alpha <= 0) return;
		const s = this.size * (this.life / this.maxLife);
		ctx.save();
		ctx.globalAlpha = alpha;
		ctx.fillStyle = `hsla(${this.hue}, 90%, 80%, 1)`;
		ctx.shadowColor = `hsla(${this.hue}, 100%, 85%, 0.8)`;
		ctx.shadowBlur = 6;
		// Tiny star shape
		ctx.beginPath();
		for (let i = 0; i < 4; i++) {
			const a = (i / 4) * Math.PI * 2 - Math.PI / 4;
			const ox = Math.cos(a) * s;
			const oy = Math.sin(a) * s;
			if (i === 0) ctx.moveTo(this.x + ox, this.y + oy);
			else ctx.lineTo(this.x + ox, this.y + oy);
			const midA = a + Math.PI / 4;
			ctx.lineTo(this.x + Math.cos(midA) * s * 0.35, this.y + Math.sin(midA) * s * 0.35);
		}
		ctx.closePath();
		ctx.fill();
		ctx.restore();
	}

	get alive() { return this.life > 0; }
}

// ─── Floating Pollen / Sparkle ─────────────────────────────────────
class Pollen {
	constructor() { this.reset(); }

	reset() {
		this.x = rand(0, width || 800);
		this.y = rand(0, height || 600);
		this.vy = rand(-0.4, -0.1);
		this.vx = rand(-0.2, 0.2);
		this.size = rand(1, 3);
		this.alpha = rand(0.15, 0.5);
		this.phase = rand(0, Math.PI * 2);
		this.drift = rand(0.3, 0.8);
		this.hue = rand(40, 70); // warm golden
	}

	update() {
		this.x += this.vx + Math.sin(time * 0.5 + this.phase) * this.drift * 0.3;
		this.y += this.vy;
		if (this.y < -10) { this.y = height + 10; this.x = rand(0, width); }
		if (this.x < -10) this.x = width + 10;
		if (this.x > width + 10) this.x = -10;
	}

	draw(ctx) {
		const pulse = 0.7 + 0.3 * Math.sin(time * 2 + this.phase);
		ctx.save();
		ctx.globalAlpha = this.alpha * pulse;
		const grad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.size * 2);
		grad.addColorStop(0, `hsla(${this.hue}, 100%, 90%, 1)`);
		grad.addColorStop(1, `hsla(${this.hue}, 100%, 80%, 0)`);
		ctx.fillStyle = grad;
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size * 2, 0, Math.PI * 2);
		ctx.fill();
		ctx.restore();
	}
}

// ─── Ground Flower ─────────────────────────────────────────────────
class Flower {
	constructor() {
		this.x = rand(20, (width || 800) - 20);
		this.y = (height || 600) - rand(5, 40);
		this.petalCount = Math.floor(rand(5, 8));
		this.petalSize = rand(5, 10);
		this.color = CONFIG.flowerColors[Math.floor(rand(0, CONFIG.flowerColors.length))];
		this.centerColor = `hsl(${rand(40, 60)}, 100%, 65%)`;
		this.stemHeight = rand(15, 35);
		this.phase = rand(0, Math.PI * 2);
		this.alpha = rand(0.4, 0.7);
	}

	draw(ctx) {
		const sway = Math.sin(time * 0.5 + this.phase) * 3;
		ctx.save();
		ctx.globalAlpha = this.alpha;

		// Stem
		ctx.strokeStyle = 'hsla(120, 50%, 35%, 0.6)';
		ctx.lineWidth = 1.5;
		ctx.beginPath();
		ctx.moveTo(this.x, this.y);
		ctx.quadraticCurveTo(this.x + sway, this.y - this.stemHeight * 0.5, this.x + sway * 0.5, this.y - this.stemHeight);
		ctx.stroke();

		const fx = this.x + sway * 0.5;
		const fy = this.y - this.stemHeight;

		// Petals
		for (let i = 0; i < this.petalCount; i++) {
			const angle = (i / this.petalCount) * Math.PI * 2;
			const px = fx + Math.cos(angle) * this.petalSize * 0.7;
			const py = fy + Math.sin(angle) * this.petalSize * 0.7;
			ctx.beginPath();
			ctx.arc(px, py, this.petalSize * 0.45, 0, Math.PI * 2);
			ctx.fillStyle = this.color;
			ctx.fill();
		}

		// Center
		ctx.beginPath();
		ctx.arc(fx, fy, this.petalSize * 0.3, 0, Math.PI * 2);
		ctx.fillStyle = this.centerColor;
		ctx.fill();

		ctx.restore();
	}
}

// ─── Butterfly ─────────────────────────────────────────────────────
class Butterfly {
	constructor() {
		this.x = rand(50, (width || 800) - 50);
		this.y = rand(50, (height || 600) - 100);
		this.vx = rand(-0.5, 0.5);
		this.vy = rand(-0.5, 0.5);
		this.size = rand(10, 18);
		this.angle = rand(0, Math.PI * 2);
		this.angularVel = 0;
		this.flapPhase = rand(0, Math.PI * 2);
		this.flapSpeed = rand(CONFIG.wingFlapSpeed * 0.8, CONFIG.wingFlapSpeed * 1.2);
		this.wanderAngle = rand(0, Math.PI * 2);
		this.wanderVel = 0;
		this.palette = CONFIG.wingColors[Math.floor(rand(0, CONFIG.wingColors.length))];
		this.lightness = rand(55, 75);
		this.sparkleTimer = 0;
		this.bobPhase = rand(0, Math.PI * 2);
		this.bobAmount = rand(0.3, 0.8);
		// Flight direction for perspective
		this.heading = rand(0, Math.PI * 2);
	}

	update() {
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const d = Math.sqrt(dx * dx + dy * dy);

		// Attraction to mouse
		if (d < CONFIG.attractRadius && d > 20) {
			const force = CONFIG.attractForce * (1 - d / CONFIG.attractRadius);
			this.vx += (dx / d) * force;
			this.vy += (dy / d) * force;
			// Flap faster near mouse (excited)
			this.flapPhase += 0.02;
		} else if (d <= 20 && d > 0) {
			// Too close — gentle repel
			this.vx -= (dx / d) * 0.1;
			this.vy -= (dy / d) * 0.1;
		}

		// Random wandering
		this.wanderVel += rand(-0.06, 0.06);
		this.wanderVel *= 0.9;
		this.wanderAngle += this.wanderVel;
		const wx = Math.cos(this.wanderAngle) * CONFIG.wanderSpeed * 0.3;
		const wy = Math.sin(this.wanderAngle) * CONFIG.wanderSpeed * 0.3;
		this.vx += (wx - this.vx) * 0.02;
		this.vy += (wy - this.vy) * 0.02;

		// Vertical bob
		this.vy += Math.sin(time * 1.5 + this.bobPhase) * 0.02 * this.bobAmount;

		// Speed limit
		const speed = Math.sqrt(this.vx * this.vx + this.vy * this.vy);
		const maxSpeed = 2.5;
		if (speed > maxSpeed) {
			this.vx = (this.vx / speed) * maxSpeed;
			this.vy = (this.vy / speed) * maxSpeed;
		}

		// Damping
		this.vx *= 0.98;
		this.vy *= 0.98;

		this.x += this.vx;
		this.y += this.vy;

		// Update heading based on velocity
		if (speed > 0.2) {
			const targetHeading = Math.atan2(this.vy, this.vx);
			let diff = targetHeading - this.heading;
			while (diff > Math.PI) diff -= Math.PI * 2;
			while (diff < -Math.PI) diff += Math.PI * 2;
			this.heading += diff * 0.08;
		}

		// Soft boundary
		const margin = 40;
		if (this.x < margin) this.vx += 0.1;
		if (this.x > width - margin) this.vx -= 0.1;
		if (this.y < margin) this.vy += 0.1;
		if (this.y > height - margin - 40) this.vy -= 0.1;

		// Wrap if way off screen
		if (this.x < -80) this.x = width + 40;
		if (this.x > width + 80) this.x = -40;
		if (this.y < -80) this.y = height + 40;
		if (this.y > height + 80) this.y = -40;

		// Flap
		this.flapPhase += this.flapSpeed * 0.016;

		// Sparkle trail
		this.sparkleTimer++;
		if (this.sparkleTimer >= CONFIG.sparkleTrailInterval) {
			this.sparkleTimer = 0;
			sparkles.push(new SparkleTrail(this.x, this.y, this.palette.h1));
		}
	}

	draw(ctx) {
		const flap = Math.sin(this.flapPhase);
		// Perspective: wings appear narrower when heading horizontally
		const perspX = Math.cos(this.heading);
		const perspScale = 0.3 + 0.7 * Math.abs(Math.sin(this.heading));

		ctx.save();
		ctx.translate(this.x, this.y);
		// Tilt body slightly in direction of movement
		ctx.rotate(this.heading * 0.15);

		// === Draw Wings ===
		const wingSpan = this.size;
		// Flap creates a scale along the x-axis for each wing
		const flapScale = flap; // -1 to 1

		// Upper wings (larger)
		this.drawWing(ctx, -1, wingSpan * 1.0, wingSpan * 1.3, flapScale, perspScale, true);
		this.drawWing(ctx, 1, wingSpan * 1.0, wingSpan * 1.3, flapScale, perspScale, true);

		// Lower wings (smaller, slightly behind)
		this.drawWing(ctx, -1, wingSpan * 0.65, wingSpan * 0.85, flapScale * 0.8, perspScale, false);
		this.drawWing(ctx, 1, wingSpan * 0.65, wingSpan * 0.85, flapScale * 0.8, perspScale, false);

		// === Body ===
		ctx.beginPath();
		ctx.ellipse(0, 0, 1.5, this.size * 0.35, 0, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(${this.palette.h1}, 30%, 20%, 0.9)`;
		ctx.fill();

		// === Antennae ===
		const antLen = this.size * 0.45;
		ctx.strokeStyle = `hsla(${this.palette.h1}, 30%, 25%, 0.7)`;
		ctx.lineWidth = 0.8;
		for (const side of [-1, 1]) {
			const wave = Math.sin(time * 3 + this.flapPhase + side) * 2;
			ctx.beginPath();
			ctx.moveTo(0, -this.size * 0.25);
			ctx.quadraticCurveTo(
				side * antLen * 0.5 + wave, -this.size * 0.25 - antLen * 0.6,
				side * antLen * 0.6 + wave, -this.size * 0.25 - antLen
			);
			ctx.stroke();
			// Antenna tip
			ctx.beginPath();
			ctx.arc(side * antLen * 0.6 + wave, -this.size * 0.25 - antLen, 1.2, 0, Math.PI * 2);
			ctx.fillStyle = `hsla(${this.palette.h1}, 40%, 30%, 0.7)`;
			ctx.fill();
		}

		ctx.restore();
	}

	drawWing(ctx, side, ww, wh, flapScale, perspScale, isUpper) {
		// side: -1 = left, 1 = right
		const wingWidth = ww * Math.abs(flapScale) * (side === 1 ? perspScale : (2 - perspScale) * 0.5 + 0.5);
		const wingHeight = wh;
		const yOff = isUpper ? -wingHeight * 0.15 : wingHeight * 0.15;

		ctx.save();
		ctx.globalAlpha = 0.55 + 0.3 * Math.abs(flapScale);

		// Wing shape using bezier curves
		ctx.beginPath();
		ctx.moveTo(0, yOff);
		if (isUpper) {
			ctx.bezierCurveTo(
				side * wingWidth * 0.4, yOff - wingHeight * 0.7,
				side * wingWidth * 1.0, yOff - wingHeight * 0.6,
				side * wingWidth, yOff - wingHeight * 0.1
			);
			ctx.bezierCurveTo(
				side * wingWidth * 0.9, yOff + wingHeight * 0.2,
				side * wingWidth * 0.3, yOff + wingHeight * 0.15,
				0, yOff
			);
		} else {
			ctx.bezierCurveTo(
				side * wingWidth * 0.5, yOff + wingHeight * 0.6,
				side * wingWidth * 0.95, yOff + wingHeight * 0.7,
				side * wingWidth * 0.7, yOff + wingHeight * 0.2
			);
			ctx.bezierCurveTo(
				side * wingWidth * 0.4, yOff - wingHeight * 0.05,
				side * wingWidth * 0.15, yOff - wingHeight * 0.05,
				0, yOff
			);
		}
		ctx.closePath();

		// Gradient fill
		const gx1 = 0, gy1 = yOff;
		const gx2 = side * wingWidth, gy2 = yOff;
		const grad = ctx.createLinearGradient(gx1, gy1, gx2, gy2);
		const h1 = this.palette.h1, h2 = this.palette.h2;
		const L = this.lightness;
		grad.addColorStop(0, `hsla(${h1}, 85%, ${L}%, 0.9)`);
		grad.addColorStop(0.4, `hsla(${lerp(h1, h2, 0.4)}, 90%, ${L + 5}%, 0.85)`);
		grad.addColorStop(0.7, `hsla(${h2}, 80%, ${L + 10}%, 0.75)`);
		grad.addColorStop(1, `hsla(${h2}, 70%, ${L + 15}%, 0.5)`);
		ctx.fillStyle = grad;
		ctx.fill();

		// Wing vein pattern — subtle inner line
		ctx.strokeStyle = `hsla(${h1}, 50%, ${L - 15}%, 0.2)`;
		ctx.lineWidth = 0.5;
		ctx.beginPath();
		ctx.moveTo(0, yOff);
		ctx.lineTo(side * wingWidth * 0.6, yOff + (isUpper ? -wingHeight * 0.35 : wingHeight * 0.35));
		ctx.stroke();
		ctx.beginPath();
		ctx.moveTo(0, yOff);
		ctx.lineTo(side * wingWidth * 0.7, yOff + (isUpper ? -wingHeight * 0.1 : wingHeight * 0.15));
		ctx.stroke();

		// Spot decorations on upper wings
		if (isUpper) {
			const sx = side * wingWidth * 0.55;
			const sy = yOff - wingHeight * 0.3;
			const spotR = wingWidth * 0.12;
			const spotGrad = ctx.createRadialGradient(sx, sy, 0, sx, sy, spotR);
			spotGrad.addColorStop(0, `hsla(${h2 + 30}, 90%, 90%, 0.6)`);
			spotGrad.addColorStop(1, `hsla(${h2}, 80%, 70%, 0)`);
			ctx.beginPath();
			ctx.arc(sx, sy, spotR, 0, Math.PI * 2);
			ctx.fillStyle = spotGrad;
			ctx.fill();
		}

		// Wing edge glow
		ctx.strokeStyle = `hsla(${h1}, 70%, ${L + 20}%, 0.15)`;
		ctx.lineWidth = 1;
		ctx.stroke();

		ctx.restore();
	}
}

// ─── Scene Init ────────────────────────────────────────────────────
function initScene() {
	butterflies = [];
	sparkles = [];
	flowers = [];
	pollen = [];

	for (let i = 0; i < CONFIG.butterflyCount; i++) {
		butterflies.push(new Butterfly());
	}
	for (let i = 0; i < CONFIG.flowerCount; i++) {
		flowers.push(new Flower());
	}
	for (let i = 0; i < CONFIG.pollenCount; i++) {
		pollen.push(new Pollen());
	}
}

// ─── Render Loop ───────────────────────────────────────────────────
function startAnimation() {
	function render() {
		if (!ctx) return;
		time += 0.016;
		ctx.clearRect(0, 0, width, height);

		// Draw flowers (background layer)
		for (const f of flowers) {
			f.draw(ctx);
		}

		// Update and draw pollen
		for (const p of pollen) {
			p.update();
			p.draw(ctx);
		}

		// Update and draw sparkle trails
		for (let i = sparkles.length - 1; i >= 0; i--) {
			sparkles[i].update();
			sparkles[i].draw(ctx);
			if (!sparkles[i].alive) sparkles.splice(i, 1);
		}

		// Cap sparkles to prevent memory issues
		if (sparkles.length > 300) {
			sparkles.splice(0, sparkles.length - 300);
		}

		// Update and draw butterflies
		for (const b of butterflies) {
			b.update();
			b.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── Worker Message Handler ────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initScene();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initScene();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Celestial Orrery
 * Description: A luminous astronomical clockwork floating in space. A pulsing golden
 *   star at the center with orbiting gemstone planets leaving glowing trails along
 *   engraved brass orbital rings. Planets with moons, gravitational connection
 *   threads, twinkling background stars, and decorative gear-tooth accents.
 *   Mouse proximity warps orbital speeds; clicks send radial pulse waves.
 */

// ─── CONFIG ────────────────────────────────────────────────────────────────────
const CONFIG = {
	// Star
	starRadius: 22,
	starGlowRadius: 80,
	starPulseSpeed: 0.8,
	starPulseAmount: 0.15,

	// Planets
	planetCount: 6,
	orbitBaseRadius: 80,
	orbitSpacing: 55,
	planetMinSize: 4,
	planetMaxSize: 9,
	trailLength: 60,
	trailMaxAlpha: 0.5,

	// Moons (indices of planets that have moons)
	moonPlanets: [1, 3],
	moonOrbitRadius: 18,
	moonSize: 2.5,
	moonSpeed: 3.5,

	// Orbital rings
	ringAlpha: 0.12,
	ringDashLength: 6,
	ringGapLength: 8,
	gearRings: [1, 4],        // Which rings get gear teeth
	gearTeethCount: 24,
	gearToothSize: 4,

	// Connection threads
	connectionMaxDist: 200,
	connectionAlpha: 0.08,

	// Background stars
	starFieldCount: 100,
	starFieldMaxSize: 1.8,
	twinkleSpeed: 0.4,

	// Interaction
	mouseInfluenceRadius: 180,
	mouseSpeedBoost: 2.5,
	clickPulseSpeed: 200,
	clickPulseDecay: 0.97,
	clickPulseStrength: 0.8,

	// Colors (HSLA hues for gemstone planets)
	planetHues: [0, 220, 145, 38, 280, 175],   // ruby, sapphire, emerald, amber, amethyst, topaz
	planetSats: [72, 68, 65, 75, 60, 70],
	planetLights: [58, 62, 55, 65, 60, 58],

	// Ring color
	ringHue: 42,
	ringSat: 50,
	ringLight: 55,
};

// ─── STATE ─────────────────────────────────────────────────────────────────────
let canvas, ctx, W, H, cx, cy;
let mouse = { x: -9999, y: -9999 };
let time = 0, lastNow = 0;
let planets = [];
let stars = [];
let pulses = [];

// ─── HEARTBEAT ─────────────────────────────────────────────────────────────────
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

// ─── UTILITIES ─────────────────────────────────────────────────────────────────
function rand(a, b) { return Math.random() * (b - a) + a; }

// ─── PLANET ────────────────────────────────────────────────────────────────────
class Planet {
	constructor(index) {
		this.index = index;
		this.orbitRadius = CONFIG.orbitBaseRadius + index * CONFIG.orbitSpacing;
		// Keplerian: period proportional to radius^1.5
		this.baseSpeed = 0.4 / Math.pow(this.orbitRadius / CONFIG.orbitBaseRadius, 1.5);
		this.angle = rand(0, Math.PI * 2);
		this.size = CONFIG.planetMinSize + (CONFIG.planetMaxSize - CONFIG.planetMinSize) * rand(0.3, 1);
		this.hue = CONFIG.planetHues[index % CONFIG.planetHues.length];
		this.sat = CONFIG.planetSats[index % CONFIG.planetSats.length];
		this.light = CONFIG.planetLights[index % CONFIG.planetLights.length];

		// Trail ring buffer
		this.trail = new Float32Array(CONFIG.trailLength * 2);
		this.trailHead = 0;
		this.trailFilled = 0;

		// Moon
		this.hasMoon = CONFIG.moonPlanets.includes(index);
		this.moonAngle = rand(0, Math.PI * 2);

		this.x = 0;
		this.y = 0;
	}

	update(dt) {
		// Mouse gravitational influence
		let speedMult = 1;
		const dx = this.x - mouse.x;
		const dy = this.y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < CONFIG.mouseInfluenceRadius && dist > 1) {
			const influence = 1 - dist / CONFIG.mouseInfluenceRadius;
			speedMult = 1 + influence * influence * (CONFIG.mouseSpeedBoost - 1);
		}

		// Pulse disturbances
		for (const p of pulses) {
			const pdx = this.x - p.x;
			const pdy = this.y - p.y;
			const pdist = Math.sqrt(pdx * pdx + pdy * pdy);
			const ringDist = Math.abs(pdist - p.radius);
			if (ringDist < 40) {
				speedMult += p.strength * (1 - ringDist / 40) * 0.8;
			}
		}

		this.angle += this.baseSpeed * speedMult * dt;

		this.x = cx + Math.cos(this.angle) * this.orbitRadius;
		this.y = cy + Math.sin(this.angle) * this.orbitRadius;

		// Push to trail
		const ti = this.trailHead * 2;
		this.trail[ti] = this.x;
		this.trail[ti + 1] = this.y;
		this.trailHead = (this.trailHead + 1) % CONFIG.trailLength;
		if (this.trailFilled < CONFIG.trailLength) this.trailFilled++;

		// Moon
		if (this.hasMoon) {
			this.moonAngle += CONFIG.moonSpeed * dt;
		}
	}

	drawTrail() {
		if (this.trailFilled < 2) return;
		for (let i = 1; i < this.trailFilled; i++) {
			const idx0 = ((this.trailHead - this.trailFilled + i - 1 + CONFIG.trailLength) % CONFIG.trailLength) * 2;
			const idx1 = ((this.trailHead - this.trailFilled + i + CONFIG.trailLength) % CONFIG.trailLength) * 2;
			const t = i / this.trailFilled;
			const alpha = t * t * CONFIG.trailMaxAlpha;
			const width = t * this.size * 0.6;

			ctx.beginPath();
			ctx.moveTo(this.trail[idx0], this.trail[idx0 + 1]);
			ctx.lineTo(this.trail[idx1], this.trail[idx1 + 1]);
			ctx.strokeStyle = `hsla(${this.hue}, ${this.sat}%, ${this.light}%, ${alpha})`;
			ctx.lineWidth = Math.max(0.5, width);
			ctx.lineCap = 'round';
			ctx.stroke();
		}
	}

	drawPlanet() {
		const s = this.size;

		// Outer glow
		const glow = ctx.createRadialGradient(this.x, this.y, s * 0.5, this.x, this.y, s * 3);
		glow.addColorStop(0, `hsla(${this.hue}, ${this.sat}%, ${this.light}%, 0.25)`);
		glow.addColorStop(1, `hsla(${this.hue}, ${this.sat}%, ${this.light}%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, s * 3, 0, Math.PI * 2);
		ctx.fillStyle = glow;
		ctx.fill();

		// Planet body
		const grad = ctx.createRadialGradient(
			this.x - s * 0.3, this.y - s * 0.3, s * 0.1,
			this.x, this.y, s
		);
		grad.addColorStop(0, `hsla(${this.hue}, ${this.sat - 10}%, ${Math.min(90, this.light + 25)}%, 0.95)`);
		grad.addColorStop(0.6, `hsla(${this.hue}, ${this.sat}%, ${this.light}%, 0.9)`);
		grad.addColorStop(1, `hsla(${this.hue}, ${this.sat + 10}%, ${Math.max(20, this.light - 20)}%, 0.8)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, s, 0, Math.PI * 2);
		ctx.fillStyle = grad;
		ctx.fill();

		// Specular highlight
		ctx.beginPath();
		ctx.arc(this.x - s * 0.25, this.y - s * 0.25, s * 0.35, 0, Math.PI * 2);
		ctx.fillStyle = 'rgba(255, 255, 255, 0.25)';
		ctx.fill();

		// Moon
		if (this.hasMoon) {
			const mx = this.x + Math.cos(this.moonAngle) * CONFIG.moonOrbitRadius;
			const my = this.y + Math.sin(this.moonAngle) * CONFIG.moonOrbitRadius;
			const ms = CONFIG.moonSize;

			// Moon orbit ring
			ctx.beginPath();
			ctx.arc(this.x, this.y, CONFIG.moonOrbitRadius, 0, Math.PI * 2);
			ctx.strokeStyle = `hsla(${this.hue}, 20%, 60%, 0.06)`;
			ctx.lineWidth = 0.5;
			ctx.stroke();

			// Moon glow
			const mg = ctx.createRadialGradient(mx, my, 0, mx, my, ms * 3);
			mg.addColorStop(0, `hsla(${this.hue}, 30%, 80%, 0.2)`);
			mg.addColorStop(1, `hsla(${this.hue}, 30%, 80%, 0)`);
			ctx.beginPath();
			ctx.arc(mx, my, ms * 3, 0, Math.PI * 2);
			ctx.fillStyle = mg;
			ctx.fill();

			// Moon body
			ctx.beginPath();
			ctx.arc(mx, my, ms, 0, Math.PI * 2);
			ctx.fillStyle = `hsla(${this.hue}, 25%, 75%, 0.85)`;
			ctx.fill();
		}
	}
}

// ─── BACKGROUND STAR ───────────────────────────────────────────────────────────
class Star {
	constructor() {
		this.x = rand(0, W || 800);
		this.y = rand(0, H || 600);
		this.size = rand(0.3, CONFIG.starFieldMaxSize);
		this.phase = rand(0, Math.PI * 2);
		this.speed = rand(0.2, CONFIG.twinkleSpeed);
		this.baseAlpha = rand(0.1, 0.4);
	}

	draw(t) {
		const alpha = this.baseAlpha + Math.sin(t * this.speed + this.phase) * this.baseAlpha * 0.6;
		if (alpha <= 0) return;
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(220, 230, 255, ${alpha})`;
		ctx.fill();
	}
}

// ─── CLICK PULSE ───────────────────────────────────────────────────────────────
class Pulse {
	constructor(x, y) {
		this.x = x;
		this.y = y;
		this.radius = 0;
		this.strength = CONFIG.clickPulseStrength;
	}

	update(dt) {
		this.radius += CONFIG.clickPulseSpeed * dt;
		this.strength *= CONFIG.clickPulseDecay;
		return this.strength > 0.01;
	}

	draw() {
		if (this.strength < 0.01) return;
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2);
		ctx.strokeStyle = `rgba(255, 220, 150, ${this.strength * 0.3})`;
		ctx.lineWidth = 2;
		ctx.stroke();
	}
}

// ─── DRAWING HELPERS ───────────────────────────────────────────────────────────

function drawStar() {
	const pulse = 1 + Math.sin(time * CONFIG.starPulseSpeed) * CONFIG.starPulseAmount;
	const r = CONFIG.starRadius * pulse;
	const gr = CONFIG.starGlowRadius * pulse;

	// Outermost corona
	const g3 = ctx.createRadialGradient(cx, cy, r * 0.5, cx, cy, gr * 1.3);
	g3.addColorStop(0, 'rgba(255, 200, 100, 0.06)');
	g3.addColorStop(0.5, 'rgba(255, 180, 60, 0.02)');
	g3.addColorStop(1, 'rgba(255, 160, 40, 0)');
	ctx.beginPath();
	ctx.arc(cx, cy, gr * 1.3, 0, Math.PI * 2);
	ctx.fillStyle = g3;
	ctx.fill();

	// Mid glow
	const g2 = ctx.createRadialGradient(cx, cy, r * 0.3, cx, cy, gr);
	g2.addColorStop(0, 'rgba(255, 230, 160, 0.3)');
	g2.addColorStop(0.4, 'rgba(255, 200, 100, 0.1)');
	g2.addColorStop(1, 'rgba(255, 180, 60, 0)');
	ctx.beginPath();
	ctx.arc(cx, cy, gr, 0, Math.PI * 2);
	ctx.fillStyle = g2;
	ctx.fill();

	// Core
	const g1 = ctx.createRadialGradient(cx - r * 0.15, cy - r * 0.15, r * 0.1, cx, cy, r);
	g1.addColorStop(0, 'rgba(255, 255, 240, 0.95)');
	g1.addColorStop(0.5, 'rgba(255, 220, 140, 0.85)');
	g1.addColorStop(0.85, 'rgba(255, 180, 80, 0.6)');
	g1.addColorStop(1, 'rgba(255, 150, 50, 0.2)');
	ctx.beginPath();
	ctx.arc(cx, cy, r, 0, Math.PI * 2);
	ctx.fillStyle = g1;
	ctx.fill();
}

function drawOrbitalRing(radius, index) {
	const isGear = CONFIG.gearRings.includes(index);
	const h = CONFIG.ringHue;
	const s = CONFIG.ringSat;
	const l = CONFIG.ringLight;

	// Dashed ring
	ctx.beginPath();
	ctx.arc(cx, cy, radius, 0, Math.PI * 2);
	ctx.setLineDash([CONFIG.ringDashLength, CONFIG.ringGapLength]);
	ctx.strokeStyle = `hsla(${h}, ${s}%, ${l}%, ${CONFIG.ringAlpha})`;
	ctx.lineWidth = 1;
	ctx.stroke();
	ctx.setLineDash([]);

	// Gear teeth
	if (isGear) {
		const teeth = CONFIG.gearTeethCount;
		const ts = CONFIG.gearToothSize;
		// Rotate gear slowly based on time
		const gearAngle = time * 0.1 * (index % 2 === 0 ? 1 : -1);
		for (let i = 0; i < teeth; i++) {
			const a = gearAngle + (i / teeth) * Math.PI * 2;
			const outerR = radius + ts;
			const innerR = radius;
			const halfTooth = (Math.PI / teeth) * 0.3;

			ctx.beginPath();
			ctx.moveTo(
				cx + Math.cos(a - halfTooth) * innerR,
				cy + Math.sin(a - halfTooth) * innerR
			);
			ctx.lineTo(
				cx + Math.cos(a - halfTooth * 0.6) * outerR,
				cy + Math.sin(a - halfTooth * 0.6) * outerR
			);
			ctx.lineTo(
				cx + Math.cos(a + halfTooth * 0.6) * outerR,
				cy + Math.sin(a + halfTooth * 0.6) * outerR
			);
			ctx.lineTo(
				cx + Math.cos(a + halfTooth) * innerR,
				cy + Math.sin(a + halfTooth) * innerR
			);
			ctx.closePath();
			ctx.fillStyle = `hsla(${h}, ${s}%, ${l}%, ${CONFIG.ringAlpha * 0.6})`;
			ctx.fill();
		}
	}
}

function drawConnections() {
	const maxDist = CONFIG.connectionMaxDist;
	const maxDistSq = maxDist * maxDist;

	for (let i = 0; i < planets.length; i++) {
		for (let j = i + 1; j < planets.length; j++) {
			const a = planets[i];
			const b = planets[j];
			const dx = a.x - b.x;
			const dy = a.y - b.y;
			const distSq = dx * dx + dy * dy;

			if (distSq < maxDistSq) {
				const dist = Math.sqrt(distSq);
				const t = 1 - dist / maxDist;
				const alpha = t * t * CONFIG.connectionAlpha;
				// Shimmer
				const shimmer = 0.5 + 0.5 * Math.sin(time * 2 + i * 1.7 + j * 2.3);
				const finalAlpha = alpha * shimmer;

				if (finalAlpha > 0.003) {
					const midHue = (a.hue + b.hue) / 2;
					ctx.beginPath();
					ctx.moveTo(a.x, a.y);
					ctx.lineTo(b.x, b.y);
					ctx.strokeStyle = `hsla(${midHue}, 50%, 70%, ${finalAlpha})`;
					ctx.lineWidth = t * 1.5;
					ctx.stroke();
				}
			}
		}
	}
}

// ─── INITIALIZATION ────────────────────────────────────────────────────────────
function initScene() {
	cx = W / 2;
	cy = H / 2;

	planets = [];
	for (let i = 0; i < CONFIG.planetCount; i++) {
		planets.push(new Planet(i));
	}

	stars = [];
	for (let i = 0; i < CONFIG.starFieldCount; i++) {
		stars.push(new Star());
	}

	pulses = [];
}

// ─── RENDER ────────────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) return;

		const dt = Math.min((now - lastNow) / 1000, 0.1);
		lastNow = now;
		time += dt;

		ctx.clearRect(0, 0, W, H);

		// Background stars
		for (const s of stars) {
			s.draw(time);
		}

		// Orbital rings
		for (let i = 0; i < planets.length; i++) {
			drawOrbitalRing(planets[i].orbitRadius, i);
		}

		// Update planets
		for (const p of planets) {
			p.update(dt);
		}

		// Connection threads
		drawConnections();

		// Planet trails (behind planets)
		for (const p of planets) {
			p.drawTrail();
		}

		// Central star (drawn after trails so it glows on top)
		drawStar();

		// Planets (on top of everything)
		for (const p of planets) {
			p.drawPlanet();
		}

		// Click pulses
		for (let i = pulses.length - 1; i >= 0; i--) {
			if (!pulses[i].update(dt)) {
				pulses.splice(i, 1);
			} else {
				pulses[i].draw();
			}
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

function spawnPulse(x, y) {
	if (pulses.length < 5) {
		pulses.push(new Pulse(x, y));
	}
}

// ─── MESSAGE HANDLER ───────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			lastNow = performance.now();
			initScene();
			startAnimation();
			break;
		case 'resize':
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			cx = W / 2;
			cy = H / 2;
			// Recalculate star positions
			for (const s of stars) {
				s.x = rand(0, W);
				s.y = rand(0, H);
			}
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
		case 'click':
			spawnPulse(e.data.x, e.data.y);
			break;
		case 'mousedown':
			break;
		case 'mouseup':
			break;
		case 'touchstart':
			if (e.data.touches && e.data.touches.length > 0) {
				spawnPulse(e.data.touches[0].x, e.data.touches[0].y);
			}
			break;
		case 'touchmove':
			if (e.data.touches && e.data.touches.length > 0) {
				mouse.x = e.data.touches[0].x;
				mouse.y = e.data.touches[0].y;
			}
			break;
		case 'touchend':
			break;
		case 'context':
			break;
	}
};

/**
 * Title: Cell Division
 * Description: Mitosis-like cells that grow, develop a cleavage furrow, and divide
 *   into daughter cells. Features nucleus, membrane, cytoplasm, collision detection,
 *   and mouse repulsion.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Cell Population --
  initialCells: 4,                        // Starting number of cells
  maxCells: 40,                           // Maximum cells before oldest die off
  divisionTime: 400,                      // Frames until a cell divides

  // -- Cell Appearance --
  cellMinRadius: 18,                      // Minimum cell radius in px
  cellMaxRadius: 35,                      // Maximum cell radius (at division time)
  membraneColor: 'rgba(100, 200, 180, 0.4)',  // Cell membrane stroke color
  membraneWidth: 2,                       // Membrane stroke width in px
  nucleusColor: 'rgba(80, 160, 220, 0.5)',    // Nucleus fill color
  nucleusSizeRatio: 0.3,                  // Nucleus radius as fraction of cell radius (0-1)
  cytoplasmColor: 'rgba(120, 220, 200, 0.08)', // Inner cell fill color

  // -- Animation --
  divisionSpeed: 1.0,                     // Division animation speed multiplier (0-3)
  jiggleAmount: 0.5,                      // Random cell movement jitter in px

  // -- Mouse Interaction --
  mouseRepelRadius: 150,                  // Mouse repulsion radius in px
  mouseRepelForce: 5,                     // Mouse repulsion strength (0-15)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let cells = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

class Cell {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.vx = (Math.random() - 0.5) * 0.5;
    this.vy = (Math.random() - 0.5) * 0.5;
    this.age = 0;
    this.dividing = false;
    this.divideProgress = 0;
    this.divideAngle = Math.random() * Math.PI;
    this.wobble = Math.random() * Math.PI * 2;
  }

  get radius() {
    const growth = Math.min(1, this.age / (CONFIG.divisionTime * 0.7));
    return CONFIG.cellMinRadius + (CONFIG.cellMaxRadius - CONFIG.cellMinRadius) * growth;
  }

  update() {
    this.age += CONFIG.divisionSpeed;
    this.wobble += 0.02;

    // Start dividing
    if (!this.dividing && this.age >= CONFIG.divisionTime * 0.8) {
      this.dividing = true;
    }

    if (this.dividing) {
      this.divideProgress = Math.min(1, this.divideProgress + 0.008 * CONFIG.divisionSpeed);
    }

    // Jiggle
    this.vx += (Math.random() - 0.5) * CONFIG.jiggleAmount * 0.1;
    this.vy += (Math.random() - 0.5) * CONFIG.jiggleAmount * 0.1;

    // Mouse repulsion
    const dx = this.x - mouse.x;
    const dy = this.y - mouse.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < CONFIG.mouseRepelRadius && dist > 0) {
      const force = (1 - dist / CONFIG.mouseRepelRadius) * CONFIG.mouseRepelForce * 0.1;
      this.vx += (dx / dist) * force;
      this.vy += (dy / dist) * force;
    }

    // Damping
    this.vx *= 0.95;
    this.vy *= 0.95;
    this.x += this.vx;
    this.y += this.vy;

    // Boundary
    const r = this.radius;
    if (this.x < r) { this.x = r; this.vx *= -0.5; }
    if (this.x > width - r) { this.x = width - r; this.vx *= -0.5; }
    if (this.y < r) { this.y = r; this.vy *= -0.5; }
    if (this.y > height - r) { this.y = height - r; this.vy *= -0.5; }
  }

  draw() {
    const r = this.radius;
    const wobX = Math.sin(this.wobble) * 1.5;
    const wobY = Math.cos(this.wobble * 1.3) * 1.5;

    if (this.dividing && this.divideProgress > 0) {
      // Draw two separating daughter cells
      const sep = this.divideProgress * r * 1.2;
      const cos = Math.cos(this.divideAngle);
      const sin = Math.sin(this.divideAngle);
      const r1 = r * (0.6 + 0.4 * this.divideProgress);
      const r2 = r * (0.6 + 0.4 * this.divideProgress);

      for (let side = -1; side <= 1; side += 2) {
        const cx = this.x + cos * sep * side * 0.5 + wobX;
        const cy = this.y + sin * sep * side * 0.5 + wobY;
        const cr = side === -1 ? r1 : r2;

        // Cytoplasm
        ctx.beginPath();
        ctx.arc(cx, cy, cr * 0.95, 0, Math.PI * 2);
        ctx.fillStyle = CONFIG.cytoplasmColor;
        ctx.fill();

        // Membrane
        ctx.beginPath();
        ctx.arc(cx, cy, cr, 0, Math.PI * 2);
        ctx.strokeStyle = CONFIG.membraneColor;
        ctx.lineWidth = CONFIG.membraneWidth;
        ctx.stroke();

        // Nucleus
        ctx.beginPath();
        ctx.arc(cx, cy, cr * CONFIG.nucleusSizeRatio, 0, Math.PI * 2);
        ctx.fillStyle = CONFIG.nucleusColor;
        ctx.fill();
      }

      // Cleavage furrow line
      if (this.divideProgress < 0.8) {
        const furrLen = r * (1 - this.divideProgress) * 0.8;
        ctx.beginPath();
        ctx.moveTo(this.x - sin * furrLen, this.y + cos * furrLen);
        ctx.lineTo(this.x + sin * furrLen, this.y - cos * furrLen);
        ctx.strokeStyle = CONFIG.membraneColor;
        ctx.lineWidth = CONFIG.membraneWidth * 0.5;
        ctx.stroke();
      }
    } else {
      // Normal cell
      const cx = this.x + wobX;
      const cy = this.y + wobY;

      // Cytoplasm
      ctx.beginPath();
      ctx.arc(cx, cy, r * 0.95, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.cytoplasmColor;
      ctx.fill();

      // Membrane
      ctx.beginPath();
      ctx.arc(cx, cy, r, 0, Math.PI * 2);
      ctx.strokeStyle = CONFIG.membraneColor;
      ctx.lineWidth = CONFIG.membraneWidth;
      ctx.stroke();

      // Nucleus
      ctx.beginPath();
      ctx.arc(cx, cy, r * CONFIG.nucleusSizeRatio, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.nucleusColor;
      ctx.fill();
    }
  }

  shouldDivide() {
    return this.dividing && this.divideProgress >= 1;
  }

  createDaughters() {
    const sep = this.radius * 0.7;
    const cos = Math.cos(this.divideAngle);
    const sin = Math.sin(this.divideAngle);
    const d1 = new Cell(this.x + cos * sep, this.y + sin * sep);
    const d2 = new Cell(this.x - cos * sep, this.y - sin * sep);
    d1.vx = cos * 0.5;
    d1.vy = sin * 0.5;
    d2.vx = -cos * 0.5;
    d2.vy = -sin * 0.5;
    return [d1, d2];
  }
}

function collide(cells) {
  for (let i = 0; i < cells.length; i++) {
    for (let j = i + 1; j < cells.length; j++) {
      const a = cells[i], b = cells[j];
      const dx = b.x - a.x;
      const dy = b.y - a.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const minDist = a.radius + b.radius;
      if (dist < minDist && dist > 0) {
        const overlap = (minDist - dist) * 0.5;
        const nx = dx / dist;
        const ny = dy / dist;
        a.x -= nx * overlap * 0.5;
        a.y -= ny * overlap * 0.5;
        b.x += nx * overlap * 0.5;
        b.y += ny * overlap * 0.5;
        a.vx -= nx * 0.2;
        a.vy -= ny * 0.2;
        b.vx += nx * 0.2;
        b.vy += ny * 0.2;
      }
    }
  }
}

function initCells() {
  cells = [];
  for (let i = 0; i < CONFIG.initialCells; i++) {
    cells.push(new Cell(
      Math.random() * (width - 100) + 50,
      Math.random() * (height - 100) + 50,
    ));
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, width, height);

    // Update and collect new divisions
    const newCells = [];
    const toRemove = [];
    for (let i = 0; i < cells.length; i++) {
      cells[i].update();
      if (cells[i].shouldDivide()) {
        if (cells.length + newCells.length < CONFIG.maxCells) {
          newCells.push(...cells[i].createDaughters());
        }
        toRemove.push(i);
      }
    }

    // Remove divided cells
    for (let i = toRemove.length - 1; i >= 0; i--) {
      cells.splice(toRemove[i], 1);
    }
    cells.push(...newCells);

    // Trim excess
    while (cells.length > CONFIG.maxCells) {
      cells.shift();
    }

    collide(cells);

    // Draw
    for (const cell of cells) {
      cell.draw();
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initCells();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Chroma RGB Liquid Grid – Cyber-Neon Edition
 * Description: Elastic neon lattice that breathes, ripples and explodes into RGB when touched.
 */

let canvas, ctx, width, height;
let points = [];
let mouse = { x: -5000, y: -5000 };
let tick = 0;
let rgbPhase = 0;                // 0-360° hue rotator
let lastMouse = { x: 0, y: 0 };  // for velocity tracking

const CONFIG = {
    // VISUALS
    gridSpacing: 40,
    crossSize: 3,
    colorIdle: 'rgba(255,255,255,0.15)',
    mouseSize: 140,
    mouseForce: 0.7,
    tension: 0.16,
    friction: 0.86,
    breatheSpeed: 0.025,
    breatheDepth: 3,

    // RGB PARTY
    rgbSpeed: 4,               // hue rotation per frame
    rgbRadius: 180,          // how far the RGB wave travels
    rgbIntensity: 0.8,       // 0-1 saturation of RGB
    trailDecay: 0.92        // mouse-trail fade
};

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            startLoop();
            break;
        case 'resize':
            resize(e.data.width, e.data.height);
            break;
        case 'mousemove':
            lastMouse.x = mouse.x;
            lastMouse.y = mouse.y;
            mouse.x = e.data.x;
            mouse.y = e.data.y;
            break;
    }
};

function resize(w, h) {
    width = w;
    height = h;
    if (canvas) {
        canvas.width = width;
        canvas.height = height;
    }
    initGrid();
}

class Point {
    constructor(x, y) {
        this.ox = x;
        this.oy = y;
        this.x = x;
        this.y = y;
        this.vx = 0;
        this.vy = 0;
        this.glow = 0;       // 0-1 RGB glow
    }

    update() {
        // --- forces ---
        let dx = mouse.x - this.x;
        let dy = mouse.y - this.y;
        let dist = Math.hypot(dx, dy);

        // repulsion
        if (dist < CONFIG.mouseSize) {
            let ang = Math.atan2(dy, dx);
            let f = (CONFIG.mouseSize - dist) / CONFIG.mouseSize;
            let push = -f * CONFIG.mouseForce * 25;
            this.vx += Math.cos(ang) * push;
            this.vy += Math.sin(ang) * push;
        }

        // spring back
        let breathe = Math.sin(this.ox * 0.05 + tick) * CONFIG.breatheDepth;
        let dxSpring = this.ox - this.x;
        let dySpring = this.oy - this.y + breathe;
        this.vx += dxSpring * CONFIG.tension;
        this.vy += dySpring * CONFIG.tension;

        // friction
        this.vx *= CONFIG.friction;
        this.vy *= CONFIG.friction;
        this.x += this.vx;
        this.y += this.vy;

        // --- RGB glow ---
        let speed = Math.hypot(this.vx, this.vy);
        let disp = Math.hypot(this.x - this.ox, this.y - this.oy);
        let mouseVel = Math.hypot(mouse.x - lastMouse.x, mouse.y - lastMouse.y);
        let hotRadius = CONFIG.mouseSize + mouseVel * 2;
        let hot = Math.max(0, 1 - dist / hotRadius);
        this.glow = Math.min(1, hot + (speed > 0.3 || disp > 6 ? 0.7 : 0));
        this.glow *= CONFIG.rgbIntensity;
    }

    draw() {
        ctx.save();
        ctx.translate(this.x, this.y);

        // --- color logic ---
        let hue = (rgbPhase + (this.x + this.y) * 0.3) % 360;
        let rgb = `hsl(${hue},100%,${50 + this.glow * 40}%)`;
        let base = this.glow > 0.05 ? rgb : CONFIG.colorIdle;

        // --- crosshair ---
        ctx.strokeStyle = base;
        ctx.lineWidth = 1 + this.glow * 2;
        ctx.beginPath();
        let s = CONFIG.crossSize + this.glow * 3;
        ctx.moveTo(-s, 0); ctx.lineTo(s, 0);
        ctx.moveTo(0, -s); ctx.lineTo(0, s);
        ctx.stroke();

        // --- additive glow ---
        if (this.glow) {
            ctx.strokeStyle = `hsl(${hue},100%,70%)`;
            ctx.lineWidth = 1;
            ctx.globalAlpha = this.glow * 0.6;
            ctx.stroke();
            ctx.globalAlpha = 1;
        }
        ctx.restore();
    }
}

function initGrid() {
    points = [];
    for (let x = 0; x < width + CONFIG.gridSpacing; x += CONFIG.gridSpacing)
        for (let y = 0; y < height + CONFIG.gridSpacing; y += CONFIG.gridSpacing)
            points.push(new Point(x, y));
}

function startLoop() {
    function render() {
        if (!ctx) return;
        ctx.clearRect(0, 0, width, height);

        tick += CONFIG.breatheSpeed;
        rgbPhase = (rgbPhase + CONFIG.rgbSpeed) % 360;

        for (let p of points) {
            p.update();
            p.draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

/**
 * Title: Circuit Board
 * Description: Animated circuit board traces drawn in real-time. Lines travel horizontally
 *   and vertically with 90-degree turns. Glowing nodes at junctions/endpoints.
 *   Mouse creates signal pulses that race along nearby traces. Subtle cyan/green palette.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

const GRID = 20; // grid spacing
const MAX_TRACES = 60;
const MAX_PULSES = 40;
const TRACE_COLOR = 'rgba(0, 180, 160, 0.2)';
const NODE_COLOR = 'rgba(0, 220, 180, 0.5)';
const PULSE_COLOR = 'rgba(0, 255, 200, 0.9)';

let traces = [];
let pulses = [];
let activeTraces = []; // traces currently being drawn
let lastPulseTime = 0;

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			traces = [];
			activeTraces = [];
			pulses = [];
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function snapToGrid(v) {
	return Math.round(v / GRID) * GRID;
}

function init() {
	traces = [];
	activeTraces = [];
	pulses = [];
}

// A trace is a series of connected segments (polyline on the grid)
function spawnTrace() {
	const startX = snapToGrid(Math.random() * width);
	const startY = snapToGrid(Math.random() * height);
	// Direction: 0=right, 1=down, 2=left, 3=up
	const dir = Math.floor(Math.random() * 4);
	const segmentCount = 3 + Math.floor(Math.random() * 8);

	return {
		points: [{ x: startX, y: startY }],
		targetPoints: generatePath(startX, startY, dir, segmentCount),
		currentSegment: 0,
		progress: 0, // 0-1 along current segment
		speed: 0.02 + Math.random() * 0.03,
		complete: false,
		opacity: 0.15 + Math.random() * 0.15
	};
}

function generatePath(sx, sy, startDir, count) {
	const pts = [{ x: sx, y: sy }];
	let dir = startDir;
	let cx = sx,
		cy = sy;

	for (let i = 0; i < count; i++) {
		const len = (2 + Math.floor(Math.random() * 8)) * GRID;
		const dx = [1, 0, -1, 0][dir];
		const dy = [0, 1, 0, -1][dir];
		cx += dx * len;
		cy += dy * len;
		// Clamp to canvas
		cx = Math.max(0, Math.min(width, cx));
		cy = Math.max(0, Math.min(height, cy));
		pts.push({ x: cx, y: cy });
		// Turn 90 degrees (randomly left or right)
		dir = (dir + (Math.random() < 0.5 ? 1 : 3)) % 4;
	}
	return pts;
}

function spawnPulse(trace) {
	if (trace.targetPoints.length < 2) return;
	return {
		trace: trace,
		segment: 0,
		progress: 0,
		speed: 0.03 + Math.random() * 0.02,
		life: 1.0
	};
}

function startAnimation() {
	let frameCount = 0;

	function render(time) {
		if (!ctx) return;
		frameCount++;

		ctx.clearRect(0, 0, width, height);

		// Spawn new traces periodically
		if (frameCount % 30 === 0 && activeTraces.length < 3 && traces.length < MAX_TRACES) {
			activeTraces.push(spawnTrace());
		}

		// Update and draw active (growing) traces
		for (let i = activeTraces.length - 1; i >= 0; i--) {
			const t = activeTraces[i];

			if (t.currentSegment < t.targetPoints.length - 1) {
				t.progress += t.speed;
				if (t.progress >= 1) {
					t.progress = 0;
					t.currentSegment++;
					// Add completed point
					if (t.currentSegment < t.targetPoints.length) {
						t.points.push({
							x: t.targetPoints[t.currentSegment].x,
							y: t.targetPoints[t.currentSegment].y
						});
					}
				}
			} else {
				t.complete = true;
				traces.push(t);
				activeTraces.splice(i, 1);
			}
		}

		// Remove oldest traces if over limit
		while (traces.length > MAX_TRACES) {
			traces.shift();
		}

		// Draw all completed traces
		for (const t of traces) {
			drawTrace(t);
		}

		// Draw active traces (partially drawn)
		for (const t of activeTraces) {
			drawActiveTrace(t);
		}

		// Mouse pulse spawning — find nearby completed traces
		if (time - lastPulseTime > 300) {
			for (const t of traces) {
				if (pulses.length >= MAX_PULSES) break;
				for (const pt of t.targetPoints) {
					const dx = pt.x - mouse.x;
					const dy = pt.y - mouse.y;
					if (dx * dx + dy * dy < 150 * 150) {
						const p = spawnPulse(t);
						if (p) pulses.push(p);
						lastPulseTime = time;
						break;
					}
				}
			}
		}

		// Update and draw pulses
		for (let i = pulses.length - 1; i >= 0; i--) {
			const p = pulses[i];
			p.progress += p.speed;
			if (p.progress >= 1) {
				p.progress = 0;
				p.segment++;
			}
			p.life -= 0.005;

			if (p.segment >= p.trace.targetPoints.length - 1 || p.life <= 0) {
				pulses.splice(i, 1);
				continue;
			}

			// Interpolate pulse position
			const a = p.trace.targetPoints[p.segment];
			const b = p.trace.targetPoints[p.segment + 1];
			const px = a.x + (b.x - a.x) * p.progress;
			const py = a.y + (b.y - a.y) * p.progress;

			ctx.beginPath();
			ctx.arc(px, py, 3, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(0, 255, 200, ${p.life * 0.8})`;
			ctx.shadowColor = 'rgba(0, 255, 200, 0.6)';
			ctx.shadowBlur = 10;
			ctx.fill();
			ctx.shadowBlur = 0;
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

function drawTrace(t) {
	if (t.targetPoints.length < 2) return;

	ctx.beginPath();
	ctx.moveTo(t.targetPoints[0].x, t.targetPoints[0].y);
	for (let i = 1; i < t.targetPoints.length; i++) {
		ctx.lineTo(t.targetPoints[i].x, t.targetPoints[i].y);
	}
	ctx.strokeStyle = `rgba(0, 180, 160, ${t.opacity})`;
	ctx.lineWidth = 1.5;
	ctx.stroke();

	// Draw nodes at junctions
	for (let i = 0; i < t.targetPoints.length; i++) {
		const pt = t.targetPoints[i];
		// Glow brighter if mouse is near
		const dx = pt.x - mouse.x;
		const dy = pt.y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		const glow = dist < 120 ? 0.6 + (1 - dist / 120) * 0.4 : 0.3;

		ctx.beginPath();
		ctx.arc(pt.x, pt.y, 2.5, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(0, 220, 180, ${glow * t.opacity * 2})`;
		ctx.fill();
	}
}

function drawActiveTrace(t) {
	if (t.points.length < 1 || t.currentSegment >= t.targetPoints.length - 1) return;

	// Draw completed segments
	ctx.beginPath();
	ctx.moveTo(t.points[0].x, t.points[0].y);
	for (let i = 1; i < t.points.length; i++) {
		ctx.lineTo(t.points[i].x, t.points[i].y);
	}

	// Draw current segment (in progress)
	const a = t.targetPoints[t.currentSegment];
	const b = t.targetPoints[t.currentSegment + 1];
	const cx = a.x + (b.x - a.x) * t.progress;
	const cy = a.y + (b.y - a.y) * t.progress;
	ctx.lineTo(cx, cy);

	ctx.strokeStyle = `rgba(0, 220, 180, ${t.opacity * 1.5})`;
	ctx.lineWidth = 1.5;
	ctx.stroke();

	// Glowing tip
	ctx.beginPath();
	ctx.arc(cx, cy, 3, 0, Math.PI * 2);
	ctx.fillStyle = 'rgba(0, 255, 220, 0.8)';
	ctx.shadowColor = 'rgba(0, 255, 220, 0.6)';
	ctx.shadowBlur = 8;
	ctx.fill();
	ctx.shadowBlur = 0;

	// Draw completed nodes
	for (const pt of t.points) {
		ctx.beginPath();
		ctx.arc(pt.x, pt.y, 2, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(0, 220, 180, ${t.opacity * 2})`;
		ctx.fill();
	}
}

/**
 * Title: Comet Shower
 * Description: Comets streak diagonally across the sky with glowing heads and
 *   sparkling fading tails. Mouse gravity pulls nearby comets toward the cursor.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Comet Spawning --
  cometFrequency: 600,                    // Average ms between comet spawns
  cometFrequencyVariance: 400,            // ± random ms added to frequency
  maxComets: 15,                          // Maximum simultaneous comets on screen

  // -- Comet Appearance --
  cometSize: 3.5,                         // Head radius in px
  headGlowRadius: 18,                     // Glow halo around comet head in px
  headGlowOpacity: 0.6,                   // Head glow intensity (0-1)
  colorPalette: [                         // Array of comet head/tail colors
    'rgba(100, 180, 255, 1)',             //   Cool blue
    'rgba(255, 160, 80, 1)',              //   Warm orange
    'rgba(180, 120, 255, 1)',             //   Purple
    'rgba(100, 255, 200, 1)',             //   Teal
    'rgba(255, 255, 150, 1)',             //   Pale gold
  ],

  // -- Tail --
  tailLength: 45,                         // Number of trail points stored
  tailFade: 0.92,                         // Opacity decay per trail point (0-1)
  tailWidth: 2.5,                         // Base tail stroke width in px
  sparkleDensity: 0.4,                    // Chance per trail point to emit a sparkle (0-1)
  sparkleSize: 1.8,                       // Sparkle particle radius in px
  sparkleLife: 40,                        // Sparkle lifetime in frames

  // -- Motion --
  minSpeed: 4,                            // Minimum comet travel speed in px/frame
  maxSpeed: 9,                            // Maximum comet travel speed in px/frame
  angle: 225,                             // Travel direction in degrees (0=right, 90=down, 225=upper-right to lower-left)
  angleVariance: 20,                      // ± random degrees of angle spread

  // -- Mouse Interaction --
  mouseGravityRadius: 250,                // Radius of mouse gravity pull in px
  mouseGravityStrength: 3.5,              // Strength of gravitational pull toward mouse
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let comets = [];
let sparkles = [];
let lastSpawnTime = 0;
let nextSpawnDelay = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function parseRGBA(str) {
  const m = str.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3] };
  return { r: 200, g: 200, b: 255 };
}

function spawnComet() {
  const angleRad = (CONFIG.angle + (Math.random() - 0.5) * CONFIG.angleVariance * 2) * Math.PI / 180;
  const speed = CONFIG.minSpeed + Math.random() * (CONFIG.maxSpeed - CONFIG.minSpeed);
  const vx = Math.cos(angleRad) * speed;
  const vy = Math.sin(angleRad) * speed;

  // Spawn from the edge the comet is coming from
  let x, y;
  if (vx < 0) {
    x = width + 50;
  } else {
    x = -50;
  }
  if (vy < 0) {
    y = height + 50;
  } else {
    y = -50;
  }
  // Add randomness along the perpendicular axis
  x += (Math.random() - 0.3) * width * 0.6;
  y += (Math.random() - 0.3) * height * 0.4;

  const colorStr = CONFIG.colorPalette[Math.floor(Math.random() * CONFIG.colorPalette.length)];
  const color = parseRGBA(colorStr);

  comets.push({
    x, y, vx, vy, speed,
    color,
    colorStr,
    trail: [],
  });
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    const now = performance.now();

    ctx.clearRect(0, 0, width, height);

    // Spawn comets
    if (now - lastSpawnTime > nextSpawnDelay && comets.length < CONFIG.maxComets) {
      spawnComet();
      lastSpawnTime = now;
      nextSpawnDelay = CONFIG.cometFrequency + (Math.random() - 0.5) * 2 * CONFIG.cometFrequencyVariance;
    }

    // Update and draw comets
    for (let i = comets.length - 1; i >= 0; i--) {
      const c = comets[i];

      // Mouse gravity
      const dx = mouse.x - c.x;
      const dy = mouse.y - c.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONFIG.mouseGravityRadius && dist > 1) {
        const factor = (1 - dist / CONFIG.mouseGravityRadius);
        c.vx += (dx / dist) * CONFIG.mouseGravityStrength * factor * 0.1;
        c.vy += (dy / dist) * CONFIG.mouseGravityStrength * factor * 0.1;
      }

      c.x += c.vx;
      c.y += c.vy;

      // Store trail
      c.trail.unshift({ x: c.x, y: c.y });
      if (c.trail.length > CONFIG.tailLength) c.trail.pop();

      // Remove if off-screen
      const margin = 100;
      if (c.x < -margin || c.x > width + margin || c.y < -margin || c.y > height + margin) {
        comets.splice(i, 1);
        continue;
      }

      // Emit sparkles from trail
      for (let t = 1; t < c.trail.length; t++) {
        if (Math.random() < CONFIG.sparkleDensity * 0.1) {
          sparkles.push({
            x: c.trail[t].x + (Math.random() - 0.5) * 6,
            y: c.trail[t].y + (Math.random() - 0.5) * 6,
            life: CONFIG.sparkleLife,
            maxLife: CONFIG.sparkleLife,
            color: c.color,
          });
        }
      }

      // Draw tail
      if (c.trail.length > 1) {
        for (let t = 1; t < c.trail.length; t++) {
          const alpha = Math.pow(CONFIG.tailFade, t);
          if (alpha < 0.01) break;
          const w = CONFIG.tailWidth * (1 - t / c.trail.length);
          ctx.beginPath();
          ctx.moveTo(c.trail[t - 1].x, c.trail[t - 1].y);
          ctx.lineTo(c.trail[t].x, c.trail[t].y);
          ctx.strokeStyle = `rgba(${c.color.r}, ${c.color.g}, ${c.color.b}, ${alpha})`;
          ctx.lineWidth = Math.max(0.5, w);
          ctx.lineCap = 'round';
          ctx.stroke();
        }
      }

      // Draw head glow
      const headGrad = ctx.createRadialGradient(c.x, c.y, 0, c.x, c.y, CONFIG.headGlowRadius);
      headGrad.addColorStop(0, `rgba(${c.color.r}, ${c.color.g}, ${c.color.b}, ${CONFIG.headGlowOpacity})`);
      headGrad.addColorStop(1, `rgba(${c.color.r}, ${c.color.g}, ${c.color.b}, 0)`);
      ctx.fillStyle = headGrad;
      ctx.beginPath();
      ctx.arc(c.x, c.y, CONFIG.headGlowRadius, 0, Math.PI * 2);
      ctx.fill();

      // Draw head
      ctx.beginPath();
      ctx.arc(c.x, c.y, CONFIG.cometSize, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${Math.min(255, c.color.r + 60)}, ${Math.min(255, c.color.g + 60)}, ${Math.min(255, c.color.b + 60)}, 1)`;
      ctx.fill();
    }

    // Update and draw sparkles
    for (let i = sparkles.length - 1; i >= 0; i--) {
      const s = sparkles[i];
      s.life--;
      if (s.life <= 0) {
        sparkles.splice(i, 1);
        continue;
      }
      const alpha = (s.life / s.maxLife) * 0.8;
      ctx.beginPath();
      ctx.arc(s.x, s.y, CONFIG.sparkleSize * (s.life / s.maxLife), 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${s.color.r}, ${s.color.g}, ${s.color.b}, ${alpha})`;
      ctx.fill();
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Constellation Map
 * Description: Randomly placed stars that form connection lines (like constellation patterns)
 *              to nearby stars within a threshold distance. Stars slowly drift across the canvas.
 *              Mouse creates a gravitational pull that attracts nearby stars.
 *              Connection line opacity is based on inter-star distance.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let stars = [];

const STAR_COUNT = 120;
const CONNECTION_DIST = 150;
const MOUSE_RADIUS = 250;
const MOUSE_GRAVITY = 0.015;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Star {
	constructor() {
		this.init();
	}

	init() {
		this.x = Math.random() * width;
		this.y = Math.random() * height;
		this.vx = (Math.random() - 0.5) * 0.2;
		this.vy = (Math.random() - 0.5) * 0.2;
		this.size = 0.8 + Math.random() * 1.8;
		this.brightness = 0.3 + Math.random() * 0.7;
		// Subtle twinkle
		this.twinkleSpeed = 0.02 + Math.random() * 0.03;
		this.twinklePhase = Math.random() * Math.PI * 2;
		this.twinkleAmount = 0.1 + Math.random() * 0.3;
		// Slight color variation (white to pale blue/gold)
		const hueRoll = Math.random();
		if (hueRoll < 0.6) {
			this.color = { r: 220, g: 230, b: 255 }; // pale blue-white
		} else if (hueRoll < 0.8) {
			this.color = { r: 255, g: 240, b: 200 }; // warm white
		} else {
			this.color = { r: 200, g: 220, b: 255 }; // blue
		}
	}

	update(time) {
		// Gravitational pull from mouse
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const dist = Math.sqrt(dx * dx + dy * dy);

		if (dist < MOUSE_RADIUS && dist > 5) {
			const force = (1 - dist / MOUSE_RADIUS) * MOUSE_GRAVITY;
			this.vx += (dx / dist) * force;
			this.vy += (dy / dist) * force;
		}

		// Apply velocity with damping
		this.x += this.vx;
		this.y += this.vy;
		this.vx *= 0.995;
		this.vy *= 0.995;

		// Wrap around edges
		if (this.x < -20) this.x = width + 20;
		if (this.x > width + 20) this.x = -20;
		if (this.y < -20) this.y = height + 20;
		if (this.y > height + 20) this.y = -20;

		// Twinkle
		this.currentBrightness =
			this.brightness + Math.sin(time * this.twinkleSpeed + this.twinklePhase) * this.twinkleAmount;
		this.currentBrightness = Math.max(0.1, Math.min(1, this.currentBrightness));
	}

	draw() {
		const { r, g, b } = this.color;
		const alpha = this.currentBrightness * 0.8;

		// Star glow
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size * 3, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${alpha * 0.08})`;
		ctx.fill();

		// Star core
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${alpha})`;
		ctx.fill();
	}
}

function initStars() {
	stars = [];
	for (let i = 0; i < STAR_COUNT; i++) {
		stars.push(new Star());
	}
}

function drawConnections() {
	for (let i = 0; i < stars.length; i++) {
		// Limit connections per star to avoid visual clutter
		let connections = 0;
		for (let j = i + 1; j < stars.length; j++) {
			if (connections >= 3) break;

			const dx = stars[i].x - stars[j].x;
			const dy = stars[i].y - stars[j].y;
			const dist = Math.sqrt(dx * dx + dy * dy);

			if (dist < CONNECTION_DIST) {
				const opacity = (1 - dist / CONNECTION_DIST) * 0.15;
				ctx.beginPath();
				ctx.moveTo(stars[i].x, stars[i].y);
				ctx.lineTo(stars[j].x, stars[j].y);
				ctx.strokeStyle = `rgba(180, 200, 255, ${opacity})`;
				ctx.lineWidth = 0.5;
				ctx.stroke();
				connections++;
			}
		}
	}
}

function drawMouseConnections() {
	if (mouse.x < -1000) return;

	for (const star of stars) {
		const dx = star.x - mouse.x;
		const dy = star.y - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);

		if (dist < MOUSE_RADIUS * 0.6) {
			const opacity = (1 - dist / (MOUSE_RADIUS * 0.6)) * 0.1;
			ctx.beginPath();
			ctx.moveTo(mouse.x, mouse.y);
			ctx.lineTo(star.x, star.y);
			ctx.strokeStyle = `rgba(160, 200, 255, ${opacity})`;
			ctx.lineWidth = 0.3;
			ctx.stroke();
		}
	}
}

let time = 0;

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time += 1;

		// Update all stars
		for (const star of stars) {
			star.update(time);
		}

		// Draw constellation lines
		drawConnections();
		drawMouseConnections();

		// Draw stars on top
		for (const star of stars) {
			star.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initStars();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initStars();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Context Mushroom Farm
 * Description: A bioluminescent mushroom grow room that sprouts and fills as your
 *   chat conversation grows. Uses the 'context' message type to track token usage.
 *   Stages: mycelium threads → tiny pins → growing caps → full clusters →
 *   bioluminescent glow → spore release at capacity. Move your mouse to stir
 *   floating spores. Includes ambient fog, moisture particles, and glowing fungi.
 *
 *   Context-aware: requires the Theme Designer Pro context data channel.
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const MAX_TOKENS         = 128000;   // your model's context limit
const GROWTH_SPEED       = 1;        // multiplier for testing (set to 10–50 for fast preview)
const MUSHROOM_CLUSTERS  = 12;       // number of mushroom clusters
const SPORE_COUNT        = 60;       // ambient spore particles
const FOG_LAYERS         = 3;        // fog layers (more = thicker atmosphere)
const BIOLUM_HUE         = 165;      // bioluminescent hue (165 = cyan-teal)
const BIOLUM_HUE_ALT     = 280;      // alt glow hue (280 = purple)
const MOISTURE_COUNT     = 40;       // tiny moisture droplets
/* --------------------------------------------- */

let canvas, ctx, w, h;
let mouse = { x: -9999, y: -9999 };
let contextRatio = 0;
let targetRatio = 0;
let estimatedTokens = 0;
let time = 0;
let clusters = [];
let spores = [];
let moisture = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

// Seeded random for consistent mushroom placement
function seededRandom(seed) {
	let s = seed;
	return function() {
		s = (s * 16807 + 0) % 2147483647;
		return (s - 1) / 2147483646;
	};
}

function initClusters() {
	clusters = [];
	const rng = seededRandom(42);
	const groundY = h * 0.82;

	for (let i = 0; i < MUSHROOM_CLUSTERS; i++) {
		const clusterX = w * 0.08 + rng() * w * 0.84;
		const mushroomCount = 2 + Math.floor(rng() * 4);
		const isBiolum = rng() > 0.5;
		const hue = isBiolum ? (rng() > 0.5 ? BIOLUM_HUE : BIOLUM_HUE_ALT) : 30;
		const growStart = rng() * 0.3; // stagger growth start
		const mushrooms = [];

		for (let j = 0; j < mushroomCount; j++) {
			mushrooms.push({
				offsetX: (rng() - 0.5) * 60,
				maxHeight: 25 + rng() * 80,
				stemWidth: 3 + rng() * 6,
				capRadius: 10 + rng() * 25,
				capStyle: rng() > 0.6 ? 'round' : 'flat',
				lean: (rng() - 0.5) * 0.3,
				hueShift: (rng() - 0.5) * 20,
				phase: rng() * Math.PI * 2,
				growDelay: rng() * 0.15
			});
		}

		clusters.push({
			x: clusterX,
			y: groundY + (rng() - 0.5) * 10,
			mushrooms,
			isBiolum,
			hue,
			growStart,
			myceliumSeeds: Array.from({ length: 5 + Math.floor(rng() * 6) }, () => ({
				angle: rng() * Math.PI * 2,
				length: 15 + rng() * 40,
				branches: Math.floor(rng() * 3),
				phase: rng() * Math.PI
			}))
		});
	}
}

function initSpores() {
	spores = [];
	for (let i = 0; i < SPORE_COUNT; i++) {
		spores.push({
			x: Math.random() * w,
			y: Math.random() * h * 0.85,
			vx: 0,
			vy: -0.1 - Math.random() * 0.3,
			size: 1 + Math.random() * 2.5,
			alpha: 0.2 + Math.random() * 0.5,
			hue: Math.random() > 0.5 ? BIOLUM_HUE : BIOLUM_HUE_ALT,
			drift: Math.random() * Math.PI * 2
		});
	}
}

function initMoisture() {
	moisture = [];
	for (let i = 0; i < MOISTURE_COUNT; i++) {
		moisture.push({
			x: Math.random() * w,
			y: Math.random() * h,
			speed: 0.2 + Math.random() * 0.5,
			size: 0.5 + Math.random() * 1,
			alpha: 0.1 + Math.random() * 0.2
		});
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initClusters();
			initSpores();
			initMoisture();
			startAnimation();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initClusters();
			initSpores();
			initMoisture();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
		case 'context':
			// Prefer exact API token count, fall back to DOM-based estimate
			if (e.data.exactTokens !== undefined) {
				estimatedTokens = e.data.exactTokens;
			} else if (e.data.estimatedTokens !== undefined) {
				estimatedTokens = e.data.estimatedTokens;
			}
			targetRatio = Math.min(1, (estimatedTokens / MAX_TOKENS) * GROWTH_SPEED);
			break;
	}
};

function drawSubstrate(groundY) {
	// Dark substrate base
	const gGrad = ctx.createLinearGradient(0, groundY - 15, 0, h);
	gGrad.addColorStop(0, '#1a1510');
	gGrad.addColorStop(0.15, '#12100c');
	gGrad.addColorStop(1, '#080604');
	ctx.fillStyle = gGrad;
	ctx.fillRect(0, groundY - 5, w, h - groundY + 5);

	// Straw/substrate texture
	const rng = seededRandom(99);
	ctx.strokeStyle = 'rgba(80, 65, 40, 0.15)';
	ctx.lineWidth = 1;
	for (let i = 0; i < 30; i++) {
		const sx = rng() * w;
		const sy = groundY + rng() * (h - groundY) * 0.5;
		const len = 8 + rng() * 20;
		const angle = (rng() - 0.5) * 0.8;
		ctx.beginPath();
		ctx.moveTo(sx, sy);
		ctx.lineTo(sx + Math.cos(angle) * len, sy + Math.sin(angle) * len);
		ctx.stroke();
	}
}

function drawMycelium(cluster, progress) {
	if (progress <= 0) return;
	const p = Math.min(1, progress * 3); // mycelium grows fast

	ctx.strokeStyle = `rgba(220, 215, 200, ${p * 0.25})`;
	ctx.lineWidth = 0.8;

	for (const m of cluster.myceliumSeeds) {
		const len = m.length * p;
		const wobble = Math.sin(time * 0.01 + m.phase) * 3;

		ctx.beginPath();
		ctx.moveTo(cluster.x, cluster.y);
		const ex = cluster.x + Math.cos(m.angle) * len + wobble;
		const ey = cluster.y + Math.sin(m.angle) * len * 0.4 + Math.abs(Math.sin(m.angle)) * 5;
		ctx.quadraticCurveTo(
			cluster.x + Math.cos(m.angle) * len * 0.5 + wobble * 0.5,
			cluster.y + Math.sin(m.angle) * len * 0.2 + 5,
			ex, ey
		);
		ctx.stroke();

		// Branches
		if (p > 0.5 && m.branches > 0) {
			const bp = (p - 0.5) * 2;
			for (let b = 0; b < m.branches; b++) {
				const bStart = 0.4 + b * 0.2;
				const bx = cluster.x + Math.cos(m.angle) * len * bStart;
				const by = cluster.y + Math.sin(m.angle) * len * 0.4 * bStart;
				const bAngle = m.angle + (b % 2 === 0 ? 0.5 : -0.5);
				const bLen = len * 0.3 * bp;
				ctx.beginPath();
				ctx.moveTo(bx, by);
				ctx.lineTo(bx + Math.cos(bAngle) * bLen, by + Math.sin(bAngle) * bLen * 0.4);
				ctx.stroke();
			}
		}
	}
}

function drawMushroom(x, baseY, mush, growthP, isBiolum, baseHue) {
	if (growthP <= 0) return;

	const hue = baseHue + mush.hueShift;
	const stemH = mush.maxHeight * growthP;
	const lean = mush.lean * stemH + Math.sin(time * 0.012 + mush.phase) * 2;
	const topX = x + lean;
	const topY = baseY - stemH;
	const sw = mush.stemWidth * (0.5 + growthP * 0.5);
	const capR = mush.capRadius * Math.min(1, growthP * 1.2);

	// Stem
	ctx.beginPath();
	ctx.moveTo(x - sw / 2, baseY);
	ctx.quadraticCurveTo(x - sw / 3 + lean * 0.3, baseY - stemH * 0.5, topX - sw / 3, topY + capR * 0.3);
	ctx.lineTo(topX + sw / 3, topY + capR * 0.3);
	ctx.quadraticCurveTo(x + sw / 3 + lean * 0.3, baseY - stemH * 0.5, x + sw / 2, baseY);
	ctx.closePath();

	const stemGrad = ctx.createLinearGradient(x, baseY, topX, topY);
	stemGrad.addColorStop(0, isBiolum ? `hsla(${hue}, 20%, 25%, 0.9)` : 'rgba(200, 190, 170, 0.9)');
	stemGrad.addColorStop(1, isBiolum ? `hsla(${hue}, 30%, 35%, 0.9)` : 'rgba(220, 210, 190, 0.9)');
	ctx.fillStyle = stemGrad;
	ctx.fill();

	// Cap
	if (growthP > 0.3) {
		const capP = Math.min(1, (growthP - 0.3) / 0.5);
		const cr = capR * capP;

		if (mush.capStyle === 'round') {
			// Rounded dome cap
			ctx.beginPath();
			ctx.ellipse(topX, topY + cr * 0.15, cr, cr * 0.65, 0, 0, Math.PI * 2);

			const capGrad = ctx.createRadialGradient(topX - cr * 0.2, topY - cr * 0.1, cr * 0.1, topX, topY, cr);
			if (isBiolum) {
				capGrad.addColorStop(0, `hsla(${hue}, 70%, 55%, 0.95)`);
				capGrad.addColorStop(0.7, `hsla(${hue}, 60%, 35%, 0.9)`);
				capGrad.addColorStop(1, `hsla(${hue}, 50%, 20%, 0.85)`);
			} else {
				capGrad.addColorStop(0, `hsl(${hue}, 50%, 55%)`);
				capGrad.addColorStop(0.7, `hsl(${hue}, 45%, 35%)`);
				capGrad.addColorStop(1, `hsl(${hue}, 40%, 20%)`);
			}
			ctx.fillStyle = capGrad;
			ctx.fill();
		} else {
			// Flat/parasol cap
			ctx.beginPath();
			ctx.ellipse(topX, topY + cr * 0.1, cr * 1.1, cr * 0.35, 0, 0, Math.PI);

			const capGrad = ctx.createLinearGradient(topX - cr, topY, topX + cr, topY + cr * 0.3);
			if (isBiolum) {
				capGrad.addColorStop(0, `hsla(${hue}, 65%, 50%, 0.9)`);
				capGrad.addColorStop(1, `hsla(${hue}, 55%, 25%, 0.85)`);
			} else {
				capGrad.addColorStop(0, `hsl(${hue}, 45%, 50%)`);
				capGrad.addColorStop(1, `hsl(${hue}, 40%, 25%)`);
			}
			ctx.fillStyle = capGrad;
			ctx.fill();
		}

		// Gills (underside lines)
		if (capP > 0.5) {
			const gillP = (capP - 0.5) * 2;
			ctx.strokeStyle = isBiolum
				? `hsla(${hue}, 50%, 60%, ${gillP * 0.3})`
				: `rgba(180, 170, 150, ${gillP * 0.2})`;
			ctx.lineWidth = 0.5;
			const gillCount = 6;
			for (let g = 0; g < gillCount; g++) {
				const gx = topX - cr * 0.7 + (g / (gillCount - 1)) * cr * 1.4;
				ctx.beginPath();
				ctx.moveTo(gx, topY + cr * 0.15);
				ctx.lineTo(gx, topY + cr * 0.4);
				ctx.stroke();
			}
		}

		// Bioluminescent glow
		if (isBiolum && growthP > 0.5) {
			const glowP = (growthP - 0.5) * 2;
			const pulse = 0.6 + 0.4 * Math.sin(time * 0.02 + mush.phase);
			const glowR = cr * 2.5 * glowP;
			const glowGrad = ctx.createRadialGradient(topX, topY, 0, topX, topY, glowR);
			glowGrad.addColorStop(0, `hsla(${hue}, 80%, 60%, ${glowP * pulse * 0.2})`);
			glowGrad.addColorStop(0.5, `hsla(${hue}, 70%, 40%, ${glowP * pulse * 0.08})`);
			glowGrad.addColorStop(1, `hsla(${hue}, 60%, 30%, 0)`);
			ctx.fillStyle = glowGrad;
			ctx.beginPath();
			ctx.arc(topX, topY, glowR, 0, Math.PI * 2);
			ctx.fill();
		}

		// Spots on cap (for non-biolum mushrooms)
		if (!isBiolum && capP > 0.7) {
			const spotP = (capP - 0.7) / 0.3;
			ctx.fillStyle = `rgba(255, 250, 230, ${spotP * 0.5})`;
			const spotRng = seededRandom(Math.floor(x * 100 + mush.maxHeight));
			const spotCount = 3 + Math.floor(spotRng() * 4);
			for (let s = 0; s < spotCount; s++) {
				const sa = spotRng() * Math.PI * 2;
				const sd = spotRng() * cr * 0.6;
				const sr = 1.5 + spotRng() * 2.5;
				ctx.beginPath();
				ctx.arc(topX + Math.cos(sa) * sd, topY + Math.sin(sa) * sd * 0.5, sr * spotP, 0, Math.PI * 2);
				ctx.fill();
			}
		}
	}
}

function drawFog(groundY) {
	for (let layer = 0; layer < FOG_LAYERS; layer++) {
		const fogY = groundY - 30 - layer * 40;
		const drift = Math.sin(time * 0.003 + layer * 2) * 50;
		const fogGrad = ctx.createRadialGradient(
			w / 2 + drift, fogY, 0,
			w / 2 + drift, fogY, w * 0.6
		);
		const alpha = 0.03 + contextRatio * 0.03;
		fogGrad.addColorStop(0, `rgba(150, 160, 140, ${alpha})`);
		fogGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
		ctx.fillStyle = fogGrad;
		ctx.fillRect(0, 0, w, h);
	}
}

function updateSpores() {
	const sporeAlpha = contextRatio > 0.6 ? (contextRatio - 0.6) / 0.4 : 0;
	if (sporeAlpha <= 0) return;

	for (const s of spores) {
		// Drift
		s.x += Math.sin(time * 0.01 + s.drift) * 0.3 + s.vx;
		s.y += s.vy;
		s.drift += 0.005;

		// Mouse interaction — spores drift toward cursor
		const dx = mouse.x - s.x;
		const dy = mouse.y - s.y;
		const d2 = dx * dx + dy * dy;
		if (d2 < 20000 && d2 > 1) {
			const dist = Math.sqrt(d2);
			s.vx += (dx / dist) * 0.05;
			s.vy += (dy / dist) * 0.05;
		}
		s.vx *= 0.97;
		s.vy *= 0.97;
		s.vy -= 0.005; // gentle upward float

		// Wrap
		if (s.y < -10) { s.y = h * 0.8; s.x = Math.random() * w; }
		if (s.x < -10) s.x = w + 10;
		if (s.x > w + 10) s.x = -10;

		// Draw
		const pulse = 0.5 + 0.5 * Math.sin(time * 0.03 + s.drift);
		const a = s.alpha * sporeAlpha * pulse;
		ctx.fillStyle = `hsla(${s.hue}, 80%, 70%, ${a})`;
		ctx.beginPath();
		ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
		ctx.fill();

		// Spore glow
		if (a > 0.2) {
			const sg = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, s.size * 4);
			sg.addColorStop(0, `hsla(${s.hue}, 80%, 70%, ${a * 0.3})`);
			sg.addColorStop(1, `hsla(${s.hue}, 80%, 70%, 0)`);
			ctx.fillStyle = sg;
			ctx.beginPath();
			ctx.arc(s.x, s.y, s.size * 4, 0, Math.PI * 2);
			ctx.fill();
		}
	}
}

function updateMoisture() {
	ctx.fillStyle = 'rgba(180, 200, 220, 0.08)';
	for (const m of moisture) {
		m.y += m.speed;
		if (m.y > h) { m.y = -5; m.x = Math.random() * w; }
		ctx.beginPath();
		ctx.arc(m.x, m.y, m.size, 0, Math.PI * 2);
		ctx.fill();
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		time++;

		// Smooth context interpolation
		contextRatio += (targetRatio - contextRatio) * 0.008;

		// --- Background ---
		const bgGrad = ctx.createLinearGradient(0, 0, 0, h);
		bgGrad.addColorStop(0, '#050508');
		bgGrad.addColorStop(0.5, '#0a0a10');
		bgGrad.addColorStop(0.8, '#0f0d0a');
		bgGrad.addColorStop(1, '#080604');
		ctx.fillStyle = bgGrad;
		ctx.fillRect(0, 0, w, h);

		// Ambient bioluminescent glow from all mushrooms
		if (contextRatio > 0.3) {
			const ambP = (contextRatio - 0.3) / 0.7;
			const ambGrad = ctx.createRadialGradient(w * 0.5, h * 0.7, 0, w * 0.5, h * 0.7, h * 0.8);
			ambGrad.addColorStop(0, `hsla(${BIOLUM_HUE}, 60%, 40%, ${ambP * 0.04})`);
			ambGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
			ctx.fillStyle = ambGrad;
			ctx.fillRect(0, 0, w, h);
		}

		// Warning pulse when nearly full
		if (contextRatio > 0.88) {
			const wP = (contextRatio - 0.88) / 0.12;
			const pulse = 0.5 + 0.5 * Math.sin(time * 0.04);
			ctx.fillStyle = `rgba(255, 40, 20, ${wP * pulse * 0.06})`;
			ctx.fillRect(0, 0, w, h);
		}

		const groundY = h * 0.82;

		// Moisture particles (background)
		updateMoisture();

		// --- Substrate ---
		drawSubstrate(groundY);

		// --- Mushroom clusters ---
		// Sort by Y so lower clusters draw on top (depth)
		const sorted = [...clusters].sort((a, b) => a.y - b.y);

		for (const cluster of sorted) {
			const clusterP = Math.max(0, (contextRatio - cluster.growStart) / (1 - cluster.growStart));

			// Mycelium (always draws first)
			if (clusterP > 0) {
				drawMycelium(cluster, clusterP);
			}

			// Individual mushrooms
			for (const mush of cluster.mushrooms) {
				const mushP = Math.max(0, (clusterP - mush.growDelay) / (1 - mush.growDelay));
				if (mushP > 0) {
					drawMushroom(
						cluster.x + mush.offsetX,
						cluster.y,
						mush,
						Math.min(1, mushP),
						cluster.isBiolum,
						cluster.hue
					);
				}
			}
		}

		// Fog (on top of mushrooms)
		drawFog(groundY);

		// Spores (on top of everything)
		updateSpores();

		// --- Token counter (subtle) ---
		if (estimatedTokens > 0) {
			ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
			ctx.fillRect(w - 175, h - 38, 168, 30);
			ctx.fillStyle = contextRatio > 0.85 ? '#ef4444' : contextRatio > 0.6 ? '#facc15' : `hsl(${BIOLUM_HUE}, 70%, 60%)`;
			ctx.font = '11px monospace';
			ctx.textAlign = 'right';
			ctx.fillText(`~${(estimatedTokens / 1000).toFixed(1)}k / ${(MAX_TOKENS / 1000).toFixed(0)}k tokens`, w - 14, h - 19);
			ctx.textAlign = 'left';

			// Mini progress bar
			ctx.fillStyle = 'rgba(255, 255, 255, 0.08)';
			ctx.fillRect(w - 168, h - 14, 155, 4);
			const barColor = contextRatio > 0.85 ? '#ef4444' : contextRatio > 0.6 ? '#facc15' : `hsl(${BIOLUM_HUE}, 70%, 50%)`;
			ctx.fillStyle = barColor;
			ctx.fillRect(w - 168, h - 14, 155 * Math.min(1, contextRatio), 4);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Context Sunflower
 * Description: A single sunflower that grows from a seed as your chat conversation
 *   grows. Uses the new 'context' message type to track estimated token usage.
 *   The sunflower progresses through stages: soil → sprout → stem & leaves →
 *   bud → bloom → full flower. When context is nearly full, petals droop as
 *   a visual warning. Move your mouse to sway the flower gently in the breeze.
 *
 *   Context-aware: requires the Theme Designer Pro context data channel.
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const MAX_TOKENS         = 128000;   // your model's context limit (adjust per model)
const GROWTH_SPEED       = 1;        // multiplier for testing (set to 10–50 for fast preview)
const BG_GRADIENT_TOP    = '#0a0e1a'; // night sky top
const BG_GRADIENT_BOT    = '#1a1205'; // warm earth bottom
const SOIL_COLOR         = '#2a1f0e'; // rich soil
const STEM_COLOR         = '#2d5a1e'; // stem green
const LEAF_COLOR         = '#3a7a2a'; // leaf green
const PETAL_COLOR        = '#ffd700'; // sunflower gold
const CENTER_COLOR       = '#5a3a0a'; // brown center
const STAR_COUNT         = 80;       // background stars
const SWAY_AMOUNT        = 0.03;     // mouse-driven sway
/* --------------------------------------------- */

let canvas, ctx, w, h;
let mouse = { x: -9999, y: -9999 };
let contextRatio = 0;  // 0 to 1
let targetRatio = 0;
let estimatedTokens = 0;
let messageCount = 0;
let time = 0;
let stars = [];

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initStars() {
	stars = [];
	for (let i = 0; i < STAR_COUNT; i++) {
		stars.push({
			x: Math.random() * w,
			y: Math.random() * h * 0.6,
			size: 0.5 + Math.random() * 1.5,
			twinkleSpeed: 0.02 + Math.random() * 0.04,
			twinklePhase: Math.random() * Math.PI * 2
		});
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initStars();
			startAnimation();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initStars();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
		case 'context':
			// Prefer exact API token count, fall back to DOM-based estimate
			if (e.data.exactTokens !== undefined) {
				estimatedTokens = e.data.exactTokens;
			} else if (e.data.estimatedTokens !== undefined) {
				estimatedTokens = e.data.estimatedTokens;
			}
			messageCount = e.data.messages || messageCount;
			targetRatio = Math.min(1, (estimatedTokens / MAX_TOKENS) * GROWTH_SPEED);
			break;
	}
};

// Easing function for smooth growth
function easeOutCubic(t) {
	return 1 - Math.pow(1 - t, 3);
}

// Draw a curved stem
function drawStem(baseX, baseY, stemHeight, sway, thickness) {
	ctx.beginPath();
	ctx.moveTo(baseX, baseY);

	const cp1x = baseX + sway * 0.3;
	const cp1y = baseY - stemHeight * 0.4;
	const cp2x = baseX + sway * 0.8;
	const cp2y = baseY - stemHeight * 0.7;
	const topX = baseX + sway;
	const topY = baseY - stemHeight;

	ctx.bezierCurveTo(cp1x, cp1y, cp2x, cp2y, topX, topY);

	ctx.strokeStyle = STEM_COLOR;
	ctx.lineWidth = thickness;
	ctx.lineCap = 'round';
	ctx.stroke();

	return { x: topX, y: topY, cp2x, cp2y };
}

// Draw a leaf on the stem
function drawLeaf(stemBaseX, stemBaseY, stemTop, stemHeight, side, progress, sway) {
	const leafSize = 15 + progress * 25;
	const attachY = stemBaseY - stemHeight * (side === 'left' ? 0.35 : 0.55);
	const attachX = stemBaseX + sway * (attachY - stemBaseY) / (-stemHeight || -1);

	const angle = side === 'left' ? -0.6 - progress * 0.3 : 0.6 + progress * 0.3;
	const tipX = attachX + Math.cos(angle) * leafSize * (side === 'left' ? -1 : 1);
	const tipY = attachY + Math.sin(angle) * leafSize * -0.3;

	ctx.beginPath();
	ctx.moveTo(attachX, attachY);

	const cx1 = attachX + (tipX - attachX) * 0.3;
	const cy1 = attachY - leafSize * 0.4;
	const cx2 = tipX - (tipX - attachX) * 0.2;
	const cy2 = tipY - leafSize * 0.1;
	ctx.bezierCurveTo(cx1, cy1, cx2, cy2, tipX, tipY);

	const cx3 = tipX - (tipX - attachX) * 0.2;
	const cy3 = tipY + leafSize * 0.3;
	const cx4 = attachX + (tipX - attachX) * 0.3;
	const cy4 = attachY + leafSize * 0.15;
	ctx.bezierCurveTo(cx3, cy3, cx4, cy4, attachX, attachY);

	ctx.fillStyle = LEAF_COLOR;
	ctx.globalAlpha = 0.8;
	ctx.fill();
	ctx.globalAlpha = 1;

	// Leaf vein
	ctx.beginPath();
	ctx.moveTo(attachX, attachY);
	ctx.lineTo(tipX, tipY);
	ctx.strokeStyle = '#1e4a15';
	ctx.lineWidth = 1;
	ctx.stroke();
}

// Draw the sunflower head
function drawFlowerHead(cx, cy, radius, petalCount, openProgress, droopAngle) {
	// Petals
	for (let i = 0; i < petalCount; i++) {
		const angle = (i / petalCount) * Math.PI * 2 + Math.sin(time * 0.01 + i) * 0.05;
		const petalLen = radius * (1.6 + Math.sin(i * 2.5) * 0.2) * openProgress;
		const petalWid = radius * 0.35 * openProgress;

		// Droop: petals angle downward as context fills
		const droopOffset = droopAngle * Math.sin(angle) * 0.5;

		const tipX = cx + Math.cos(angle + droopOffset) * petalLen;
		const tipY = cy + Math.sin(angle + droopOffset) * petalLen;

		ctx.beginPath();
		const perpAngle = angle + Math.PI / 2;
		const bx1 = cx + Math.cos(perpAngle) * petalWid * 0.5;
		const by1 = cy + Math.sin(perpAngle) * petalWid * 0.5;
		const bx2 = cx - Math.cos(perpAngle) * petalWid * 0.5;
		const by2 = cy - Math.sin(perpAngle) * petalWid * 0.5;

		ctx.moveTo(bx1, by1);
		ctx.quadraticCurveTo(
			cx + Math.cos(angle + droopOffset) * petalLen * 0.6 + Math.cos(perpAngle) * petalWid * 0.3,
			cy + Math.sin(angle + droopOffset) * petalLen * 0.6 + Math.sin(perpAngle) * petalWid * 0.3,
			tipX, tipY
		);
		ctx.quadraticCurveTo(
			cx + Math.cos(angle + droopOffset) * petalLen * 0.6 - Math.cos(perpAngle) * petalWid * 0.3,
			cy + Math.sin(angle + droopOffset) * petalLen * 0.6 - Math.sin(perpAngle) * petalWid * 0.3,
			bx2, by2
		);

		// Gradient on petals — gold to dark amber
		const hueShift = Math.sin(i * 1.2) * 10;
		ctx.fillStyle = `hsl(${45 + hueShift}, 100%, ${50 + openProgress * 10}%)`;
		ctx.fill();
	}

	// Center disc
	const cGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, radius * openProgress);
	cGrad.addColorStop(0, '#8B6914');
	cGrad.addColorStop(0.5, CENTER_COLOR);
	cGrad.addColorStop(1, '#3a2505');
	ctx.beginPath();
	ctx.arc(cx, cy, radius * openProgress, 0, Math.PI * 2);
	ctx.fillStyle = cGrad;
	ctx.fill();

	// Seeds pattern in center
	if (openProgress > 0.5) {
		const seedAlpha = (openProgress - 0.5) * 2;
		ctx.fillStyle = `rgba(30, 20, 5, ${seedAlpha * 0.6})`;
		const seedCount = 30;
		for (let i = 0; i < seedCount; i++) {
			const seedAngle = (i / seedCount) * Math.PI * 2;
			const rings = 3;
			for (let r = 1; r <= rings; r++) {
				const dist = (r / rings) * radius * 0.7 * openProgress;
				const sx = cx + Math.cos(seedAngle + r * 0.5) * dist;
				const sy = cy + Math.sin(seedAngle + r * 0.5) * dist;
				ctx.beginPath();
				ctx.arc(sx, sy, 1.5, 0, Math.PI * 2);
				ctx.fill();
			}
		}
	}
}

// Draw soil/ground
function drawGround(groundY) {
	// Ground gradient
	const gGrad = ctx.createLinearGradient(0, groundY - 20, 0, h);
	gGrad.addColorStop(0, SOIL_COLOR);
	gGrad.addColorStop(0.3, '#1f170a');
	gGrad.addColorStop(1, '#0f0a04');
	ctx.fillStyle = gGrad;
	ctx.fillRect(0, groundY, w, h - groundY);

	// Soil texture bumps
	ctx.fillStyle = 'rgba(60, 45, 20, 0.3)';
	for (let i = 0; i < 20; i++) {
		const bx = (i / 20) * w + Math.sin(i * 3.7) * 30;
		const by = groundY + Math.sin(i * 2.3) * 5;
		ctx.beginPath();
		ctx.ellipse(bx, by, 25 + Math.sin(i) * 10, 6, 0, 0, Math.PI * 2);
		ctx.fill();
	}
}

// Draw a tiny sprout
function drawSprout(x, groundY, progress) {
	const sproutH = progress * 30;
	const curl = Math.sin(time * 0.03) * 3 * progress;

	// Tiny stem
	ctx.beginPath();
	ctx.moveTo(x, groundY);
	ctx.quadraticCurveTo(x + curl, groundY - sproutH * 0.6, x + curl * 0.5, groundY - sproutH);
	ctx.strokeStyle = '#4a8a30';
	ctx.lineWidth = 2;
	ctx.lineCap = 'round';
	ctx.stroke();

	// Two tiny leaves unfurling
	if (progress > 0.3) {
		const leafP = (progress - 0.3) / 0.7;
		const leafSize = leafP * 10;
		const topX = x + curl * 0.5;
		const topY = groundY - sproutH;

		// Left cotyledon
		ctx.beginPath();
		ctx.ellipse(topX - leafSize * 0.6, topY - leafSize * 0.2, leafSize, leafSize * 0.4, -0.5, 0, Math.PI * 2);
		ctx.fillStyle = '#5aaa3a';
		ctx.fill();

		// Right cotyledon
		ctx.beginPath();
		ctx.ellipse(topX + leafSize * 0.6, topY - leafSize * 0.2, leafSize, leafSize * 0.4, 0.5, 0, Math.PI * 2);
		ctx.fill();
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		time++;

		// Smoothly interpolate toward target ratio
		contextRatio += (targetRatio - contextRatio) * 0.01;

		// --- Background ---
		const bgGrad = ctx.createLinearGradient(0, 0, 0, h);
		bgGrad.addColorStop(0, BG_GRADIENT_TOP);
		bgGrad.addColorStop(0.7, BG_GRADIENT_BOT);
		bgGrad.addColorStop(1, SOIL_COLOR);
		ctx.fillStyle = bgGrad;
		ctx.fillRect(0, 0, w, h);

		// Stars (fade as context grows — dawn approaching)
		const starAlpha = Math.max(0, 1 - contextRatio * 1.5);
		if (starAlpha > 0) {
			for (const s of stars) {
				const twinkle = 0.3 + 0.7 * Math.sin(time * s.twinkleSpeed + s.twinklePhase);
				ctx.fillStyle = `rgba(255, 255, 230, ${twinkle * starAlpha * 0.8})`;
				ctx.beginPath();
				ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
				ctx.fill();
			}
		}

		// Dawn glow as context grows (sunrise = approaching limit)
		if (contextRatio > 0.3) {
			const dawnP = (contextRatio - 0.3) / 0.7;
			const dawnGrad = ctx.createRadialGradient(w * 0.7, h * 0.5, 0, w * 0.7, h * 0.5, h * 0.8);
			dawnGrad.addColorStop(0, `rgba(255, ${140 + dawnP * 60}, ${40 + dawnP * 30}, ${dawnP * 0.15})`);
			dawnGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
			ctx.fillStyle = dawnGrad;
			ctx.fillRect(0, 0, w, h);
		}

		// Warning glow when context is nearly full
		if (contextRatio > 0.85) {
			const warnP = (contextRatio - 0.85) / 0.15;
			const pulse = 0.5 + 0.5 * Math.sin(time * 0.05);
			const warnGrad = ctx.createRadialGradient(w / 2, h * 0.4, 0, w / 2, h * 0.4, h);
			warnGrad.addColorStop(0, `rgba(255, 50, 20, ${warnP * pulse * 0.08})`);
			warnGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
			ctx.fillStyle = warnGrad;
			ctx.fillRect(0, 0, w, h);
		}

		// --- Ground ---
		const groundY = h * 0.78;
		drawGround(groundY);

		// --- Mouse sway ---
		const mouseOffsetX = (mouse.x - w / 2) / (w / 2); // -1 to 1
		const sway = mouseOffsetX * w * SWAY_AMOUNT + Math.sin(time * 0.015) * 5;

		// --- Growth stages ---
		const baseX = w / 2;
		const baseY = groundY;

		// Stage 0: nothing (ratio 0)
		// Stage 1: sprout emerging (0 - 0.08)
		// Stage 2: stem growing (0.08 - 0.3)
		// Stage 3: leaves appearing (0.2 - 0.5)
		// Stage 4: bud forming (0.4 - 0.6)
		// Stage 5: flower opening (0.5 - 0.8)
		// Stage 6: full bloom (0.8 - 1.0)
		// Beyond 0.9: petals start drooping (warning)

		if (contextRatio < 0.01) {
			// Just soil — nothing yet
		} else if (contextRatio < 0.08) {
			// Sprout emerging
			const sproutP = contextRatio / 0.08;
			drawSprout(baseX, baseY, sproutP);
		} else {
			// Full plant from stem onward
			const stemProgress = easeOutCubic(Math.min(1, (contextRatio - 0.08) / 0.3));
			const maxStemH = h * 0.45;
			const stemHeight = 30 + stemProgress * (maxStemH - 30);
			const stemThickness = 3 + stemProgress * 5;

			const top = drawStem(baseX, baseY, stemHeight, sway, stemThickness);

			// Leaves
			if (contextRatio > 0.15) {
				const leafP = Math.min(1, (contextRatio - 0.15) / 0.25);
				drawLeaf(baseX, baseY, top, stemHeight, 'left', leafP, sway);
			}
			if (contextRatio > 0.25) {
				const leafP = Math.min(1, (contextRatio - 0.25) / 0.25);
				drawLeaf(baseX, baseY, top, stemHeight, 'right', leafP, sway);
			}

			// Bud / Flower
			if (contextRatio > 0.4) {
				const budP = Math.min(1, (contextRatio - 0.4) / 0.15);
				const bloomP = contextRatio > 0.55 ? Math.min(1, (contextRatio - 0.55) / 0.3) : 0;
				const flowerRadius = 8 + budP * 12;
				const petalCount = 16;

				// Droop when context is nearly full
				const droop = contextRatio > 0.9 ? (contextRatio - 0.9) / 0.1 * 0.8 : 0;

				drawFlowerHead(top.x, top.y, flowerRadius, petalCount, bloomP > 0 ? bloomP : budP * 0.3, droop);
			}
		}

		// --- Token counter overlay (subtle) ---
		if (estimatedTokens > 0) {
			ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
			ctx.fillRect(w - 175, h - 38, 168, 30);
			ctx.fillStyle = contextRatio > 0.85 ? '#ef4444' : contextRatio > 0.6 ? '#facc15' : '#4ade80';
			ctx.font = '11px monospace';
			ctx.textAlign = 'right';
			ctx.fillText(`~${(estimatedTokens / 1000).toFixed(1)}k / ${(MAX_TOKENS / 1000).toFixed(0)}k tokens`, w - 14, h - 19);
			ctx.textAlign = 'left';

			// Mini progress bar
			ctx.fillStyle = 'rgba(255, 255, 255, 0.1)';
			ctx.fillRect(w - 168, h - 14, 155, 4);
			ctx.fillStyle = contextRatio > 0.85 ? '#ef4444' : contextRatio > 0.6 ? '#facc15' : '#4ade80';
			ctx.fillRect(w - 168, h - 14, 155 * Math.min(1, contextRatio), 4);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Cymatics
 * Description: Chladni plate vibration pattern simulator. Mouse position controls
 *   the vibration frequency modes — X controls horizontal, Y controls vertical.
 *   Sand particles are pushed from vibrating antinodes toward still nodal lines,
 *   forming beautiful geometric patterns: crosses, stars, diamonds, and complex
 *   symmetries. Move the mouse to morph between patterns in real-time.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Particles --
  particleCount: 2500,                    // Number of sand grains (500-5000)
  particleSize: 1.5,                      // Grain size in px (0.8-3)
  particleColor: '#c4a46c',               // Sand grain color
  particleOpacity: 0.7,                   // Grain opacity (0.3-0.95)

  // -- Physics --
  pushForce: 2.0,                         // Antinode push strength (0.5-8)
  pushDamping: 0.94,                      // Particle damping (0.88-0.98)
  transitionSpeed: 0.06,                  // Pattern morph speed (0.01-0.2)

  // -- Frequency Modes --
  modeRangeX: 6,                          // Max horizontal mode number (2-12)
  modeRangeY: 6,                          // Max vertical mode number (2-12)

  // -- Plate Appearance --
  plateColor: [35, 30, 25],               // Surface plate color [r,g,b]
  plateTexture: true,                     // Subtle wood/metal texture
  borderEnabled: true,                    // Show plate border
  borderColor: '#554433',                 // Border color
  borderWidth: 3,                         // Border width (1-6)

  // -- Visual Effects --
  glowEnabled: true,                      // Glow along particle concentrations
  glowColor: '#ffdd88',                   // Glow color
  glowIntensity: 0.15,                    // Glow strength (0.05-0.5)
  vibrationVisible: true,                 // Show jitter at antinodes
  vibrationAmount: 1.5,                   // Jitter displacement (0.3-4)

  // -- Overlay --
  nodalLineHint: true,                    // Faintly show mathematical nodal lines
  nodalLineOpacity: 0.06,                 // Nodal line hint opacity (0.02-0.15)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let particles = [];
let currentN = 2, currentM = 3; // active modes (smooth interpolated)
let textureData = null;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

// Chladni equation: value at (x,y) for modes (n,m)
// Nodes where cos(n*pi*x)*cos(m*pi*y) - cos(m*pi*x)*cos(n*pi*y) = 0
function chladniValue(x, y, n, m) {
  const nx = x * Math.PI;
  const ny = y * Math.PI;
  return Math.cos(n * nx) * Math.cos(m * ny) - Math.cos(m * nx) * Math.cos(n * ny);
}

// Gradient of Chladni function (direction particles are pushed)
function chladniGradient(x, y, n, m) {
  const h = 0.005;
  const dx = chladniValue(x + h, y, n, m) - chladniValue(x - h, y, n, m);
  const dy = chladniValue(x, y + h, n, m) - chladniValue(x, y - h, n, m);
  return { dx: dx / (2 * h), dy: dy / (2 * h) };
}

class SandGrain {
  constructor() {
    this.x = rand(0.02, 0.98);
    this.y = rand(0.02, 0.98);
    this.vx = 0;
    this.vy = 0;
    this.size = CONFIG.particleSize * rand(0.7, 1.3);
  }

  update(n, m) {
    const val = chladniValue(this.x, this.y, n, m);
    const absVal = Math.abs(val);

    // Push from antinodes toward nodes
    // Antinodes have high |val|, nodes have val≈0
    if (absVal > 0.01) {
      const grad = chladniGradient(this.x, this.y, n, m);
      const mag = Math.sqrt(grad.dx * grad.dx + grad.dy * grad.dy) + 0.001;
      // Push along gradient toward zero crossings
      const force = CONFIG.pushForce * 0.0003 * absVal;
      // Push toward nearest node = against gradient of |val|
      const sign = val > 0 ? 1 : -1;
      this.vx -= sign * (grad.dx / mag) * force;
      this.vy -= sign * (grad.dy / mag) * force;
    }

    // Vibration jitter at antinodes
    if (CONFIG.vibrationVisible && absVal > 0.3) {
      const jitter = absVal * CONFIG.vibrationAmount * 0.0005;
      this.vx += (Math.random() - 0.5) * jitter;
      this.vy += (Math.random() - 0.5) * jitter;
    }

    this.vx *= CONFIG.pushDamping;
    this.vy *= CONFIG.pushDamping;
    this.x += this.vx;
    this.y += this.vy;

    // Boundary (stay on plate)
    if (this.x < 0.01) { this.x = 0.01; this.vx *= -0.3; }
    if (this.x > 0.99) { this.x = 0.99; this.vx *= -0.3; }
    if (this.y < 0.01) { this.y = 0.01; this.vy *= -0.3; }
    if (this.y > 0.99) { this.y = 0.99; this.vy *= -0.3; }
  }
}

function generateTexture() {
  if (!CONFIG.plateTexture) return;
  const pc = CONFIG.plateColor;
  const id = ctx.createImageData(width, height);
  const d = id.data;
  for (let i = 0; i < d.length; i += 4) {
    const noise = (Math.random() - 0.5) * 8;
    d[i] = Math.max(0, Math.min(255, pc[0] + noise));
    d[i+1] = Math.max(0, Math.min(255, pc[1] + noise));
    d[i+2] = Math.max(0, Math.min(255, pc[2] + noise));
    d[i+3] = 255;
  }
  textureData = id;
}

function initParticles() {
  particles = [];
  for (let i = 0; i < CONFIG.particleCount; i++) particles.push(new SandGrain());
}

function startAnimation() {
  const pc = CONFIG.plateColor;
  const sc = hexRgb(CONFIG.particleColor);
  const gc = hexRgb(CONFIG.glowColor);

  function render() {
    if (!ctx) return;

    // -- Smoothly interpolate toward target modes from mouse --
    if (mouse.x >= 0 && mouse.y >= 0) {
      const targetN = 1 + (mouse.x / width) * (CONFIG.modeRangeX - 1);
      const targetM = 1 + (mouse.y / height) * (CONFIG.modeRangeY - 1);
      currentN += (targetN - currentN) * CONFIG.transitionSpeed;
      currentM += (targetM - currentM) * CONFIG.transitionSpeed;
    }

    // -- Background --
    if (textureData) {
      ctx.putImageData(textureData, 0, 0);
    } else {
      ctx.fillStyle = `rgb(${pc[0]},${pc[1]},${pc[2]})`;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Nodal line hints --
    if (CONFIG.nodalLineHint) {
      const step = 3;
      const n = currentN, m = currentM;
      ctx.fillStyle = `rgba(200,200,180,${CONFIG.nodalLineOpacity})`;
      for (let py = 0; py < height; py += step) {
        for (let px = 0; px < width; px += step) {
          const nx = px / width, ny = py / height;
          const v = Math.abs(chladniValue(nx, ny, n, m));
          if (v < 0.08) {
            ctx.fillRect(px, py, step, step);
          }
        }
      }
    }

    // -- Update particles --
    for (const p of particles) p.update(currentN, currentM);

    // -- Glow pass (draw dim glow first) --
    if (CONFIG.glowEnabled) {
      for (const p of particles) {
        const px = p.x * width, py = p.y * height;
        ctx.beginPath();
        ctx.arc(px, py, p.size * 4, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${gc[0]},${gc[1]},${gc[2]},${CONFIG.glowIntensity * 0.02})`;
        ctx.fill();
      }
    }

    // -- Draw particles --
    for (const p of particles) {
      const px = p.x * width, py = p.y * height;
      ctx.beginPath();
      ctx.arc(px, py, p.size, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${sc[0]},${sc[1]},${sc[2]},${CONFIG.particleOpacity})`;
      ctx.fill();
    }

    // -- Border --
    if (CONFIG.borderEnabled) {
      ctx.strokeStyle = CONFIG.borderColor;
      ctx.lineWidth = CONFIG.borderWidth;
      ctx.strokeRect(0, 0, width, height);
    }

    // -- Mode indicator --
    ctx.fillStyle = 'rgba(200,200,180,0.25)';
    ctx.font = '10px monospace';
    ctx.fillText(`n=${currentN.toFixed(1)} m=${currentM.toFixed(1)}`, 8, height - 8);

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initParticles();
      generateTexture();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initParticles();
      generateTexture();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Data Stream
 * Description: Horizontal streams of flowing data represented as small rectangles of varying
 *   lengths zipping across the screen. Like watching network traffic visualized.
 *   Dim blue/cyan palette. Mouse creates a vortex that curves nearby streams.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

const MAX_PARTICLES = 200;
const VORTEX_RADIUS = 180;
const VORTEX_STRENGTH = 3;

let particles = [];
let lanes = [];

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function init() {
	particles = [];
	// Create lanes at various y positions
	const laneCount = Math.floor(height / 12);
	lanes = [];
	for (let i = 0; i < laneCount; i++) {
		lanes.push({
			y: (i + 0.5) * (height / laneCount),
			baseSpeed: 0.5 + Math.random() * 2.5,
			direction: Math.random() < 0.7 ? 1 : -1 // mostly left-to-right
		});
	}

	// Pre-populate some particles
	for (let i = 0; i < MAX_PARTICLES * 0.6; i++) {
		spawnParticle(true);
	}
}

function spawnParticle(randomX) {
	if (particles.length >= MAX_PARTICLES) return;

	const lane = lanes[Math.floor(Math.random() * lanes.length)];
	const pWidth = 4 + Math.random() * 30; // rectangle width
	const pHeight = 1.5 + Math.random() * 2.5;

	// Color variation in blue/cyan spectrum
	const hue = 190 + Math.random() * 30; // 190-220 range (blue to cyan)
	const sat = 60 + Math.random() * 40;
	const light = 40 + Math.random() * 20;
	const alpha = 0.1 + Math.random() * 0.25;

	let x;
	if (randomX) {
		x = Math.random() * width;
	} else {
		x = lane.direction > 0 ? -pWidth : width + pWidth;
	}

	particles.push({
		x: x,
		y: lane.y + (Math.random() - 0.5) * 6, // slight y jitter within lane
		baseY: lane.y,
		w: pWidth,
		h: pHeight,
		vx: lane.baseSpeed * lane.direction * (0.7 + Math.random() * 0.6),
		vy: 0,
		color: `hsla(${hue}, ${sat}%, ${light}%, ${alpha})`,
		glowColor: `hsla(${hue}, ${sat}%, ${light + 20}%, ${alpha * 0.6})`,
		alpha: alpha
	});
}

function startAnimation() {
	function render(time) {
		if (!ctx) return;

		ctx.clearRect(0, 0, width, height);

		// Spawn new particles
		if (particles.length < MAX_PARTICLES && Math.random() < 0.3) {
			spawnParticle(false);
		}

		// Update and draw particles
		for (let i = particles.length - 1; i >= 0; i--) {
			const p = particles[i];

			// Vortex effect from mouse
			const dx = p.x - mouse.x;
			const dy = p.y - mouse.y;
			const dist = Math.sqrt(dx * dx + dy * dy);

			if (dist < VORTEX_RADIUS && dist > 1) {
				const force = (1 - dist / VORTEX_RADIUS) * VORTEX_STRENGTH;
				// Perpendicular force (creates swirl) + slight attraction
				const angle = Math.atan2(dy, dx);
				const perpX = -Math.sin(angle) * force;
				const perpY = Math.cos(angle) * force;
				p.vy += perpY * 0.1;
				p.vx += perpX * 0.05;
			}

			// Return to base Y (spring force)
			const yDiff = p.baseY - p.y;
			p.vy += yDiff * 0.01;
			p.vy *= 0.92; // damping

			// Move
			p.x += p.vx;
			p.y += p.vy;

			// Remove if off-screen
			if (
				(p.vx > 0 && p.x > width + p.w + 10) ||
				(p.vx < 0 && p.x < -p.w - 10) ||
				p.y < -50 ||
				p.y > height + 50
			) {
				particles.splice(i, 1);
				continue;
			}

			// Draw the data packet
			// Subtle glow
			ctx.shadowColor = p.glowColor;
			ctx.shadowBlur = 4;
			ctx.fillStyle = p.color;
			ctx.fillRect(p.x, p.y - p.h / 2, p.w, p.h);
			ctx.shadowBlur = 0;
		}

		// Draw faint lane lines for depth
		ctx.strokeStyle = 'rgba(0, 100, 140, 0.03)';
		ctx.lineWidth = 0.5;
		for (const lane of lanes) {
			ctx.beginPath();
			ctx.moveTo(0, lane.y);
			ctx.lineTo(width, lane.y);
			ctx.stroke();
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Digital Fishtank V2
 * Description: A living aquarium with hungry fish that chase and eat food you
 *   drop from the surface. Move your cursor to the top of the tank to sprinkle
 *   food pellets — fish detect them, race to eat, and do a happy wiggle.
 *   Features bezier-curve fish with stripe patterns, leaf-shaped plants,
 *   aerator bubble streams, decorative rocks, caustic lighting, depth
 *   layering, fish shadows, and an animated water surface.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Fish --
  fishCount: 14,                          // Number of fish (3-30)
  fishMinSize: 14,                        // Smallest fish body length in px
  fishMaxSize: 34,                        // Largest fish body length in px
  fishSpeed: 0.6,                         // Base swim speed multiplier (0.2-2)
  fishChaseSpeed: 1.8,                    // Speed when chasing food (1-4)
  fishPalette: [                          // [body, fin, stripe] color triplets
    ['#ff6b3d', '#ff9a6c', '#ffffff'],    // Clownfish orange + white stripes
    ['#4fc3f7', '#81d4fa', '#1565c0'],    // Neon blue + dark stripes
    ['#ffd54f', '#ffe082', '#ff8f00'],    // Golden + amber stripes
    ['#e57373', '#ef9a9a', '#b71c1c'],    // Red + crimson stripes
    ['#81c784', '#a5d6a7', '#2e7d32'],    // Green + dark green stripes
    ['#ce93d8', '#e1bee7', '#7b1fa2'],    // Purple + deep purple stripes
    ['#4dd0e1', '#80deea', '#00695c'],    // Cyan + teal stripes
    ['#ffb74d', '#ffcc80', '#e65100'],    // Amber + orange stripes
  ],
  fishStripes: true,                      // Draw stripe pattern on fish bodies
  fishUndulation: 0.3,                    // Body wave amplitude (0.1-0.6)
  fishTailSpeed: 5,                       // Tail beat frequency (2-10)
  fishShadows: true,                      // Draw shadow on sand below each fish
  schooling: false,                       // Fish loosely school together

  // -- Food --
  feedingEnabled: true,                   // Enable food dropping from surface
  feedZoneHeight: 0.15,                   // Top fraction of tank that triggers feeding (0.05-0.3)
  foodDropRate: 18,                       // Frames between food drops when feeding (5-60)
  foodSinkSpeed: 0.4,                     // Food sink speed (0.1-1.5)
  foodSize: 3,                            // Food pellet radius in px (2-6)
  foodColor: '#d4a056',                   // Food pellet color
  foodDetectRadius: 200,                  // How far fish can "see" food in px (50-400)
  maxFood: 30,                            // Max food pellets on screen

  // -- Bubbles --
  bubbleCount: 15,                        // Ambient bubble count (0-60)
  bubbleMinSize: 1.5,                     // Min bubble radius in px
  bubbleMaxSize: 5,                       // Max bubble radius in px
  bubbleSpeed: 0.5,                       // Rise speed multiplier (0.2-2)
  bubbleColor: 'rgba(180, 220, 255, 0.25)', // Bubble color
  bubbleShine: true,                      // Show highlight on bubbles
  aeratorCount: 2,                        // Fixed bubble stream sources on bottom (0-5)
  aeratorRate: 12,                        // Frames between aerator bubbles (4-30)

  // -- Plants --
  plantCount: 10,                         // Number of seaweed plants (0-20)
  plantMinHeight: 50,                     // Shortest plant in px
  plantMaxHeight: 150,                    // Tallest plant in px
  plantSegments: 10,                      // Segments per plant (more=smoother)
  plantSwayAmount: 14,                    // Sway displacement in px (0-30)
  plantSwaySpeed: 0.7,                    // Sway speed (0.2-3)
  plantLeafWidth: 6,                      // Leaf width in px (3-12)
  plantColors: ['#2e7d32', '#388e3c', '#43a047', '#1b5e20', '#66bb6a'],

  // -- Water & Lighting --
  waterTopColor: [8, 35, 70],             // RGB for top of tank
  waterBottomColor: [3, 12, 30],          // RGB for bottom of tank
  causticsEnabled: true,                  // Animated light caustics
  causticsSpeed: 0.5,                     // Caustic animation speed (0.2-2)
  lightRaysEnabled: true,                 // Show god-rays from surface
  lightRayCount: 5,                       // Number of light rays (2-10)
  lightRayOpacity: 0.025,                 // Ray opacity (0.01-0.08)
  surfaceRipple: true,                    // Animated wavy surface line

  // -- Environment --
  sandColor: [55, 45, 28],               // RGB for sandy bottom
  sandHeight: 35,                         // Sand strip height in px
  rockCount: 6,                           // Decorative rocks on sand (0-15)
  particleCount: 35,                      // Floating detritus particles (0-100)

  // -- Mouse --
  mouseScatterRadius: 100,               // Fish flee radius in px (below feed zone)
  mouseScatterForce: 2.5,                // Scatter strength (1-10)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let allFish = [], bubbles = [], plants = [], particles = [], foodPellets = [];
let rocks = [], aerators = [];
let feedTimer = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

// ════════════════════════════════════════════
// ██  FOOD PELLET
// ════════════════════════════════════════════
class Food {
  constructor(x) {
    this.x = x + rand(-8, 8);
    this.y = 5;
    this.vy = CONFIG.foodSinkSpeed * rand(0.7, 1.3);
    this.vx = rand(-0.15, 0.15);
    this.r = CONFIG.foodSize * rand(0.7, 1.2);
    this.eaten = false;
    this.phase = rand(0, Math.PI * 2);
    this.color = hexRgb(CONFIG.foodColor);
  }
  update() {
    if (this.eaten) return false;
    this.phase += 0.04;
    this.x += this.vx + Math.sin(this.phase) * 0.12;
    this.y += this.vy;
    this.vy *= 0.999; // slight deceleration
    const floor = height - CONFIG.sandHeight - this.r;
    if (this.y >= floor) { this.y = floor; this.vy = 0; this.vx = 0; }
    return true;
  }
  draw() {
    if (this.eaten) return;
    const c = this.color;
    // Glow
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r * 2.5, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},0.06)`;
    ctx.fill();
    // Pellet
    const g = ctx.createRadialGradient(this.x - this.r * 0.3, this.y - this.r * 0.3, 0, this.x, this.y, this.r);
    g.addColorStop(0, `rgba(${Math.min(255,c[0]+50)},${Math.min(255,c[1]+50)},${Math.min(255,c[2]+30)},0.9)`);
    g.addColorStop(1, `rgba(${c[0]},${c[1]},${c[2]},0.8)`);
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
    ctx.fillStyle = g;
    ctx.fill();
  }
}

// ════════════════════════════════════════════
// ██  FISH
// ════════════════════════════════════════════
class Fish {
  constructor() {
    this.size = rand(CONFIG.fishMinSize, CONFIG.fishMaxSize);
    const palIdx = Math.floor(Math.random() * CONFIG.fishPalette.length);
    const pal = CONFIG.fishPalette[palIdx];
    this.bodyColor = hexRgb(pal[0]);
    this.finColor = hexRgb(pal[1]);
    this.stripeColor = pal[2] ? hexRgb(pal[2]) : this.bodyColor;
    this.x = rand(this.size * 2, width - this.size * 2);
    this.y = rand(50, height - CONFIG.sandHeight - this.size * 2);
    this.angle = rand(-Math.PI, Math.PI);
    this.targetAngle = this.angle;
    this.baseSpeed = rand(0.3, 0.7) * CONFIG.fishSpeed;
    this.speed = this.baseSpeed;
    this.phase = rand(0, Math.PI * 2);
    this.wanderTimer = rand(60, 200);
    this.wanderTarget = { x: this.x, y: this.y };
    this.turnRate = rand(0.025, 0.06);
    this.depth = rand(0, 1); // 0=far, 1=near
    this.depthScale = 0.7 + this.depth * 0.3;
    this.depthAlpha = 0.5 + this.depth * 0.5;
    this.vx = 0; this.vy = 0;
    this.chasing = null; // food target
    this.nibbleTimer = 0; // happy wiggle after eating
    this.stripeCount = Math.floor(rand(2, 4));
  }

  pickWanderTarget() {
    const m = this.size * 2;
    this.wanderTarget.x = rand(m, width - m);
    this.wanderTarget.y = rand(40, height - CONFIG.sandHeight - m - 20);
    this.wanderTimer = rand(100, 300);
  }

  findFood() {
    if (!CONFIG.feedingEnabled || foodPellets.length === 0) return null;
    let best = null, bestD = CONFIG.foodDetectRadius;
    for (const f of foodPellets) {
      if (f.eaten) continue;
      const d = Math.hypot(f.x - this.x, f.y - this.y);
      if (d < bestD) { bestD = d; best = f; }
    }
    return best;
  }

  update() {
    this.phase += 0.05;
    if (this.nibbleTimer > 0) this.nibbleTimer--;

    // Look for food
    const food = this.findFood();
    if (food && !food.eaten) {
      this.chasing = food;
      this.targetAngle = Math.atan2(food.y - this.y, food.x - this.x);
      this.speed = CONFIG.fishChaseSpeed * this.baseSpeed;
      this.turnRate = 0.08; // turn faster when chasing

      // Eat if close enough
      const ed = Math.hypot(food.x - this.x, food.y - this.y);
      if (ed < this.size * 0.6) {
        food.eaten = true;
        this.chasing = null;
        this.nibbleTimer = 40;
        this.speed = this.baseSpeed;
        this.turnRate = rand(0.025, 0.06);
      }
    } else {
      this.chasing = null;
      this.speed = this.baseSpeed;
      this.turnRate = rand(0.025, 0.06);

      this.wanderTimer--;
      if (this.wanderTimer <= 0) this.pickWanderTarget();
      this.targetAngle = Math.atan2(this.wanderTarget.y - this.y, this.wanderTarget.x - this.x);

      // Schooling
      if (CONFIG.schooling) {
        let cx = 0, cy = 0, n = 0;
        for (const o of allFish) {
          if (o === this) continue;
          if (Math.hypot(o.x - this.x, o.y - this.y) < 100) { cx += o.x; cy += o.y; n++; }
        }
        if (n > 0) {
          const sa = Math.atan2(cy / n - this.y, cx / n - this.x);
          this.targetAngle = this.targetAngle * 0.7 + sa * 0.3;
        }
      }
    }

    // Smooth turn
    let da = this.targetAngle - this.angle;
    while (da > Math.PI) da -= Math.PI * 2;
    while (da < -Math.PI) da += Math.PI * 2;
    this.angle += da * this.turnRate;

    // Mouse scatter (only below feed zone)
    const inFeedZone = mouse.y >= 0 && mouse.y < height * CONFIG.feedZoneHeight;
    if (!inFeedZone) {
      const mdx = this.x - mouse.x, mdy = this.y - mouse.y;
      const md = Math.sqrt(mdx * mdx + mdy * mdy);
      if (md < CONFIG.mouseScatterRadius && md > 0) {
        const f = (1 - md / CONFIG.mouseScatterRadius) * CONFIG.mouseScatterForce;
        this.vx += (mdx / md) * f;
        this.vy += (mdy / md) * f;
      }
    }

    // Nibble wiggle
    const wiggle = this.nibbleTimer > 0 ? Math.sin(this.nibbleTimer * 0.8) * 0.15 : 0;

    this.vx += Math.cos(this.angle + wiggle) * this.speed * 0.15;
    this.vy += Math.sin(this.angle + wiggle) * this.speed * 0.15;
    this.vx *= 0.93; this.vy *= 0.93;
    this.x += this.vx; this.y += this.vy;

    // Boundary
    const m = this.size * 1.5;
    if (this.x < m) { this.x = m; this.vx = Math.abs(this.vx); this.pickWanderTarget(); }
    if (this.x > width - m) { this.x = width - m; this.vx = -Math.abs(this.vx); this.pickWanderTarget(); }
    if (this.y < 15) { this.y = 15; this.vy = Math.abs(this.vy); }
    if (this.y > height - CONFIG.sandHeight - m) { this.y = height - CONFIG.sandHeight - m; this.vy = -Math.abs(this.vy); }
  }

  drawShadow() {
    if (!CONFIG.fishShadows) return;
    const sandY = height - CONFIG.sandHeight + 3;
    const shadowAlpha = Math.max(0.02, 0.06 * (1 - (sandY - this.y) / height));
    const shadowScale = 0.6 + (sandY - this.y) / height * 0.4;
    ctx.beginPath();
    ctx.ellipse(this.x, sandY, this.size * shadowScale, this.size * 0.15, 0, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(0,0,0,${shadowAlpha})`;
    ctx.fill();
  }

  draw() {
    const s = this.size * this.depthScale;
    const swimPhase = Math.sin(this.phase * CONFIG.fishTailSpeed);
    const und = CONFIG.fishUndulation;
    const tailWag = swimPhase * s * und * 0.7;
    const bw1 = Math.sin(this.phase * CONFIG.fishTailSpeed + 1) * s * und * 0.15;
    const bw2 = Math.sin(this.phase * CONFIG.fishTailSpeed + 2) * s * und * 0.08;

    ctx.save();
    ctx.globalAlpha = this.depthAlpha;
    ctx.translate(this.x, this.y);
    ctx.rotate(this.angle);

    // ── Tail ──
    ctx.beginPath();
    ctx.moveTo(-s * 0.4, 0);
    ctx.quadraticCurveTo(-s * 0.7, -s * 0.35 + tailWag * 0.3, -s * 0.95 + tailWag * 0.5, -s * 0.42 + tailWag);
    ctx.lineTo(-s * 0.5, tailWag * 0.15);
    ctx.lineTo(-s * 0.95 + tailWag * 0.5, s * 0.42 + tailWag);
    ctx.quadraticCurveTo(-s * 0.7, s * 0.35 + tailWag * 0.3, -s * 0.4, 0);
    ctx.fillStyle = `rgba(${this.finColor[0]},${this.finColor[1]},${this.finColor[2]},0.65)`;
    ctx.fill();

    // ── Body ──
    ctx.beginPath();
    ctx.moveTo(s * 0.52, 0);
    ctx.bezierCurveTo(s * 0.38, -s * 0.3 + bw2, 0, -s * 0.34 + bw1, -s * 0.35, -s * 0.13 + bw1);
    ctx.lineTo(-s * 0.42, 0);
    ctx.bezierCurveTo(-s * 0.35, s * 0.13 + bw1, 0, s * 0.34 + bw1, s * 0.38, s * 0.3 + bw2);
    ctx.closePath();
    const bc = this.bodyColor;
    const bg = ctx.createLinearGradient(0, -s * 0.3, 0, s * 0.3);
    bg.addColorStop(0, `rgba(${Math.min(255,bc[0]+50)},${Math.min(255,bc[1]+50)},${Math.min(255,bc[2]+50)},0.88)`);
    bg.addColorStop(0.45, `rgba(${bc[0]},${bc[1]},${bc[2]},0.92)`);
    bg.addColorStop(1, `rgba(${Math.max(0,bc[0]-35)},${Math.max(0,bc[1]-35)},${Math.max(0,bc[2]-35)},0.88)`);
    ctx.fillStyle = bg;
    ctx.fill();

    // ── Stripes ──
    if (CONFIG.fishStripes) {
      ctx.save();
      // Clip to body shape (re-draw path)
      ctx.beginPath();
      ctx.moveTo(s * 0.52, 0);
      ctx.bezierCurveTo(s * 0.38, -s * 0.3 + bw2, 0, -s * 0.34 + bw1, -s * 0.35, -s * 0.13 + bw1);
      ctx.lineTo(-s * 0.42, 0);
      ctx.bezierCurveTo(-s * 0.35, s * 0.13 + bw1, 0, s * 0.34 + bw1, s * 0.38, s * 0.3 + bw2);
      ctx.closePath();
      ctx.clip();
      const sc = this.stripeColor;
      ctx.fillStyle = `rgba(${sc[0]},${sc[1]},${sc[2]},0.25)`;
      const stripeW = s * 0.1;
      for (let i = 0; i < this.stripeCount; i++) {
        const sx = s * 0.2 - i * s * 0.25;
        ctx.fillRect(sx - stripeW / 2, -s * 0.5, stripeW, s);
      }
      ctx.restore();
    }

    // ── Dorsal fin ──
    const dw = Math.sin(this.phase * CONFIG.fishTailSpeed + 0.5) * s * und * 0.1;
    ctx.beginPath();
    ctx.moveTo(s * 0.18, -s * 0.28 + bw2);
    ctx.quadraticCurveTo(0, -s * 0.52 + dw, -s * 0.22, -s * 0.26 + bw1);
    ctx.fillStyle = `rgba(${this.finColor[0]},${this.finColor[1]},${this.finColor[2]},0.45)`;
    ctx.fill();

    // ── Pectoral fin ──
    const pp = Math.sin(this.phase * CONFIG.fishTailSpeed * 0.7 + 1);
    ctx.beginPath();
    ctx.moveTo(s * 0.1, s * 0.22);
    ctx.quadraticCurveTo(0, s * 0.44 + pp * s * 0.07, -s * 0.15, s * 0.3);
    ctx.fillStyle = `rgba(${this.finColor[0]},${this.finColor[1]},${this.finColor[2]},0.35)`;
    ctx.fill();

    // ── Eye ──
    const eyeX = s * 0.32, eyeY = -s * 0.05;
    ctx.beginPath();
    ctx.arc(eyeX, eyeY, s * 0.065, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255,255,255,0.92)';
    ctx.fill();
    ctx.beginPath();
    ctx.arc(eyeX + s * 0.02, eyeY, s * 0.035, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(5,5,5,0.95)';
    ctx.fill();
    // Eye glint
    ctx.beginPath();
    ctx.arc(eyeX + s * 0.04, eyeY - s * 0.02, s * 0.015, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(255,255,255,0.7)';
    ctx.fill();

    // ── Mouth (opens when near food) ──
    if (this.chasing) {
      const md = Math.hypot(this.chasing.x - this.x, this.chasing.y - this.y);
      if (md < this.size * 2) {
        const open = Math.sin(this.phase * 12) * 0.5 + 0.5;
        ctx.beginPath();
        ctx.arc(s * 0.5, 0, s * 0.06 * (0.5 + open), 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${Math.max(0,bc[0]-60)},${Math.max(0,bc[1]-60)},${Math.max(0,bc[2]-60)},0.6)`;
        ctx.fill();
      }
    }

    // ── Happy flash after eating ──
    if (this.nibbleTimer > 20) {
      const flash = (this.nibbleTimer - 20) / 20;
      ctx.beginPath();
      ctx.ellipse(0, 0, s * 0.6, s * 0.35, 0, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(255,255,200,${flash * 0.12})`;
      ctx.fill();
    }

    ctx.restore();
  }
}

// ════════════════════════════════════════════
// ██  BUBBLE
// ════════════════════════════════════════════
class Bubble {
  constructor(x, y, sizeScale) {
    this.r = rand(CONFIG.bubbleMinSize, CONFIG.bubbleMaxSize) * (sizeScale || 1);
    this.x = x !== undefined ? x + rand(-3, 3) : rand(0, width);
    this.y = y !== undefined ? y : height + rand(0, 20);
    this.speed = rand(0.3, 0.7) * CONFIG.bubbleSpeed;
    this.wobblePhase = rand(0, Math.PI * 2);
    this.wobbleAmp = rand(0.2, 0.6);
  }
  update() {
    this.y -= this.speed;
    this.wobblePhase += 0.03;
    this.x += Math.sin(this.wobblePhase) * this.wobbleAmp;
    // Pop at surface with tiny chance
    return this.y + this.r > -5;
  }
  draw() {
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r, 0, Math.PI * 2);
    ctx.strokeStyle = CONFIG.bubbleColor;
    ctx.lineWidth = 0.7;
    ctx.stroke();
    ctx.fillStyle = CONFIG.bubbleColor.replace(/[\d.]+\)$/, '0.06)');
    ctx.fill();
    if (CONFIG.bubbleShine && this.r > 2) {
      ctx.beginPath();
      ctx.arc(this.x - this.r * 0.25, this.y - this.r * 0.3, this.r * 0.25, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.3)';
      ctx.fill();
    }
  }
}

// ════════════════════════════════════════════
// ██  PLANT
// ════════════════════════════════════════════
class Plant {
  constructor(x) {
    this.x = x;
    this.baseY = height - CONFIG.sandHeight * 0.5;
    this.h = rand(CONFIG.plantMinHeight, CONFIG.plantMaxHeight);
    this.segs = CONFIG.plantSegments;
    const c = CONFIG.plantColors[Math.floor(Math.random() * CONFIG.plantColors.length)];
    this.color = hexRgb(c);
    this.phase = rand(0, Math.PI * 2);
    this.leafW = CONFIG.plantLeafWidth * rand(0.7, 1.3);
    this.depth = rand(0.4, 1); // depth dimming
  }
  draw() {
    const sway = CONFIG.plantSwayAmount;
    const sp = CONFIG.plantSwaySpeed;
    const segH = this.h / this.segs;
    const c = this.color;

    // Build spine points
    const pts = [{ x: this.x, y: this.baseY }];
    for (let i = 1; i <= this.segs; i++) {
      const t = i / this.segs;
      const swayX = Math.sin(time * sp + this.phase + i * 0.45) * sway * t * t
                   + Math.sin(time * sp * 0.6 + this.phase + i * 0.8) * sway * 0.3 * t;
      pts.push({ x: this.x + swayX, y: this.baseY - i * segH });
    }

    // Draw as filled leaf shape (tapered)
    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) {
      const t = i / this.segs;
      const w = this.leafW * (1 - t * 0.7) * 0.5; // taper toward tip
      ctx.lineTo(pts[i].x - w, pts[i].y);
    }
    // Tip
    ctx.lineTo(pts[pts.length - 1].x, pts[pts.length - 1].y - 3);
    // Return down the other side
    for (let i = pts.length - 1; i >= 1; i--) {
      const t = i / this.segs;
      const w = this.leafW * (1 - t * 0.7) * 0.5;
      ctx.lineTo(pts[i].x + w, pts[i].y);
    }
    ctx.closePath();

    const alpha = 0.25 * this.depth;
    ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha})`;
    ctx.fill();

    // Midrib line
    ctx.beginPath();
    ctx.moveTo(pts[0].x, pts[0].y);
    for (let i = 1; i < pts.length; i++) {
      ctx.lineTo(pts[i].x, pts[i].y);
    }
    ctx.strokeStyle = `rgba(${Math.max(0,c[0]-30)},${Math.max(0,c[1]-30)},${Math.max(0,c[2]-20)},${alpha * 0.8})`;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

// ════════════════════════════════════════════
// ██  PARTICLE / ROCK
// ════════════════════════════════════════════
class Particle {
  constructor() { this.reset(); }
  reset() {
    this.x = rand(0, width); this.y = rand(10, height - CONFIG.sandHeight - 10);
    this.size = rand(0.8, 2.2); this.vx = rand(-0.08, 0.08); this.vy = rand(-0.1, 0.04);
    this.phase = rand(0, Math.PI * 2);
  }
  update() {
    this.phase += 0.008;
    this.x += this.vx + Math.sin(this.phase) * 0.04;
    this.y += this.vy;
    if (this.y < -5 || this.y > height - CONFIG.sandHeight || this.x < -5 || this.x > width + 5) this.reset();
  }
  draw() {
    ctx.beginPath(); ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = 'rgba(160,190,150,0.1)'; ctx.fill();
  }
}

function makeRock(x) {
  const w = rand(8, 22), h = rand(5, 14);
  const shade = rand(40, 70);
  return { x, y: height - CONFIG.sandHeight + rand(-3, 3), w, h,
    color: `rgba(${shade},${shade - 5},${shade - 15},0.5)`,
    highlight: `rgba(${shade + 30},${shade + 25},${shade + 15},0.2)` };
}

// ════════════════════════════════════════════
// ██  INIT & RENDER
// ════════════════════════════════════════════
function initScene() {
  allFish = []; for (let i = 0; i < CONFIG.fishCount; i++) allFish.push(new Fish());
  bubbles = []; for (let i = 0; i < CONFIG.bubbleCount; i++) { const b = new Bubble(); b.y = rand(10, height); bubbles.push(b); }
  plants = []; for (let i = 0; i < CONFIG.plantCount; i++) plants.push(new Plant(rand(15, width - 15)));
  particles = []; for (let i = 0; i < CONFIG.particleCount; i++) particles.push(new Particle());
  rocks = []; for (let i = 0; i < CONFIG.rockCount; i++) rocks.push(makeRock(rand(10, width - 10)));
  aerators = []; for (let i = 0; i < CONFIG.aeratorCount; i++) aerators.push({ x: width * (i + 1) / (CONFIG.aeratorCount + 1), timer: 0 });
  foodPellets = [];
  feedTimer = 0;
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 0.016;

    // ── Water background ──
    const tc = CONFIG.waterTopColor, wbc = CONFIG.waterBottomColor;
    const wg = ctx.createLinearGradient(0, 0, 0, height);
    wg.addColorStop(0, `rgb(${tc[0]},${tc[1]},${tc[2]})`);
    wg.addColorStop(1, `rgb(${wbc[0]},${wbc[1]},${wbc[2]})`);
    ctx.fillStyle = wg;
    ctx.fillRect(0, 0, width, height);

    // ── Light rays ──
    if (CONFIG.lightRaysEnabled) {
      for (let i = 0; i < CONFIG.lightRayCount; i++) {
        const bx = width * (i + 0.5) / CONFIG.lightRayCount;
        const sw = Math.sin(time * 0.25 + i * 2.1) * 35;
        const sp = 45 + Math.sin(time * 0.18 + i * 1.3) * 18;
        ctx.beginPath();
        ctx.moveTo(bx + sw - 6, 0); ctx.lineTo(bx + sw + 6, 0);
        ctx.lineTo(bx + sp + sw * 0.4, height); ctx.lineTo(bx - sp + sw * 0.4, height);
        ctx.closePath();
        ctx.fillStyle = `rgba(140,210,255,${CONFIG.lightRayOpacity})`;
        ctx.fill();
      }
    }

    // ── Caustics ──
    if (CONFIG.causticsEnabled) {
      const sandTop = height - CONFIG.sandHeight;
      const cs = CONFIG.causticsSpeed;
      for (let x = 0; x < width; x += 10) {
        for (let y = sandTop - 15; y < height; y += 10) {
          const v = Math.sin(x * 0.028 + time * cs) * Math.cos(y * 0.035 + time * cs * 0.65)
                  + Math.sin(x * 0.018 - time * cs * 0.4 + y * 0.012) * 0.5;
          if (v > 0.35) {
            ctx.fillStyle = `rgba(100,200,255,${(v - 0.35) * 0.06})`;
            ctx.fillRect(x, y, 10, 10);
          }
        }
      }
    }

    // ── Sand ──
    const sc = CONFIG.sandColor;
    const sandBase = height - CONFIG.sandHeight;
    const sg = ctx.createLinearGradient(0, sandBase, 0, height);
    sg.addColorStop(0, `rgba(${sc[0]},${sc[1]},${sc[2]},0.65)`);
    sg.addColorStop(0.35, `rgba(${sc[0]},${sc[1]},${sc[2]},0.85)`);
    sg.addColorStop(1, `rgba(${Math.max(0,sc[0]-20)},${Math.max(0,sc[1]-18)},${Math.max(0,sc[2]-12)},0.92)`);
    ctx.fillStyle = sg;
    ctx.beginPath(); ctx.moveTo(0, height); ctx.lineTo(0, sandBase);
    for (let x = 0; x <= width; x += 3) {
      ctx.lineTo(x, sandBase + Math.sin(x * 0.02 + time * 0.25) * 3 + Math.sin(x * 0.055 + 0.8) * 1.5);
    }
    ctx.lineTo(width, height); ctx.closePath(); ctx.fill();

    // Sand speckles
    ctx.fillStyle = `rgba(${Math.min(255,sc[0]+25)},${Math.min(255,sc[1]+20)},${Math.min(255,sc[2]+12)},0.12)`;
    for (let i = 0; i < 50; i++) {
      ctx.fillRect((i * 41 + i * i * 11) % width, sandBase + 6 + ((i * 59 + i * 17) % Math.max(1, CONFIG.sandHeight - 8)), rand(1, 2.5), 1);
    }

    // ── Rocks ──
    for (const r of rocks) {
      ctx.beginPath();
      ctx.ellipse(r.x, r.y, r.w * 0.5, r.h * 0.5, 0, 0, Math.PI * 2);
      ctx.fillStyle = r.color; ctx.fill();
      ctx.beginPath();
      ctx.ellipse(r.x - r.w * 0.1, r.y - r.h * 0.15, r.w * 0.3, r.h * 0.25, -0.3, 0, Math.PI * 2);
      ctx.fillStyle = r.highlight; ctx.fill();
    }

    // ── Plants ──
    plants.sort((a, b) => a.depth - b.depth);
    for (const p of plants) p.draw();

    // ── Particles ──
    for (const p of particles) { p.update(); p.draw(); }

    // ── Food ──
    // Drop food when mouse is in feed zone
    if (CONFIG.feedingEnabled && mouse.x > 0 && mouse.y >= 0 && mouse.y < height * CONFIG.feedZoneHeight) {
      feedTimer++;
      if (feedTimer % CONFIG.foodDropRate === 0 && foodPellets.length < CONFIG.maxFood) {
        foodPellets.push(new Food(mouse.x));
      }
    }
    // Update and draw food
    for (let i = foodPellets.length - 1; i >= 0; i--) {
      if (!foodPellets[i].update() || foodPellets[i].eaten) { foodPellets.splice(i, 1); }
      else { foodPellets[i].draw(); }
    }

    // ── Fish shadows ──
    for (const f of allFish) f.drawShadow();

    // ── Fish ──
    for (const f of allFish) f.update();
    allFish.sort((a, b) => a.depth - b.depth);
    for (const f of allFish) f.draw();

    // ── Bubbles ──
    // Aerator streams
    for (const a of aerators) {
      a.timer++;
      if (a.timer % CONFIG.aeratorRate === 0) {
        bubbles.push(new Bubble(a.x, height - CONFIG.sandHeight - 2, 0.6));
      }
    }
    while (bubbles.length < CONFIG.bubbleCount) bubbles.push(new Bubble());
    for (let i = bubbles.length - 1; i >= 0; i--) {
      if (!bubbles[i].update()) bubbles.splice(i, 1);
      else bubbles[i].draw();
    }
    if (bubbles.length > CONFIG.bubbleCount * 4) bubbles.splice(0, bubbles.length - CONFIG.bubbleCount * 2);

    // ── Surface ripple ──
    if (CONFIG.surfaceRipple) {
      ctx.beginPath();
      ctx.moveTo(0, 0);
      for (let x = 0; x <= width; x += 3) {
        const wave = Math.sin(x * 0.015 + time * 1.2) * 2.5
                   + Math.sin(x * 0.04 + time * 0.8) * 1
                   + Math.cos(x * 0.025 - time * 0.6) * 1.5;
        ctx.lineTo(x, 4 + wave);
      }
      ctx.lineTo(width, 0); ctx.closePath();
      ctx.fillStyle = 'rgba(120,200,255,0.07)';
      ctx.fill();
      // Bright line
      ctx.beginPath();
      for (let x = 0; x <= width; x += 2) {
        const wave = Math.sin(x * 0.015 + time * 1.2) * 2.5
                   + Math.sin(x * 0.04 + time * 0.8) * 1
                   + Math.cos(x * 0.025 - time * 0.6) * 1.5;
        if (x === 0) ctx.moveTo(x, 4 + wave); else ctx.lineTo(x, 4 + wave);
      }
      ctx.strokeStyle = 'rgba(180,230,255,0.15)';
      ctx.lineWidth = 1;
      ctx.stroke();
    }

    // ── Feed zone indicator ──
    if (CONFIG.feedingEnabled && mouse.x > 0 && mouse.y >= 0 && mouse.y < height * CONFIG.feedZoneHeight) {
      const zoneH = height * CONFIG.feedZoneHeight;
      const ig = ctx.createLinearGradient(0, 0, 0, zoneH);
      ig.addColorStop(0, 'rgba(255,220,100,0.04)');
      ig.addColorStop(1, 'rgba(255,220,100,0)');
      ctx.fillStyle = ig;
      ctx.fillRect(0, 0, width, zoneH);
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initScene(); startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initScene();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: DNA Double Helix
 * Description: A rotating double-helix DNA strand rendered in 3D perspective with
 *   base-pair rungs, phosphate backbone nodes, and ambient bio-glow particles.
 *   Mouse Y modulates rotation speed; mouse X shifts the helix horizontally.
 */

// ─── CONFIG ──────────────────────────────────────────────────────────────────
const CONFIG = {
	helixRadius: 80, // px – radius of each helical strand
	helixPitch: 300, // px – vertical distance per full 360° turn
	basePairCount: 60, // number of base-pair rungs visible
	basePairWidth: 3, // px – thickness of each rung bar
	basePairGap: 6, // px – gap in the centre of each rung
	rotationSpeed: 0.4, // radians/s – base rotation speed
	verticalScroll: 30, // px/s – upward scroll speed of the helix
	depthFade: 0.55, // 0-1 – alpha multiplier for furthest depth
	backboneNodeRadius: 4, // px – radius of phosphate backbone spheres
	backboneNodeCount: 120, // total backbone nodes per strand
	glowParticleCount: 90, // ambient glow particles floating around
	glowParticleRadius: 2.5, // px – max radius of glow particles
	glowParticleAlpha: 0.35, // base alpha of glow particles
	glowParticleDrift: 20, // px/s – max drift speed
	perspectiveScale: 0.4, // depth scale factor (0 = flat, 1 = extreme)
	strandWidth: 2.5, // px – width of the backbone line
	strandAlpha: 0.85, // base alpha of backbone strands
	glowPasses: 3, // number of additive glow blur passes
	glowExpand: 6, // px expansion per glow pass
	glowAlpha: 0.07, // alpha per glow pass
	trailAlpha: 0.12, // motion trail overlay alpha (lower = longer trails)
	colors: {
		a: '#ff4466', // Adenine
		t: '#4488ff', // Thymine
		g: '#44dd88', // Guanine
		c: '#ffcc44', // Cytosine
		strand1: '#88ccff', // strand 1 backbone colour
		strand2: '#ff88cc', // strand 2 backbone colour
		glow: '#66ddff' // ambient glow particle colour
	}
};

// ─── GLOBALS ─────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;
let phase = 0; // current rotation phase in radians
let scrollOffset = 0; // vertical scroll accumulator

// Typed arrays for glow particles (x, y, z, vx, vy, radius, hueShift)
const GLOW_STRIDE = 7;
let glowData = null; // Float32Array

// Base pair sequence cache
let basePairSequence = null; // Uint8Array: 0=AT, 1=TA, 2=GC, 3=CG

// Heartbeat
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function hexToRgb(hex) {
	const v = parseInt(hex.slice(1), 16);
	return [(v >> 16) & 255, (v >> 8) & 255, v & 255];
}

function lerpColor(r, g, b, a) {
	return `rgba(${r},${g},${b},${a.toFixed(3)})`;
}

function seededRandom(i) {
	let x = Math.sin(i * 127.1 + 311.7) * 43758.5453;
	return x - Math.floor(x);
}

// ─── INIT ────────────────────────────────────────────────────────────────────
function initGlowParticles() {
	const count = CONFIG.glowParticleCount;
	glowData = new Float32Array(count * GLOW_STRIDE);
	for (let i = 0; i < count; i++) {
		const off = i * GLOW_STRIDE;
		glowData[off + 0] = Math.random() * width; // x
		glowData[off + 1] = Math.random() * height; // y
		glowData[off + 2] = Math.random(); // z (0=far, 1=near)
		glowData[off + 3] = (Math.random() - 0.5) * CONFIG.glowParticleDrift; // vx
		glowData[off + 4] = (Math.random() - 0.5) * CONFIG.glowParticleDrift; // vy
		glowData[off + 5] = Math.random() * CONFIG.glowParticleRadius; // radius
		glowData[off + 6] = Math.random() * 60 - 30; // hue shift
	}
}

function initBasePairs() {
	basePairSequence = new Uint8Array(CONFIG.basePairCount);
	for (let i = 0; i < CONFIG.basePairCount; i++) {
		basePairSequence[i] = Math.floor(Math.random() * 4);
	}
}

function initAll() {
	initGlowParticles();
	initBasePairs();
	lastTime = 0;
}

// ─── BASE PAIR COLORS ───────────────────────────────────────────────────────
const pairMap = [
	{ left: 'a', right: 't' },
	{ left: 't', right: 'a' },
	{ left: 'g', right: 'c' },
	{ left: 'c', right: 'g' }
];

const colorCache = {};
function getRgb(key) {
	if (!colorCache[key]) colorCache[key] = hexToRgb(CONFIG.colors[key]);
	return colorCache[key];
}

// ─── RENDER ──────────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) {
			requestAnimationFrame(render);
			return;
		}
		now *= 0.001; // ms → s
		const dt = lastTime ? Math.min(now - lastTime, 0.05) : 0.016;
		lastTime = now;

		// Mouse influence
		const mouseNormY =
			mouse.y >= 0 && mouse.y <= height
				? (mouse.y / height - 0.5) * 2 // -1 to 1
				: 0;
		const mouseShiftX =
			mouse.x >= 0 && mouse.x <= width ? (mouse.x / width - 0.5) * width * 0.3 : 0;

		const effectiveRotSpeed = CONFIG.rotationSpeed * (1 + mouseNormY * 1.5);
		phase += effectiveRotSpeed * dt;
		scrollOffset += CONFIG.verticalScroll * dt;

		// ── Motion trail (semi-transparent overlay instead of full clear) ──
		ctx.fillStyle = `rgba(0,0,0,${CONFIG.trailAlpha})`;
		ctx.fillRect(0, 0, width, height);

		const cx = width / 2 + mouseShiftX;
		const cy = height / 2;

		// ── Draw ambient glow particles ──
		updateAndDrawGlow(dt);

		// ── Collect all helix elements, sort by depth, then draw ──
		const elements = buildHelixElements(cx, cy);
		elements.sort((a, b) => a.z - b.z); // painter's order: far first

		// Pass 1: glow (additive)
		ctx.globalCompositeOperation = 'lighter';
		for (let pass = 0; pass < CONFIG.glowPasses; pass++) {
			const expand = (pass + 1) * CONFIG.glowExpand;
			const alpha = CONFIG.glowAlpha / (pass + 1);
			for (const el of elements) {
				drawElementGlow(el, expand, alpha);
			}
		}

		// Pass 2: solid
		ctx.globalCompositeOperation = 'source-over';
		for (const el of elements) {
			drawElement(el);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── BUILD HELIX ELEMENTS ───────────────────────────────────────────────────
function buildHelixElements(cx, cy) {
	const elements = [];
	const {
		helixRadius,
		helixPitch,
		basePairCount,
		basePairGap,
		backboneNodeRadius,
		perspectiveScale,
		depthFade,
		strandWidth,
		strandAlpha
	} = CONFIG;
	const spacing = helixPitch / basePairCount;

	for (let i = 0; i < basePairCount; i++) {
		const vertPos = i * spacing - (scrollOffset % helixPitch);
		const y = cy + vertPos - (basePairCount * spacing) / 2;

		// Skip off-screen
		if (y < -60 || y > height + 60) continue;

		const angle = phase + (i / basePairCount) * Math.PI * 2;
		const cosA = Math.cos(angle);
		const sinA = Math.sin(angle);

		// Strand 1 and Strand 2 positions (offset by π)
		const x1 = cx + cosA * helixRadius;
		const z1 = sinA; // -1 to 1 normalised depth
		const x2 = cx - cosA * helixRadius;
		const z2 = -sinA;

		const scale1 = 1 + z1 * perspectiveScale;
		const scale2 = 1 + z2 * perspectiveScale;
		const alpha1 = strandAlpha * (1 - (1 - depthFade) * (1 - (z1 + 1) / 2));
		const alpha2 = strandAlpha * (1 - (1 - depthFade) * (1 - (z2 + 1) / 2));

		// Base pair rung
		const pair = pairMap[basePairSequence[i % basePairSequence.length]];
		const leftRgb = getRgb(pair.left);
		const rightRgb = getRgb(pair.right);
		const avgZ = (z1 + z2) / 2;
		const rungAlpha = strandAlpha * (1 - (1 - depthFade) * (1 - (avgZ + 1) / 2));

		// Push rung (two halves)
		elements.push({
			type: 'rung',
			x1,
			y,
			x2,
			y2: y,
			gap: basePairGap * ((scale1 + scale2) / 2),
			width: CONFIG.basePairWidth * ((scale1 + scale2) / 2),
			leftColor: leftRgb,
			rightColor: rightRgb,
			alpha: rungAlpha * 0.8,
			z: avgZ
		});

		// Backbone nodes
		elements.push({
			type: 'node',
			x: x1,
			y,
			r: backboneNodeRadius * scale1,
			color: getRgb(CONFIG.colors.strand1.replace('#', '').length ? 'strand1' : 'a'),
			colorHex: CONFIG.colors.strand1,
			alpha: alpha1,
			z: z1
		});
		elements.push({
			type: 'node',
			x: x2,
			y,
			r: backboneNodeRadius * scale2,
			color: hexToRgb(CONFIG.colors.strand2),
			colorHex: CONFIG.colors.strand2,
			alpha: alpha2,
			z: z2
		});
	}

	return elements;
}

function drawElementGlow(el, expand, alpha) {
	const a = el.alpha * alpha;
	if (a < 0.005) return;

	if (el.type === 'node') {
		ctx.beginPath();
		ctx.arc(el.x, el.y, el.r + expand, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(el.color[0], el.color[1], el.color[2], a);
		ctx.fill();
	} else if (el.type === 'rung') {
		const midX = (el.x1 + el.x2) / 2;
		ctx.lineWidth = el.width + expand;
		ctx.lineCap = 'round';
		// Left half
		ctx.beginPath();
		ctx.moveTo(el.x1, el.y);
		ctx.lineTo(midX - el.gap / 2, el.y);
		ctx.strokeStyle = lerpColor(el.leftColor[0], el.leftColor[1], el.leftColor[2], a);
		ctx.stroke();
		// Right half
		ctx.beginPath();
		ctx.moveTo(midX + el.gap / 2, el.y);
		ctx.lineTo(el.x2, el.y);
		ctx.strokeStyle = lerpColor(el.rightColor[0], el.rightColor[1], el.rightColor[2], a);
		ctx.stroke();
	}
}

function drawElement(el) {
	if (el.type === 'node') {
		// Phosphate backbone sphere
		const r = el.r;
		const col = el.color;
		ctx.beginPath();
		ctx.arc(el.x, el.y, r, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(col[0], col[1], col[2], el.alpha);
		ctx.fill();
		// Highlight
		ctx.beginPath();
		ctx.arc(el.x - r * 0.25, el.y - r * 0.25, r * 0.4, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(255, 255, 255, el.alpha * 0.4);
		ctx.fill();
	} else if (el.type === 'rung') {
		const midX = (el.x1 + el.x2) / 2;
		ctx.lineWidth = el.width;
		ctx.lineCap = 'round';
		// Left half
		ctx.beginPath();
		ctx.moveTo(el.x1, el.y);
		ctx.lineTo(midX - el.gap / 2, el.y);
		ctx.strokeStyle = lerpColor(el.leftColor[0], el.leftColor[1], el.leftColor[2], el.alpha);
		ctx.stroke();
		// Right half
		ctx.beginPath();
		ctx.moveTo(midX + el.gap / 2, el.y);
		ctx.lineTo(el.x2, el.y);
		ctx.strokeStyle = lerpColor(el.rightColor[0], el.rightColor[1], el.rightColor[2], el.alpha);
		ctx.stroke();
	}
}

// ─── GLOW PARTICLES ─────────────────────────────────────────────────────────
function updateAndDrawGlow(dt) {
	const count = CONFIG.glowParticleCount;
	const rgb = hexToRgb(CONFIG.colors.glow);

	ctx.globalCompositeOperation = 'lighter';
	for (let i = 0; i < count; i++) {
		const off = i * GLOW_STRIDE;
		let x = glowData[off + 0];
		let y = glowData[off + 1];
		const z = glowData[off + 2];
		const vx = glowData[off + 3];
		const vy = glowData[off + 4];
		const r = glowData[off + 5];
		const hueShift = glowData[off + 6];

		x += vx * dt;
		y += vy * dt;

		// Wrap
		if (x < -20) x += width + 40;
		if (x > width + 20) x -= width + 40;
		if (y < -20) y += height + 40;
		if (y > height + 20) y -= height + 40;

		glowData[off + 0] = x;
		glowData[off + 1] = y;

		const alpha = CONFIG.glowParticleAlpha * (0.3 + z * 0.7);
		const scaledR = r * (0.5 + z * 0.5);

		// Soft glow circle
		ctx.beginPath();
		ctx.arc(x, y, scaledR * 3, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(rgb[0], rgb[1], rgb[2], alpha * 0.15);
		ctx.fill();

		ctx.beginPath();
		ctx.arc(x, y, scaledR, 0, Math.PI * 2);
		ctx.fillStyle = lerpColor(rgb[0], rgb[1], rgb[2], alpha);
		ctx.fill();
	}
	ctx.globalCompositeOperation = 'source-over';
}

// ─── MESSAGE HANDLER ─────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initAll();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Electric Tendrils
 * Description: Branching electric arcs reach from screen edge anchors toward your
 *   mouse cursor. Bolts fork recursively with configurable depth, render in 3
 *   glow layers, and flash with impact circles. Proximity makes anchors fire
 *   faster. Ambient mini-arcs crackle between anchors.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Anchors --
  anchorCount: 8,                         // Edge anchor points (3-12)
  proximityBoost: true,                   // Fire faster when mouse is close

  // -- Bolt Appearance --
  boltColor: '#00ccff',                   // Primary bolt color
  boltCoreColor: '#ffffff',               // White-hot center color
  boltSegments: 16,                       // Segments per bolt (8-30)
  boltJitter: 22,                         // Random displacement per segment px (5-40)
  boltWidth: 4,                           // Outer glow width (2-8)
  boltCoreWidth: 1.5,                     // Center line width (0.5-3)

  // -- Bolt Behavior --
  boltDuration: 8,                        // Frames a bolt stays visible (3-15)
  boltFrequency: 28,                      // Base frames between bolts per anchor (10-60)

  // -- Forking --
  forkProbability: 0.25,                  // Branch chance at each segment (0-0.5)
  forkMaxDepth: 3,                        // Max branch recursion depth (1-4)
  forkLengthRatio: 0.45,                  // Branch length relative to remaining (0.2-0.7)

  // -- Flash --
  flashRadius: 40,                        // Impact flash circle radius (15-80)
  flashOpacity: 0.3,                      // Impact flash brightness (0.1-0.6)

  // -- Ambient --
  ambientArcs: true,                      // Random mini-arcs between anchors
  ambientArcFrequency: 35,               // Frames between ambient arcs (15-120)
  fieldGlow: true,                        // Background electric field gradient
  fieldGlowColor: '#001a33',             // Field gradient color
  fieldGlowIntensity: 0.04,              // Field gradient opacity (0.01-0.1)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let time = 0;
let anchors = [];
let activeBolts = [];
let ambientTimer = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }
function rand(a, b) { return Math.random() * (b - a) + a; }

function initAnchors() {
  anchors = [];
  const n = CONFIG.anchorCount;
  const perimeter = (width + height) * 2;
  for (let i = 0; i < n; i++) {
    const p = (i / n) * perimeter;
    let x, y;
    if (p < width) { x = p; y = 0; }
    else if (p < width + height) { x = width; y = p - width; }
    else if (p < width * 2 + height) { x = width - (p - width - height); y = height; }
    else { x = 0; y = height - (p - width * 2 - height); }
    anchors.push({ x, y, timer: Math.floor(rand(0, CONFIG.boltFrequency)) });
  }
}

function generateBolt(x0, y0, x1, y1, segments, jitter, depth) {
  const points = [{ x: x0, y: y0 }];
  const forks = [];

  for (let i = 1; i < segments; i++) {
    const t = i / segments;
    const bx = x0 + (x1 - x0) * t + (Math.random() - 0.5) * jitter * 2;
    const by = y0 + (y1 - y0) * t + (Math.random() - 0.5) * jitter * 2;
    points.push({ x: bx, y: by });

    // Fork chance
    if (depth < CONFIG.forkMaxDepth && Math.random() < CONFIG.forkProbability && i > 2 && i < segments - 2) {
      const remaining = segments - i;
      const forkSegs = Math.max(3, Math.floor(remaining * CONFIG.forkLengthRatio));
      const angle = Math.atan2(y1 - y0, x1 - x0) + (Math.random() - 0.5) * 1.2;
      const forkLen = Math.hypot(x1 - bx, y1 - by) * CONFIG.forkLengthRatio;
      const fx = bx + Math.cos(angle) * forkLen;
      const fy = by + Math.sin(angle) * forkLen;
      forks.push(generateBolt(bx, by, fx, fy, forkSegs, jitter * 0.7, depth + 1));
    }
  }
  points.push({ x: x1, y: y1 });

  return { points, forks, depth };
}

function drawBoltPath(bolt, alpha) {
  const pts = bolt.points;
  if (pts.length < 2) return;
  const c = hexRgb(CONFIG.boltColor);
  const depthFade = Math.pow(0.6, bolt.depth);

  // Build path once
  ctx.beginPath();
  ctx.moveTo(pts[0].x, pts[0].y);
  for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);

  // Layer 1: outer glow
  ctx.strokeStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha * 0.12 * depthFade})`;
  ctx.lineWidth = CONFIG.boltWidth * 3 * depthFade;
  ctx.lineJoin = 'round';
  ctx.stroke();

  // Layer 2: colored core
  ctx.strokeStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha * 0.5 * depthFade})`;
  ctx.lineWidth = CONFIG.boltWidth * depthFade;
  ctx.stroke();

  // Layer 3: white-hot center
  const cc = hexRgb(CONFIG.boltCoreColor);
  ctx.strokeStyle = `rgba(${cc[0]},${cc[1]},${cc[2]},${alpha * 0.8 * depthFade})`;
  ctx.lineWidth = CONFIG.boltCoreWidth * depthFade;
  ctx.stroke();

  // Draw forks recursively
  for (const fork of bolt.forks) {
    drawBoltPath(fork, alpha * 0.7);
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 1;

    // -- Clear with slight fade for afterimage --
    ctx.fillStyle = 'rgba(2,2,8,0.25)';
    ctx.fillRect(0, 0, width, height);

    // -- Background field glow toward mouse --
    if (CONFIG.fieldGlow && mouse.x >= 0) {
      const fc = hexRgb(CONFIG.fieldGlowColor);
      const g = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, Math.max(width, height) * 0.6);
      g.addColorStop(0, `rgba(${fc[0]},${fc[1]},${fc[2]},${CONFIG.fieldGlowIntensity})`);
      g.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = g;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Fire bolts from anchors --
    if (mouse.x >= 0 && mouse.y >= 0) {
      for (const a of anchors) {
        a.timer--;
        let freq = CONFIG.boltFrequency;
        if (CONFIG.proximityBoost) {
          const d = Math.hypot(a.x - mouse.x, a.y - mouse.y);
          const boost = Math.max(0.3, d / Math.max(width, height));
          freq = Math.floor(freq * boost);
        }
        if (a.timer <= 0) {
          a.timer = Math.max(5, freq + Math.floor(rand(-5, 5)));
          const bolt = generateBolt(a.x, a.y, mouse.x + rand(-10, 10), mouse.y + rand(-10, 10),
            CONFIG.boltSegments, CONFIG.boltJitter, 0);
          activeBolts.push({ bolt, life: CONFIG.boltDuration, maxLife: CONFIG.boltDuration,
            anchorX: a.x, anchorY: a.y, targetX: mouse.x, targetY: mouse.y });
        }
      }
    }

    // -- Ambient arcs --
    if (CONFIG.ambientArcs && anchors.length > 1) {
      ambientTimer--;
      if (ambientTimer <= 0) {
        ambientTimer = CONFIG.ambientArcFrequency + Math.floor(rand(-8, 8));
        const i = Math.floor(rand(0, anchors.length));
        let j = (i + 1 + Math.floor(rand(0, 2))) % anchors.length;
        const a1 = anchors[i], a2 = anchors[j];
        const bolt = generateBolt(a1.x, a1.y, a2.x, a2.y, 8, CONFIG.boltJitter * 0.5, 1);
        activeBolts.push({ bolt, life: 4, maxLife: 4, anchorX: a1.x, anchorY: a1.y, targetX: a2.x, targetY: a2.y });
      }
    }

    // -- Draw active bolts --
    const bc = hexRgb(CONFIG.boltColor);
    for (let i = activeBolts.length - 1; i >= 0; i--) {
      const ab = activeBolts[i];
      ab.life--;
      if (ab.life <= 0) { activeBolts.splice(i, 1); continue; }

      const alpha = ab.life / ab.maxLife;

      // Flash at initial frame
      if (ab.life === ab.maxLife - 1) {
        // Anchor flash
        ctx.beginPath();
        ctx.arc(ab.anchorX, ab.anchorY, CONFIG.flashRadius * 0.6, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${bc[0]},${bc[1]},${bc[2]},${CONFIG.flashOpacity * 0.5})`;
        ctx.fill();
        // Target flash
        ctx.beginPath();
        ctx.arc(ab.targetX, ab.targetY, CONFIG.flashRadius, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${bc[0]},${bc[1]},${bc[2]},${CONFIG.flashOpacity})`;
        ctx.fill();
      }

      drawBoltPath(ab.bolt, alpha);
    }

    // -- Anchor point indicators --
    for (const a of anchors) {
      ctx.beginPath();
      ctx.arc(a.x, a.y, 3, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${bc[0]},${bc[1]},${bc[2]},0.15)`;
      ctx.fill();
    }

    // Cap bolts
    if (activeBolts.length > 50) activeBolts.splice(0, activeBolts.length - 40);

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      ctx.fillStyle = '#020208'; ctx.fillRect(0, 0, width, height);
      initAnchors();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      ctx.fillStyle = '#020208'; ctx.fillRect(0, 0, width, height);
      initAnchors();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Ember Dream
 * Description: A warm, hypnotic field of drifting embers and ghostly flame wisps
 *   rising through the screen like a campfire viewed in a trance. Features pooled
 *   glowing particles with pulsing halos, translucent bezier flame shapes that
 *   morph as they rise, ambient glow pools, and a subtle heat shimmer. Mouse
 *   creates a wind-dispersal effect; clicks burst new embers outward.
 */

// ─── CONFIG ────────────────────────────────────────────────────────────────────
const CONFIG = {
	// Embers
	emberCount: 180,
	emberMinCore: 1,
	emberMaxCore: 3.5,
	emberMinGlow: 8,
	emberMaxGlow: 18,
	emberRiseSpeed: 0.3,
	emberRiseVariance: 0.2,
	emberSwayAmount: 30,
	emberSwaySpeed: 0.5,
	emberPulseSpeed: 1.2,
	emberPulseAmount: 0.4,
	emberFadeInZone: 0.15,      // Bottom 15% of screen: embers fade in
	emberFadeOutZone: 0.1,      // Top 10%: embers fade out
	emberSpawnSpread: 1.2,      // Horizontal spawn spread (1 = screen width)

	// Flame wisps
	wispCount: 10,
	wispMinAlpha: 0.025,
	wispMaxAlpha: 0.065,
	wispRiseSpeed: 0.15,
	wispWidth: 60,
	wispHeight: 200,
	wispSwayAmount: 40,
	wispControlPoints: 5,
	wispFlickerSpeed: 0.8,

	// Glow pools
	glowPoolCount: 4,
	glowPoolRadius: 200,
	glowPoolAlpha: 0.035,
	glowPoolDriftSpeed: 0.1,

	// Heat shimmer
	shimmerEnabled: true,
	shimmerAlpha: 0.015,
	shimmerWaveCount: 8,
	shimmerSpeed: 0.6,

	// Interaction
	windRadius: 160,
	windStrength: 2.5,
	burstCount: 25,
	burstSpeed: 3,
	burstDecay: 0.96,

	// Colors (HSLA)
	coreColor: [42, 100, 95],       // Near-white yellow
	glowColorHot: [30, 100, 60],    // Orange
	glowColorCool: [8, 90, 40],     // Deep red-orange
	wispColorTop: [45, 100, 65],    // Bright yellow
	wispColorMid: [25, 95, 50],     // Orange
	wispColorBase: [5, 85, 30],     // Deep crimson
	glowPoolColor: [20, 90, 45],    // Warm amber-orange
};

// ─── STATE ─────────────────────────────────────────────────────────────────────
let canvas, ctx, W, H;
let mouse = { x: -9999, y: -9999 };
let time = 0, lastNow = 0;

// Ember pool — flat arrays for performance
let emberX, emberY, emberVx, emberVy;
let emberCoreSize, emberGlowSize, emberPhase, emberSpeed, emberAlpha;
let emberHue, emberLife, emberMaxLife;
let emberActive;

// Wisps
let wisps = [];

// Glow pools
let glowPools = [];

// Burst embers (separate short-lived pool)
let bursts = [];

// ─── HEARTBEAT ─────────────────────────────────────────────────────────────────
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

// ─── UTILITIES ─────────────────────────────────────────────────────────────────
function rand(a, b) { return Math.random() * (b - a) + a; }
function lerp(a, b, t) { return a + (b - a) * t; }

// ─── EMBER POOL ────────────────────────────────────────────────────────────────
function initEmberPool() {
	const n = CONFIG.emberCount;
	emberX = new Float32Array(n);
	emberY = new Float32Array(n);
	emberVx = new Float32Array(n);
	emberVy = new Float32Array(n);
	emberCoreSize = new Float32Array(n);
	emberGlowSize = new Float32Array(n);
	emberPhase = new Float32Array(n);
	emberSpeed = new Float32Array(n);
	emberAlpha = new Float32Array(n);
	emberHue = new Float32Array(n);
	emberLife = new Float32Array(n);
	emberMaxLife = new Float32Array(n);
	emberActive = new Uint8Array(n);

	for (let i = 0; i < n; i++) {
		resetEmber(i, true);
	}
}

function resetEmber(i, scatter) {
	const w = W || 800;
	const h = H || 600;
	emberX[i] = rand(w * (1 - CONFIG.emberSpawnSpread) / 2, w * (1 + CONFIG.emberSpawnSpread) / 2);
	emberY[i] = scatter ? rand(0, h) : rand(h * 0.85, h * 1.05);
	emberVx[i] = rand(-0.2, 0.2);
	emberVy[i] = -(CONFIG.emberRiseSpeed + rand(0, CONFIG.emberRiseVariance));
	emberCoreSize[i] = rand(CONFIG.emberMinCore, CONFIG.emberMaxCore);
	emberGlowSize[i] = rand(CONFIG.emberMinGlow, CONFIG.emberMaxGlow);
	emberPhase[i] = rand(0, Math.PI * 2);
	emberSpeed[i] = rand(0.7, 1.3);
	emberHue[i] = rand(8, 42); // Red-orange to yellow
	emberLife[i] = 0;
	emberMaxLife[i] = rand(6, 14); // Seconds
	emberActive[i] = 1;
}

function updateEmbers(dt) {
	const n = CONFIG.emberCount;
	const fadeInY = H * (1 - CONFIG.emberFadeInZone);
	const fadeOutY = H * CONFIG.emberFadeOutZone;

	for (let i = 0; i < n; i++) {
		if (!emberActive[i]) {
			resetEmber(i, false);
			continue;
		}

		emberLife[i] += dt;
		if (emberLife[i] > emberMaxLife[i] || emberY[i] < -20) {
			resetEmber(i, false);
			continue;
		}

		// Phase for pulsing
		emberPhase[i] += CONFIG.emberPulseSpeed * dt * emberSpeed[i];

		// Sway
		const sway = Math.sin(time * CONFIG.emberSwaySpeed + emberPhase[i]) * CONFIG.emberSwayAmount * 0.01;
		emberVx[i] += sway * dt;

		// Wind from mouse
		const dx = emberX[i] - mouse.x;
		const dy = emberY[i] - mouse.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < CONFIG.windRadius && dist > 1) {
			const force = (1 - dist / CONFIG.windRadius) * CONFIG.windStrength;
			emberVx[i] += (dx / dist) * force * dt;
		}

		// Apply velocity
		emberX[i] += emberVx[i];
		emberY[i] += emberVy[i] * emberSpeed[i];

		// Dampen horizontal drift
		emberVx[i] *= 0.98;

		// Wrap horizontally
		if (emberX[i] < -20) emberX[i] = W + 20;
		if (emberX[i] > W + 20) emberX[i] = -20;

		// Calculate display alpha
		const lifeFrac = emberLife[i] / emberMaxLife[i];
		let alpha = 1;
		if (lifeFrac < 0.1) alpha = lifeFrac / 0.1;         // Fade in
		if (lifeFrac > 0.8) alpha = (1 - lifeFrac) / 0.2;   // Fade out
		// Spatial fade
		if (emberY[i] > fadeInY) alpha *= (H - emberY[i]) / (H * CONFIG.emberFadeInZone);
		if (emberY[i] < fadeOutY) alpha *= emberY[i] / (H * CONFIG.emberFadeOutZone);
		// Pulse
		alpha *= 1 + Math.sin(emberPhase[i]) * CONFIG.emberPulseAmount;
		emberAlpha[i] = Math.max(0, Math.min(1, alpha));
	}
}

function drawEmbers() {
	const n = CONFIG.emberCount;
	for (let i = 0; i < n; i++) {
		if (!emberActive[i] || emberAlpha[i] < 0.01) continue;

		const x = emberX[i];
		const y = emberY[i];
		const a = emberAlpha[i];
		const core = emberCoreSize[i];
		const glow = emberGlowSize[i];
		const hue = emberHue[i];

		// Glow halo
		const g = ctx.createRadialGradient(x, y, core * 0.5, x, y, glow);
		const hotA = a * 0.3;
		const coolA = 0;
		g.addColorStop(0, `hsla(${hue}, 100%, 70%, ${hotA})`);
		g.addColorStop(0.3, `hsla(${Math.max(5, hue - 15)}, 95%, 50%, ${hotA * 0.6})`);
		g.addColorStop(1, `hsla(${Math.max(0, hue - 25)}, 90%, 35%, ${coolA})`);
		ctx.beginPath();
		ctx.arc(x, y, glow, 0, Math.PI * 2);
		ctx.fillStyle = g;
		ctx.fill();

		// Bright core
		const cg = ctx.createRadialGradient(x, y, 0, x, y, core);
		cg.addColorStop(0, `hsla(45, 100%, 95%, ${a * 0.9})`);
		cg.addColorStop(1, `hsla(${hue}, 100%, 70%, ${a * 0.4})`);
		ctx.beginPath();
		ctx.arc(x, y, core, 0, Math.PI * 2);
		ctx.fillStyle = cg;
		ctx.fill();
	}
}

// ─── FLAME WISPS ───────────────────────────────────────────────────────────────
class Wisp {
	constructor() {
		this.reset();
	}

	reset() {
		const w = W || 800;
		const h = H || 600;
		this.x = rand(w * 0.1, w * 0.9);
		this.y = rand(h * 0.5, h * 1.1);
		this.width = CONFIG.wispWidth * rand(0.5, 1.5);
		this.height = CONFIG.wispHeight * rand(0.6, 1.4);
		this.alpha = rand(CONFIG.wispMinAlpha, CONFIG.wispMaxAlpha);
		this.phase = rand(0, Math.PI * 2);
		this.speed = rand(0.6, 1.4);
		this.swayPhase = rand(0, Math.PI * 2);
	}

	update(dt) {
		this.y -= CONFIG.wispRiseSpeed * this.speed * dt * 60;
		this.phase += CONFIG.wispFlickerSpeed * dt;
		this.swayPhase += 0.3 * dt;

		// Thin as it rises
		this.width *= (1 - 0.001 * dt * 60);
		this.height *= (1 - 0.0005 * dt * 60);

		if (this.y + this.height < -50 || this.alpha < 0.005) {
			this.reset();
		}
	}

	draw() {
		const cp = CONFIG.wispControlPoints;
		const x = this.x + Math.sin(this.swayPhase) * CONFIG.wispSwayAmount;
		const baseY = this.y;
		const h = this.height;
		const w = this.width;

		// Build a flickering flame shape with bezier curves
		ctx.beginPath();

		// Left side (bottom to top)
		ctx.moveTo(x, baseY);
		for (let i = 1; i < cp; i++) {
			const t = i / cp;
			const py = baseY - h * t;
			const widthAtT = w * 0.5 * (1 - t * t); // Parabolic taper
			const flicker = Math.sin(this.phase * 3 + i * 1.7) * w * 0.08 * (1 - t);
			const px = x - widthAtT + flicker;
			ctx.lineTo(px, py);
		}

		// Tip
		const tipFlicker = Math.sin(this.phase * 5) * w * 0.05;
		ctx.lineTo(x + tipFlicker, baseY - h);

		// Right side (top to bottom)
		for (let i = cp - 1; i >= 1; i--) {
			const t = i / cp;
			const py = baseY - h * t;
			const widthAtT = w * 0.5 * (1 - t * t);
			const flicker = Math.sin(this.phase * 3.3 + i * 2.1 + 1) * w * 0.08 * (1 - t);
			const px = x + widthAtT + flicker;
			ctx.lineTo(px, py);
		}

		ctx.closePath();

		// Gradient fill: red at base → orange mid → yellow tip
		const grad = ctx.createLinearGradient(x, baseY, x, baseY - h);
		const a = this.alpha;
		const bc = CONFIG.wispColorBase;
		const mc = CONFIG.wispColorMid;
		const tc = CONFIG.wispColorTop;
		grad.addColorStop(0, `hsla(${bc[0]}, ${bc[1]}%, ${bc[2]}%, ${a})`);
		grad.addColorStop(0.4, `hsla(${mc[0]}, ${mc[1]}%, ${mc[2]}%, ${a * 0.8})`);
		grad.addColorStop(0.7, `hsla(${tc[0]}, ${tc[1]}%, ${tc[2]}%, ${a * 0.5})`);
		grad.addColorStop(1, `hsla(${tc[0]}, ${tc[1]}%, ${tc[2]}%, 0)`);
		ctx.fillStyle = grad;
		ctx.fill();
	}
}

// ─── GLOW POOLS ────────────────────────────────────────────────────────────────
class GlowPool {
	constructor() {
		this.x = rand(0, W || 800);
		this.y = rand((H || 600) * 0.4, (H || 600) * 0.9);
		this.radius = CONFIG.glowPoolRadius * rand(0.7, 1.3);
		this.phase = rand(0, Math.PI * 2);
		this.driftX = rand(-1, 1) * CONFIG.glowPoolDriftSpeed;
		this.driftY = rand(-0.5, -0.1) * CONFIG.glowPoolDriftSpeed;
	}

	update(dt) {
		this.x += this.driftX * dt * 60;
		this.y += this.driftY * dt * 60;
		this.phase += 0.2 * dt;

		// Wrap
		if (this.x < -this.radius) this.x = W + this.radius;
		if (this.x > W + this.radius) this.x = -this.radius;
		if (this.y < -this.radius) {
			this.y = H * rand(0.6, 0.95);
			this.x = rand(0, W);
		}
	}

	draw() {
		const pulse = 1 + Math.sin(this.phase) * 0.3;
		const r = this.radius * pulse;
		const a = CONFIG.glowPoolAlpha * (0.7 + Math.sin(this.phase * 0.7) * 0.3);
		const c = CONFIG.glowPoolColor;

		const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r);
		g.addColorStop(0, `hsla(${c[0]}, ${c[1]}%, ${c[2]}%, ${a})`);
		g.addColorStop(0.5, `hsla(${c[0]}, ${c[1]}%, ${c[2]}%, ${a * 0.4})`);
		g.addColorStop(1, `hsla(${c[0]}, ${c[1]}%, ${c[2]}%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, r, 0, Math.PI * 2);
		ctx.fillStyle = g;
		ctx.fill();
	}
}

// ─── BURST EMBER ───────────────────────────────────────────────────────────────
class BurstEmber {
	constructor(x, y) {
		const angle = rand(0, Math.PI * 2);
		const speed = rand(1, CONFIG.burstSpeed);
		this.x = x;
		this.y = y;
		this.vx = Math.cos(angle) * speed;
		this.vy = Math.sin(angle) * speed - rand(0.5, 1.5); // Bias upward
		this.size = rand(1.5, 4);
		this.hue = rand(15, 50);
		this.life = 1;
		this.decay = CONFIG.burstDecay;
	}

	update(dt) {
		this.x += this.vx * dt * 60;
		this.y += this.vy * dt * 60;
		this.vy += 0.02 * dt * 60; // Gentle gravity
		this.life *= this.decay;
		this.vx *= 0.99;
		this.vy *= 0.99;
		return this.life > 0.01;
	}

	draw() {
		const a = this.life;
		// Glow
		const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.size * 5);
		g.addColorStop(0, `hsla(${this.hue}, 100%, 70%, ${a * 0.4})`);
		g.addColorStop(1, `hsla(${this.hue}, 90%, 40%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size * 5, 0, Math.PI * 2);
		ctx.fillStyle = g;
		ctx.fill();

		// Core
		ctx.beginPath();
		ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(45, 100%, 90%, ${a * 0.9})`;
		ctx.fill();
	}
}

// ─── HEAT SHIMMER ──────────────────────────────────────────────────────────────
function drawHeatShimmer() {
	if (!CONFIG.shimmerEnabled) return;
	const zoneTop = H * 0.65;
	const alpha = CONFIG.shimmerAlpha;

	for (let i = 0; i < CONFIG.shimmerWaveCount; i++) {
		const y = zoneTop + (H - zoneTop) * (i / CONFIG.shimmerWaveCount);
		const waveOffset = Math.sin(time * CONFIG.shimmerSpeed + i * 1.2) * 20;

		ctx.beginPath();
		for (let x = 0; x <= W; x += 4) {
			const wy = y + Math.sin(x * 0.01 + time * CONFIG.shimmerSpeed * 2 + i) * 3 + waveOffset;
			if (x === 0) ctx.moveTo(x, wy);
			else ctx.lineTo(x, wy);
		}
		ctx.strokeStyle = `hsla(25, 80%, 50%, ${alpha * (1 - (i / CONFIG.shimmerWaveCount) * 0.5)})`;
		ctx.lineWidth = rand(15, 30);
		ctx.stroke();
	}
}

// ─── INITIALIZATION ────────────────────────────────────────────────────────────
function initScene() {
	initEmberPool();

	wisps = [];
	for (let i = 0; i < CONFIG.wispCount; i++) {
		wisps.push(new Wisp());
	}

	glowPools = [];
	for (let i = 0; i < CONFIG.glowPoolCount; i++) {
		glowPools.push(new GlowPool());
	}

	bursts = [];
}

function spawnBurst(x, y) {
	for (let i = 0; i < CONFIG.burstCount; i++) {
		bursts.push(new BurstEmber(x, y));
	}
	// Cap burst pool
	if (bursts.length > 150) {
		bursts.splice(0, bursts.length - 100);
	}
}

// ─── RENDER ────────────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) return;

		const dt = Math.min((now - lastNow) / 1000, 0.1);
		lastNow = now;
		time += dt;

		ctx.clearRect(0, 0, W, H);

		// Layer 1: Heat shimmer (very bottom)
		drawHeatShimmer();

		// Layer 2: Glow pools (warm ambient light)
		for (const pool of glowPools) {
			pool.update(dt);
			pool.draw();
		}

		// Layer 3: Flame wisps (ghostly, behind embers)
		for (const wisp of wisps) {
			wisp.update(dt);
			wisp.draw();
		}

		// Layer 4: Embers (main attraction)
		updateEmbers(dt);
		drawEmbers();

		// Layer 5: Burst embers (on top)
		for (let i = bursts.length - 1; i >= 0; i--) {
			if (!bursts[i].update(dt)) {
				bursts.splice(i, 1);
			} else {
				bursts[i].draw();
			}
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

// ─── MESSAGE HANDLER ───────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			lastNow = performance.now();
			initScene();
			startAnimation();
			break;
		case 'resize':
			W = e.data.width;
			H = e.data.height;
			canvas.width = W;
			canvas.height = H;
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
		case 'click':
			spawnBurst(e.data.x, e.data.y);
			break;
		case 'mousedown':
			break;
		case 'mouseup':
			break;
		case 'touchstart':
			if (e.data.touches && e.data.touches.length > 0) {
				spawnBurst(e.data.touches[0].x, e.data.touches[0].y);
			}
			break;
		case 'touchmove':
			if (e.data.touches && e.data.touches.length > 0) {
				mouse.x = e.data.touches[0].x;
				mouse.y = e.data.touches[0].y;
			}
			break;
		case 'touchend':
			break;
		case 'context':
			break;
	}
};

/**
 * Title: Falling Leaves
 * Description: Leaves of various sizes and muted autumn colors (amber, rust, gold, olive)
 *   tumble and spiral downward with realistic rotation and swaying. They drift horizontally.
 *   Mouse creates an updraft that blows nearby leaves upward.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let leaves = [];
let time = 0;

const MAX_LEAVES = 50;

// Autumn palette — muted, warm tones
const LEAF_COLORS = [
	{ fill: [200, 120, 40], stroke: [170, 90, 30] }, // Amber
	{ fill: [180, 70, 40], stroke: [150, 50, 30] }, // Rust
	{ fill: [210, 170, 50], stroke: [180, 140, 40] }, // Gold
	{ fill: [130, 140, 50], stroke: [100, 110, 40] }, // Olive
	{ fill: [190, 90, 35], stroke: [160, 65, 25] }, // Burnt orange
	{ fill: [160, 50, 35], stroke: [130, 35, 25] } // Deep rust
];

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Leaf {
	constructor() {
		this.reset(true);
	}

	reset(randomY = false) {
		this.x = Math.random() * (width || 800);
		this.y = randomY ? Math.random() * (height || 600) : -20 - Math.random() * 80;
		this.size = 4 + Math.random() * 10;
		this.rotation = Math.random() * Math.PI * 2;
		this.rotationSpeed = (Math.random() - 0.5) * 0.03;
		this.vx = (Math.random() - 0.5) * 0.5;
		this.vy = 0.3 + Math.random() * 0.8;
		// Sway parameters — sinusoidal horizontal drift
		this.swayAmplitude = 0.3 + Math.random() * 0.8;
		this.swayFrequency = 0.01 + Math.random() * 0.02;
		this.swayPhase = Math.random() * Math.PI * 2;
		// Tumble — 3D rotation effect via scale modulation
		this.tumblePhase = Math.random() * Math.PI * 2;
		this.tumbleSpeed = 0.015 + Math.random() * 0.025;
		// Visual
		const palette = LEAF_COLORS[Math.floor(Math.random() * LEAF_COLORS.length)];
		this.fillColor = palette.fill;
		this.strokeColor = palette.stroke;
		this.opacity = 0.12 + Math.random() * 0.18;
		// Leaf shape variant
		this.shapeType = Math.floor(Math.random() * 3); // 0: simple, 1: pointed, 2: round
		this.stemLength = this.size * (0.4 + Math.random() * 0.3);
	}

	update(t) {
		// Horizontal sway
		const sway = Math.sin(t * this.swayFrequency + this.swayPhase) * this.swayAmplitude;
		this.vx += (sway - this.vx) * 0.02;

		// Mouse updraft effect
		const dx = this.x - mouse.x;
		const dy = this.y - mouse.y;
		const distSq = dx * dx + dy * dy;
		const updraftRadius = 180;
		if (distSq < updraftRadius * updraftRadius && distSq > 0) {
			const dist = Math.sqrt(distSq);
			const strength = 1 - dist / updraftRadius;
			// Blow upward and outward
			this.vy -= strength * 0.4;
			this.vx += (dx / dist) * strength * 0.3;
			// Spin faster near mouse
			this.rotationSpeed += strength * 0.005 * Math.sign(this.rotationSpeed);
		}

		// Gravity
		this.vy += 0.005;
		// Terminal velocity
		this.vy = Math.min(this.vy, 2);
		this.vx *= 0.995;

		this.x += this.vx;
		this.y += this.vy;

		// Rotation and tumble
		this.rotation += this.rotationSpeed;
		this.tumblePhase += this.tumbleSpeed;

		// Off-screen reset
		if (this.y > (height || 600) + 30 || this.x < -50 || this.x > (width || 800) + 50) {
			this.reset(false);
		}
	}

	draw(ctx) {
		const s = this.size;
		// 3D tumble effect — scale X by cosine to simulate rotation in depth
		const tumbleScale = 0.3 + 0.7 * Math.abs(Math.cos(this.tumblePhase));

		ctx.save();
		ctx.translate(this.x, this.y);
		ctx.rotate(this.rotation);
		ctx.scale(tumbleScale, 1);

		const [fr, fg, fb] = this.fillColor;
		const [sr, sg, sb] = this.strokeColor;

		// Draw leaf body
		ctx.beginPath();
		if (this.shapeType === 0) {
			// Simple oval leaf
			ctx.ellipse(0, 0, s * 0.5, s, 0, 0, Math.PI * 2);
		} else if (this.shapeType === 1) {
			// Pointed leaf
			ctx.moveTo(0, -s);
			ctx.quadraticCurveTo(s * 0.6, -s * 0.3, s * 0.4, s * 0.3);
			ctx.quadraticCurveTo(0, s * 0.8, 0, s);
			ctx.quadraticCurveTo(0, s * 0.8, -s * 0.4, s * 0.3);
			ctx.quadraticCurveTo(-s * 0.6, -s * 0.3, 0, -s);
		} else {
			// Round maple-ish leaf
			ctx.moveTo(0, -s * 0.9);
			ctx.bezierCurveTo(s * 0.8, -s * 0.6, s * 0.5, s * 0.2, s * 0.3, s * 0.5);
			ctx.quadraticCurveTo(0, s * 0.9, -s * 0.3, s * 0.5);
			ctx.bezierCurveTo(-s * 0.5, s * 0.2, -s * 0.8, -s * 0.6, 0, -s * 0.9);
		}
		ctx.closePath();
		ctx.fillStyle = `rgba(${fr}, ${fg}, ${fb}, ${this.opacity})`;
		ctx.fill();
		ctx.strokeStyle = `rgba(${sr}, ${sg}, ${sb}, ${this.opacity * 0.6})`;
		ctx.lineWidth = 0.5;
		ctx.stroke();

		// Center vein
		ctx.beginPath();
		ctx.moveTo(0, -s * 0.7);
		ctx.lineTo(0, s * 0.6);
		ctx.strokeStyle = `rgba(${sr}, ${sg}, ${sb}, ${this.opacity * 0.4})`;
		ctx.lineWidth = 0.4;
		ctx.stroke();

		// Stem
		ctx.beginPath();
		ctx.moveTo(0, s * 0.6);
		ctx.lineTo(0, s * 0.6 + this.stemLength);
		ctx.strokeStyle = `rgba(${sr}, ${sg}, ${sb}, ${this.opacity * 0.5})`;
		ctx.lineWidth = 0.6;
		ctx.stroke();

		ctx.restore();
	}
}

function initLeaves() {
	leaves = [];
	for (let i = 0; i < MAX_LEAVES; i++) {
		leaves.push(new Leaf());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initLeaves();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initLeaves();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		ctx.clearRect(0, 0, width, height);

		time++;

		for (const leaf of leaves) {
			leaf.update(time);
			leaf.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Firefly Meadow
 * Description: Softly glowing firefly particles drifting with organic, non-linear
 *   movement. They pulse brighter occasionally with warm yellow/green glow.
 *   Mouse creates a gentle attraction zone that fireflies investigate.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let fireflies = [];
let time = 0;

const MAX_FIREFLIES = 60;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Firefly {
	constructor() {
		this.x = Math.random() * (width || 800);
		this.y = Math.random() * (height || 600);
		this.vx = 0;
		this.vy = 0;
		this.radius = 1.5 + Math.random() * 2;
		this.baseGlow = 0.08 + Math.random() * 0.12;
		this.glow = this.baseGlow;
		this.glowTarget = this.baseGlow;
		this.pulseTimer = Math.random() * 400;
		this.pulseInterval = 200 + Math.random() * 500;
		// Organic movement: use angular wandering
		this.angle = Math.random() * Math.PI * 2;
		this.angularVelocity = 0;
		this.speed = 0.2 + Math.random() * 0.4;
		// Color warmth — yellow to green spectrum
		this.hue = 50 + Math.random() * 80; // 50 (yellow) to 130 (green)
		this.saturation = 70 + Math.random() * 30;
		// Phase offset for individual timing
		this.phase = Math.random() * Math.PI * 2;
	}

	update(t) {
		// Organic angular wandering (like a random walk in angle space)
		this.angularVelocity += (Math.random() - 0.5) * 0.08;
		this.angularVelocity *= 0.92; // dampen
		this.angle += this.angularVelocity;

		// Gentle sinusoidal modulation of speed
		const speedMod = 0.7 + 0.3 * Math.sin(t * 0.005 + this.phase);
		const targetVx = Math.cos(this.angle) * this.speed * speedMod;
		const targetVy = Math.sin(this.angle) * this.speed * speedMod;

		// Smooth velocity transition
		this.vx += (targetVx - this.vx) * 0.05;
		this.vy += (targetVy - this.vy) * 0.05;

		// Mouse attraction — gentle investigation behavior
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const distSq = dx * dx + dy * dy;
		const attractRadius = 200;
		if (distSq < attractRadius * attractRadius && distSq > 400) {
			const dist = Math.sqrt(distSq);
			const force = 0.15 * (1 - dist / attractRadius);
			this.vx += (dx / dist) * force;
			this.vy += (dy / dist) * force;
		}
		// Very close to mouse — shy away slightly
		if (distSq < 400 && distSq > 0) {
			const dist = Math.sqrt(distSq);
			this.vx -= (dx / dist) * 0.3;
			this.vy -= (dy / dist) * 0.3;
		}

		this.x += this.vx;
		this.y += this.vy;

		// Wrap around edges with padding
		const pad = 30;
		if (this.x < -pad) this.x = width + pad;
		if (this.x > width + pad) this.x = -pad;
		if (this.y < -pad) this.y = height + pad;
		if (this.y > height + pad) this.y = -pad;

		// Pulsing glow
		this.pulseTimer++;
		if (this.pulseTimer > this.pulseInterval) {
			this.pulseTimer = 0;
			this.pulseInterval = 200 + Math.random() * 500;
			this.glowTarget = this.baseGlow + 0.2 + Math.random() * 0.3;
		}
		// Smooth glow transition
		this.glow += (this.glowTarget - this.glow) * 0.03;
		// Decay glow back to base
		this.glowTarget += (this.baseGlow - this.glowTarget) * 0.01;
	}

	draw(ctx) {
		const r = this.radius;
		const g = this.glow;

		// Outer soft glow (large radius, very transparent)
		const gradient = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r * 12);
		gradient.addColorStop(0, `hsla(${this.hue}, ${this.saturation}%, 70%, ${g * 0.6})`);
		gradient.addColorStop(0.3, `hsla(${this.hue}, ${this.saturation}%, 60%, ${g * 0.25})`);
		gradient.addColorStop(1, `hsla(${this.hue}, ${this.saturation}%, 50%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, r * 12, 0, Math.PI * 2);
		ctx.fillStyle = gradient;
		ctx.fill();

		// Inner bright core
		const coreGrad = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r * 2);
		coreGrad.addColorStop(0, `hsla(${this.hue}, ${this.saturation}%, 90%, ${g * 1.5})`);
		coreGrad.addColorStop(1, `hsla(${this.hue}, ${this.saturation}%, 70%, 0)`);
		ctx.beginPath();
		ctx.arc(this.x, this.y, r * 2, 0, Math.PI * 2);
		ctx.fillStyle = coreGrad;
		ctx.fill();
	}
}

function initFireflies() {
	fireflies = [];
	for (let i = 0; i < MAX_FIREFLIES; i++) {
		fireflies.push(new Firefly());
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initFireflies();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initFireflies();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;
		// Slight trail for dreamy effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.15)';
		ctx.fillRect(0, 0, width, height);

		time++;
		for (const ff of fireflies) {
			ff.update(time);
			ff.draw(ctx);
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Fireworks Show
 * Description: An interactive fireworks display! Fireworks launch automatically from the
 *   bottom and explode in colorful bursts. Move your mouse around to launch fireworks
 *   toward the cursor — move fast to create a dazzling barrage! Features three burst
 *   types: spherical, ring, and crackle/glitter with realistic gravity and fading trails.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Auto-Launch --
  autoLaunchMinMs: 1000,                  // Minimum ms between auto launches
  autoLaunchMaxMs: 3000,                  // Maximum ms between auto launches
  maxRockets: 8,                          // Max simultaneous rockets in flight
  maxParticles: 600,                      // Max explosion particles on screen
  maxSmoke: 200,                          // Max smoke particles on screen

  // -- Rocket --
  rocketSpeed: 6,                         // Base upward speed of rockets
  rocketSpeedVariance: 3,                 // ± random speed added
  rocketTrailLength: 12,                  // Number of trail dots behind rocket
  rocketSize: 3,                          // Rocket head radius
  rocketGlowRadius: 15,                   // Glow halo around rocket head
  rocketSparkRate: 0.6,                   // Chance per frame to emit a trail spark

  // -- Explosion --
  burstParticlesMin: 60,                  // Min particles in a standard burst
  burstParticlesMax: 100,                 // Max particles in a standard burst
  ringParticles: 36,                      // Particles in a ring burst
  crackleParticles: 50,                   // Particles in crackle/glitter burst
  burstSpeedMin: 1.5,                     // Min initial particle speed
  burstSpeedMax: 6,                       // Max initial particle speed
  particleGravity: 0.04,                  // Gravity acceleration per frame
  particleLifeMin: 60,                    // Min particle lifetime in frames
  particleLifeMax: 120,                   // Max particle lifetime in frames
  particleTrailLength: 5,                 // Trail points per particle
  particleFriction: 0.985,               // Speed decay per frame (closer to 1 = less friction)
  crackleFlickerRate: 0.3,               // Chance per frame for crackle particles to flicker
  crackleLifeMultiplier: 1.8,            // Crackle particles live longer

  // -- Smoke --
  smokePerExplosion: 8,                   // Smoke particles spawned per explosion
  smokeLife: 80,                          // Smoke lifetime in frames
  smokeSize: 15,                          // Max smoke particle radius
  smokeDrift: 0.3,                        // Smoke horizontal drift speed

  // -- Mouse Interaction --
  mouseTriggerDistance: 50,               // px mouse must move to trigger a launch
  mouseCooldownMs: 200,                   // Min ms between mouse-triggered launches

  // -- Color Palettes --
  palettes: [
    ['#FFD700', '#FFA500', '#FF6347'],                      // Gold / Orange / Tomato
    ['#FF1744', '#FF5252', '#FF8A80'],                      // Reds
    ['#448AFF', '#2979FF', '#82B1FF'],                      // Blues
    ['#00E676', '#69F0AE', '#B9F6CA'],                      // Greens
    ['#D500F9', '#E040FB', '#EA80FC'],                      // Purples
    ['#FF4081', '#FF80AB', '#F48FB1'],                      // Pinks
    ['#ECEFF1', '#CFD8DC', '#B0BEC5'],                      // Silver
    ['#FFD700', '#FF1744', '#448AFF', '#00E676', '#D500F9'], // Multi-color
    ['#FF6347', '#FFD700', '#ECEFF1'],                      // Fire + Silver
    ['#82B1FF', '#EA80FC', '#B9F6CA', '#FFD700'],           // Pastel Multi
  ],
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastMouse = { x: -5000, y: -5000 };
let lastMouseLaunchTime = 0;
let rockets = [];
let particles = [];
let smokeParticles = [];
let lastAutoLaunch = 0;
let nextAutoDelay = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function randInt(a, b) { return Math.floor(rand(a, b + 1)); }
function dist(x1, y1, x2, y2) {
  const dx = x2 - x1, dy = y2 - y1;
  return Math.sqrt(dx * dx + dy * dy);
}

function hexToRgb(hex) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return { r, g, b };
}

function pickPalette() {
  return CONFIG.palettes[Math.floor(Math.random() * CONFIG.palettes.length)];
}

function pickColor(palette) {
  const hex = palette[Math.floor(Math.random() * palette.length)];
  return hexToRgb(hex);
}

// ─── Rocket ────────────────────────────────────────────────
function launchRocket(targetX, targetY) {
  if (rockets.length >= CONFIG.maxRockets) return;

  const startX = rand(width * 0.1, width * 0.9);
  const startY = height + 10;
  const dx = targetX - startX;
  const dy = targetY - startY;
  const d = Math.sqrt(dx * dx + dy * dy);
  const speed = CONFIG.rocketSpeed + rand(0, CONFIG.rocketSpeedVariance);
  const palette = pickPalette();
  const headColor = pickColor(palette);

  // Determine burst type: 0 = standard, 1 = ring, 2 = crackle
  const burstType = Math.random() < 0.5 ? 0 : (Math.random() < 0.5 ? 1 : 2);

  rockets.push({
    x: startX,
    y: startY,
    vx: (dx / d) * speed,
    vy: (dy / d) * speed,
    targetY,
    trail: [],
    palette,
    headColor,
    burstType,
    sparkTimer: 0,
  });
}

function updateRockets(now) {
  for (let i = rockets.length - 1; i >= 0; i--) {
    const r = rockets[i];

    r.x += r.vx;
    r.y += r.vy;

    // Store trail
    r.trail.unshift({ x: r.x, y: r.y });
    if (r.trail.length > CONFIG.rocketTrailLength) r.trail.pop();

    // Decelerate as approaching target (simulate fuse burning out)
    const distToTarget = Math.abs(r.y - r.targetY);

    // Explode when near target or slowed down
    if (r.y <= r.targetY || distToTarget < 10) {
      explode(r.x, r.y, r.palette, r.burstType);
      spawnSmoke(r.x, r.y);
      rockets.splice(i, 1);
      continue;
    }

    // Off-screen safety
    if (r.y < -100 || r.x < -100 || r.x > width + 100) {
      rockets.splice(i, 1);
      continue;
    }
  }
}

function drawRockets() {
  for (const r of rockets) {
    // Draw trail sparks
    for (let t = 0; t < r.trail.length; t++) {
      const alpha = 1 - t / r.trail.length;
      const size = CONFIG.rocketSize * (1 - t / r.trail.length) * 0.8;
      if (size < 0.3) continue;

      // Jitter for sparkle effect
      const jx = r.trail[t].x + rand(-2, 2);
      const jy = r.trail[t].y + rand(-1, 3);

      ctx.beginPath();
      ctx.arc(jx, jy, size, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${r.headColor.r}, ${r.headColor.g}, ${r.headColor.b}, ${alpha * 0.7})`;
      ctx.fill();
    }

    // Draw rocket head glow
    const glow = ctx.createRadialGradient(r.x, r.y, 0, r.x, r.y, CONFIG.rocketGlowRadius);
    glow.addColorStop(0, `rgba(255, 255, 220, 0.8)`);
    glow.addColorStop(0.3, `rgba(${r.headColor.r}, ${r.headColor.g}, ${r.headColor.b}, 0.4)`);
    glow.addColorStop(1, `rgba(${r.headColor.r}, ${r.headColor.g}, ${r.headColor.b}, 0)`);
    ctx.fillStyle = glow;
    ctx.beginPath();
    ctx.arc(r.x, r.y, CONFIG.rocketGlowRadius, 0, Math.PI * 2);
    ctx.fill();

    // Draw rocket head
    ctx.beginPath();
    ctx.arc(r.x, r.y, CONFIG.rocketSize, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(255, 255, 240, 1)`;
    ctx.fill();
  }
}

// ─── Explosion ─────────────────────────────────────────────
function explode(x, y, palette, burstType) {
  switch (burstType) {
    case 0: burstStandard(x, y, palette); break;
    case 1: burstRing(x, y, palette); break;
    case 2: burstCrackle(x, y, palette); break;
  }
}

function burstStandard(x, y, palette) {
  const count = randInt(CONFIG.burstParticlesMin, CONFIG.burstParticlesMax);
  for (let i = 0; i < count && particles.length < CONFIG.maxParticles; i++) {
    const angle = rand(0, Math.PI * 2);
    const speed = rand(CONFIG.burstSpeedMin, CONFIG.burstSpeedMax);
    const color = pickColor(palette);
    const life = randInt(CONFIG.particleLifeMin, CONFIG.particleLifeMax);
    particles.push({
      x, y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color,
      life,
      maxLife: life,
      trail: [],
      type: 'standard',
    });
  }
}

function burstRing(x, y, palette) {
  const count = CONFIG.ringParticles;
  const speed = rand(3, 5);
  for (let i = 0; i < count && particles.length < CONFIG.maxParticles; i++) {
    const angle = (i / count) * Math.PI * 2;
    const color = pickColor(palette);
    const life = randInt(CONFIG.particleLifeMin, CONFIG.particleLifeMax);
    particles.push({
      x, y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color,
      life,
      maxLife: life,
      trail: [],
      type: 'ring',
    });
  }

  // Add a few inner particles for depth
  for (let i = 0; i < 15 && particles.length < CONFIG.maxParticles; i++) {
    const angle = rand(0, Math.PI * 2);
    const spd = rand(1, 2.5);
    const color = pickColor(palette);
    const life = randInt(CONFIG.particleLifeMin * 0.6, CONFIG.particleLifeMax * 0.6);
    particles.push({
      x, y,
      vx: Math.cos(angle) * spd,
      vy: Math.sin(angle) * spd,
      color,
      life,
      maxLife: life,
      trail: [],
      type: 'standard',
    });
  }
}

function burstCrackle(x, y, palette) {
  const count = CONFIG.crackleParticles;
  for (let i = 0; i < count && particles.length < CONFIG.maxParticles; i++) {
    const angle = rand(0, Math.PI * 2);
    const speed = rand(CONFIG.burstSpeedMin * 0.8, CONFIG.burstSpeedMax * 0.7);
    const color = pickColor(palette);
    const life = randInt(
      CONFIG.particleLifeMin * CONFIG.crackleLifeMultiplier,
      CONFIG.particleLifeMax * CONFIG.crackleLifeMultiplier
    );
    particles.push({
      x, y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      color,
      life,
      maxLife: life,
      trail: [],
      type: 'crackle',
    });
  }
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.life--;

    if (p.life <= 0) {
      particles.splice(i, 1);
      continue;
    }

    // Store trail
    p.trail.unshift({ x: p.x, y: p.y });
    if (p.trail.length > CONFIG.particleTrailLength) p.trail.pop();

    // Physics
    p.vy += CONFIG.particleGravity;
    p.vx *= CONFIG.particleFriction;
    p.vy *= CONFIG.particleFriction;
    p.x += p.vx;
    p.y += p.vy;
  }
}

function drawParticles() {
  for (const p of particles) {
    const lifeRatio = p.life / p.maxLife;
    const { r, g, b } = p.color;

    // Crackle flicker effect
    if (p.type === 'crackle' && Math.random() < CONFIG.crackleFlickerRate) {
      // Skip drawing this frame for twinkle effect
      if (Math.random() < 0.4) continue;
    }

    // Draw trail
    for (let t = 0; t < p.trail.length; t++) {
      const trailAlpha = lifeRatio * (1 - t / p.trail.length) * 0.4;
      if (trailAlpha < 0.01) break;
      const trailSize = (2.5 - t * 0.4) * lifeRatio;
      if (trailSize < 0.2) break;
      ctx.beginPath();
      ctx.arc(p.trail[t].x, p.trail[t].y, trailSize, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${trailAlpha})`;
      ctx.fill();
    }

    // Draw particle with glow
    const size = p.type === 'crackle'
      ? rand(1, 3) * lifeRatio
      : 2.5 * lifeRatio;
    const alpha = p.type === 'crackle'
      ? lifeRatio * rand(0.5, 1)
      : lifeRatio;

    // Outer glow
    if (size > 0.5) {
      const glowSize = size * 3;
      const glowGrad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, glowSize);
      glowGrad.addColorStop(0, `rgba(${r}, ${g}, ${b}, ${alpha * 0.3})`);
      glowGrad.addColorStop(1, `rgba(${r}, ${g}, ${b}, 0)`);
      ctx.fillStyle = glowGrad;
      ctx.beginPath();
      ctx.arc(p.x, p.y, glowSize, 0, Math.PI * 2);
      ctx.fill();
    }

    // Core
    ctx.beginPath();
    ctx.arc(p.x, p.y, Math.max(0.5, size), 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${Math.min(255, r + 40)}, ${Math.min(255, g + 40)}, ${Math.min(255, b + 40)}, ${alpha})`;
    ctx.fill();
  }
}

// ─── Smoke ─────────────────────────────────────────────────
function spawnSmoke(x, y) {
  for (let i = 0; i < CONFIG.smokePerExplosion && smokeParticles.length < CONFIG.maxSmoke; i++) {
    smokeParticles.push({
      x: x + rand(-20, 20),
      y: y + rand(-20, 20),
      vx: rand(-CONFIG.smokeDrift, CONFIG.smokeDrift),
      vy: rand(-0.5, -0.1),
      size: rand(5, CONFIG.smokeSize),
      life: CONFIG.smokeLife + randInt(-15, 15),
      maxLife: CONFIG.smokeLife,
    });
  }
}

function updateSmoke() {
  for (let i = smokeParticles.length - 1; i >= 0; i--) {
    const s = smokeParticles[i];
    s.life--;
    if (s.life <= 0) {
      smokeParticles.splice(i, 1);
      continue;
    }
    s.x += s.vx;
    s.y += s.vy;
    s.size += 0.1; // Expand slowly
  }
}

function drawSmoke() {
  for (const s of smokeParticles) {
    const alpha = (s.life / s.maxLife) * 0.08;
    if (alpha < 0.005) continue;
    const grad = ctx.createRadialGradient(s.x, s.y, 0, s.x, s.y, s.size);
    grad.addColorStop(0, `rgba(180, 180, 180, ${alpha})`);
    grad.addColorStop(1, `rgba(100, 100, 100, 0)`);
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
    ctx.fill();
  }
}

// ─── Main Loop ─────────────────────────────────────────────
function startAnimation() {
  lastAutoLaunch = performance.now();
  nextAutoDelay = rand(CONFIG.autoLaunchMinMs, CONFIG.autoLaunchMaxMs);

  function render() {
    if (!ctx) return;
    const now = performance.now();

    ctx.clearRect(0, 0, width, height);

    // Auto-launch fireworks
    if (now - lastAutoLaunch > nextAutoDelay) {
      const targetX = rand(width * 0.1, width * 0.9);
      const targetY = rand(height * 0.1, height * 0.5);
      launchRocket(targetX, targetY);
      lastAutoLaunch = now;
      nextAutoDelay = rand(CONFIG.autoLaunchMinMs, CONFIG.autoLaunchMaxMs);
    }

    // Mouse-triggered launches
    if (mouse.x > 0 && mouse.y > 0) {
      const mouseDist = dist(mouse.x, mouse.y, lastMouse.x, lastMouse.y);
      if (mouseDist > CONFIG.mouseTriggerDistance && now - lastMouseLaunchTime > CONFIG.mouseCooldownMs) {
        launchRocket(mouse.x, mouse.y);
        lastMouse.x = mouse.x;
        lastMouse.y = mouse.y;
        lastMouseLaunchTime = now;
      }
    }

    // Update
    updateRockets(now);
    updateParticles();
    updateSmoke();

    // Draw (back to front: smoke → particles → rockets)
    drawSmoke();
    drawParticles();
    drawRockets();

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

// ─── Worker Message Handler ────────────────────────────────
self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Fluid Ribbons
 * Description: Graceful, flowing silk-like ribbons that trail across the screen in smooth
 *   sine/bezier curves. Ribbons taper from thick centers to thin edges, carry color gradients
 *   along their length, attract toward the mouse cursor, and glow at intersection points.
 *   Uses ring-buffer position history, Float32Array bulk storage, and delta-time animation.
 */

// ─── CONFIG ────────────────────────────────────────────────────────────────────
const CONFIG = {
	ribbonCount: 10, // Number of independent ribbons
	ribbonLength: 120, // History points per ribbon (ring buffer depth)
	ribbonWidth: 18, // Maximum width at the ribbon's center
	taperAmount: 0.92, // How sharply ribbon tapers at edges (0 = none, 1 = full)
	flowSpeed: 0.6, // Base movement speed (px per frame at 60fps)
	flowAmplitude: 150, // Sine-wave amplitude for vertical undulation (px)
	flowFrequency: 0.008, // Sine-wave frequency (lower = wider waves)
	attractRadius: 280, // Distance within which mouse attracts ribbons (px)
	attractStrength: 0.035, // How strongly ribbons curve toward the cursor
	colorSaturation: 72, // HSL saturation for ribbon color (%)
	colorLightness: 62, // HSL lightness for ribbon color (%)
	intersectionGlow: 0.35, // Glow intensity at ribbon crossings (0-1)
	trailAlpha: 0.06, // Base alpha for the oldest trail points
	glowPasses: 3, // Number of multi-pass glow layers
	glowWidthStep: 4, // Extra width added per glow pass
	glowAlphaDecay: 0.35 // Alpha multiplier per successive glow pass
};

// ─── STATE ─────────────────────────────────────────────────────────────────────
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;
let ribbons = [];

// ─── HEARTBEAT ─────────────────────────────────────────────────────────────────
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

// ─── RIBBON CLASS (pooled, zero-alloc render loop) ─────────────────────────────
class Ribbon {
	constructor(index) {
		this.index = index;
		const len = CONFIG.ribbonLength;

		// Ring buffer for x, y positions — Float32Array for performance
		this.xBuf = new Float32Array(len);
		this.yBuf = new Float32Array(len);
		this.head = 0; // Current write position in ring buffer
		this.filled = 0; // How many slots are filled (up to len)

		// Movement state
		this.x = 0;
		this.y = 0;
		this.vx = 0;
		this.vy = 0;
		this.angle = 0; // Current heading angle
		this.phase = 0; // Sine-wave phase offset
		this.baseHue = 0; // Starting hue for this ribbon

		// Precomputed taper widths — avoids per-frame allocation
		this.taperWidths = new Float32Array(len);
	}

	init(w, h) {
		const len = CONFIG.ribbonLength;
		this.x = Math.random() * w;
		this.y = Math.random() * h;
		this.angle = Math.random() * Math.PI * 2;
		this.phase = Math.random() * Math.PI * 2;
		this.baseHue = (this.index / CONFIG.ribbonCount) * 360 + Math.random() * 40;
		this.vx = Math.cos(this.angle) * CONFIG.flowSpeed;
		this.vy = Math.sin(this.angle) * CONFIG.flowSpeed;
		this.head = 0;
		this.filled = 0;

		// Fill the entire buffer with the starting position
		for (let i = 0; i < len; i++) {
			this.xBuf[i] = this.x;
			this.yBuf[i] = this.y;
		}
		this.filled = 1;

		// Precompute taper widths (bell-curve shape)
		for (let i = 0; i < len; i++) {
			const t = i / (len - 1); // 0 at head, 1 at tail
			const bell = Math.sin(t * Math.PI); // 0→1→0 bell
			const taper = 1 - CONFIG.taperAmount * (1 - bell);
			this.taperWidths[i] = CONFIG.ribbonWidth * taper;
		}
	}

	update(dt) {
		const speed = CONFIG.flowSpeed * dt;

		// Sine-wave undulation perpendicular to heading
		this.phase += CONFIG.flowFrequency * dt * 60;
		const perpAngle = this.angle + Math.PI * 0.5;
		const sineOffset = Math.sin(this.phase) * CONFIG.flowAmplitude * CONFIG.flowFrequency;

		// Base velocity
		this.vx = Math.cos(this.angle) * speed + Math.cos(perpAngle) * sineOffset * dt;
		this.vy = Math.sin(this.angle) * speed + Math.sin(perpAngle) * sineOffset * dt;

		// Mouse attraction
		const dx = mouse.x - this.x;
		const dy = mouse.y - this.y;
		const dist = Math.sqrt(dx * dx + dy * dy);
		if (dist < CONFIG.attractRadius && dist > 1) {
			const force = CONFIG.attractStrength * (1 - dist / CONFIG.attractRadius);
			this.vx += (dx / dist) * force * dt * 60;
			this.vy += (dy / dist) * force * dt * 60;
		}

		// Slowly drift the heading angle (smooth wandering)
		this.angle += (Math.random() - 0.5) * 0.04 * dt * 60;

		// Apply velocity
		this.x += this.vx;
		this.y += this.vy;

		// Soft edge wrapping with margin
		const margin = 100;
		if (this.x < -margin) this.x = width + margin;
		if (this.x > width + margin) this.x = -margin;
		if (this.y < -margin) this.y = height + margin;
		if (this.y > height + margin) this.y = -margin;

		// Push position into ring buffer
		this.xBuf[this.head] = this.x;
		this.yBuf[this.head] = this.y;
		this.head = (this.head + 1) % CONFIG.ribbonLength;
		if (this.filled < CONFIG.ribbonLength) this.filled++;
	}

	// Get the i-th oldest point (0 = oldest visible, filled-1 = newest/head)
	getPoint(i) {
		const idx = (this.head - this.filled + i + CONFIG.ribbonLength) % CONFIG.ribbonLength;
		return { x: this.xBuf[idx], y: this.yBuf[idx] };
	}

	draw(ctx, pass) {
		if (this.filled < 4) return;

		const count = this.filled;
		const isGlow = pass > 0;
		const extraWidth = isGlow ? pass * CONFIG.glowWidthStep : 0;
		const alphaScale = isGlow ? Math.pow(CONFIG.glowAlphaDecay, pass) : 1;

		// Draw as a sequence of quadratic bezier segments
		for (let i = 1; i < count - 1; i++) {
			const prev = this.getPoint(i - 1);
			const curr = this.getPoint(i);
			const next = this.getPoint(i + 1);

			// Midpoints for smooth bezier connections
			const mx0 = (prev.x + curr.x) * 0.5;
			const my0 = (prev.y + curr.y) * 0.5;
			const mx1 = (curr.x + next.x) * 0.5;
			const my1 = (curr.y + next.y) * 0.5;

			// Age factor: 0 at tail, 1 at head
			const t = i / (count - 1);
			const alpha = (CONFIG.trailAlpha + (1 - CONFIG.trailAlpha) * t) * alphaScale;
			const w = this.taperWidths[Math.min(i, CONFIG.ribbonLength - 1)] + extraWidth;

			// Color gradient along ribbon length
			const hue = (this.baseHue + t * 60) % 360;

			ctx.beginPath();
			ctx.moveTo(mx0, my0);
			ctx.quadraticCurveTo(curr.x, curr.y, mx1, my1);
			ctx.lineWidth = Math.max(0.5, w);
			ctx.strokeStyle = `hsla(${hue}, ${CONFIG.colorSaturation}%, ${CONFIG.colorLightness}%, ${alpha * 0.4})`;
			ctx.lineCap = 'round';
			ctx.lineJoin = 'round';
			ctx.stroke();
		}
	}
}

// ─── INTERSECTION DETECTION ────────────────────────────────────────────────────
// Lightweight: only check head positions of each ribbon pair for glow
function drawIntersectionGlows(ctx) {
	if (CONFIG.intersectionGlow <= 0) return;

	const checkRadius = CONFIG.ribbonWidth * 2;
	for (let a = 0; a < ribbons.length; a++) {
		for (let b = a + 1; b < ribbons.length; b++) {
			const ra = ribbons[a];
			const rb = ribbons[b];

			// Sample a few points along each ribbon for crossing detection
			const samplesA = Math.min(ra.filled, 30);
			const samplesB = Math.min(rb.filled, 30);
			const stepA = Math.max(1, Math.floor(ra.filled / samplesA));
			const stepB = Math.max(1, Math.floor(rb.filled / samplesB));

			for (let i = 0; i < ra.filled; i += stepA) {
				const pa = ra.getPoint(i);
				for (let j = 0; j < rb.filled; j += stepB) {
					const pb = rb.getPoint(j);
					const dx = pa.x - pb.x;
					const dy = pa.y - pb.y;
					const distSq = dx * dx + dy * dy;
					if (distSq < checkRadius * checkRadius) {
						const dist = Math.sqrt(distSq);
						const intensity = (1 - dist / checkRadius) * CONFIG.intersectionGlow;
						const midX = (pa.x + pb.x) * 0.5;
						const midY = (pa.y + pb.y) * 0.5;
						const hue = (ra.baseHue + rb.baseHue) * 0.5;

						const grad = ctx.createRadialGradient(midX, midY, 0, midX, midY, checkRadius);
						grad.addColorStop(0, `hsla(${hue}, 80%, 80%, ${intensity * 0.5})`);
						grad.addColorStop(1, `hsla(${hue}, 80%, 80%, 0)`);
						ctx.fillStyle = grad;
						ctx.fillRect(midX - checkRadius, midY - checkRadius, checkRadius * 2, checkRadius * 2);
					}
				}
			}
		}
	}
}

// ─── INITIALIZATION ────────────────────────────────────────────────────────────
function initRibbons() {
	ribbons = [];
	for (let i = 0; i < CONFIG.ribbonCount; i++) {
		const r = new Ribbon(i);
		r.init(width, height);
		ribbons.push(r);
	}
}

// ─── MESSAGE HANDLER ───────────────────────────────────────────────────────────
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			ctx.lineCap = 'round';
			ctx.lineJoin = 'round';
			initRibbons();
			lastTime = performance.now();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			// Don't reinitialize — ribbons will naturally drift into the new area
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

// ─── RENDER LOOP ───────────────────────────────────────────────────────────────
function startAnimation() {
	function render(now) {
		if (!ctx) return;

		// Delta time in seconds, capped to prevent spiral-of-death
		const dt = Math.min((now - lastTime) / 16.667, 3);
		lastTime = now;

		// Semi-transparent clear for motion trail effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.08)';
		ctx.fillRect(0, 0, width, height);

		// Update all ribbons
		for (let i = 0; i < ribbons.length; i++) {
			ribbons[i].update(dt);
		}

		// Multi-pass glow rendering (widest/faintest first)
		for (let pass = CONFIG.glowPasses; pass >= 0; pass--) {
			for (let i = 0; i < ribbons.length; i++) {
				ribbons[i].draw(ctx, pass);
			}
		}

		// Intersection glows
		drawIntersectionGlows(ctx);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Galaxy Forge
 * Description: A spiral galaxy with thousands of orbiting stars. Mouse creates a
 *   gravitational well that warps star orbits, pulling tidal streams. Stars have
 *   color variation by distance, orbital trails, and a pulsing central core.
 *   Move the mouse to sculpt the galaxy in real-time.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Stars --
  starCount: 2200,                        // Total stars (500-5000)
  starMinSize: 0.5,                       // Smallest star radius (0.3-2)
  starMaxSize: 2.5,                       // Largest star radius (1.5-5)
  starGlow: true,                         // Soft glow on bright stars
  trailEnabled: true,                     // Stars leave brief orbital trails
  trailLength: 4,                         // Trail persistence (2-8)
  trailOpacity: 0.08,                     // Trail opacity (0.02-0.2)

  // -- Galaxy Structure --
  armCount: 3,                            // Number of spiral arms (2-6)
  armSpread: 0.35,                        // How tightly wound (0.1-1, lower=tighter)
  armWidth: 0.45,                         // Angular spread of each arm (0.1-0.8)
  rotationSpeed: 0.0018,                  // Base orbital speed (0.0005-0.005)

  // -- Core --
  coreRadius: 45,                         // Central bright region radius (20-80)
  coreColor: '#ffe0a0',                   // Core glow color
  corePulseSpeed: 0.8,                    // Core brightness pulse (0-3)

  // -- Dust & Nebula --
  dustLanes: true,                        // Dark bands between arms
  dustOpacity: 0.2,                       // Dust lane darkness (0.05-0.5)
  nebulaEnabled: true,                    // Colored nebula patches
  nebulaColors: ['#331155', '#113355', '#553311', '#115533'],

  // -- Mouse Gravity --
  mouseGravityStrength: 4,                // Pull force (0.5-15)
  mouseGravityRadius: 250,               // Influence radius in px (80-500)

  // -- Background --
  backgroundColor: '#030308',             // Deep space color
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -1, y: -1 };
let time = 0;
let stars = [];
let cx, cy;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function rand(a, b) { return Math.random() * (b - a) + a; }
function hexRgb(h) { return [parseInt(h.slice(1,3),16), parseInt(h.slice(3,5),16), parseInt(h.slice(5,7),16)]; }

function initStars() {
  cx = width / 2;
  cy = height / 2;
  stars = [];
  const maxR = Math.min(width, height) * 0.42;

  for (let i = 0; i < CONFIG.starCount; i++) {
    // Distribute in spiral arms with some scatter
    const arm = Math.floor(rand(0, CONFIG.armCount));
    const armAngle = (arm / CONFIG.armCount) * Math.PI * 2;
    const dist = Math.pow(Math.random(), 0.6) * maxR; // more stars near center
    const spiralAngle = armAngle + dist * CONFIG.armSpread * 0.03;
    const scatter = (Math.random() - 0.5) * CONFIG.armWidth * 2;
    const angle = spiralAngle + scatter;

    const x = cx + Math.cos(angle) * dist;
    const y = cy + Math.sin(angle) * dist;

    // Color by distance — blue-white near core, amber/red at edges
    const distNorm = dist / maxR;
    let r, g, b;
    if (distNorm < 0.3) {
      r = 200 + rand(30, 55); g = 210 + rand(20, 45); b = 240 + rand(10, 15);
    } else if (distNorm < 0.6) {
      r = 240 + rand(0, 15); g = 220 + rand(0, 30); b = 180 + rand(0, 50);
    } else {
      r = 220 + rand(0, 35); g = 160 + rand(0, 60); b = 100 + rand(0, 60);
    }

    stars.push({
      x, y,
      ox: x, oy: y, // original position for trail
      dist,
      angle,
      orbitSpeed: (1 / (dist + 20)) * CONFIG.rotationSpeed * 60 * rand(0.8, 1.2),
      size: rand(CONFIG.starMinSize, CONFIG.starMaxSize) * (1 - distNorm * 0.4),
      color: [Math.min(255, r), Math.min(255, g), Math.min(255, b)],
      brightness: rand(0.5, 1),
    });
  }
}

function startAnimation() {
  const coreRgb = hexRgb(CONFIG.coreColor);
  const bgRgb = hexRgb(CONFIG.backgroundColor);

  function render() {
    if (!ctx) return;
    time += 0.016;

    // -- Background with trail fade --
    if (CONFIG.trailEnabled) {
      ctx.fillStyle = `rgba(${bgRgb[0]},${bgRgb[1]},${bgRgb[2]},${CONFIG.trailOpacity})`;
      ctx.fillRect(0, 0, width, height);
    } else {
      ctx.fillStyle = CONFIG.backgroundColor;
      ctx.fillRect(0, 0, width, height);
    }

    // -- Nebula clouds --
    if (CONFIG.nebulaEnabled) {
      for (let i = 0; i < CONFIG.nebulaColors.length; i++) {
        const nc = hexRgb(CONFIG.nebulaColors[i]);
        const na = 0.6 + i * 1.2;
        const nx = cx + Math.cos(na + time * 0.03) * 120;
        const ny = cy + Math.sin(na * 1.3 + time * 0.02) * 100;
        const ng = ctx.createRadialGradient(nx, ny, 0, nx, ny, 100);
        ng.addColorStop(0, `rgba(${nc[0]},${nc[1]},${nc[2]},0.02)`);
        ng.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.fillStyle = ng;
        ctx.fillRect(nx - 100, ny - 100, 200, 200);
      }
    }

    // -- Dust lanes --
    if (CONFIG.dustLanes) {
      const maxR = Math.min(width, height) * 0.42;
      for (let arm = 0; arm < CONFIG.armCount; arm++) {
        const baseAngle = (arm + 0.5) / CONFIG.armCount * Math.PI * 2;
        for (let d = 20; d < maxR; d += 15) {
          const angle = baseAngle + d * CONFIG.armSpread * 0.03 + time * CONFIG.rotationSpeed * 8;
          const dx = cx + Math.cos(angle) * d;
          const dy = cy + Math.sin(angle) * d;
          ctx.beginPath();
          ctx.arc(dx, dy, 12 + d * 0.04, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(0,0,0,${CONFIG.dustOpacity * 0.04})`;
          ctx.fill();
        }
      }
    }

    // -- Update and draw stars --
    const mActive = mouse.x >= 0 && mouse.y >= 0;
    const mgr = CONFIG.mouseGravityRadius;
    const mgs = CONFIG.mouseGravityStrength;

    for (const s of stars) {
      // Orbital rotation around center
      s.angle += s.orbitSpeed;
      s.x = cx + Math.cos(s.angle) * s.dist;
      s.y = cy + Math.sin(s.angle) * s.dist;

      // Mouse gravity pull
      if (mActive) {
        const dx = mouse.x - s.x;
        const dy = mouse.y - s.y;
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < mgr && d > 5) {
          const force = (1 - d / mgr) * mgs * 0.5;
          s.x += (dx / d) * force;
          s.y += (dy / d) * force;
        }
      }

      // Draw star
      const c = s.color;
      const alpha = s.brightness * (0.6 + Math.sin(time * 3 + s.angle * 5) * 0.1);
      ctx.beginPath();
      ctx.arc(s.x, s.y, s.size, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha})`;
      ctx.fill();

      // Star glow
      if (CONFIG.starGlow && s.size > 1.5) {
        ctx.beginPath();
        ctx.arc(s.x, s.y, s.size * 3, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${c[0]},${c[1]},${c[2]},${alpha * 0.04})`;
        ctx.fill();
      }
    }

    // -- Core glow --
    const corePulse = 0.8 + Math.sin(time * CONFIG.corePulseSpeed * 3) * 0.2;
    for (let i = 3; i >= 0; i--) {
      const r = CONFIG.coreRadius * (0.3 + i * 0.6) * corePulse;
      const cg = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
      cg.addColorStop(0, `rgba(${coreRgb[0]},${coreRgb[1]},${coreRgb[2]},${0.08 / (i + 1)})`);
      cg.addColorStop(1, 'rgba(0,0,0,0)');
      ctx.fillStyle = cg;
      ctx.beginPath();
      ctx.arc(cx, cy, r, 0, Math.PI * 2);
      ctx.fill();
    }
    // Bright core center
    ctx.beginPath();
    ctx.arc(cx, cy, 3, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(255,255,240,${0.5 * corePulse})`;
    ctx.fill();

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initStars();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width; height = e.data.height;
      canvas.width = width; canvas.height = height;
      initStars();
      break;
    case 'mousemove':
      mouse.x = e.data.x; mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Glitch Grid
 * Description: A subtle grid overlay that occasionally glitches — random cells flash,
 *   scan lines appear and disappear, small sections shift position briefly.
 *   Restrained HUD aesthetic with intermittent interference.
 *   Mouse proximity increases glitch frequency nearby.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

const CELL_SIZE = 40;
let cols, rows;
let glitches = []; // active glitch effects
let scanLines = []; // horizontal scan line distortions
let shiftBlocks = []; // section shifts

setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			init();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function init() {
	cols = Math.ceil(width / CELL_SIZE);
	rows = Math.ceil(height / CELL_SIZE);
	glitches = [];
	scanLines = [];
	shiftBlocks = [];
}

// Glitch types
function spawnCellFlash(nearMouse) {
	let col, row;
	if (nearMouse && mouse.x > 0) {
		// Spawn near mouse
		col = Math.floor(mouse.x / CELL_SIZE) + Math.floor((Math.random() - 0.5) * 6);
		row = Math.floor(mouse.y / CELL_SIZE) + Math.floor((Math.random() - 0.5) * 6);
	} else {
		col = Math.floor(Math.random() * cols);
		row = Math.floor(Math.random() * rows);
	}

	col = Math.max(0, Math.min(cols - 1, col));
	row = Math.max(0, Math.min(rows - 1, row));

	const hue = Math.random() < 0.5 ? 180 : 120; // cyan or green
	glitches.push({
		type: 'cell',
		col: col,
		row: row,
		life: 0.3 + Math.random() * 0.5, // seconds
		maxLife: 0.3 + Math.random() * 0.5,
		hue: hue,
		alpha: 0.05 + Math.random() * 0.1
	});
}

function spawnScanLine() {
	scanLines.push({
		y: Math.random() * height,
		speed: (1 + Math.random() * 3) * (Math.random() < 0.5 ? 1 : -1),
		width: 1 + Math.random() * 2,
		life: 0.5 + Math.random() * 1.5,
		alpha: 0.03 + Math.random() * 0.07
	});
}

function spawnShiftBlock(nearMouse) {
	let x, y;
	if (nearMouse && mouse.x > 0) {
		x = mouse.x + (Math.random() - 0.5) * 200;
		y = mouse.y + (Math.random() - 0.5) * 200;
	} else {
		x = Math.random() * width;
		y = Math.random() * height;
	}

	const blockW = CELL_SIZE * (1 + Math.floor(Math.random() * 4));
	const blockH = CELL_SIZE * (1 + Math.floor(Math.random() * 2));

	shiftBlocks.push({
		x: x,
		y: y,
		w: blockW,
		h: blockH,
		shiftX: (Math.random() - 0.5) * 8,
		shiftY: 0,
		life: 0.05 + Math.random() * 0.15, // very brief
		maxLife: 0.05 + Math.random() * 0.15,
		alpha: 0.04 + Math.random() * 0.06
	});
}

function startAnimation() {
	let lastTime = 0;
	let spawnAccum = 0;

	function render(time) {
		if (!ctx) return;
		const dt = lastTime ? (time - lastTime) / 1000 : 0.016;
		lastTime = time;

		ctx.clearRect(0, 0, width, height);

		// === Draw the base grid ===
		ctx.strokeStyle = 'rgba(100, 200, 180, 0.03)';
		ctx.lineWidth = 0.5;

		// Vertical lines
		for (let c = 0; c <= cols; c++) {
			const x = c * CELL_SIZE;
			ctx.beginPath();
			ctx.moveTo(x, 0);
			ctx.lineTo(x, height);
			ctx.stroke();
		}
		// Horizontal lines
		for (let r = 0; r <= rows; r++) {
			const y = r * CELL_SIZE;
			ctx.beginPath();
			ctx.moveTo(0, y);
			ctx.lineTo(width, y);
			ctx.stroke();
		}

		// === Mouse proximity — glow nearby grid intersections ===
		if (mouse.x > 0 && mouse.y > 0) {
			const mc = Math.floor(mouse.x / CELL_SIZE);
			const mr = Math.floor(mouse.y / CELL_SIZE);
			const range = 3;

			for (let dc = -range; dc <= range; dc++) {
				for (let dr = -range; dr <= range; dr++) {
					const c = mc + dc;
					const r = mr + dr;
					if (c < 0 || c > cols || r < 0 || r > rows) continue;

					const px = c * CELL_SIZE;
					const py = r * CELL_SIZE;
					const dx = px - mouse.x;
					const dy = py - mouse.y;
					const dist = Math.sqrt(dx * dx + dy * dy);
					const maxDist = range * CELL_SIZE;

					if (dist < maxDist) {
						const glow = (1 - dist / maxDist) * 0.12;
						ctx.beginPath();
						ctx.arc(px, py, 2, 0, Math.PI * 2);
						ctx.fillStyle = `rgba(0, 220, 180, ${glow})`;
						ctx.fill();
					}
				}
			}
		}

		// === Spawn glitches ===
		spawnAccum += dt;

		// Mouse proximity increases spawn rate
		const mouseOnScreen = mouse.x > 0 && mouse.x < width && mouse.y > 0 && mouse.y < height;
		const baseRate = 0.15; // seconds between spawns
		const mouseRate = mouseOnScreen ? 0.05 : baseRate;

		if (spawnAccum > mouseRate) {
			spawnAccum = 0;

			// Cell flashes
			if (Math.random() < 0.5) {
				spawnCellFlash(mouseOnScreen && Math.random() < 0.7);
			}

			// Scan lines (less frequent)
			if (Math.random() < 0.15) {
				spawnScanLine();
			}

			// Shift blocks (rare)
			if (Math.random() < 0.1) {
				spawnShiftBlock(mouseOnScreen && Math.random() < 0.6);
			}
		}

		// === Update and draw cell flashes ===
		for (let i = glitches.length - 1; i >= 0; i--) {
			const g = glitches[i];
			g.life -= dt;

			if (g.life <= 0) {
				glitches.splice(i, 1);
				continue;
			}

			const fadeIn = Math.min(1, (g.maxLife - g.life) / 0.05);
			const fadeOut = Math.min(1, g.life / 0.1);
			const fade = fadeIn * fadeOut;

			const x = g.col * CELL_SIZE;
			const y = g.row * CELL_SIZE;

			// Flickering effect
			const flicker = Math.random() < 0.3 ? 0 : 1;

			ctx.fillStyle = `rgba(0, ${g.hue === 180 ? '200, 220' : '220, 150'}, ${g.alpha * fade * flicker})`;
			ctx.fillRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);

			// Cell border highlight
			ctx.strokeStyle = `rgba(0, ${g.hue === 180 ? '220, 240' : '240, 180'}, ${g.alpha * fade * 1.5 * flicker})`;
			ctx.lineWidth = 0.5;
			ctx.strokeRect(x + 1, y + 1, CELL_SIZE - 2, CELL_SIZE - 2);
		}

		// === Update and draw scan lines ===
		for (let i = scanLines.length - 1; i >= 0; i--) {
			const s = scanLines[i];
			s.y += s.speed;
			s.life -= dt;

			if (s.life <= 0 || s.y < -10 || s.y > height + 10) {
				scanLines.splice(i, 1);
				continue;
			}

			// Draw the scan line
			ctx.fillStyle = `rgba(0, 200, 180, ${s.alpha})`;
			ctx.fillRect(0, s.y, width, s.width);

			// Slight chromatic aberration
			ctx.fillStyle = `rgba(200, 0, 100, ${s.alpha * 0.3})`;
			ctx.fillRect(0, s.y - 1, width, 0.5);
			ctx.fillStyle = `rgba(0, 100, 200, ${s.alpha * 0.3})`;
			ctx.fillRect(0, s.y + s.width, width, 0.5);
		}

		// === Update and draw shift blocks ===
		for (let i = shiftBlocks.length - 1; i >= 0; i--) {
			const b = shiftBlocks[i];
			b.life -= dt;

			if (b.life <= 0) {
				shiftBlocks.splice(i, 1);
				continue;
			}

			// Copy and shift a region (simulated with colored overlay)
			const fadeOut = b.life / b.maxLife;

			// Draw a slightly shifted duplicate overlay
			ctx.save();
			ctx.globalAlpha = b.alpha * fadeOut;
			ctx.fillStyle = 'rgba(0, 180, 160, 1)';
			ctx.fillRect(b.x + b.shiftX, b.y + b.shiftY, b.w, b.h);
			ctx.restore();

			// Draw corruption lines within the block
			const lineCount = 2 + Math.floor(Math.random() * 3);
			for (let l = 0; l < lineCount; l++) {
				const ly = b.y + Math.random() * b.h;
				ctx.fillStyle = `rgba(0, 255, 200, ${b.alpha * fadeOut * 0.5})`;
				ctx.fillRect(b.x, ly, b.w, 1);
			}
		}

		// === Occasional full-screen micro-glitch (very rare) ===
		if (Math.random() < 0.002) {
			ctx.fillStyle = 'rgba(0, 200, 180, 0.01)';
			ctx.fillRect(0, 0, width, height);
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Hexagonal Pulse
 * Description: A grid of hexagons that pulse with a ripple effect emanating from
 * the mouse position. Each hex glows with a subtle accent color that fades with
 * distance from the ripple origin. Clean, geometric feel.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };

// Hex grid config
const HEX_RADIUS = 28;
const HEX_GAP = 4;
const RIPPLE_SPEED = 180; // pixels per second
const RIPPLE_LIFETIME = 3.0; // seconds
const MAX_RIPPLES = 5;

let hexagons = [];
let ripples = [];
let lastTime = 0;
let lastClickTime = 0;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			buildGrid();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			buildGrid();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			// Spawn ripples on movement (throttled)
			const now = performance.now() / 1000;
			if (now - lastClickTime > 0.6) {
				lastClickTime = now;
				ripples.push({ x: mouse.x, y: mouse.y, time: now, radius: 0 });
				if (ripples.length > MAX_RIPPLES) ripples.shift();
			}
			break;
	}
};

function buildGrid() {
	hexagons = [];
	const hexW = (HEX_RADIUS + HEX_GAP) * Math.sqrt(3);
	const hexH = (HEX_RADIUS + HEX_GAP) * 1.5;
	const cols = Math.ceil(width / hexW) + 2;
	const rows = Math.ceil(height / hexH) + 2;

	for (let row = -1; row < rows; row++) {
		for (let col = -1; col < cols; col++) {
			const offsetX = (row % 2) * (hexW / 2);
			hexagons.push({
				x: col * hexW + offsetX,
				y: row * hexH,
				pulse: 0
			});
		}
	}
}

function hexPath(cx, cy, r) {
	ctx.beginPath();
	for (let i = 0; i < 6; i++) {
		const angle = (Math.PI / 3) * i - Math.PI / 6;
		const px = cx + r * Math.cos(angle);
		const py = cy + r * Math.sin(angle);
		if (i === 0) ctx.moveTo(px, py);
		else ctx.lineTo(px, py);
	}
	ctx.closePath();
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;

		ctx.clearRect(0, 0, width, height);

		// Update ripples
		for (let i = ripples.length - 1; i >= 0; i--) {
			const r = ripples[i];
			r.radius += RIPPLE_SPEED * dt;
			if (now - r.time > RIPPLE_LIFETIME) {
				ripples.splice(i, 1);
			}
		}

		// Calculate mouse distance influence for ambient glow
		const mouseInfluenceRadius = 250;

		for (let i = 0; i < hexagons.length; i++) {
			const hex = hexagons[i];
			let pulseIntensity = 0;

			// Ripple influence
			for (let j = 0; j < ripples.length; j++) {
				const rip = ripples[j];
				const dist = Math.hypot(hex.x - rip.x, hex.y - rip.y);
				const rippleAge = now - rip.time;
				const rippleFront = rip.radius;
				const ringWidth = 80;
				const distFromFront = Math.abs(dist - rippleFront);

				if (distFromFront < ringWidth) {
					const ringFade = 1 - distFromFront / ringWidth;
					const ageFade = 1 - rippleAge / RIPPLE_LIFETIME;
					pulseIntensity = Math.max(pulseIntensity, ringFade * ageFade);
				}
			}

			// Ambient mouse proximity glow
			const mouseDist = Math.hypot(hex.x - mouse.x, hex.y - mouse.y);
			if (mouseDist < mouseInfluenceRadius) {
				const proximity = 1 - mouseDist / mouseInfluenceRadius;
				pulseIntensity = Math.max(pulseIntensity, proximity * 0.3);
			}

			// Smooth the pulse
			hex.pulse += (pulseIntensity - hex.pulse) * 0.15;

			// Draw hexagon
			const scale = 1 + hex.pulse * 0.12;
			const drawRadius = HEX_RADIUS * scale;

			// Base hex outline
			const baseAlpha = 0.06 + hex.pulse * 0.25;
			hexPath(hex.x, hex.y, drawRadius);
			ctx.strokeStyle = `rgba(255, 255, 255, ${baseAlpha})`;
			ctx.lineWidth = 1;
			ctx.stroke();

			// Pulse fill with accent color (subtle cyan-blue)
			if (hex.pulse > 0.01) {
				hexPath(hex.x, hex.y, drawRadius);
				const fillAlpha = hex.pulse * 0.1;
				ctx.fillStyle = `rgba(100, 180, 255, ${fillAlpha})`;
				ctx.fill();

				// Inner glow ring
				hexPath(hex.x, hex.y, drawRadius * 0.7);
				ctx.strokeStyle = `rgba(140, 200, 255, ${hex.pulse * 0.15})`;
				ctx.lineWidth = 0.5;
				ctx.stroke();
			}
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Hyperspace Warp Drive
 * Description: A 3D starfield with speed lines. Move the mouse to steer the warp tunnel!
 */

const CONFIG = {
    starCount: 600,
    baseSpeed: 2.5,       // Forward speed
    fov: 300,             // Field of view (stretches the Z axis)
    starColor: '255, 255, 255', // RGB components (must be comma separated for opacity logic)
    tailLength: 1.5       // Multiplier for the speed line trails
};

let canvas, ctx, width, height;
let stars =[];
let mouse = { x: 0, y: 0 };
let centerX, centerY;

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            mouse = { x: width / 2, y: height / 2 };
            startAnimation();
            break;
        case 'resize': resize(e.data.width, e.data.height); break;
        case 'mousemove': mouse.x = e.data.x; mouse.y = e.data.y; break;
    }
};

function resize(w, h) {
    width = w; height = h;
    centerX = width / 2; centerY = height / 2;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initStars();
}

class Star {
    constructor() {
        this.reset();
        this.z = Math.random() * width; 
    }
    reset() {
        this.x = (Math.random() - 0.5) * width * 2;
        this.y = (Math.random() - 0.5) * height * 2;
        this.z = width; 
        this.pz = this.z;
    }
    update() {
        this.pz = this.z; 
        this.z -= CONFIG.baseSpeed;
        if (this.z < 1) this.reset();
    }
    draw() {
        let targetX = centerX + (mouse.x - centerX) * 0.3;
        let targetY = centerY + (mouse.y - centerY) * 0.3;

        let px = (this.x / this.pz) * CONFIG.fov + targetX;
        let py = (this.y / this.pz) * CONFIG.fov + targetY;
        let nx = (this.x / this.z) * CONFIG.fov + targetX;
        let ny = (this.y / this.z) * CONFIG.fov + targetY;

        let opacity = 1 - (this.z / width);

        ctx.beginPath();
        ctx.moveTo(px, py);

        let tailX = nx + (nx - px) * CONFIG.tailLength;
        let tailY = ny + (ny - py) * CONFIG.tailLength;
        ctx.lineTo(tailX, tailY);

        // Respecting the starColor from config while applying dynamic opacity
        ctx.strokeStyle = `rgba(${CONFIG.starColor}, ${opacity})`;
        ctx.lineWidth = (1 - (this.z / width)) * 2.5; 
        ctx.stroke();
    }
}

function initStars() {
    stars =[];
    for (let i = 0; i < CONFIG.starCount; i++) {
        stars.push(new Star());
    }
}

function startAnimation() {
    function render() {
        if (!ctx) return;

        // ClearRect is the gold standard for transparency. 
        // It ensures the Chat Background Image set in Open WebUI is fully visible.
        ctx.clearRect(0, 0, width, height);

        for (let i = 0; i < stars.length; i++) {
            stars[i].update();
            stars[i].draw();
        }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: HypnoSpiral
 * Description: A slowly fading, hypnotic spiral made of concentric colored rings
 *   that rotate and drift outward. Full-spectrum hue cycling with configurable
 *   trail fade, ring spacing, and rotation speed.
 */

// =========================================================================
// CONFIG ––––––––––––––––––––––––––––––––––––––––––––––––––––––––––––––––
const CONFIG = {
  TRAIL_ALPHA: 0.04,      // Controls fade speed to transparency (0.01 - 0.1)
  RING_SPACING: 4,        // px between rings
  RING_THICKNESS: 15,     // divisor for ring radius → stroke thickness
  ROTATION_SPEED: 0.02,   // rad/frame
  HUE_SHIFT: 2,           // hue += HUE_SHIFT per frame
  HUE_RANGE: 360,        // 360 = full spectrum
  SATURATION: '90%',       // CSS saturation string
  LIGHTNESS: '60%',        // CSS lightness string
};
// =========================================================================

let c, ctx, w, h, t = 0, frames = 0;

self.onmessage = e => {
  if (e.data.type === 'init') {
    c = e.data.canvas;
    ctx = c.getContext('2d');
    w = c.width = e.data.width;
    h = c.height = e.data.height;
    animate();
  }
  if (e.data.type === 'resize') {
    w = c.width = e.data.width;
    h = c.height = e.data.height;
  }
};

function animate() {
  // 1. Erase previous frame into transparency instead of layering black paint
  ctx.globalCompositeOperation = 'destination-out';
  ctx.fillStyle = `rgba(0, 0, 0, ${CONFIG.TRAIL_ALPHA})`;
  ctx.fillRect(0, 0, w, h);

  // 2. Set back to normal drawing mode
  ctx.globalCompositeOperation = 'source-over';

  const cx = w / 2;
  const cy = h / 2;
  const rMax = Math.hypot(cx, cy);

  for (let r = 1; r < rMax; r += CONFIG.RING_SPACING) {
    const a = r * 0.04 + t;
    const x = cx + Math.cos(a) * r;
    const y = cy + Math.sin(a) * r;
    ctx.strokeStyle = `hsl(${(frames * CONFIG.HUE_SHIFT + r / 4) % CONFIG.HUE_RANGE},${CONFIG.SATURATION},${CONFIG.LIGHTNESS})`;
    ctx.beginPath();
    ctx.arc(x, y, r / CONFIG.RING_THICKNESS, 0, Math.PI * 2);
    ctx.stroke();
  }

  t += CONFIG.ROTATION_SPEED;
  frames++;
  requestAnimationFrame(animate);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
