// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let particles = [];
let time = 0;
let gustActive = false;
let gustFactor = 0;
let lastGustTime = 0;
let nextGustDelay = 0;
let gustStartTime = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initParticles();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initParticles();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function parseRGBA(str) {
  const m = str.match(/rgba?\((\d+),\s*(\d+),\s*(\d+)/);
  if (m) return { r: +m[1], g: +m[2], b: +m[3] };
  return { r: 200, g: 180, b: 130 };
}

function initParticles() {
  particles = [];
  const windRad = CONFIG.windDirection * Math.PI / 180;

  for (let i = 0; i < CONFIG.particleCount; i++) {
    particles.push(createParticle(true, windRad));
  }
}

function createParticle(randomPos, windRad) {
  const colorStr = CONFIG.colorPalette[Math.floor(Math.random() * CONFIG.colorPalette.length)];
  const color = parseRGBA(colorStr);
  const size = CONFIG.minParticleSize + Math.random() * (CONFIG.maxParticleSize - CONFIG.minParticleSize);
  const opacity = CONFIG.minOpacity + Math.random() * (CONFIG.maxOpacity - CONFIG.minOpacity);
  // Smaller particles move slower (depth illusion)
  const depthFactor = 0.4 + (size / CONFIG.maxParticleSize) * 0.6;

  let x, y;
  if (randomPos) {
    x = Math.random() * width;
    y = Math.random() * height;
  } else {
    // Spawn from upwind edge
    const wx = Math.cos(windRad);
    if (wx >= 0) {
      x = -size * 2;
    } else {
      x = width + size * 2;
    }
    y = Math.random() * height;
  }

  return {
    x, y, size, color, opacity, depthFactor,
    turbPhase: Math.random() * Math.PI * 2,
    vx: 0, vy: 0,
  };
}

function startAnimation() {
  const windRad = CONFIG.windDirection * Math.PI / 180;
  const windDirX = Math.cos(windRad);
  const windDirY = Math.sin(windRad);

  function render() {
    if (!ctx) return;
    const now = performance.now();
    time++;

    ctx.clearRect(0, 0, width, height);

    // Background haze
    ctx.save();
    ctx.globalAlpha = CONFIG.hazeOpacity;
    ctx.fillStyle = CONFIG.hazeColor;
    ctx.fillRect(0, 0, width, height);
    ctx.restore();

    // Gust logic
    if (!gustActive) {
      if (now - lastGustTime > nextGustDelay) {
        gustActive = true;
        gustStartTime = now;
        lastGustTime = now;
      }
    } else {
      const elapsed = now - gustStartTime;
      if (elapsed >= CONFIG.gustDuration) {
        gustActive = false;
        gustFactor = 0;
        nextGustDelay = CONFIG.gustFrequency + (Math.random() - 0.5) * 2 * CONFIG.gustFrequencyVariance;
      } else if (elapsed < CONFIG.gustRampUp) {
        gustFactor = (elapsed / CONFIG.gustRampUp) * (CONFIG.gustStrength - 1);
      } else {
        const fadeStart = CONFIG.gustDuration * 0.6;
        if (elapsed > fadeStart) {
          gustFactor = (CONFIG.gustStrength - 1) * (1 - (elapsed - fadeStart) / (CONFIG.gustDuration - fadeStart));
        } else {
          gustFactor = CONFIG.gustStrength - 1;
        }
      }
    }

    const currentSpeedMult = 1 + gustFactor;

    // Update and draw particles
    for (let i = 0; i < particles.length; i++) {
      const p = particles[i];

      // Turbulence
      p.turbPhase += CONFIG.turbulenceFrequency;
      const turbX = Math.sin(p.turbPhase * 1.3 + i) * CONFIG.turbulence * 0.3;
      const turbY = Math.sin(p.turbPhase + i * 0.7) * CONFIG.turbulence;

      // Wind force
      const windForce = CONFIG.windSpeed * p.depthFactor * currentSpeedMult;
      p.vx = windDirX * windForce + turbX;
      p.vy = windDirY * windForce + turbY;

      // Mouse shelter — deflect particles
      const dx = p.x - mouse.x;
      const dy = p.y - mouse.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONFIG.mouseShelterRadius && dist > 1) {
        const factor = Math.pow(1 - dist / CONFIG.mouseShelterRadius, 2);
        const nx = dx / dist;
        const ny = dy / dist;
        p.vx += nx * CONFIG.mouseShelterStrength * factor;
        p.vy += ny * CONFIG.mouseShelterStrength * factor;
      }

      p.x += p.vx;
      p.y += p.vy;

      // Recycle particles that leave the screen
      const margin = CONFIG.maxParticleSize * 3;
      if (p.x > width + margin || p.x < -margin ||
          p.y > height + margin || p.y < -margin) {
        const fresh = createParticle(false, windRad);
        particles[i] = fresh;
        continue;
      }

      // Draw particle
      ctx.globalAlpha = p.opacity;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
      ctx.fillStyle = `rgb(${p.color.r}, ${p.color.g}, ${p.color.b})`;
      ctx.fill();
    }

    // Draw haze streaks during gusts for visual emphasis
    if (gustFactor > 0.5) {
      const streakAlpha = Math.min(0.06, gustFactor * 0.02);
      ctx.save();
      ctx.globalAlpha = streakAlpha;
      ctx.strokeStyle = CONFIG.hazeColor;
      ctx.lineWidth = 1;
      for (let s = 0; s < 8; s++) {
        const sy = Math.random() * height;
        const sx = Math.random() * width * 0.3;
        const sl = 80 + Math.random() * 200;
        ctx.beginPath();
        ctx.moveTo(sx, sy);
        ctx.lineTo(sx + sl * windDirX, sy + sl * windDirY);
        ctx.stroke();
      }
      ctx.restore();
    }

    ctx.globalAlpha = 1;
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Snow Globe
 * Description: Gentle snowfall with drifting flakes, shimmer sparkles,
 *   bottom-edge accumulation, and a mouse-driven swirl wind effect.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Flake Appearance --
  flakeCount: 180,                        // Total number of snowflakes
  minFlakeSize: 1.5,                      // Smallest flake radius in px
  maxFlakeSize: 5,                        // Largest flake radius in px
  flakeColor: 'rgba(255, 255, 255, 1)',   // Base flake color
  flakeOpacity: 0.85,                     // Global flake opacity (0-1)
  shimmerChance: 0.02,                    // Per-frame chance a flake sparkles (0-1)
  shimmerGlowRadius: 12,                  // Glow radius when a flake shimmers in px
  shimmerColor: 'rgba(200, 230, 255, 0.9)', // Color of the shimmer glow

  // -- Motion --
  gravity: 0.35,                          // Downward acceleration per frame
  windDirection: 1,                       // Horizontal wind bias (-1 left, 1 right)
  windStrength: 0.4,                      // Base horizontal wind force
  driftRandomness: 0.6,                   // Per-frame random horizontal jitter
  speed: 1.0,                             // Global speed multiplier

  // -- Accumulation --
  accumulationHeight: 18,                 // Max snow buildup height at bottom in px
  accumulationRate: 0.012,                // How fast snow accumulates (0-1)

  // -- Mouse Interaction --
  mouseRadius: 160,                       // Radius of mouse swirl influence in px
  mouseSwirl: 3.5,                        // Tangential swirl force strength
  mouseRepel: 1.2,                        // Radial push-away force strength
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let flakes = [];
let accumulation = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initFlakes();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initFlakes();
      accumulation = 0;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function initFlakes() {
  flakes = [];
  for (let i = 0; i < CONFIG.flakeCount; i++) {
    flakes.push(createFlake(true));
  }
}

function createFlake(randomY) {
  const size = CONFIG.minFlakeSize + Math.random() * (CONFIG.maxFlakeSize - CONFIG.minFlakeSize);
  return {
    x: Math.random() * width,
    y: randomY ? Math.random() * height : -size * 2,
    size,
    vx: 0,
    vy: 0.5 + Math.random() * 1.5,
    wobblePhase: Math.random() * Math.PI * 2,
    wobbleSpeed: 0.01 + Math.random() * 0.03,
    opacity: 0.4 + Math.random() * 0.6,
  };
}

function startAnimation() {
  function render() {
    if (!ctx) return;

    ctx.clearRect(0, 0, width, height);

    const floorY = height - accumulation;

    // Update and draw flakes
    for (let i = 0; i < flakes.length; i++) {
      const f = flakes[i];

      // Wobble drift
      f.wobblePhase += f.wobbleSpeed * CONFIG.speed;
      const wobble = Math.sin(f.wobblePhase) * CONFIG.driftRandomness;

      // Wind
      f.vx += (CONFIG.windDirection * CONFIG.windStrength + wobble) * 0.02 * CONFIG.speed;
      f.vy += CONFIG.gravity * 0.02 * CONFIG.speed;

      // Mouse swirl
      const dx = f.x - mouse.x;
      const dy = f.y - mouse.y;
      const dist = Math.sqrt(dx * dx + dy * dy);
      if (dist < CONFIG.mouseRadius && dist > 1) {
        const factor = 1 - dist / CONFIG.mouseRadius;
        const nx = dx / dist;
        const ny = dy / dist;
        // Tangential swirl
        f.vx += (-ny * CONFIG.mouseSwirl * factor) * 0.1;
        f.vy += (nx * CONFIG.mouseSwirl * factor) * 0.1;
        // Radial repel
        f.vx += nx * CONFIG.mouseRepel * factor * 0.1;
        f.vy += ny * CONFIG.mouseRepel * factor * 0.1;
      }

      // Damping
      f.vx *= 0.96;
      f.vy *= 0.98;

      // Clamp terminal velocity
      f.vy = Math.min(f.vy, 3 * CONFIG.speed);

      f.x += f.vx;
      f.y += f.vy;

      // Reached bottom — recycle and add to accumulation
      if (f.y >= floorY) {
        accumulation = Math.min(accumulation + CONFIG.accumulationRate * f.size, CONFIG.accumulationHeight);
        flakes[i] = createFlake(false);
        continue;
      }

      // Wrap horizontally
      if (f.x < -10) f.x = width + 10;
      if (f.x > width + 10) f.x = -10;

      // Draw flake
      const alpha = f.opacity * CONFIG.flakeOpacity;

      // Shimmer check
      const isShimmering = Math.random() < CONFIG.shimmerChance;
      if (isShimmering) {
        ctx.save();
        ctx.shadowBlur = CONFIG.shimmerGlowRadius;
        ctx.shadowColor = CONFIG.shimmerColor;
        ctx.beginPath();
        ctx.arc(f.x, f.y, f.size * 1.3, 0, Math.PI * 2);
        ctx.fillStyle = CONFIG.shimmerColor;
        ctx.globalAlpha = alpha;
        ctx.fill();
        ctx.restore();
      }

      ctx.beginPath();
      ctx.arc(f.x, f.y, f.size, 0, Math.PI * 2);
      ctx.fillStyle = CONFIG.flakeColor;
      ctx.globalAlpha = alpha;
      ctx.fill();
    }

    // Draw accumulation mound
    if (accumulation > 0.5) {
      ctx.globalAlpha = 0.9;
      ctx.fillStyle = 'rgba(240, 245, 255, 0.6)';
      ctx.beginPath();
      ctx.moveTo(0, height);
      const segments = 24;
      for (let i = 0; i <= segments; i++) {
        const sx = (i / segments) * width;
        const waveOffset = Math.sin(i * 0.8) * accumulation * 0.2;
        ctx.lineTo(sx, height - accumulation + waveOffset);
      }
      ctx.lineTo(width, height);
      ctx.closePath();
      ctx.fill();
    }

    ctx.globalAlpha = 1;
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Solar Wind Embers
 * Description: Floating amber particles that drift upward and react to the sun (mouse).
 */

const CONFIG = {
    particleCount: 80,
    minSize: 1,
    maxSize: 4,
    baseColor: 'rgba(255, 180, 50, 0.2)',
    glowColor: 'rgba(255, 255, 200, 0.5)',
    driftSpeed: 0.4,
    mouseRadius: 200
};

let canvas, ctx, width, height;
let particles = [];
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas;
        ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x;
        mouse.y = e.data.y;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initParticles();
}

function initParticles() {
    particles = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * width,
            y: Math.random() * height,
            vx: (Math.random() - 0.5) * 0.5,
            vy: -(Math.random() * CONFIG.driftSpeed + 0.2),
            size: Math.random() * (CONFIG.maxSize - CONFIG.minSize) + CONFIG.minSize,
            angle: Math.random() * Math.PI * 2
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, width, height);

    for (let p of particles) {
        p.y += p.vy;
        p.x += p.vx + Math.sin(p.angle) * 0.2;
        p.angle += 0.01;

        // Screen wrap
        if (p.y < -10) p.y = height + 10;
        if (p.x < -10) p.x = width + 10;
        if (p.x > width + 10) p.x = -10;

        // Mouse reaction
        let dx = mouse.x - p.x;
        let dy = mouse.y - p.y;
        let dist = Math.hypot(dx, dy);

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);

        if (dist < CONFIG.mouseRadius) {
            ctx.fillStyle = CONFIG.glowColor;
            p.x -= dx * 0.01;
            p.y -= dy * 0.01;
        } else {
            ctx.fillStyle = CONFIG.baseColor;
        }

        ctx.fill();
    }

    requestAnimationFrame(render);
}

/**
 * Title: Starfall Pulse
 * Description: Interactive floating embers that react to the user.
 */

const CONFIG = {
    particleCount: 120,
    minSize: 1,
    maxSize: 4,
    baseColor: '255, 200, 100', // Embers (Gold)
    riseSpeed: 0.8,
    swayAmount: 1.5,
    reactionRadius: 150
};

let canvas, ctx, width, height;
let particles = [];
let mouse = { x: -1000, y: -1000 };

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            startAnimation();
            break;
        case 'resize': resize(e.data.width, e.data.height); break;
        case 'mousemove': mouse.x = e.data.x; mouse.y = e.data.y; break;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initParticles();
}

function initParticles() {
    particles = [];
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push({
            x: Math.random() * width,
            y: Math.random() * height,
            size: Math.random() * (CONFIG.maxSize - CONFIG.minSize) + CONFIG.minSize,
            speed: Math.random() * CONFIG.riseSpeed + 0.2,
            offset: Math.random() * Math.PI * 2
        });
    }
}

function startAnimation() {
    function render() {
        if (!ctx) return;
        ctx.clearRect(0, 0, width, height);

        particles.forEach(p => {
            // Float up and sway
            p.y -= p.speed;
            p.x += Math.sin(p.y * 0.01 + p.offset) * (CONFIG.swayAmount * 0.5);

            // Interaction
            let dx = mouse.x - p.x;
            let dy = mouse.y - p.y;
            let dist = Math.sqrt(dx * dx + dy * dy);
            let scale = 1;
            let alpha = 0.3;

            if (dist < CONFIG.reactionRadius) {
                let factor = 1 - (dist / CONFIG.reactionRadius);
                scale = 1 + factor * 2;
                alpha = 0.3 + factor * 0.6;
            }

            // Recycle to bottom
            if (p.y < -20) {
                p.y = height + 20;
                p.x = Math.random() * width;
            }

            ctx.fillStyle = `rgba(${CONFIG.baseColor}, ${alpha})`;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size * scale, 0, Math.PI * 2);
            ctx.fill();

            // Add a small soft glow to scaled particles
            if (scale > 1.2) {
                ctx.shadowBlur = 10;
                ctx.shadowColor = `rgba(${CONFIG.baseColor}, ${alpha})`;
                ctx.fill();
                ctx.shadowBlur = 0;
            }
        });

        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Starfield Warp
 * Description: A classic starfield effect where stars fly toward the viewer from the center.
 *              Stars have trails and speed up when the mouse is near them.
 *              Deep space feel with white/blue stars of varying sizes.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let stars = [];
const STAR_COUNT = 280;
const BASE_SPEED = 0.4;
const MAX_SPEED = 2.5;
const TRAIL_LENGTH = 0.6;

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class Star {
	constructor() {
		this.reset();
	}

	reset() {
		// Place star at random position in 3D space, projected from center
		this.x = (Math.random() - 0.5) * width * 2;
		this.y = (Math.random() - 0.5) * height * 2;
		this.z = Math.random() * 1500 + 500;
		this.pz = this.z; // previous z for trail
		this.size = Math.random() * 1.8 + 0.4;
		// Color: white to pale blue
		const blue = Math.random();
		if (blue < 0.3) {
			this.color = { r: 180, g: 200, b: 255 }; // blue-ish
		} else if (blue < 0.5) {
			this.color = { r: 200, g: 220, b: 255 }; // light blue
		} else {
			this.color = { r: 240, g: 245, b: 255 }; // near white
		}
	}

	update(speed) {
		this.pz = this.z;
		this.z -= speed;
		if (this.z <= 1) {
			this.reset();
			this.z = 1500;
			this.pz = this.z;
		}
	}

	draw() {
		const cx = width / 2;
		const cy = height / 2;

		// Current projected position
		const sx = (this.x / this.z) * cx + cx;
		const sy = (this.y / this.z) * cy + cy;

		// Previous projected position (for trail)
		const px = (this.x / this.pz) * cx + cx;
		const py = (this.y / this.pz) * cy + cy;

		// Size scales with proximity
		const r = Math.max(0.3, (1 - this.z / 1500) * this.size * 2.5);

		// Brightness scales with proximity
		const brightness = Math.min(1, (1 - this.z / 1500) * 1.5);
		const alpha = brightness * 0.85;

		const { r: cr, g: cg, b: cb } = this.color;

		// Draw trail
		if (Math.abs(sx - px) > 0.5 || Math.abs(sy - py) > 0.5) {
			ctx.beginPath();
			ctx.moveTo(px, py);
			ctx.lineTo(sx, sy);
			ctx.strokeStyle = `rgba(${cr}, ${cg}, ${cb}, ${alpha * TRAIL_LENGTH})`;
			ctx.lineWidth = r * 0.6;
			ctx.stroke();
		}

		// Draw star point
		ctx.beginPath();
		ctx.arc(sx, sy, r, 0, Math.PI * 2);
		ctx.fillStyle = `rgba(${cr}, ${cg}, ${cb}, ${alpha})`;
		ctx.fill();

		// Glow for close stars
		if (brightness > 0.6) {
			ctx.beginPath();
			ctx.arc(sx, sy, r * 2.5, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(${cr}, ${cg}, ${cb}, ${alpha * 0.15})`;
			ctx.fill();
		}

		return { sx, sy };
	}
}

function initStars() {
	stars = [];
	for (let i = 0; i < STAR_COUNT; i++) {
		stars.push(new Star());
	}
}

function startAnimation() {
	function render() {
		if (!ctx) return;
		// Slight fade for persistence effect
		ctx.fillStyle = 'rgba(0, 0, 0, 0.15)';
		ctx.fillRect(0, 0, width, height);

		const cx = width / 2;
		const cy = height / 2;

		for (const star of stars) {
			// Project current position to check mouse distance
			const sx = (star.x / star.z) * cx + cx;
			const sy = (star.y / star.z) * cy + cy;

			const dx = mouse.x - sx;
			const dy = mouse.y - sy;
			const dist = Math.sqrt(dx * dx + dy * dy);

			// Speed up stars near mouse
			const mouseInfluence = Math.max(0, 1 - dist / 250);
			const speed = BASE_SPEED + mouseInfluence * (MAX_SPEED - BASE_SPEED);

			star.update(speed * 8);
			star.draw();
		}

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			ctx.fillStyle = '#000';
			ctx.fillRect(0, 0, width, height);
			initStars();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			ctx.fillStyle = '#000';
			ctx.fillRect(0, 0, width, height);
			initStars();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

/**
 * Title: Stress Test — Particle Inferno
 * Description: A brutal CPU stress test that pushes Canvas FX to its absolute
 *   limits. Renders 100,000 particles with real-time physics, per-particle
 *   velocity-to-heat color mapping, additive blending, and a multi-pass glow
 *   bloom. Particles are violently attracted to the cursor, creating a molten
 *   vortex that heats up on impact. A live FPS HUD shows how your system copes.
 *
 *   Move your mouse to pull the inferno toward you. If FPS stays above 30,
 *   your machine wins.
 */

/* ============ STRESS INTENSITY KNOBS ============ */
const PARTICLE_COUNT    = 100000;   // 100k (raise to 200k+ for extreme)
const PARTICLE_SIZE     = 3;        // px size of each particle
const ENABLE_BLOOM      = true;     // multi-pass box blur bloom (VERY expensive)
const BLOOM_PASSES      = 2;        // blur iterations per frame
const BLOOM_RADIUS      = 3;        // blur kernel radius
const ENABLE_HEAT_COLOR = true;     // per-particle velocity → color mapping
const MOUSE_FORCE       = 6000;     // attraction strength toward cursor
const MOUSE_RADIUS      = 280;      // pixel radius of mouse influence
const GRAVITY           = 0.015;    // downward pull
const FRICTION          = 0.965;    // velocity damping (lower = more drag)
const JITTER            = 0.25;     // random turbulence per frame
const BOUNCE            = 0.5;      // wall bounce energy retention
const TRAIL_OPACITY     = 0.06;     // trail fade per frame (lower = longer trails)
/* ================================================ */

let canvas, ctx, w, h;
let N = PARTICLE_COUNT;
let px, py, vx, vy, heat;
let mx = -9999, my = -9999;
let mouseR2 = MOUSE_RADIUS * MOUSE_RADIUS;
let time = 0;
let lastTime = 0;
let fps = 0;
let frameCount = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function initParticles() {
	px   = new Float32Array(N);
	py   = new Float32Array(N);
	vx   = new Float32Array(N);
	vy   = new Float32Array(N);
	heat = new Float32Array(N);

	for (let i = 0; i < N; i++) {
		px[i] = Math.random() * w;
		py[i] = Math.random() * h;
		vx[i] = (Math.random() - 0.5) * 2;
		vy[i] = (Math.random() - 0.5) * 2;
		heat[i] = Math.random() * 0.2;
	}
}

// Pre-compute a palette LUT (256 entries) to avoid per-particle branching
const PALETTE = new Array(256);
(function buildPalette() {
	for (let i = 0; i < 256; i++) {
		const t = i / 255;
		let r, g, b;
		if (t < 0.25) {
			// Dark red → bright red
			const s = t / 0.25;
			r = 80 + s * 175; g = 0; b = 0;
		} else if (t < 0.5) {
			// Red → orange
			const s = (t - 0.25) / 0.25;
			r = 255; g = s * 160; b = 0;
		} else if (t < 0.75) {
			// Orange → yellow
			const s = (t - 0.5) / 0.25;
			r = 255; g = 160 + s * 95; b = s * 40;
		} else {
			// Yellow → white-hot
			const s = (t - 0.75) / 0.25;
			r = 255; g = 255; b = 40 + s * 215;
		}
		PALETTE[i] = `rgb(${r | 0},${g | 0},${b | 0})`;
	}
})();

function heatToColor(t) {
	return PALETTE[Math.min(255, Math.max(0, (t * 255) | 0))];
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d', { willReadFrequently: ENABLE_BLOOM });
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initParticles();
			lastTime = performance.now();
			startAnimation();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initParticles();
			break;
		case 'mousemove':
			mx = e.data.x;
			my = e.data.y;
			break;
	}
};

// Separable box blur for bloom (operates on ImageData.data)
function boxBlurH(src, dst, w, h, r) {
	const iarr = 1 / (r + r + 1);
	for (let y = 0; y < h; y++) {
		const rowStart = y * w * 4;
		const rowEnd = rowStart + w * 4;
		let ri = rowStart, li = rowStart, idx = rowStart;
		let rA = src[ri], gA = src[ri + 1], bA = src[ri + 2];
		for (let j = 0; j < r; j++) { rA += src[ri]; gA += src[ri + 1]; bA += src[ri + 2]; }
		for (let j = 0; j <= r; j++) {
			ri = Math.min(ri + 4, rowEnd - 4);
			rA += src[ri] - src[li]; gA += src[ri + 1] - src[li + 1]; bA += src[ri + 2] - src[li + 2];
			dst[idx] = (rA * iarr) | 0; dst[idx + 1] = (gA * iarr) | 0; dst[idx + 2] = (bA * iarr) | 0; dst[idx + 3] = 255;
			idx += 4;
		}
		for (let j = r + 1; j < w - r; j++) {
			ri += 4; li += 4;
			rA += src[ri] - src[li]; gA += src[ri + 1] - src[li + 1]; bA += src[ri + 2] - src[li + 2];
			dst[idx] = (rA * iarr) | 0; dst[idx + 1] = (gA * iarr) | 0; dst[idx + 2] = (bA * iarr) | 0; dst[idx + 3] = 255;
			idx += 4;
		}
		for (let j = w - r; j < w; j++) {
			li += 4;
			rA += src[ri] - src[li]; gA += src[ri + 1] - src[li + 1]; bA += src[ri + 2] - src[li + 2];
			dst[idx] = (rA * iarr) | 0; dst[idx + 1] = (gA * iarr) | 0; dst[idx + 2] = (bA * iarr) | 0; dst[idx + 3] = 255;
			idx += 4;
		}
	}
}

function boxBlurV(src, dst, w, h, r) {
	const iarr = 1 / (r + r + 1);
	const stride = w * 4;
	const totalLen = w * h * 4;
	for (let x = 0; x < w; x++) {
		const col = x * 4;
		let ti = col, bi = col, idx = col;
		let rA = src[ti], gA = src[ti + 1], bA = src[ti + 2];
		for (let j = 0; j < r; j++) { rA += src[ti]; gA += src[ti + 1]; bA += src[ti + 2]; }
		for (let j = 0; j <= r; j++) {
			ti = Math.min(ti + stride, totalLen - stride + col);
			rA += src[ti] - src[bi]; gA += src[ti + 1] - src[bi + 1]; bA += src[ti + 2] - src[bi + 2];
			dst[idx] = (rA * iarr) | 0; dst[idx + 1] = (gA * iarr) | 0; dst[idx + 2] = (bA * iarr) | 0; dst[idx + 3] = 255;
			idx += stride;
		}
		for (let j = r + 1; j < h - r; j++) {
			ti += stride; bi += stride;
			rA += src[ti] - src[bi]; gA += src[ti + 1] - src[bi + 1]; bA += src[ti + 2] - src[bi + 2];
			dst[idx] = (rA * iarr) | 0; dst[idx + 1] = (gA * iarr) | 0; dst[idx + 2] = (bA * iarr) | 0; dst[idx + 3] = 255;
			idx += stride;
		}
		for (let j = h - r; j < h; j++) {
			bi += stride;
			rA += src[ti] - src[bi]; gA += src[ti + 1] - src[bi + 1]; bA += src[ti + 2] - src[bi + 2];
			dst[idx] = (rA * iarr) | 0; dst[idx + 1] = (gA * iarr) | 0; dst[idx + 2] = (bA * iarr) | 0; dst[idx + 3] = 255;
			idx += stride;
		}
	}
}

function startAnimation() {
	let tempBuf = ENABLE_BLOOM ? new Uint8ClampedArray(w * h * 4) : null;

	function render() {
		if (!ctx) return;
		time++;
		frameCount++;

		const now = performance.now();
		if (now - lastTime >= 1000) {
			fps = frameCount;
			frameCount = 0;
			lastTime = now;
		}

		// --- Phase 1: Fade previous frame (trail persistence) ---
		ctx.fillStyle = `rgba(0, 0, 0, ${TRAIL_OPACITY})`;
		ctx.fillRect(0, 0, w, h);

		// --- Phase 2: Physics + draw (100k fillRect calls = brutal) ---
		ctx.globalCompositeOperation = 'lighter'; // additive blending

		for (let i = 0; i < N; i++) {
			// Mouse attraction
			const dx = mx - px[i];
			const dy = my - py[i];
			const d2 = dx * dx + dy * dy;

			if (d2 < mouseR2 && d2 > 1) {
				const dist = Math.sqrt(d2);
				const f = MOUSE_FORCE / (d2 + 100);
				vx[i] += (dx / dist) * f;
				vy[i] += (dy / dist) * f;
				heat[i] = Math.min(1, heat[i] + 0.04);
			}

			vy[i] += GRAVITY;
			vx[i] += (Math.random() - 0.5) * JITTER;
			vy[i] += (Math.random() - 0.5) * JITTER;
			vx[i] *= FRICTION;
			vy[i] *= FRICTION;
			px[i] += vx[i];
			py[i] += vy[i];

			// Velocity-based heat
			if (ENABLE_HEAT_COLOR) {
				const speed = Math.sqrt(vx[i] * vx[i] + vy[i] * vy[i]);
				heat[i] = Math.min(1, heat[i] + speed * 0.006);
			}
			heat[i] *= 0.993;

			// Wall bounce
			if (px[i] < 0)  { px[i] = 0;     vx[i] *= -BOUNCE; heat[i] = Math.min(1, heat[i] + 0.08); }
			if (px[i] >= w)  { px[i] = w - 1; vx[i] *= -BOUNCE; heat[i] = Math.min(1, heat[i] + 0.08); }
			if (py[i] < 0)  { py[i] = 0;     vy[i] *= -BOUNCE; heat[i] = Math.min(1, heat[i] + 0.08); }
			if (py[i] >= h)  { py[i] = h - 1; vy[i] *= -BOUNCE; heat[i] = Math.min(1, heat[i] + 0.08); }

			// Draw — each particle is a fillRect call (100k per frame!)
			ctx.fillStyle = ENABLE_HEAT_COLOR ? heatToColor(heat[i]) : '#ff8c28';
			ctx.fillRect((px[i] + 0.5) | 0, (py[i] + 0.5) | 0, PARTICLE_SIZE, PARTICLE_SIZE);
		}

		ctx.globalCompositeOperation = 'source-over';

		// --- Phase 3: Bloom post-process ---
		if (ENABLE_BLOOM) {
			if (!tempBuf || tempBuf.length !== w * h * 4) {
				tempBuf = new Uint8ClampedArray(w * h * 4);
			}
			const img = ctx.getImageData(0, 0, w, h);
			const src = img.data;
			const tmp = tempBuf;
			for (let pass = 0; pass < BLOOM_PASSES; pass++) {
				boxBlurH(src, tmp, w, h, BLOOM_RADIUS);
				boxBlurV(tmp, src, w, h, BLOOM_RADIUS);
			}
			ctx.putImageData(img, 0, 0);
		}

		// --- Phase 4: HUD overlay ---
		ctx.fillStyle = 'rgba(0, 0, 0, 0.75)';
		ctx.fillRect(8, 8, 260, 94);
		ctx.strokeStyle = 'rgba(255,255,255,0.1)';
		ctx.strokeRect(8, 8, 260, 94);
		ctx.fillStyle = fps >= 50 ? '#4ade80' : fps >= 30 ? '#facc15' : '#ef4444';
		ctx.font = 'bold 28px monospace';
		ctx.fillText(`${fps} FPS`, 18, 42);
		ctx.fillStyle = '#d4d4d8';
		ctx.font = '13px monospace';
		ctx.fillText(`${(N / 1000).toFixed(0)}k particles × ${PARTICLE_SIZE}px`, 18, 62);
		ctx.fillText(`bloom: ${ENABLE_BLOOM ? `ON ×${BLOOM_PASSES} r${BLOOM_RADIUS}` : 'OFF'} | heat: ${ENABLE_HEAT_COLOR ? 'ON' : 'OFF'}`, 18, 78);
		ctx.fillText(`mouse: (${mx | 0}, ${my | 0})`, 18, 94);

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Tactical Liquid Grid
 * Description: An interactive grid of crosshairs that behaves like an elastic fabric.
 */

let canvas, ctx, width, height;
let points =[];
let mouse = { x: -5000, y: -5000 };

const CONFIG = { spacing: 40, friction: 0.85, ease: 0.1, mouseDist: 150, mouseForce: 50, color: 'rgba(255, 255, 255, 0.15)', activeColor: '#00ffff' };

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            startAnimation();
            break;
        case 'resize': resize(e.data.width, e.data.height); break;
        case 'mousemove': mouse.x = e.data.x; mouse.y = e.data.y; break;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }
    initGrid();
}

class Point {
    constructor(x, y) { this.originX = x; this.originY = y; this.x = x; this.y = y; this.vx = 0; this.vy = 0; }
    update() {
        const dx = mouse.x - this.x, dy = mouse.y - this.y;
        const dist = Math.sqrt(dx*dx + dy*dy);
        if (dist < CONFIG.mouseDist) {
            const angle = Math.atan2(dy, dx);
            const force = (CONFIG.mouseDist - dist) / CONFIG.mouseDist;
            this.vx -= Math.cos(angle) * force * CONFIG.mouseForce;
            this.vy -= Math.sin(angle) * force * CONFIG.mouseForce;
        }
        this.vx += (this.originX - this.x) * CONFIG.ease;
        this.vy += (this.originY - this.y) * CONFIG.ease;
        this.vx *= CONFIG.friction; this.vy *= CONFIG.friction;
        this.x += this.vx; this.y += this.vy;
    }
    draw() {
        const speed = Math.abs(this.vx) + Math.abs(this.vy);
        ctx.strokeStyle = speed > 0.5 ? CONFIG.activeColor : CONFIG.color;
        ctx.lineWidth = speed > 0.5 ? 1.5 : 1;
        ctx.beginPath();
        ctx.moveTo(this.x - 3, this.y); ctx.lineTo(this.x + 3, this.y);
        ctx.moveTo(this.x, this.y - 3); ctx.lineTo(this.x, this.y + 3);
        ctx.stroke();
    }
}

function initGrid() {
    points =[];
    for (let x = 0; x <= width + CONFIG.spacing; x += CONFIG.spacing) {
        for (let y = 0; y <= height + CONFIG.spacing; y += CONFIG.spacing) {
            points.push(new Point(x, y));
        }
    }
}

function startAnimation() {
    function render() {
        if (!ctx) return;
        ctx.clearRect(0, 0, width, height);
        for (let i = 0; i < points.length; i++) { points[i].update(); points[i].draw(); }
        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

/**
 * Title: Tap Fireworks
 * Description: Click or tap anywhere to launch a firework burst! Each click
 *   spawns a colorful explosion with trails, sparkles, and gravity. Multiple
 *   fireworks can exist simultaneously. Hold mousedown to charge up a bigger
 *   burst. Works on both desktop (click) and mobile (touch/multi-touch).
 *
 *   Showcases: click, mousedown, mouseup, touchstart, touchend
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const PARTICLES_PER_BURST = 60;      // particles per firework
const CHARGE_MAX_MS       = 1500;    // max hold time for bigger burst
const GRAVITY             = 0.06;    // downward acceleration
const FRICTION            = 0.985;   // velocity decay per frame
const TRAIL_LENGTH        = 6;       // past positions to draw as trail
const SPARKLE_COUNT       = 20;      // tiny sparkles per burst
const BG_FADE             = 0.08;    // background fade speed (lower = longer trails)
/* --------------------------------------------- */

let canvas, ctx, w, h;
let fireworks = [];
let chargeStart = 0;
let chargeX = 0, chargeY = 0;
let isCharging = false;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function randomHue() { return Math.floor(Math.random() * 360); }

function createBurst(x, y, power) {
	const hue = randomHue();
	const count = Math.floor(PARTICLES_PER_BURST * power);
	const sparkles = Math.floor(SPARKLE_COUNT * power);
	const particles = [];

	for (let i = 0; i < count; i++) {
		const angle = (i / count) * Math.PI * 2 + (Math.random() - 0.5) * 0.5;
		const speed = (1.5 + Math.random() * 3) * power;
		const hueShift = (Math.random() - 0.5) * 60;
		particles.push({
			x, y,
			vx: Math.cos(angle) * speed,
			vy: Math.sin(angle) * speed,
			hue: hue + hueShift,
			alpha: 1,
			size: 2 + Math.random() * 2 * power,
			decay: 0.008 + Math.random() * 0.008,
			trail: [],
			isSparkle: false
		});
	}

	// Add sparkles (tiny fast particles)
	for (let i = 0; i < sparkles; i++) {
		const angle = Math.random() * Math.PI * 2;
		const speed = (3 + Math.random() * 4) * power;
		particles.push({
			x, y,
			vx: Math.cos(angle) * speed,
			vy: Math.sin(angle) * speed,
			hue: 45 + Math.random() * 15, // golden sparkles
			alpha: 1,
			size: 1 + Math.random(),
			decay: 0.015 + Math.random() * 0.015,
			trail: [],
			isSparkle: true
		});
	}

	fireworks.push(...particles);
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			animate();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			break;
		case 'click':
			// Quick tap = small burst (if not charging)
			if (!isCharging) {
				createBurst(e.data.x, e.data.y, 0.7);
			}
			break;
		case 'mousedown':
			// Start charging
			isCharging = true;
			chargeStart = Date.now();
			chargeX = e.data.x;
			chargeY = e.data.y;
			break;
		case 'mouseup': {
			// Release = launch with charge power
			if (isCharging) {
				const held = Math.min(Date.now() - chargeStart, CHARGE_MAX_MS);
				const power = 0.5 + (held / CHARGE_MAX_MS) * 1.5;
				createBurst(e.data.x, e.data.y, power);
				isCharging = false;
			}
			break;
		}
		case 'touchstart':
			// Multi-touch: launch a burst at each finger
			if (e.data.touches) {
				for (const t of e.data.touches) {
					createBurst(t.x, t.y, 0.8);
				}
			}
			break;
		case 'mousemove':
			// Update charge position while holding
			if (isCharging) {
				chargeX = e.data.x;
				chargeY = e.data.y;
			}
			break;
	}
};

function animate() {
	if (!ctx) return;

	// Fade background
	ctx.fillStyle = `rgba(5, 5, 15, ${BG_FADE})`;
	ctx.fillRect(0, 0, w, h);

	// Draw charge indicator
	if (isCharging) {
		const held = Math.min(Date.now() - chargeStart, CHARGE_MAX_MS);
		const ratio = held / CHARGE_MAX_MS;
		const radius = 10 + ratio * 40;
		const pulse = 0.5 + 0.5 * Math.sin(Date.now() * 0.01);

		// Pulsing ring
		ctx.beginPath();
		ctx.arc(chargeX, chargeY, radius, 0, Math.PI * 2);
		ctx.strokeStyle = `hsla(${45 + ratio * 300}, 100%, 70%, ${0.3 + pulse * 0.4})`;
		ctx.lineWidth = 2 + ratio * 3;
		ctx.stroke();

		// Progress arc
		ctx.beginPath();
		ctx.arc(chargeX, chargeY, radius + 5, -Math.PI / 2, -Math.PI / 2 + ratio * Math.PI * 2);
		ctx.strokeStyle = `hsla(${45 + ratio * 300}, 100%, 80%, 0.8)`;
		ctx.lineWidth = 3;
		ctx.stroke();

		// Center glow
		const glow = ctx.createRadialGradient(chargeX, chargeY, 0, chargeX, chargeY, radius);
		glow.addColorStop(0, `hsla(${45 + ratio * 300}, 100%, 80%, ${ratio * 0.2})`);
		glow.addColorStop(1, 'hsla(0, 0%, 0%, 0)');
		ctx.fillStyle = glow;
		ctx.beginPath();
		ctx.arc(chargeX, chargeY, radius, 0, Math.PI * 2);
		ctx.fill();
	}

	// Update and draw particles
	for (let i = fireworks.length - 1; i >= 0; i--) {
		const p = fireworks[i];

		// Save trail
		p.trail.push({ x: p.x, y: p.y });
		if (p.trail.length > TRAIL_LENGTH) p.trail.shift();

		// Physics
		p.vy += GRAVITY;
		p.vx *= FRICTION;
		p.vy *= FRICTION;
		p.x += p.vx;
		p.y += p.vy;
		p.alpha -= p.decay;

		if (p.alpha <= 0) {
			fireworks.splice(i, 1);
			continue;
		}

		// Draw trail
		if (!p.isSparkle && p.trail.length > 1) {
			ctx.beginPath();
			ctx.moveTo(p.trail[0].x, p.trail[0].y);
			for (let t = 1; t < p.trail.length; t++) {
				ctx.lineTo(p.trail[t].x, p.trail[t].y);
			}
			ctx.lineTo(p.x, p.y);
			ctx.strokeStyle = `hsla(${p.hue}, 100%, 60%, ${p.alpha * 0.3})`;
			ctx.lineWidth = p.size * 0.5;
			ctx.stroke();
		}

		// Draw particle
		ctx.beginPath();
		ctx.arc(p.x, p.y, p.size * p.alpha, 0, Math.PI * 2);
		ctx.fillStyle = p.isSparkle
			? `hsla(${p.hue}, 100%, 90%, ${p.alpha})`
			: `hsla(${p.hue}, 100%, 65%, ${p.alpha})`;
		ctx.fill();

		// Glow
		if (!p.isSparkle && p.alpha > 0.5) {
			const g = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 3);
			g.addColorStop(0, `hsla(${p.hue}, 100%, 70%, ${p.alpha * 0.15})`);
			g.addColorStop(1, 'hsla(0, 0%, 0%, 0)');
			ctx.fillStyle = g;
			ctx.beginPath();
			ctx.arc(p.x, p.y, p.size * 3, 0, Math.PI * 2);
			ctx.fill();
		}
	}

	// Hint text when idle
	if (fireworks.length === 0 && !isCharging) {
		ctx.fillStyle = 'rgba(255, 255, 255, 0.08)';
		ctx.font = '14px sans-serif';
		ctx.textAlign = 'center';
		ctx.fillText('Click or tap anywhere \u2728', w / 2, h / 2);
		ctx.textAlign = 'left';
	}

	requestAnimationFrame(animate);
}

/**
 * Title: The Genesis Lattice
 * Description: An emergent cellular automaton rendered as a breathing, 3D interconnected fabric.
 */

const CONFIG = {
    cellSize: 22,               // Scale of the grid
    tickRate: 6,                // How many frames between logic updates (lower = faster evolution)
    lerpSpeed: 0.12,            // How smoothly cells fade in and out
    aliveColor:[0, 255, 180],  // RGB: Cyan/Mint
    deadColor: [70, 0, 150],    // RGB: Deep Indigo/Purple
    waveAmplitude: 15,          // Height of the 3D breathing effect
    waveSpeed: 0.02,            // Speed of the breathing
    density: 0.15               // Initial random life density
};

let canvas, ctx, width, height;
let cols, rows, totalCells;
let grid = [];
let nextGrid = [];
let visuals = [];
let drawPoints =[];

let time = 0;
let targetMouse = { x: -1000, y: -1000, active: false };
let currentMouse = { x: 0, y: 0 };
let ticks = 0;

self.onmessage = (e) => {
    switch (e.data.type) {
        case 'init':
            canvas = e.data.canvas;
            ctx = canvas.getContext('2d');
            resize(e.data.width, e.data.height);
            // Default center mouse
            targetMouse.x = width / 2; targetMouse.y = height / 2;
            currentMouse.x = width / 2; currentMouse.y = height / 2;
            startAnimation();
            break;
        case 'resize': resize(e.data.width, e.data.height); break;
        case 'mousemove': 
            targetMouse.x = e.data.x; targetMouse.y = e.data.y; 
            targetMouse.active = true;
            break;
    }
};

function resize(w, h) {
    width = w; height = h;
    if (canvas) { canvas.width = width; canvas.height = height; }

    // Add extra columns/rows to bleed off the edges of the screen
    cols = Math.floor(width / CONFIG.cellSize) + 4;
    rows = Math.floor(height / CONFIG.cellSize) + 4;
    totalCells = cols * rows;

    initGrid();
}

function initGrid() {
    grid = new Uint8Array(totalCells);
    nextGrid = new Uint8Array(totalCells);
    visuals = new Float32Array(totalCells);
    drawPoints = new Array(totalCells);

    // Seed initial random life
    for (let i = 0; i < totalCells; i++) {
        let isAlive = Math.random() < CONFIG.density ? 1 : 0;
        grid[i] = isAlive;
        visuals[i] = isAlive; // Start visuals matched so it doesn't all fade in at once
    }
}

function seedBurst(centerX, centerY, radius, probability) {
    for (let dy = -radius; dy <= radius; dy++) {
        for (let dx = -radius; dx <= radius; dx++) {
            if (Math.random() < probability) {
                let nx = (centerX + dx + cols) % cols;
                let ny = (centerY + dy + rows) % rows;
                grid[ny * cols + nx] = 1;
            }
        }
    }
}

function updateLogic() {
    let population = 0;

    for (let y = 0; y < rows; y++) {
        for (let x = 0; x < cols; x++) {
            let idx = y * cols + x;
            let alive = grid[idx];
            let neighbors = 0;

            // Count 8 surrounding neighbors with screen wrapping
            for (let dy = -1; dy <= 1; dy++) {
                for (let dx = -1; dx <= 1; dx++) {
                    if (dx === 0 && dy === 0) continue;
                    let nx = (x + dx + cols) % cols;
                    let ny = (y + dy + rows) % rows;
                    neighbors += grid[ny * cols + nx];
                }
            }

            // Conway's Rules: Birth on 3, Survive on 2 or 3
            if (alive && (neighbors === 2 || neighbors === 3)) {
                nextGrid[idx] = 1;
                population++;
            } else if (!alive && neighbors === 3) {
                nextGrid[idx] = 1;
                population++;
            } else {
                nextGrid[idx] = 0;
            }
        }
    }

    // Swap buffers efficiently
    let temp = grid;
    grid = nextGrid;
    nextGrid = temp;

    // Failsafe: If the ecosystem dies out, seed a new colony
    if (population < totalCells * 0.02) {
        seedBurst(Math.floor(Math.random() * cols), Math.floor(Math.random() * rows), 6, 0.4);
    }
}

function startAnimation() {
    function render() {
        if (!ctx) return;
        ctx.clearRect(0, 0, width, height); // Native transparency safe

        time += CONFIG.waveSpeed;
        ticks++;

        // Smooth mouse for parallax
        if (targetMouse.active) {
            currentMouse.x += (targetMouse.x - currentMouse.x) * 0.08;
            currentMouse.y += (targetMouse.y - currentMouse.y) * 0.08;
        }

        // 1. UPDATE LOGIC ENGINE
        if (ticks % CONFIG.tickRate === 0) {
            updateLogic();
        }

        // Interactive Mouse Seeding
        if (targetMouse.active) {
            let offsetX = (width - cols * CONFIG.cellSize) / 2;
            let offsetY = (height - rows * CONFIG.cellSize) / 2;
            let gridX = Math.floor((targetMouse.x - offsetX) / CONFIG.cellSize);
            let gridY = Math.floor((targetMouse.y - offsetY) / CONFIG.cellSize);

            if (gridX >= 0 && gridX < cols && gridY >= 0 && gridY < rows) {
                if (Math.random() > 0.5) grid[gridY * cols + gridX] = 1; // Inject life
            }
        }

        let cx = width / 2;
        let cy = height / 2;

        // 2. PRE-COMPUTE 3D DISPLACEMENT POINTS & SMOOTH VISUALS
        for (let y = 0; y < rows; y++) {
            for (let x = 0; x < cols; x++) {
                let idx = y * cols + x;

                // Lerp the visual scale towards the actual logic state
                visuals[idx] += (grid[idx] - visuals[idx]) * CONFIG.lerpSpeed;

                // Base 2D position (Centered)
                let px = x * CONFIG.cellSize + (width - cols * CONFIG.cellSize) / 2;
                let py = y * CONFIG.cellSize + (height - rows * CONFIG.cellSize) / 2;

                // 3D Radial Sine Wave Displacement
                let dist = Math.sqrt(Math.pow(px - cx, 2) + Math.pow(py - cy, 2));
                let waveZ = Math.sin(dist * 0.008 - time) * CONFIG.waveAmplitude;

                // Mouse Parallax Perspective Shift
                let pXOffset = (currentMouse.x - cx) * 0.08 * ((y - rows/2) / rows);
                let pYOffset = (currentMouse.y - cy) * 0.08 * ((x - cols/2) / cols);

                drawPoints[idx] = { 
                    x: px + pXOffset, 
                    y: py + waveZ + pYOffset,
                    v: visuals[idx] 
                };
            }
        }

        ctx.lineWidth = 1.2;

        // 3. DRAW STRUCTURAL BONDS (Underneath)
        for (let y = 0; y < rows - 1; y++) {
            for (let x = 0; x < cols - 1; x++) {
                let idx = y * cols + x;
                let p1 = drawPoints[idx];

                if (p1.v > 0.05) {
                    let rIdx = y * cols + (x + 1);       // Right neighbor
                    let bIdx = (y + 1) * cols + x;       // Bottom neighbor
                    let drIdx = (y + 1) * cols + (x + 1); // Bottom-Right Diagonal neighbor

                    let pR = drawPoints[rIdx];
                    let pB = drawPoints[bIdx];
                    let pDR = drawPoints[drIdx];

                    ctx.beginPath();
                    let drawn = false;

                    if (pR.v > 0.05) { ctx.moveTo(p1.x, p1.y); ctx.lineTo(pR.x, pR.y); drawn = true; }
                    if (pB.v > 0.05) { ctx.moveTo(p1.x, p1.y); ctx.lineTo(pB.x, pB.y); drawn = true; }
                    // Add diagonal structural bonds for a "webbed" look
                    if (pDR.v > 0.05) { ctx.moveTo(p1.x, p1.y); ctx.lineTo(pDR.x, pDR.y); drawn = true; }

                    if (drawn) {
                        ctx.strokeStyle = `rgba(${CONFIG.aliveColor.join(',')}, ${p1.v * 0.3})`;
                        ctx.stroke();
                    }
                }
            }
        }

        // 4. DRAW LIVING NODES (On top)
        for (let i = 0; i < totalCells; i++) {
            let p = drawPoints[i];
            if (p.v > 0.05) {
                // Color interpolation: Alive = Cyan, Dying = Purple
                let r = Math.floor(CONFIG.deadColor[0] + (CONFIG.aliveColor[0] - CONFIG.deadColor[0]) * p.v);
                let g = Math.floor(CONFIG.deadColor[1] + (CONFIG.aliveColor[1] - CONFIG.deadColor[1]) * p.v);
                let b = Math.floor(CONFIG.deadColor[2] + (CONFIG.aliveColor[2] - CONFIG.deadColor[2]) * p.v);

                ctx.beginPath();
                ctx.arc(p.x, p.y, p.v * (CONFIG.cellSize * 0.35), 0, Math.PI * 2);
                ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${p.v * 0.9})`;
                ctx.fill();
            }
        }

        requestAnimationFrame(render);
    }
    requestAnimationFrame(render);
}

// Reset mouse tracking if user leaves canvas area
let mouseTimeout;
self.addEventListener('message', (e) => {
    if (e.data.type === 'mousemove') {
        clearTimeout(mouseTimeout);
        mouseTimeout = setTimeout(() => { targetMouse.active = false; }, 2000);
    }
});

// Heartbeat — prevents host from terminating idle workers
setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

/**
 * Title: Thunderstorm
 * Description: Dramatic lightning bolts that fork and flash against a dark sky.
 *   Mouse click area triggers a targeted bolt. Background flashes and rumble glow
 *   create an immersive storm atmosphere.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Bolt Appearance --
  boltColor: 'rgba(180, 200, 255, 0.95)',   // Main bolt stroke color
  boltWidth: 2.5,                            // Base stroke width of the main bolt in px
  boltSegments: 12,                          // Number of jagged segments per bolt
  boltJagOffset: 35,                         // Max horizontal offset per segment in px
  boltGlowColor: 'rgba(140, 170, 255, 0.5)',// Glow halo around bolts
  boltGlowWidth: 10,                         // Glow blur radius in px

  // -- Forking --
  forkProbability: 0.35,                     // Chance each segment spawns a fork (0-1)
  maxForkDepth: 3,                           // Maximum recursive fork depth
  forkLengthFactor: 0.55,                    // Fork length relative to remaining bolt (0-1)
  forkWidthDecay: 0.6,                       // Stroke width multiplier per fork depth

  // -- Flash --
  flashBrightness: 0.35,                     // Peak screen-flash opacity (0-1)
  flashDuration: 350,                        // Flash fade-out duration in ms
  backgroundFlashColor: 'rgba(200, 215, 255, 1)', // Color of the full-screen flash

  // -- Timing --
  boltFrequency: 2200,                       // Average ms between auto bolts
  boltFrequencyVariance: 1500,               // ± random ms added to frequency
  boltLifetime: 180,                         // How long a bolt stays visible in ms

  // -- Rumble --
  rumbleGlowColor: 'rgba(100, 120, 180, 0.08)', // Subtle ambient storm glow at horizon
  rumbleGlowHeight: 0.25,                       // Fraction of canvas height for rumble glow

  // -- Mouse Interaction --
  mouseClickBolt: true,                      // Whether mouse area triggers targeted bolts
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let bolts = [];
let flashAlpha = 0;
let flashStart = 0;
let lastBoltTime = 0;
let nextBoltDelay = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      nextBoltDelay = CONFIG.boltFrequency;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
    case 'mousedown':
    case 'click':
      if (CONFIG.mouseClickBolt) {
        spawnBolt(e.data.x || mouse.x, 0, e.data.x || mouse.x, e.data.y || mouse.y);
      }
      break;
  }
};

function generateBoltPath(x1, y1, x2, y2, segments, depth) {
  const points = [{ x: x1, y: y1 }];
  const dx = x2 - x1;
  const dy = y2 - y1;

  for (let i = 1; i < segments; i++) {
    const t = i / segments;
    const px = x1 + dx * t + (Math.random() - 0.5) * CONFIG.boltJagOffset * 2;
    const py = y1 + dy * t + (Math.random() - 0.5) * CONFIG.boltJagOffset * 0.5;
    points.push({ x: px, y: py });
  }
  points.push({ x: x2, y: y2 });

  // Generate forks
  const forks = [];
  if (depth < CONFIG.maxForkDepth) {
    for (let i = 2; i < points.length - 1; i++) {
      if (Math.random() < CONFIG.forkProbability) {
        const p = points[i];
        const remainLen = Math.sqrt(
          (x2 - p.x) ** 2 + (y2 - p.y) ** 2
        ) * CONFIG.forkLengthFactor;
        const angle = Math.atan2(y2 - y1, x2 - x1) + (Math.random() - 0.5) * 1.2;
        const fx = p.x + Math.cos(angle) * remainLen;
        const fy = p.y + Math.sin(angle) * remainLen;
        const forkSegs = Math.max(3, Math.floor(segments * 0.5));
        forks.push(generateBoltPath(p.x, p.y, fx, fy, forkSegs, depth + 1));
      }
    }
  }

  return { points, forks, depth };
}

function spawnBolt(x1, y1, x2, y2) {
  const path = generateBoltPath(
    x1 || Math.random() * width, y1 || 0,
    x2 || (x1 + (Math.random() - 0.5) * width * 0.4),
    y2 || height * (0.5 + Math.random() * 0.5),
    CONFIG.boltSegments, 0
  );
  bolts.push({ path, born: performance.now() });

  // Trigger flash
  flashAlpha = CONFIG.flashBrightness;
  flashStart = performance.now();
}

function drawBoltPath(boltPath, alpha) {
  const w = CONFIG.boltWidth * Math.pow(CONFIG.forkWidthDecay, boltPath.depth);

  // Glow
  ctx.save();
  ctx.strokeStyle = CONFIG.boltGlowColor;
  ctx.lineWidth = w + CONFIG.boltGlowWidth;
  ctx.globalAlpha = alpha * 0.5;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(boltPath.points[0].x, boltPath.points[0].y);
  for (let i = 1; i < boltPath.points.length; i++) {
    ctx.lineTo(boltPath.points[i].x, boltPath.points[i].y);
  }
  ctx.stroke();
  ctx.restore();

  // Core
  ctx.save();
  ctx.strokeStyle = CONFIG.boltColor;
  ctx.lineWidth = w;
  ctx.globalAlpha = alpha;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';
  ctx.beginPath();
  ctx.moveTo(boltPath.points[0].x, boltPath.points[0].y);
  for (let i = 1; i < boltPath.points.length; i++) {
    ctx.lineTo(boltPath.points[i].x, boltPath.points[i].y);
  }
  ctx.stroke();
  ctx.restore();

  // Inner bright core
  ctx.save();
  ctx.strokeStyle = 'rgba(255, 255, 255, 0.9)';
  ctx.lineWidth = Math.max(1, w * 0.35);
  ctx.globalAlpha = alpha * 0.8;
  ctx.lineCap = 'round';
  ctx.beginPath();
  ctx.moveTo(boltPath.points[0].x, boltPath.points[0].y);
  for (let i = 1; i < boltPath.points.length; i++) {
    ctx.lineTo(boltPath.points[i].x, boltPath.points[i].y);
  }
  ctx.stroke();
  ctx.restore();

  // Draw forks recursively
  for (const fork of boltPath.forks) {
    drawBoltPath(fork, alpha * 0.75);
  }
}

function startAnimation() {
  function render() {
    if (!ctx) return;
    const now = performance.now();

    ctx.clearRect(0, 0, width, height);

    // Rumble glow at bottom
    const rumbleGrad = ctx.createLinearGradient(0, height * (1 - CONFIG.rumbleGlowHeight), 0, height);
    rumbleGrad.addColorStop(0, 'transparent');
    rumbleGrad.addColorStop(1, CONFIG.rumbleGlowColor);
    ctx.fillStyle = rumbleGrad;
    ctx.fillRect(0, height * (1 - CONFIG.rumbleGlowHeight), width, height * CONFIG.rumbleGlowHeight);

    // Auto-spawn bolts
    if (now - lastBoltTime > nextBoltDelay) {
      const startX = Math.random() * width;
      spawnBolt(startX, 0, startX + (Math.random() - 0.5) * width * 0.3, height * (0.4 + Math.random() * 0.6));
      lastBoltTime = now;
      nextBoltDelay = CONFIG.boltFrequency + (Math.random() - 0.5) * 2 * CONFIG.boltFrequencyVariance;
    }

    // Draw active bolts
    for (let i = bolts.length - 1; i >= 0; i--) {
      const b = bolts[i];
      const age = now - b.born;
      if (age > CONFIG.boltLifetime) {
        bolts.splice(i, 1);
        continue;
      }
      const alpha = 1 - age / CONFIG.boltLifetime;
      drawBoltPath(b.path, alpha);
    }

    // Screen flash overlay
    if (flashAlpha > 0.001) {
      const elapsed = now - flashStart;
      const currentFlash = flashAlpha * Math.max(0, 1 - elapsed / CONFIG.flashDuration);
      if (currentFlash > 0.001) {
        ctx.save();
        ctx.globalAlpha = currentFlash;
        ctx.fillStyle = CONFIG.backgroundFlashColor;
        ctx.fillRect(0, 0, width, height);
        ctx.restore();
      } else {
        flashAlpha = 0;
      }
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Topographic Map
 * Description: Smooth, flowing topographic contour lines over a continuously
 *   evolving terrain. Bilinear-interpolated gradient fills and organic multi-axis
 *   time drift create a fluid, living map feel. Mouse creates a soft hill.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Contour Appearance --
  contourCount: 14,                // Number of contour elevation bands (4-30)
  contourOpacity: 0.55,            // Contour line opacity (0-1)
  contourWidth: 1.0,               // Contour line width in px (0.5-4)
  fillEnabled: true,               // Smooth gradient fill between contour bands
  fillOpacity: 0.18,               // Fill opacity (0-1)

  // -- Color Palette --
  colorPalette: [                  // Colors for elevation bands (low → high)
    '#0a2463', '#1e6091', '#168aad',
    '#34a0a4', '#52b69a', '#76c893',
    '#99d98c', '#b5e48c', '#d9ed92',
    '#f0f3bd', '#fefae0', '#faedcd',
    '#e6ccb2', '#ddb892'
  ],

  // -- Noise / Terrain --
  animationSpeed: 0.0006,          // Time evolution speed (0.0001-0.005)
  noiseScale: 0.0035,              // Spatial noise frequency (0.001-0.02)
  noiseOctaves: 4,                 // Noise detail layers (1-6)
  elevationRange: 1.0,             // Total elevation range scalar (0.5-2.0)

  // -- Sampling --
  gridStep: 6,                     // Grid cell size in px (4-10, higher=faster)

  // -- Mouse Interaction --
  mousePeakRadius: 200,            // Radius of mouse hill in px (50-400)
  mousePeakHeight: 0.4,            // Height of mouse hill (0-1)
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let cols, rows, grid;
let imageData, pixels;
let paletteRgb;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

// ── Permutation-table gradient noise ──
const PERM = new Uint8Array(512);
(function initPerm() {
  const p = new Uint8Array(256);
  for (let i = 0; i < 256; i++) p[i] = i;
  let seed = 42;
  for (let i = 255; i > 0; i--) {
    seed = (seed * 16807) % 2147483647;
    const j = seed % (i + 1);
    const tmp = p[i]; p[i] = p[j]; p[j] = tmp;
  }
  for (let i = 0; i < 512; i++) PERM[i] = p[i & 255];
})();

const GRAD_X = new Float32Array([1, -1, 1, -1, 1, 0, -1, 0]);
const GRAD_Y = new Float32Array([1, 1, -1, -1, 0, 1, 0, -1]);

function gradNoise(x, y) {
  const ix = Math.floor(x), iy = Math.floor(y);
  const fx = x - ix, fy = y - iy;
  const sx = fx * fx * fx * (fx * (fx * 6 - 15) + 10);
  const sy = fy * fy * fy * (fy * (fy * 6 - 15) + 10);
  const ixa = ix & 255, iya = iy & 255;

  const i00 = PERM[(PERM[ixa] + iya) & 511] & 7;
  const i10 = PERM[(PERM[(ixa + 1) & 255] + iya) & 511] & 7;
  const i01 = PERM[(PERM[ixa] + ((iya + 1) & 255)) & 511] & 7;
  const i11 = PERM[(PERM[(ixa + 1) & 255] + ((iya + 1) & 255)) & 511] & 7;

  const nx0 = (GRAD_X[i00] * fx + GRAD_Y[i00] * fy)
    + sx * ((GRAD_X[i10] * (fx - 1) + GRAD_Y[i10] * fy) - (GRAD_X[i00] * fx + GRAD_Y[i00] * fy));
  const nx1 = (GRAD_X[i01] * fx + GRAD_Y[i01] * (fy - 1))
    + sx * ((GRAD_X[i11] * (fx - 1) + GRAD_Y[i11] * (fy - 1)) - (GRAD_X[i01] * fx + GRAD_Y[i01] * (fy - 1)));
  return (nx0 + sy * (nx1 - nx0)) * 0.5 + 0.5;
}

function fbm(x, y, octaves) {
  let val = 0, amp = 0.5, freq = 1;
  for (let i = 0; i < octaves; i++) {
    val += amp * gradNoise(x * freq, y * freq);
    amp *= 0.5;
    freq *= 2.0;
  }
  return val;
}

function buildPalette() {
  paletteRgb = CONFIG.colorPalette.map(hex => ({
    r: parseInt(hex.slice(1, 3), 16),
    g: parseInt(hex.slice(3, 5), 16),
    b: parseInt(hex.slice(5, 7), 16),
  }));
}

function initGrid() {
  const step = CONFIG.gridStep;
  cols = Math.ceil(width / step) + 2;
  rows = Math.ceil(height / step) + 2;
  grid = new Float32Array(cols * rows);
  imageData = ctx.createImageData(width, height);
  pixels = imageData.data;
  buildPalette();
}

function sampleGrid() {
  const step = CONFIG.gridStep;
  const ns = CONFIG.noiseScale;
  const oct = CONFIG.noiseOctaves;
  const er = CONFIG.elevationRange;
  const mx = mouse.x, my = mouse.y;
  const mpr = CONFIG.mousePeakRadius;
  const mph = CONFIG.mousePeakHeight;
  const mpr2 = mpr * mpr;

  // Organic multi-axis drift — terrain flows, not just shifts
  const tx = time * 0.25;
  const ty = time * 0.18;
  const drift = Math.sin(time * 0.4) * 0.3;

  for (let r = 0; r < rows; r++) {
    const py = r * step;
    const rowOff = r * cols;
    for (let c = 0; c < cols; c++) {
      const px = c * step;
      let elev = fbm(px * ns + tx + drift, py * ns + ty - drift * 0.7, oct) * er;

      const dx = px - mx;
      const dy = py - my;
      const dist2 = dx * dx + dy * dy;
      if (dist2 < mpr2) {
        const f = 1 - Math.sqrt(dist2) / mpr;
        // Smooth cubic falloff instead of quadratic — softer hill
        elev += mph * f * f * (3 - 2 * f);
      }

      grid[rowOff + c] = elev;
    }
  }
}

// ── Bilinear interpolation of grid elevation at any pixel ──
function elevAt(px, py) {
  const step = CONFIG.gridStep;
  const gx = px / step;
  const gy = py / step;
  const c0 = gx | 0;
  const r0 = gy | 0;
  const c1 = Math.min(c0 + 1, cols - 1);
  const r1 = Math.min(r0 + 1, rows - 1);
  const fx = gx - c0;
  const fy = gy - r0;

  const tl = grid[r0 * cols + c0];
  const tr = grid[r0 * cols + c1];
  const bl = grid[r1 * cols + c0];
  const br = grid[r1 * cols + c1];

  return tl + (tr - tl) * fx + (bl - tl) * fy + (tl - tr - bl + br) * fx * fy;
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initGrid();
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      initGrid();
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

function startAnimation() {
  // Precompute a smooth 256-entry color LUT from the palette
  const LUT_R = new Uint8Array(256);
  const LUT_G = new Uint8Array(256);
  const LUT_B = new Uint8Array(256);

  function rebuildLUT() {
    const pal = paletteRgb;
    const n = pal.length;
    for (let i = 0; i < 256; i++) {
      const t = i / 255 * (n - 1);
      const lo = Math.floor(t);
      const hi = Math.min(lo + 1, n - 1);
      const f = t - lo;
      LUT_R[i] = pal[lo].r + (pal[hi].r - pal[lo].r) * f;
      LUT_G[i] = pal[lo].g + (pal[hi].g - pal[lo].g) * f;
      LUT_B[i] = pal[lo].b + (pal[hi].b - pal[lo].b) * f;
    }
  }
  rebuildLUT();

  // Fill sub-sampling: render every Nth pixel for speed, interpolate the rest
  const FILL_STEP = 2;

  function render() {
    if (!ctx) return;
    time += CONFIG.animationSpeed;

    sampleGrid();

    // ── Find min/max ──
    let minE = Infinity, maxE = -Infinity;
    const len = cols * rows;
    for (let i = 0; i < len; i++) {
      const v = grid[i];
      if (v < minE) minE = v;
      if (v > maxE) maxE = v;
    }
    const range = maxE - minE || 1;
    const invRange = 255 / range;
    const step = CONFIG.gridStep;
    const levels = CONFIG.contourCount;

    // ── Smooth gradient fill via bilinear interpolation + color LUT ──
    if (CONFIG.fillEnabled) {
      const fillAlpha = Math.round(CONFIG.fillOpacity * 255);
      const w = width, h = height;

      // Sample every FILL_STEP pixel, write FILL_STEP×FILL_STEP blocks
      for (let y = 0; y < h; y += FILL_STEP) {
        const rowOff = y * w;
        for (let x = 0; x < w; x += FILL_STEP) {
          const elev = elevAt(x, y);
          const ci = Math.max(0, Math.min(255, ((elev - minE) * invRange) | 0));
          const cr = LUT_R[ci], cg = LUT_G[ci], cb = LUT_B[ci];

          // Fill the FILL_STEP×FILL_STEP block
          const xEnd = Math.min(x + FILL_STEP, w);
          const yEnd = Math.min(y + FILL_STEP, h);
          for (let py = y; py < yEnd; py++) {
            const pRowOff = py * w;
            for (let px = x; px < xEnd; px++) {
              const idx = (pRowOff + px) << 2;
              pixels[idx] = cr;
              pixels[idx + 1] = cg;
              pixels[idx + 2] = cb;
              pixels[idx + 3] = fillAlpha;
            }
          }
        }
      }
      ctx.putImageData(imageData, 0, 0);
    } else {
      ctx.clearRect(0, 0, width, height);
    }

    // ── Contour lines ──
    for (let l = 0; l < levels; l++) {
      const threshold = minE + (l + 1) * range / (levels + 1);
      const ci = Math.max(0, Math.min(255, (((l + 1) / (levels + 1)) * 255) | 0));

      ctx.strokeStyle = `rgba(${LUT_R[ci]},${LUT_G[ci]},${LUT_B[ci]},${CONFIG.contourOpacity})`;
      ctx.lineWidth = CONFIG.contourWidth;
      ctx.beginPath();

      for (let r = 0; r < rows - 2; r++) {
        const rowOff = r * cols;
        const nextRowOff = (r + 1) * cols;
        const y = r * step;

        for (let c = 0; c < cols - 2; c++) {
          const tl = grid[rowOff + c];
          const tr = grid[rowOff + c + 1];
          const bl = grid[nextRowOff + c];
          const br = grid[nextRowOff + c + 1];
          const x = c * step;

          const dTL = tl - threshold;
          const dTR = tr - threshold;
          const dBL = bl - threshold;
          const dBR = br - threshold;

          let n = 0;
          let e0x, e0y, e1x, e1y, e2x, e2y, e3x, e3y;

          if (dTL * dTR < 0) {
            const t = dTL / (dTL - dTR);
            if (n === 0) { e0x = x + t * step; e0y = y; }
            else if (n === 1) { e1x = x + t * step; e1y = y; }
            else if (n === 2) { e2x = x + t * step; e2y = y; }
            else { e3x = x + t * step; e3y = y; }
            n++;
          }
          if (dTR * dBR < 0) {
            const t = dTR / (dTR - dBR);
            if (n === 0) { e0x = x + step; e0y = y + t * step; }
            else if (n === 1) { e1x = x + step; e1y = y + t * step; }
            else if (n === 2) { e2x = x + step; e2y = y + t * step; }
            else { e3x = x + step; e3y = y + t * step; }
            n++;
          }
          if (dBL * dBR < 0) {
            const t = dBL / (dBL - dBR);
            if (n === 0) { e0x = x + t * step; e0y = y + step; }
            else if (n === 1) { e1x = x + t * step; e1y = y + step; }
            else if (n === 2) { e2x = x + t * step; e2y = y + step; }
            else { e3x = x + t * step; e3y = y + step; }
            n++;
          }
          if (dTL * dBL < 0) {
            const t = dTL / (dTL - dBL);
            if (n === 0) { e0x = x; e0y = y + t * step; }
            else if (n === 1) { e1x = x; e1y = y + t * step; }
            else if (n === 2) { e2x = x; e2y = y + t * step; }
            else { e3x = x; e3y = y + t * step; }
            n++;
          }

          if (n >= 2) {
            ctx.moveTo(e0x, e0y);
            ctx.lineTo(e1x, e1y);
            if (n === 4) {
              ctx.moveTo(e2x, e2y);
              ctx.lineTo(e3x, e3y);
            }
          }
        }
      }
      ctx.stroke();
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

/**
 * Title: Touch Garden
 * Description: An interactive garden where you plant flowers by tapping!
 *   Each click/tap plants a flower that grows from a seed. Drag your finger
 *   or mouse to scatter seed particles. Multi-touch plants multiple flowers
 *   at once. Flowers sway gently in the breeze and butterflies occasionally
 *   flutter between them. Perfect for little ones who love to click!
 *
 *   Showcases: click, touchstart, touchmove, mousemove, mousedown, mouseup
 */

/* ---------- CONFIGURABLE VARIABLES ---------- */
const MAX_FLOWERS         = 30;       // max flowers on screen
const GROW_SPEED          = 0.008;    // how fast flowers grow (0-1)
const BREEZE_STRENGTH     = 0.02;     // sway amount
const SEED_PARTICLE_COUNT = 5;        // particles per drag frame
const BUTTERFLY_COUNT     = 4;        // ambient butterflies
const GROUND_Y_RATIO      = 0.85;    // ground position (% of height)
/* --------------------------------------------- */

let canvas, ctx, w, h;
let mouse = { x: -9999, y: -9999 };
let flowers = [];
let seedParticles = [];
let butterflies = [];
let isDragging = false;
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

const PETAL_COLORS = [
	{ h: 340, s: 80, l: 65 }, // pink
	{ h: 270, s: 70, l: 65 }, // purple
	{ h: 45,  s: 90, l: 60 }, // golden
	{ h: 10,  s: 80, l: 60 }, // red-orange
	{ h: 200, s: 70, l: 60 }, // blue
	{ h: 320, s: 75, l: 70 }, // magenta
	{ h: 30,  s: 85, l: 55 }, // orange
	{ h: 170, s: 60, l: 50 }, // teal
];

function createFlower(x, y) {
	const groundY = h * GROUND_Y_RATIO;
	const plantY = Math.max(y, groundY - 20); // plant at ground level or where clicked
	const color = PETAL_COLORS[Math.floor(Math.random() * PETAL_COLORS.length)];

	if (flowers.length >= MAX_FLOWERS) {
		flowers.shift(); // remove oldest
	}

	flowers.push({
		x,
		y: Math.min(plantY, groundY),
		growth: 0,
		maxHeight: 40 + Math.random() * 80,
		stemWidth: 2 + Math.random() * 2,
		petalCount: 5 + Math.floor(Math.random() * 4),
		petalSize: 6 + Math.random() * 10,
		color,
		phase: Math.random() * Math.PI * 2,
		swayOffset: (Math.random() - 0.5) * 0.5
	});
}

function createSeedParticles(x, y) {
	for (let i = 0; i < SEED_PARTICLE_COUNT; i++) {
		seedParticles.push({
			x: x + (Math.random() - 0.5) * 20,
			y: y + (Math.random() - 0.5) * 20,
			vx: (Math.random() - 0.5) * 2,
			vy: -1 - Math.random() * 2,
			size: 1.5 + Math.random() * 2,
			alpha: 0.8,
			hue: 80 + Math.random() * 40 // green-yellow
		});
	}
}

function initButterflies() {
	butterflies = [];
	for (let i = 0; i < BUTTERFLY_COUNT; i++) {
		butterflies.push({
			x: Math.random() * w,
			y: h * 0.3 + Math.random() * h * 0.4,
			vx: (Math.random() - 0.5) * 1.5,
			vy: (Math.random() - 0.5) * 0.5,
			wingPhase: Math.random() * Math.PI * 2,
			wingSpeed: 0.1 + Math.random() * 0.1,
			hue: Math.random() * 360,
			size: 4 + Math.random() * 4,
			targetX: Math.random() * w,
			targetY: h * 0.3 + Math.random() * h * 0.3,
			changeTimer: Math.floor(Math.random() * 200)
		});
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initButterflies();
			animate();
			break;
		case 'resize':
			w = e.data.width;
			h = e.data.height;
			canvas.width = w;
			canvas.height = h;
			initButterflies();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			if (isDragging) {
				createSeedParticles(e.data.x, e.data.y);
			}
			break;
		case 'click':
			createFlower(e.data.x, e.data.y);
			break;
		case 'mousedown':
			isDragging = true;
			break;
		case 'mouseup':
			isDragging = false;
			break;
		case 'touchstart':
			// Plant a flower at each touch point
			if (e.data.touches) {
				for (const t of e.data.touches) {
					createFlower(t.x, t.y);
				}
			}
			break;
		case 'touchmove':
			// Scatter seeds at each moving finger
			if (e.data.touches) {
				for (const t of e.data.touches) {
					createSeedParticles(t.x, t.y);
				}
			}
			break;
	}
};

function drawGround() {
	const groundY = h * GROUND_Y_RATIO;
	const gGrad = ctx.createLinearGradient(0, groundY - 10, 0, h);
	gGrad.addColorStop(0, '#2a5a1e');
	gGrad.addColorStop(0.15, '#1e4515');
	gGrad.addColorStop(1, '#0a1a05');
	ctx.fillStyle = gGrad;
	ctx.fillRect(0, groundY - 5, w, h - groundY + 5);

	// Grass tufts
	ctx.strokeStyle = 'rgba(60, 120, 40, 0.3)';
	ctx.lineWidth = 1;
	for (let i = 0; i < 40; i++) {
		const gx = (i / 40) * w + Math.sin(i * 7.3) * 20;
		const gy = groundY;
		const sway = Math.sin(time * 0.02 + i) * 3;
		ctx.beginPath();
		ctx.moveTo(gx, gy);
		ctx.quadraticCurveTo(gx + sway, gy - 8 - Math.random() * 6, gx + sway * 1.5, gy - 12 - Math.random() * 8);
		ctx.stroke();
	}
}

function drawFlower(f) {
	const growth = Math.min(1, f.growth);
	if (growth <= 0) return;

	const sway = Math.sin(time * BREEZE_STRENGTH + f.phase + f.swayOffset) * 5 * growth;
	const stemH = f.maxHeight * growth;
	const topX = f.x + sway;
	const topY = f.y - stemH;

	// Stem
	ctx.beginPath();
	ctx.moveTo(f.x, f.y);
	ctx.quadraticCurveTo(f.x + sway * 0.5, f.y - stemH * 0.5, topX, topY);
	ctx.strokeStyle = `hsl(120, 40%, ${25 + growth * 15}%)`;
	ctx.lineWidth = f.stemWidth * growth;
	ctx.lineCap = 'round';
	ctx.stroke();

	// Leaves
	if (growth > 0.3) {
		const leafP = Math.min(1, (growth - 0.3) / 0.4);
		const leafY = f.y - stemH * 0.4;
		const leafX = f.x + sway * 0.3;
		const leafSize = 8 * leafP;

		ctx.fillStyle = 'hsl(110, 50%, 35%)';
		ctx.beginPath();
		ctx.ellipse(leafX - leafSize, leafY, leafSize, leafSize * 0.4, -0.4, 0, Math.PI * 2);
		ctx.fill();
		ctx.beginPath();
		ctx.ellipse(leafX + leafSize, leafY - 5, leafSize * 0.8, leafSize * 0.35, 0.4, 0, Math.PI * 2);
		ctx.fill();
	}

	// Petals
	if (growth > 0.5) {
		const petalP = Math.min(1, (growth - 0.5) / 0.4);
		const pr = f.petalSize * petalP;

		for (let i = 0; i < f.petalCount; i++) {
			const angle = (i / f.petalCount) * Math.PI * 2 + Math.sin(time * 0.01 + f.phase) * 0.05;
			const px = topX + Math.cos(angle) * pr;
			const py = topY + Math.sin(angle) * pr;

			ctx.beginPath();
			ctx.ellipse(px, py, pr * 0.6, pr * 0.35, angle, 0, Math.PI * 2);
			ctx.fillStyle = `hsla(${f.color.h}, ${f.color.s}%, ${f.color.l}%, ${0.85 * petalP})`;
			ctx.fill();
		}

		// Center
		ctx.beginPath();
		ctx.arc(topX, topY, pr * 0.3 * petalP, 0, Math.PI * 2);
		ctx.fillStyle = `hsla(45, 90%, 55%, ${petalP})`;
		ctx.fill();
	}

	// Sprouting animation (tiny seed poking out)
	if (growth < 0.15) {
		const sproutP = growth / 0.15;
		ctx.fillStyle = '#4a8a30';
		ctx.beginPath();
		ctx.arc(f.x, f.y - 3 * sproutP, 2, 0, Math.PI * 2);
		ctx.fill();
	}
}

function drawButterfly(b) {
	const wingAngle = Math.sin(time * b.wingSpeed + b.wingPhase) * 0.8;
	const size = b.size;

	ctx.save();
	ctx.translate(b.x, b.y);

	// Body
	ctx.fillStyle = `hsl(${b.hue}, 30%, 25%)`;
	ctx.beginPath();
	ctx.ellipse(0, 0, 1.5, size * 0.5, 0, 0, Math.PI * 2);
	ctx.fill();

	// Wings
	ctx.fillStyle = `hsla(${b.hue}, 80%, 65%, 0.7)`;

	// Left wing
	ctx.save();
	ctx.scale(Math.cos(wingAngle), 1);
	ctx.beginPath();
	ctx.ellipse(-size * 0.5, -size * 0.2, size, size * 0.6, -0.2, 0, Math.PI * 2);
	ctx.fill();
	ctx.restore();

	// Right wing
	ctx.save();
	ctx.scale(Math.cos(wingAngle + 0.3), 1);
	ctx.beginPath();
	ctx.ellipse(size * 0.5, -size * 0.2, size, size * 0.6, 0.2, 0, Math.PI * 2);
	ctx.fill();
	ctx.restore();

	ctx.restore();
}

function updateButterflies() {
	for (const b of butterflies) {
		b.changeTimer--;
		if (b.changeTimer <= 0) {
			// Pick a new target — maybe near a flower
			if (flowers.length > 0 && Math.random() > 0.3) {
				const f = flowers[Math.floor(Math.random() * flowers.length)];
				b.targetX = f.x + (Math.random() - 0.5) * 60;
				b.targetY = f.y - f.maxHeight * f.growth + (Math.random() - 0.5) * 30;
			} else {
				b.targetX = Math.random() * w;
				b.targetY = h * 0.2 + Math.random() * h * 0.4;
			}
			b.changeTimer = 100 + Math.floor(Math.random() * 200);
		}

		// Move toward target
		const dx = b.targetX - b.x;
		const dy = b.targetY - b.y;
		b.vx += dx * 0.002;
		b.vy += dy * 0.002;
		b.vx *= 0.95;
		b.vy *= 0.95;
		b.x += b.vx;
		b.y += b.vy;

		// Wrap
		if (b.x < -20) b.x = w + 20;
		if (b.x > w + 20) b.x = -20;

		drawButterfly(b);
	}
}

function updateSeedParticles() {
	for (let i = seedParticles.length - 1; i >= 0; i--) {
		const p = seedParticles[i];
		p.x += p.vx;
		p.y += p.vy;
		p.vy += 0.05; // gravity
		p.alpha -= 0.015;

		if (p.alpha <= 0) {
			// When a seed particle lands, sometimes plant a flower
			if (p.y >= h * GROUND_Y_RATIO && Math.random() > 0.85) {
				createFlower(p.x, p.y);
			}
			seedParticles.splice(i, 1);
			continue;
		}

		ctx.fillStyle = `hsla(${p.hue}, 70%, 60%, ${p.alpha})`;
		ctx.beginPath();
		ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
		ctx.fill();
	}
}

function animate() {
	if (!ctx) return;
	time++;

	// Background sky
	const skyGrad = ctx.createLinearGradient(0, 0, 0, h);
	skyGrad.addColorStop(0, '#0a1628');
	skyGrad.addColorStop(0.5, '#162a45');
	skyGrad.addColorStop(0.8, '#1a3520');
	skyGrad.addColorStop(1, '#0a1a05');
	ctx.fillStyle = skyGrad;
	ctx.fillRect(0, 0, w, h);

	// Stars
	ctx.fillStyle = 'rgba(255, 255, 240, 0.5)';
	for (let i = 0; i < 30; i++) {
		const sx = ((i * 137.508) % w);
		const sy = ((i * 89.3) % (h * 0.5));
		const twinkle = 0.3 + 0.7 * Math.sin(time * 0.02 + i * 2.5);
		ctx.globalAlpha = twinkle * 0.4;
		ctx.beginPath();
		ctx.arc(sx, sy, 0.8, 0, Math.PI * 2);
		ctx.fill();
	}
	ctx.globalAlpha = 1;

	// Moon
	const moonGrad = ctx.createRadialGradient(w * 0.8, h * 0.12, 0, w * 0.8, h * 0.12, 30);
	moonGrad.addColorStop(0, 'rgba(255, 250, 220, 0.9)');
	moonGrad.addColorStop(0.7, 'rgba(255, 250, 220, 0.2)');
	moonGrad.addColorStop(1, 'rgba(255, 250, 220, 0)');
	ctx.fillStyle = moonGrad;
	ctx.beginPath();
	ctx.arc(w * 0.8, h * 0.12, 30, 0, Math.PI * 2);
	ctx.fill();

	// Ground
	drawGround();

	// Grow flowers
	for (const f of flowers) {
		if (f.growth < 1) f.growth += GROW_SPEED;
		drawFlower(f);
	}

	// Butterflies
	updateButterflies();

	// Seed particles
	updateSeedParticles();

	// Hint text
	if (flowers.length === 0 && seedParticles.length === 0) {
		ctx.fillStyle = 'rgba(255, 255, 255, 0.08)';
		ctx.font = '14px sans-serif';
		ctx.textAlign = 'center';
		ctx.fillText('Tap anywhere to plant a flower \uD83C\uDF3B', w / 2, h / 2);
		ctx.textAlign = 'left';
	}

	requestAnimationFrame(animate);
}

/**
 * Title: VHS Static
 * Description: Authentic VHS tracking effect with rolling tracking bars, random static
 *   noise, horizontal jitter, chromatic aberration, scanlines, and mouse-proximity
 *   distortion amplification.
 */

// ═══════════════════════════════════════════════════════════
// ██  CONFIGURATION — Tweak these values to customize!   ██
// ═══════════════════════════════════════════════════════════
const CONFIG = {
  // -- Static Noise --
  staticDensity: 0.03,                    // Fraction of pixels that get static (0-1)
  staticColor: 'rgba(255, 255, 255, 0.1)', // Base static noise color
  noiseGrainSize: 2,                      // Size of noise grain pixels
  noiseOpacity: 0.08,                     // Overall noise layer opacity (0-1)

  // -- Tracking Bars --
  trackingBarHeight: 30,                  // Height of rolling tracking bar in px
  trackingBarSpeed: 1.5,                  // Scroll speed of tracking bar (px/frame)
  trackingBarOpacity: 0.15,              // Tracking bar opacity (0-1)
  trackingBarColor: 'rgba(255, 255, 255, 0.2)', // Tracking bar fill color

  // -- Distortion --
  colorBleedAmount: 3,                    // Chromatic aberration offset in px
  horizontalJitter: 2,                    // Max horizontal shift in px

  // -- Scanlines --
  scanlineEnabled: true,                  // Show CRT-style scanlines
  scanlineSpacing: 3,                     // Pixels between scanlines

  // -- Overall --
  overallIntensity: 0.7,                  // Master intensity multiplier (0-1)

  // -- Mouse --
  mouseDistortRadius: 200,               // Mouse influence radius for distortion boost
};
// ═══════════════════════════════════════════════════════════

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let trackingY = 0;
let time = 0;

setInterval(() => { self.postMessage({ type: 'heartbeat' }); }, 1000);

function startAnimation() {
  function render() {
    if (!ctx) return;
    time += 0.016;
    ctx.clearRect(0, 0, width, height);

    const intensity = CONFIG.overallIntensity;

    // -- Tracking bar --
    trackingY = (trackingY + CONFIG.trackingBarSpeed) % (height + CONFIG.trackingBarHeight * 2);
    const barY = trackingY - CONFIG.trackingBarHeight;

    ctx.fillStyle = CONFIG.trackingBarColor;
    ctx.globalAlpha = CONFIG.trackingBarOpacity * intensity;
    ctx.fillRect(0, barY, width, CONFIG.trackingBarHeight);

    // Bright edge lines on tracking bar
    ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
    ctx.globalAlpha = CONFIG.trackingBarOpacity * intensity * 0.8;
    ctx.fillRect(0, barY, width, 1);
    ctx.fillRect(0, barY + CONFIG.trackingBarHeight - 1, width, 1);
    ctx.globalAlpha = 1;

    // -- Horizontal jitter near tracking bar --
    const jitterZone = CONFIG.trackingBarHeight * 3;
    for (let y = Math.max(0, barY - jitterZone); y < Math.min(height, barY + CONFIG.trackingBarHeight + jitterZone); y += 2) {
      const distToBar = Math.abs(y - (barY + CONFIG.trackingBarHeight / 2));
      const jitterAmount = Math.max(0, 1 - distToBar / jitterZone);
      if (jitterAmount > 0.1) {
        const shift = (Math.random() - 0.5) * CONFIG.horizontalJitter * jitterAmount * intensity * 4;
        if (Math.abs(shift) > 0.5) {
          ctx.globalAlpha = 0.05 * intensity;
          ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
          ctx.fillRect(shift > 0 ? 0 : width + shift, y, Math.abs(shift), 2);
          ctx.globalAlpha = 1;
        }
      }
    }

    // -- Chromatic aberration / color bleed --
    if (CONFIG.colorBleedAmount > 0) {
      const bleed = CONFIG.colorBleedAmount * intensity;
      // Red channel shift
      ctx.globalAlpha = 0.02 * intensity;
      ctx.fillStyle = 'rgba(255, 0, 0, 0.5)';
      for (let y = 0; y < height; y += 8) {
        if (Math.random() < 0.3) {
          const shift = (Math.random() - 0.5) * bleed * 2;
          ctx.fillRect(shift, y, width, 1);
        }
      }
      // Cyan channel shift
      ctx.fillStyle = 'rgba(0, 255, 255, 0.5)';
      for (let y = 0; y < height; y += 8) {
        if (Math.random() < 0.3) {
          const shift = (Math.random() - 0.5) * bleed * 2;
          ctx.fillRect(-shift, y, width, 1);
        }
      }
      ctx.globalAlpha = 1;
    }

    // -- Static noise --
    const grainSize = CONFIG.noiseGrainSize;
    const cols = Math.ceil(width / grainSize);
    const rows = Math.ceil(height / grainSize);
    const totalPixels = cols * rows;
    const staticCount = Math.floor(totalPixels * CONFIG.staticDensity * intensity);

    ctx.globalAlpha = CONFIG.noiseOpacity * intensity;
    for (let i = 0; i < staticCount; i++) {
      const x = Math.floor(Math.random() * cols) * grainSize;
      const y = Math.floor(Math.random() * rows) * grainSize;
      const brightness = Math.floor(Math.random() * 200 + 55);
      ctx.fillStyle = `rgba(${brightness}, ${brightness}, ${brightness}, 0.6)`;
      ctx.fillRect(x, y, grainSize, grainSize);
    }
    ctx.globalAlpha = 1;

    // -- Mouse proximity distortion --
    if (mouse.x > 0 && mouse.y > 0) {
      const mRadius = CONFIG.mouseDistortRadius;
      // Extra noise burst near mouse
      ctx.globalAlpha = 0.06 * intensity;
      for (let i = 0; i < 40; i++) {
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.random() * mRadius;
        const px = mouse.x + Math.cos(angle) * dist;
        const py = mouse.y + Math.sin(angle) * dist;
        const falloff = 1 - dist / mRadius;
        const brightness = Math.floor(Math.random() * 255);
        ctx.fillStyle = `rgba(${brightness}, ${brightness}, ${brightness}, ${falloff * 0.5})`;
        ctx.fillRect(px, py, grainSize * 2, grainSize);
      }
      ctx.globalAlpha = 1;

      // Horizontal tear near mouse
      const tearCount = 3;
      for (let i = 0; i < tearCount; i++) {
        const tearY = mouse.y + (Math.random() - 0.5) * mRadius * 0.6;
        if (tearY > 0 && tearY < height) {
          const tearShift = (Math.random() - 0.5) * CONFIG.horizontalJitter * 6 * intensity;
          ctx.globalAlpha = 0.04 * intensity;
          ctx.fillStyle = 'rgba(255, 255, 255, 0.4)';
          ctx.fillRect(tearShift, tearY, width, 1);
          ctx.globalAlpha = 1;
        }
      }
    }

    // -- Scanlines --
    if (CONFIG.scanlineEnabled) {
      ctx.fillStyle = 'rgba(0, 0, 0, 0.08)';
      ctx.globalAlpha = intensity * 0.5;
      for (let y = 0; y < height; y += CONFIG.scanlineSpacing) {
        ctx.fillRect(0, y, width, 1);
      }
      ctx.globalAlpha = 1;
    }

    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);
}

self.onmessage = (e) => {
  switch (e.data.type) {
    case 'init':
      canvas = e.data.canvas;
      ctx = canvas.getContext('2d');
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      startAnimation();
      break;
    case 'resize':
      width = e.data.width;
      height = e.data.height;
      canvas.width = width;
      canvas.height = height;
      break;
    case 'mousemove':
      mouse.x = e.data.x;
      mouse.y = e.data.y;
      break;
  }
};

/**
 * Title: Voronoi Cells
 * Description: Animated Voronoi diagram where seed points drift slowly. Cell edges
 * are drawn with subtle glowing lines. Mouse acts as an additional seed point.
 * Colors use very subtle edge highlights against a transparent background.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let seeds = [];
let lastTime = 0;

const NUM_SEEDS = 30;
const EDGE_RESOLUTION = 4; // pixel step for edge detection (higher = faster, coarser)

// Keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initSeeds();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function initSeeds() {
	seeds = [];
	for (let i = 0; i < NUM_SEEDS; i++) {
		seeds.push({
			x: Math.random() * width,
			y: Math.random() * height,
			vx: (Math.random() - 0.5) * 20,
			vy: (Math.random() - 0.5) * 20,
			hue: 200 + Math.random() * 40 // subtle blue range
		});
	}
}

/** Find the index of the closest seed to point (px, py) */
function closestSeed(px, py, allSeeds) {
	let minDist = Infinity;
	let minIdx = 0;
	for (let i = 0; i < allSeeds.length; i++) {
		const dx = px - allSeeds[i].x;
		const dy = py - allSeeds[i].y;
		const d = dx * dx + dy * dy;
		if (d < minDist) {
			minDist = d;
			minIdx = i;
		}
	}
	return minIdx;
}

/**
 * Find Voronoi edges by scanning pixels and detecting where the nearest seed changes.
 * Returns an array of edge pixel positions.
 */
function findEdges(allSeeds) {
	const edges = [];
	const step = EDGE_RESOLUTION;
	const cols = Math.ceil(width / step);
	const rows = Math.ceil(height / step);

	// Build a grid of nearest-seed indices
	const grid = new Int16Array(cols * rows);
	for (let gy = 0; gy < rows; gy++) {
		for (let gx = 0; gx < cols; gx++) {
			const px = gx * step + step / 2;
			const py = gy * step + step / 2;
			grid[gy * cols + gx] = closestSeed(px, py, allSeeds);
		}
	}

	// Detect edges — pixels where neighbor has a different nearest seed
	for (let gy = 0; gy < rows; gy++) {
		for (let gx = 0; gx < cols; gx++) {
			const idx = grid[gy * cols + gx];
			let isEdge = false;

			// Check right neighbor
			if (gx < cols - 1 && grid[gy * cols + gx + 1] !== idx) isEdge = true;
			// Check bottom neighbor
			if (!isEdge && gy < rows - 1 && grid[(gy + 1) * cols + gx] !== idx) isEdge = true;
			// Check diagonal
			if (!isEdge && gx < cols - 1 && gy < rows - 1 && grid[(gy + 1) * cols + gx + 1] !== idx)
				isEdge = true;

			if (isEdge) {
				edges.push({
					x: gx * step + step / 2,
					y: gy * step + step / 2,
					seedIdx: idx
				});
			}
		}
	}

	return edges;
}

function startAnimation() {
	lastTime = performance.now() / 1000;

	function render() {
		if (!ctx) return;

		const now = performance.now() / 1000;
		const dt = Math.min(now - lastTime, 0.05);
		lastTime = now;

		ctx.clearRect(0, 0, width, height);

		// Update seed positions
		for (const seed of seeds) {
			seed.x += seed.vx * dt;
			seed.y += seed.vy * dt;

			// Bounce off edges
			if (seed.x < 0 || seed.x > width) {
				seed.vx *= -1;
				seed.x = Math.max(0, Math.min(width, seed.x));
			}
			if (seed.y < 0 || seed.y > height) {
				seed.vy *= -1;
				seed.y = Math.max(0, Math.min(height, seed.y));
			}
		}

		// Build active seed list (including mouse as extra seed)
		const allSeeds = [...seeds];
		const mouseActive = mouse.x > 0 && mouse.x < width && mouse.y > 0 && mouse.y < height;
		if (mouseActive) {
			allSeeds.push({ x: mouse.x, y: mouse.y, hue: 50 });
		}

		// Find and draw edges
		const edges = findEdges(allSeeds);

		for (const edge of edges) {
			const seed = allSeeds[edge.seedIdx];
			const dist = Math.hypot(edge.x - seed.x, edge.y - seed.y);
			const maxDist = Math.min(width, height) * 0.3;

			// Brightness based on distance from seed (closer to seed center = dimmer edge)
			const brightness = Math.min(1, dist / maxDist);

			// Mouse proximity makes edges brighter
			let mouseGlow = 0;
			if (mouseActive) {
				const md = Math.hypot(edge.x - mouse.x, edge.y - mouse.y);
				if (md < 200) {
					mouseGlow = (1 - md / 200) * 0.15;
				}
			}

			const alpha = 0.06 * brightness + mouseGlow;
			const size = EDGE_RESOLUTION * 0.9;

			ctx.fillStyle = `rgba(160, 200, 255, ${alpha})`;
			ctx.fillRect(edge.x - size / 2, edge.y - size / 2, size, size);
		}

		// Draw subtle seed points
		for (let i = 0; i < allSeeds.length; i++) {
			const seed = allSeeds[i];
			const isMouseSeed = mouseActive && i === allSeeds.length - 1;
			const alpha = isMouseSeed ? 0.2 : 0.08;
			const radius = isMouseSeed ? 3 : 1.5;

			ctx.beginPath();
			ctx.arc(seed.x, seed.y, radius, 0, Math.PI * 2);
			ctx.fillStyle = `rgba(180, 210, 255, ${alpha})`;
			ctx.fill();
		}

		requestAnimationFrame(render);
	}

	requestAnimationFrame(render);
}

/**
 * Title: Wave Interference
 * Description: Multiple circular wave sources creating beautiful constructive
 *   and destructive interference patterns. Waves emanate from fixed points and
 *   the mouse position. Subtle monochrome/blue tones.
 */

let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let time = 0;
let sources = [];
let imageData;

const NUM_FIXED_SOURCES = 4;
const WAVE_SPEED = 0.04;
const WAVELENGTH = 30;
const PIXEL_STEP = 3; // render every Nth pixel for performance
const DECAY = 0.003; // wave amplitude decay with distance

// Heartbeat to keep worker alive
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

class WaveSource {
	constructor(x, y, frequency, amplitude, phase) {
		this.x = x;
		this.y = y;
		this.frequency = frequency;
		this.amplitude = amplitude;
		this.phase = phase;
		this.isFixed = true;
	}
}

function initSources() {
	sources = [];
	// Place fixed sources at interesting positions
	const positions = [
		{ x: width * 0.2, y: height * 0.3 },
		{ x: width * 0.8, y: height * 0.25 },
		{ x: width * 0.3, y: height * 0.75 },
		{ x: width * 0.75, y: height * 0.7 }
	];

	for (let i = 0; i < NUM_FIXED_SOURCES; i++) {
		const pos = positions[i] || {
			x: Math.random() * width,
			y: Math.random() * height
		};
		sources.push(
			new WaveSource(
				pos.x,
				pos.y,
				0.8 + Math.random() * 0.4, // slight frequency variation
				1.0,
				Math.random() * Math.PI * 2
			)
		);
	}
}

self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initSources();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initSources();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};

function startAnimation() {
	function render() {
		if (!ctx) return;

		time += WAVE_SPEED;
		imageData = ctx.createImageData(width, height);
		const data = imageData.data;

		// Build active source list (fixed + mouse)
		const activeSources = [...sources];
		if (mouse.x > 0 && mouse.y > 0) {
			activeSources.push(new WaveSource(mouse.x, mouse.y, 1.2, 1.5, 0));
		}

		// Calculate wave interference at each pixel
		for (let y = 0; y < height; y += PIXEL_STEP) {
			for (let x = 0; x < width; x += PIXEL_STEP) {
				let totalAmplitude = 0;

				for (const source of activeSources) {
					const dx = x - source.x;
					const dy = y - source.y;
					const dist = Math.sqrt(dx * dx + dy * dy);

					// Wave equation: A * sin(k*r - ω*t + φ) / (1 + decay*r)
					const k = (2 * Math.PI) / WAVELENGTH;
					const wave =
						(source.amplitude * Math.sin(k * dist * source.frequency - time + source.phase)) /
						(1 + DECAY * dist);

					totalAmplitude += wave;
				}

				// Map amplitude to color — blue/cyan monochrome palette
				// Normalize roughly to [-1, 1] range
				const normalized = totalAmplitude / activeSources.length;

				// Color mapping: constructive → bright blue, destructive → dark
				const brightness = (normalized + 1) * 0.5; // 0 to 1
				const b1 = brightness * brightness; // enhance contrast

				// Subtle blue-cyan palette
				const r = Math.floor(b1 * 30);
				const g = Math.floor(b1 * 80 + brightness * 20);
				const b = Math.floor(b1 * 180 + brightness * 40);
				const a = Math.floor(40 + b1 * 60); // subtle alpha

				// Fill the pixel block
				for (let dy = 0; dy < PIXEL_STEP && y + dy < height; dy++) {
					for (let dx = 0; dx < PIXEL_STEP && x + dx < width; dx++) {
						const idx = ((y + dy) * width + (x + dx)) * 4;
						data[idx] = r;
						data[idx + 1] = g;
						data[idx + 2] = b;
						data[idx + 3] = a;
					}
				}
			}
		}

		ctx.putImageData(imageData, 0, 0);
		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/**
 * Title: Wireframe City
 * Description: A procedurally generated wireframe cityscape rendered in slight
 *   perspective view. Buildings pulse with flickering windows, flying light
 *   streaks arc between structures, and a radar-like scanning beam sweeps
 *   across the scene. Depth fog fades distant buildings. Mouse acts as a
 *   spotlight and scan-beam origin. Uses typed arrays, spatial bucketing,
 *   delta-time animation, off-screen culling, and batched draw calls.
 */

/* ───────────────────── CONFIG ───────────────────── */
const CONFIG = {
	buildingCount: 120, // total buildings to generate
	minHeight: 40, // minimum building height (px)
	maxHeight: 260, // maximum building height (px)
	minWidth: 18, // minimum building footprint width (px)
	maxWidth: 50, // maximum building footprint width (px)
	buildingSpacing: 6, // gap between adjacent buildings (px)
	perspectiveAngle: 0.25, // perspective skew factor (0 = flat, 1 = extreme)
	wireframeColor: '0,220,255', // RGB string for building edges
	wireframeAlpha: 0.45, // base alpha for wireframe lines
	windowFlickerRate: 0.003, // probability per window per frame to toggle
	windowLightColor: '0,255,200', // RGB string for lit windows
	windowLightAlpha: 0.6, // alpha for lit window rectangles
	windowRows: 5, // max window rows per building face
	windowCols: 3, // max window cols per building face
	trafficCount: 8, // number of flying light streaks
	trafficSpeed: 180, // streak speed (px/s)
	trafficTrailLength: 60, // trail length behind streak (px)
	trafficColor: '255,100,255', // RGB for traffic streaks
	trafficAlpha: 0.7, // alpha for traffic streaks
	scanBeamAngle: 0, // initial scan beam angle (radians)
	scanBeamSpeed: 0.4, // scan beam rotation speed (rad/s)
	scanBeamAlpha: 0.08, // alpha of the scan beam wedge
	scanBeamArc: 0.35, // half-angle of the scan wedge (radians)
	scanBeamRadius: 900, // max reach of the scan beam (px)
	scanBeamColor: '0,255,180', // RGB for the scan beam
	depthFogStart: 0.3, // depth ratio where fog begins (0-1)
	depthFogEnd: 1.0, // depth ratio where objects become invisible
	spotlightRadius: 200, // radius of the mouse spotlight (px)
	spotlightIntensity: 0.5, // additional alpha added under spotlight
	gridColor: '0,200,220', // RGB for the ground grid
	gridAlpha: 0.07, // alpha for the ground grid lines
	gridSpacing: 40, // ground grid cell size (px)
	glowPasses: 3, // number of glow blur passes
	glowAlpha: 0.15 // alpha per glow pass
};

/* ───────────────────── STATE ───────────────────── */
let canvas, ctx, width, height;
let mouse = { x: -5000, y: -5000 };
let lastTime = 0;

// Building data — packed in typed arrays for performance
let buildingX; // Float32Array — x position of building center
let buildingY; // Float32Array — y base (ground line)
let buildingW; // Float32Array — footprint width
let buildingH; // Float32Array — height
let buildingDepth; // Float32Array — 0-1 depth for fog
let windowStates; // Uint8Array — flattened window on/off states
let buildingCount = 0;
const MAX_WINDOWS_PER_BUILDING = 30; // windowRows * windowCols * 2 faces

// Traffic streaks — object pool
let trafficPool = [];

// Scan beam
let scanAngle = CONFIG.scanBeamAngle;

// Glow layer
let glowCanvas, glowCtx;

/* ───────────────────── HELPERS ───────────────────── */
function rand(min, max) {
	return min + Math.random() * (max - min);
}
function randInt(min, max) {
	return (min + Math.random() * (max - min)) | 0;
}
function lerp(a, b, t) {
	return a + (b - a) * t;
}
function clamp(v, lo, hi) {
	return v < lo ? lo : v > hi ? hi : v;
}

/* ───────────────────── INIT ───────────────────── */
function initBuildings() {
	buildingCount = CONFIG.buildingCount;
	buildingX = new Float32Array(buildingCount);
	buildingY = new Float32Array(buildingCount);
	buildingW = new Float32Array(buildingCount);
	buildingH = new Float32Array(buildingCount);
	buildingDepth = new Float32Array(buildingCount);
	windowStates = new Uint8Array(buildingCount * MAX_WINDOWS_PER_BUILDING);

	// Lay buildings across width, randomly assign depth rows
	const depthRows = 4;
	for (let i = 0; i < buildingCount; i++) {
		const row = randInt(0, depthRows);
		const depth = row / (depthRows - 1); // 0 = front, 1 = back
		buildingDepth[i] = depth;
		const w = rand(CONFIG.minWidth, CONFIG.maxWidth) * (1 - depth * 0.4);
		const h = rand(CONFIG.minHeight, CONFIG.maxHeight) * (1 - depth * 0.3);
		buildingW[i] = w;
		buildingH[i] = h;
		buildingX[i] = rand(-50, width + 50);
		// Ground line shifts up with depth (perspective)
		const groundY = height * 0.75 - depth * height * 0.25;
		buildingY[i] = groundY;

		// Init windows randomly
		const wCount = CONFIG.windowCols * CONFIG.windowRows * 2;
		const base = i * MAX_WINDOWS_PER_BUILDING;
		for (let j = 0; j < wCount; j++) {
			windowStates[base + j] = Math.random() < 0.3 ? 1 : 0;
		}
	}

	// Sort by depth (back-to-front) so nearer buildings draw on top
	const indices = Array.from({ length: buildingCount }, (_, i) => i);
	indices.sort((a, b) => buildingDepth[b] - buildingDepth[a]);
	const sortArrays = (src) => {
		const tmp = new Float32Array(buildingCount);
		for (let i = 0; i < buildingCount; i++) tmp[i] = src[indices[i]];
		src.set(tmp);
	};
	sortArrays(buildingX);
	sortArrays(buildingY);
	sortArrays(buildingW);
	sortArrays(buildingH);
	sortArrays(buildingDepth);
	// Also sort window states
	const tmpW = new Uint8Array(buildingCount * MAX_WINDOWS_PER_BUILDING);
	for (let i = 0; i < buildingCount; i++) {
		const srcBase = indices[i] * MAX_WINDOWS_PER_BUILDING;
		const dstBase = i * MAX_WINDOWS_PER_BUILDING;
		for (let j = 0; j < MAX_WINDOWS_PER_BUILDING; j++) {
			tmpW[dstBase + j] = windowStates[srcBase + j];
		}
	}
	windowStates = tmpW;
}

function initTraffic() {
	trafficPool.length = 0;
	for (let i = 0; i < CONFIG.trafficCount; i++) {
		trafficPool.push(spawnTraffic());
	}
}

function spawnTraffic() {
	const startX = rand(-100, width + 100);
	const endX = rand(-100, width + 100);
	const y = rand(height * 0.15, height * 0.55);
	const depth = rand(0.1, 0.9);
	return {
		x: startX,
		y: y,
		startX: startX,
		endX: endX,
		startY: y,
		endY: y + rand(-60, 60),
		depth: depth,
		t: 0,
		speed: CONFIG.trafficSpeed * rand(0.6, 1.4),
		active: true,
		trail: new Float32Array(CONFIG.trafficTrailLength * 2), // x,y pairs
		trailLen: 0
	};
}

function initGlow() {
	glowCanvas = new OffscreenCanvas(width >> 1, height >> 1);
	glowCtx = glowCanvas.getContext('2d');
}

/* ───────────────────── UPDATE ───────────────────── */
function updateWindows() {
	const rate = CONFIG.windowFlickerRate;
	const total = buildingCount * MAX_WINDOWS_PER_BUILDING;
	for (let i = 0; i < total; i++) {
		if (Math.random() < rate) {
			windowStates[i] = windowStates[i] ? 0 : 1;
		}
	}
}

function updateTraffic(dt) {
	for (let i = 0; i < trafficPool.length; i++) {
		const t = trafficPool[i];
		const dist = Math.hypot(t.endX - t.startX, t.endY - t.startY);
		const duration = dist / t.speed;
		t.t += dt / duration;
		t.x = lerp(t.startX, t.endX, clamp(t.t, 0, 1));
		t.y = lerp(t.startY, t.endY, clamp(t.t, 0, 1));

		// Push to trail
		if (t.trailLen < CONFIG.trafficTrailLength) {
			t.trail[t.trailLen * 2] = t.x;
			t.trail[t.trailLen * 2 + 1] = t.y;
			t.trailLen++;
		} else {
			// Shift trail
			t.trail.copyWithin(0, 2);
			t.trail[(t.trailLen - 1) * 2] = t.x;
			t.trail[(t.trailLen - 1) * 2 + 1] = t.y;
		}

		if (t.t >= 1) {
			// Respawn
			const spawned = spawnTraffic();
			Object.assign(t, spawned);
		}
	}
}

/* ───────────────────── DRAW ───────────────────── */
function drawGrid() {
	const gs = CONFIG.gridSpacing;
	ctx.strokeStyle = `rgba(${CONFIG.gridColor},${CONFIG.gridAlpha})`;
	ctx.lineWidth = 0.5;
	ctx.beginPath();
	// Horizontal lines fanning out with perspective
	for (let y = height * 0.5; y <= height; y += gs) {
		ctx.moveTo(0, y);
		ctx.lineTo(width, y);
	}
	// Vertical lines converging to vanishing point
	const vanishX = width * 0.5;
	const vanishY = height * 0.3;
	const bottom = height;
	for (let x = 0; x <= width; x += gs) {
		ctx.moveTo(x, bottom);
		const t = 0.6;
		ctx.lineTo(lerp(x, vanishX, t), lerp(bottom, vanishY, t));
	}
	ctx.stroke();
}

function drawBuildings() {
	const pa = CONFIG.perspectiveAngle;
	const spotR = CONFIG.spotlightRadius;
	const spotI = CONFIG.spotlightIntensity;

	for (let i = 0; i < buildingCount; i++) {
		const bx = buildingX[i];
		const by = buildingY[i];
		const bw = buildingW[i];
		const bh = buildingH[i];
		const depth = buildingDepth[i];

		// Off-screen culling
		if (bx + bw < -20 || bx - bw > width + 20) continue;

		// Depth fog
		const fogT = clamp(
			(depth - CONFIG.depthFogStart) / (CONFIG.depthFogEnd - CONFIG.depthFogStart),
			0,
			1
		);
		const alphaScale = 1 - fogT * 0.85;
		if (alphaScale < 0.02) continue;

		// Spotlight boost
		const dx = bx - mouse.x;
		const dy = by - bh * 0.5 - mouse.y;
		const distToMouse = Math.sqrt(dx * dx + dy * dy);
		const spotBoost = distToMouse < spotR ? (1 - distToMouse / spotR) * spotI : 0;

		const alpha = clamp(CONFIG.wireframeAlpha * alphaScale + spotBoost, 0, 1);

		// Perspective offset for top edges
		const topOffset = bw * pa * (1 - depth * 0.5);

		// Front face
		const flx = bx - bw * 0.5;
		const frx = bx + bw * 0.5;
		const fty = by - bh;
		const fby = by;

		// Top face (perspective receding right)
		const trx = frx + topOffset;
		const tty = fty - topOffset * 0.3;

		ctx.strokeStyle = `rgba(${CONFIG.wireframeColor},${alpha.toFixed(3)})`;
		ctx.lineWidth = 1 + (1 - depth) * 0.5;

		// Draw front face
		ctx.beginPath();
		ctx.moveTo(flx, fby);
		ctx.lineTo(flx, fty);
		ctx.lineTo(frx, fty);
		ctx.lineTo(frx, fby);
		ctx.closePath();
		ctx.stroke();

		// Draw top face
		ctx.beginPath();
		ctx.moveTo(flx, fty);
		ctx.lineTo(flx + topOffset, tty);
		ctx.lineTo(trx, tty);
		ctx.lineTo(frx, fty);
		ctx.closePath();
		ctx.stroke();

		// Draw right side face
		ctx.beginPath();
		ctx.moveTo(frx, fty);
		ctx.lineTo(trx, tty);
		ctx.lineTo(trx, tty + bh);
		ctx.lineTo(frx, fby);
		ctx.closePath();
		ctx.stroke();

		// Windows on front face
		const wRows = Math.min(CONFIG.windowRows, Math.floor(bh / 20));
		const wCols = Math.min(CONFIG.windowCols, Math.floor(bw / 12));
		const winW = (bw / (wCols + 1)) * 0.5;
		const winH = (bh / (wRows + 1)) * 0.4;
		const base = i * MAX_WINDOWS_PER_BUILDING;
		const winAlpha = clamp(CONFIG.windowLightAlpha * alphaScale + spotBoost * 0.5, 0, 1);

		for (let r = 0; r < wRows; r++) {
			for (let c = 0; c < wCols; c++) {
				const idx = base + r * wCols + c;
				if (!windowStates[idx]) continue;
				const wx = flx + (c + 1) * (bw / (wCols + 1)) - winW * 0.5;
				const wy = fty + (r + 1) * (bh / (wRows + 1)) - winH * 0.5;
				ctx.fillStyle = `rgba(${CONFIG.windowLightColor},${winAlpha.toFixed(3)})`;
				ctx.fillRect(wx, wy, winW, winH);
			}
		}

		// Windows on right side face
		for (let r = 0; r < wRows; r++) {
			for (let c = 0; c < wCols; c++) {
				const idx = base + CONFIG.windowRows * CONFIG.windowCols + r * wCols + c;
				if (!windowStates[idx]) continue;
				const sideW = topOffset * 0.8;
				if (sideW < 4) continue;
				const swCols = Math.min(wCols, Math.floor(sideW / 8));
				if (c >= swCols) continue;
				const wx = frx + (c + 1) * (topOffset / (swCols + 1));
				const ryOffset = -((c + 1) * (topOffset / (swCols + 1))) * 0.3;
				const wy = fty + ryOffset + (r + 1) * (bh / (wRows + 1)) - winH * 0.5;
				ctx.fillStyle = `rgba(${CONFIG.windowLightColor},${(winAlpha * 0.7).toFixed(3)})`;
				ctx.fillRect(wx, wy, winW * 0.7, winH);
			}
		}
	}
}

function drawTraffic() {
	for (let i = 0; i < trafficPool.length; i++) {
		const t = trafficPool[i];
		if (t.trailLen < 2) continue;

		ctx.lineWidth = 2;
		for (let j = 1; j < t.trailLen; j++) {
			const a = (j / t.trailLen) * CONFIG.trafficAlpha;
			ctx.strokeStyle = `rgba(${CONFIG.trafficColor},${a.toFixed(3)})`;
			ctx.beginPath();
			ctx.moveTo(t.trail[(j - 1) * 2], t.trail[(j - 1) * 2 + 1]);
			ctx.lineTo(t.trail[j * 2], t.trail[j * 2 + 1]);
			ctx.stroke();
		}

		// Bright head
		ctx.fillStyle = `rgba(${CONFIG.trafficColor},${CONFIG.trafficAlpha})`;
		ctx.beginPath();
		ctx.arc(t.x, t.y, 3, 0, Math.PI * 2);
		ctx.fill();
	}
}

function drawScanBeam(dt) {
	scanAngle += CONFIG.scanBeamSpeed * dt;
	if (scanAngle > Math.PI * 2) scanAngle -= Math.PI * 2;

	const cx = mouse.x > -1000 ? mouse.x : width * 0.5;
	const cy = mouse.y > -1000 ? mouse.y : height * 0.4;
	const r = CONFIG.scanBeamRadius;
	const arc = CONFIG.scanBeamArc;

	// Draw wedge
	const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, r);
	grad.addColorStop(0, `rgba(${CONFIG.scanBeamColor},${CONFIG.scanBeamAlpha * 2})`);
	grad.addColorStop(0.5, `rgba(${CONFIG.scanBeamColor},${CONFIG.scanBeamAlpha})`);
	grad.addColorStop(1, `rgba(${CONFIG.scanBeamColor},0)`);

	ctx.fillStyle = grad;
	ctx.beginPath();
	ctx.moveTo(cx, cy);
	ctx.arc(cx, cy, r, scanAngle - arc, scanAngle + arc);
	ctx.closePath();
	ctx.fill();

	// Leading edge line
	ctx.strokeStyle = `rgba(${CONFIG.scanBeamColor},${CONFIG.scanBeamAlpha * 4})`;
	ctx.lineWidth = 1.5;
	ctx.beginPath();
	ctx.moveTo(cx, cy);
	ctx.lineTo(cx + Math.cos(scanAngle) * r, cy + Math.sin(scanAngle) * r);
	ctx.stroke();
}

function drawGlow() {
	if (!glowCtx) return;
	const gw = glowCanvas.width;
	const gh = glowCanvas.height;
	glowCtx.clearRect(0, 0, gw, gh);
	glowCtx.drawImage(canvas, 0, 0, gw, gh);

	for (let p = 0; p < CONFIG.glowPasses; p++) {
		ctx.save();
		ctx.globalAlpha = CONFIG.glowAlpha;
		ctx.globalCompositeOperation = 'lighter';
		ctx.drawImage(glowCanvas, 0, 0, width, height);
		ctx.restore();
	}
}

/* ───────────────────── ANIMATION ───────────────────── */
function startAnimation() {
	lastTime = performance.now();

	function render(now) {
		if (!ctx) return;
		const dt = Math.min((now - lastTime) / 1000, 0.05); // cap delta time
		lastTime = now;

		ctx.clearRect(0, 0, width, height);

		// Layer 1: Ground grid
		drawGrid();

		// Layer 2: Scan beam (behind buildings)
		drawScanBeam(dt);

		// Layer 3: Buildings with windows
		updateWindows();
		drawBuildings();

		// Layer 4: Traffic streaks
		updateTraffic(dt);
		drawTraffic();

		// Layer 5: Glow post-process
		drawGlow();

		requestAnimationFrame(render);
	}
	requestAnimationFrame(render);
}

/* ───────────────────── HEARTBEAT ───────────────────── */
setInterval(() => {
	self.postMessage({ type: 'heartbeat' });
}, 1000);

/* ───────────────────── MESSAGES ───────────────────── */
self.onmessage = (e) => {
	switch (e.data.type) {
		case 'init':
			canvas = e.data.canvas;
			ctx = canvas.getContext('2d');
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initGlow();
			initBuildings();
			initTraffic();
			startAnimation();
			break;
		case 'resize':
			width = e.data.width;
			height = e.data.height;
			canvas.width = width;
			canvas.height = height;
			initGlow();
			initBuildings();
			initTraffic();
			break;
		case 'mousemove':
			mouse.x = e.data.x;
			mouse.y = e.data.y;
			break;
	}
};
